window.HADITH_CACHE["ahmad_6"] = {"3001":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَوَهْبُ بْنُ جَرِيرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَ سَمِعْتُ إِيَاسَ بْنَ قَتَادَةَ يُحَدِّثُ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَأَتَيْتُ الْمَدِينَةَ لِلُقِيِّ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَكُنْ فِيهِمْ رَجُلٌ أَلْقَاهُ أَحَبَّ إِلَيَّ مِنْ أُبَيٍّ فَأُقِيمَتْ الصَّلَاةُ وَخَرَجَ عُمَرُ مَعَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ فِي الصَّفِّ الْأَوَّلِ فَجَاءَ رَجُلٌ فَنَظَرَ فِي وُجُوهِ الْقَوْمِ فَعَرَفَهُمْ غَيْرِي فَنَحَّانِي وَقَامَ فِي مَكَانِي فَمَا عَقِلْتُ صَلَاتِي فَلَمَّا صَلَّى قَالَ يَا بُنَيَّ لَا يَسُوءُكَ اللَّهُ فَإِنِّي لَمْ آتِكَ الَّذِي أَتَيْتُكَ بِجَهَالَةٍ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا كُونُوا فِي الصَّفِّ الَّذِي يَلِينِي وَإِنِّي نَظَرْتُ فِي وُجُوهِ الْقَوْمِ فَعَرَفْتُهُمْ غَيْرَكَ ثُمَّ حَدَّثَ فَمَا رَأَيْتُ الرِّجَالَ مَتَحَتْ أَعْنَاقَهَا إِلَى شَيْءٍ مُتُوحَهَا إِلَيْهِ قَالَ سَمِعْتُهُ يَقُولُ هَلَكَ أَهْلُ الْعُقْدَةِ وَرَبِّ الْكَعْبَةِ أَلَا لَا عَلَيْهِمْ آسَى وَلَكِنْ آسَى عَلَى مَنْ يَهْلِكُونَ مِنْ الْمُسْلِمِينَ وَإِذَا هُوَ أُبَيٌّ وَالْحَدِيثُ عَلَى لَفْظِ سُلَيْمَانَ بْنِ دَاوُدَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud] dan [Wahab bin Jarir] keduanya berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] berkata, Aku mendengar [Iyas bin Qatadah] menceritakan dari [Qais bin Ubad] dia berkata, \"Aku datang ke Madinah untuk bertemu para sahabat Muhammad Shallalahu 'Alaihi Wasallam, dan tidak ada seorangpun dari mereka yang aku temui yang lebih aku cintai ketimbang [Ubay]. Kemudian ditegakkanlah shalat dan Umar keluar bersama para sahabat Rasulullah shallallahu 'alaihi wasallam, aku lalu berdiri di barisan pertama. Namun kemudian datanglah seorang lelaki seraya memandang ke wajah orang-orang, dan dia (seperti telah) mengenal mereka semua selain aku, kemudian dia menggeserku dan berdiri di tempatku, maka aku tidak mengingat shalatku. Ketika selesai shalat dia berkata, \"Wahai anakku, Allah tidak berbuat jahat padamu dan aku tidak datang kepadamu dengan ketidak-tahuan, akan tetapi Rasulullah shallallahu 'alaihi wasallam telah bersabda kepada kami: 'Jadilah kalian berada di barisan yang di belakangku!, ' dan sesungguhnya aku melihat ke wajah orang-orang dan aku mengenal mereka kecuali kamu.\" Kemudian dia (perawi) menceritakan, \"Aku tidak melihat para lelaki yang merendah punggungnya dengan rendah melebihinya, orang itu pun berkata, \"Aku mendengar beliau bersabda: \"Binasalah ahlul 'Uqdah (orang yang memiliki perjanjian), demi Rabb pemilik Ka'bah, ketahuilah bukan kepada mereka aku kasihan akan tetapi aku kasihan kepada orang orang muslim yang binasa.\" Dan ternyata orang itu adalah Ubay.\" -Hadits ini adalah lafadz Sulaiman bin Daud-."},"3002":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ سَمِعْتُ أَبَا إِسْحَاقَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي بَصِيرٍ يُحَدِّثُ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّهُ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَقَالَ شَاهِدٌ فُلَانٌ فَقَالُوا لَا فَقَالَ شَاهِدٌ فُلَانٌ فَقَالُوا لَا فَقَالَ شَاهِدٌ فُلَانٌ فَقَالُوا لَا فَقَالَ إِنَّ هَاتَيْنِ الصَّلَاتَيْنِ مِنْ أَثْقَلِ الصَّلَوَاتِ عَلَى الْمُنَافِقِينَ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا وَالصَّفُّ الْمُقَدَّمُ عَلَى مِثْلِ صَفِّ الْمَلَائِكَةِ وَلَوْ تَعْلَمُونَ فَضِيلَتَهُ لَابْتَدَرْتُمُوهُ وَصَلَاةُ الرَّجُلِ مَعَ الرَّجُلَيْنِ أَزْكَى مِنْ صَلَاتِهِ مَعَ رَجُلٍ وَمَا كَانَ أَكْثَرَ فَهُوَ أَحَبُّ إِلَى اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] aku mendengar [Abu Ishaq] bahwa ia mendengar [Abdullah bin Abu Bashir] menceritakan dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat shubuh, kemudian beliau bertanya: \"Apakah ada yang melihat fulan?\" Para sahabat menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah ada yang melihat fulan?\" Para sahabat menjawab; \"Tidak.\" Beliau bertanya yang ketiga kalinya: \"Apakah ada yang melihat fulan?\" Para sahabat menjawab, \"Tidak.\" Kemudian beliau bersabda: \"Sesungguhnya dua shalat ini (subuh dan isya) adalah shalat yang paling berat bagi orang-orang munafik, seandainya mereka mengetahui apa yang ada dalam shalat shubuh niscaya mereka akan mendatanginya sekalipun dengan merangkak, dan shaf (barisan) pertama adalah seperti shafnya para Malaikat. Seandainya kalian mengetahui keutamaannya niscaya kalian akan bersegera mendatanginya, shalatnya seseorang bersama dua orang adalah lebih baik ketimbang dengan satu orang, dan semakin banyak jumlahnya akan lebih dicintai oleh Allah Tabaaraka Wa Ta'ala.\""},"3003":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ فَلَمَّا صَلَّى قَالَ شَاهِدٌ فُلَانٌ فَسَكَتَ الْقَوْمُ قَالُوا نَعَمْ وَلَمْ يَحْضُرْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَثْقَلَ الصَّلَاةِ عَلَى الْمُنَافِقِينَ صَلَاةُ الْعِشَاءِ وَالْفَجْرِ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا وَإِنَّ الصَّفَّ الْأَوَّلَ عَلَى مِثْلِ صَفِّ الْمَلَائِكَةِ وَلَوْ تَعْلَمُونَ فَضِيلَتَهُ لَابْتَدَرْتُمُوهُ إِنَّ صَلَاتَكَ مَعَ رَجُلَيْنِ أَزْكَى مِنْ صَلَاتِكَ مَعَ رَجُلٍ وَصَلَاتَكَ مَعَ رَجُلٍ أَزْكَى مِنْ صَلَاتِكَ وَحْدَكَ وَمَا كَثُرَ فَهُوَ أَحَبُّ إِلَى اللَّهِ تَعَالَىقَالَ أَبِي قَالَ وَكِيعٌ عَبْدُ اللَّهِ بْنُ أَبِي بَصِيرٍ عَنْمِيٌّ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ قَالَ أَبُو إِسْحَاقَ وَقَدْ سَمِعْتُهُ مِنْهُ وَمِنْ أَبِيهِ قَالَ سَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ يَوْمًا فَذَكَرَ الْحَدِيثَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ حَدَّثَنَا أَبُو عَوْنٍ الزِّيَادِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا أَبُو كَامِلٍ مُظَفَّرُ بْنُ مُدْرِكٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ قَالَ قَدِمْتُ الْمَدِينَةَ فَلَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَقُلْتُ أَبَا الْمُنْذِرِ حَدِّثْنِي أَعْجَبَ حَدِيثٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلَّى بِنَا أَوْ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْغَدَاةِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ شَاهِدٌ فُلَانٌ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ قَالَ قَدِمْتُ الْمَدِينَةَ فَلَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَذَكَرَ مِثْلَ ذَلِكَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا شَيْبَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ أَبِي بَصِيرٍ الْعَبْدِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ صَلَّى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَدَاةَ ثُمَّ قَالَ شَاهِدٌ فُلَانٌ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat subuh, selesai shalat beliau bertanya: \"Apakah ada yang melihat fulan?\" para sahabat terdiam, lalu mereka menjawab, \"Ya.\" Dan sahabat tersebut tidak hadir. Kemudian beliau bersabda: \"Sesungguhnya shalat yang paling berat bagi orang-orang munafik adalah shalat Isya dan subuh, seandainya mereka mengetahui keutamaan yang ada dalam dua shalat tersebut, niscaya mereka akan mendatanginya sekalipun dengan merangkak. Shaf (barisan) pertama adalah seperti shafnya para Malaikat, seandainya kalian mengetahui keutamaannya niscaya kalian akan bersegera menyongsongnya. Sungguh, shalatnya seseorang bersama dua orang adalah lebih baik ketimbang dengan satu orang, dan shalatnya seseorang dengan seorang adalah lebih baik dari ia shalat sendirian, semakin banyak jumlahnya akan lebih dicintai oleh Allah Tabaraka Wa Ta'ala.\" Bapakku berkata; Waki' berkata; yaitu Abdullah bin Abu Bashir 'Anmiy. Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Khalid bin Harits] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayahnya], [Abu Ishaq] berkata, telah mendengar darinya dan dari [Ayahnya] ia berkata; Aku mendengar [Ubay bin Ka'ab] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat subuh di suatu hari…lalu ia sebutkan hadits tersebut.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bakar Muhammad bin Abdullah bin Ja'far] telah menceritakan kepada kami [Abu 'Aun Az Ziyadi] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Al A'masy] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayahnya] dari [Ubai bin Ka'ab] dari Nabi shallallahu 'alaihi wasallam…lalu ia sebutkan hadits tersebut.\" Telah menceritakan kepada kami [Abu Kamil Muzhaffar bin Mudrik] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayahnya] berkata, \"Aku datang ke Madinah dan bertemu dengan [Ubay bin Ka'ab], lalu aku bertanya padanya, 'Wahai Abu Mundzir, kabarkan kepadaku hadits yang paling berkesan yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam.' Lalu ia menjawab, 'Kami pernah shalat subuh bersama Rasulullah, lalu beliau menghadapkan wajahnya pada kami seraya bersabda: \"Apakah ada yang melihat fulan?....lalu ia sebutkan hadits tersebut.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Yahya bin Abdullah] mantan budak Bani Hasyim, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayahnya] berkata, \"Sesampai aku di Madinah, aku menjumpai [Ubay bin Ka'b] …lalu ia sebutkan semisal hadits tersebut.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Syaiban bin Abu Syaibah] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Abu Ishaq] dari [Abu Bashir Al 'Abdi] dari [Ubay bin Ka'ab] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat subuh lalu bertanya: \"Apakah ada yang melihat fulan? …lalu ia sebutkan hadits itu.\""},"3004":{"ar":"حَدَّثَنَا شَيْبَانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ أَبِي إِسْحَاقَ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي الْعِشَاءِ وَصَلَاةِ الْغَدَاةِ مِنْ الْفَضْلِ فِي جَمَاعَةٍ لَأَتَوْهُمَا وَلَوْ حَبْوًاحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ الْبَزَّارُ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَاقَ عَنْ الْعَيْزَارِ بْنِ حُرَيْثٍ عَنْ أَبِي بَصِيرٍ قَالَ قَالَ أُبَيٌّ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ فَلَمَّا قَضَى الصَّلَاةَ رَأَى مِنْ أَهْلِ الْمَسْجِدِ قِلَّةً فَقَالَ شَاهِدٌ فُلَانٌ قُلْنَا نَعَمْ حَتَّى عَدَّ ثَلَاثَةَ نَفَرٍ فَقَالَ إِنَّهُ لَيْسَ مِنْ صَلَاةٍ أَثْقَلُ عَلَى الْمُنَافِقِينَ مِنْ صَلَاةِ الْعِشَاءِ الْآخِرَةِ وَمِنْ صَلَاةِ الْفَجْرِ وَذَكَرَ الْحَدِيثَ بِطُولِهِ","id":"Telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Al Hajjaj bin Arthah] dari [Abu Ishaq Al Hamdani] dari [Abdullah bin Abu Bashir] dari [Ubay bin Ka'ab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah manusia mengetahui apa yang ada dalam shalat Isya dan shubuh berupa keutamaan shalat berjamaah, niscaya mereka akan mendatanginya sekalipun dengan merangkak.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Khalaf bin Hisyam Al Bazzar] dan [Abu Bakar bin Abu Syaibah] ia berkata; telah menceritakan kepada kami [Abu Ahwash] dari [Abu Ishaq] dari [Al 'Aizar bin Huraits] dari [Abu Bashir] ia berkata; [Ubay] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami di waktu subuh, selesai shalat beliau menyaksikan yang menghadiri shalat hanya sedikit, lalu beliau bertanya: \"Apakah ada yang melihat fulan?\" Kami menjawab, \"Ya.\" Hingga kami sebutkan tiga orang diantaranya, beliau bersabda: \"Tiada shalat yang paling berat dikerjakan orang-orang munafik ketimbang shalat yang terakhir, yaitu Isya dan shalat subuh.\" Lalu ia sebutkan hadits tersebut."},"3005":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا حُبَابٌ الْقُطَعِيُّ عَنْ أَبِي إِسْحَاقَ الْهَمْدَانِيِّ عَنْ رَجُلٍ مِنْ عَبْدِ الْقَيْسِ عَنْ أُبِيٍّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا قَضَى صَلَاتَهُ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ ثُمَّ قَالَ إِنَّ أَثْقَلَ الصَّلَوَاتِ عَلَى الْمُنَافِقِينَ هَاتَانِ الصَّلَاتَانِ","id":"Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Ja'far bin Sulaiman] telah menceritakan kepada kami [Hubbab Al Qutha'i] dari [Abu Ishaq Al Hamdani] dari [seorang laki-laki] bani Abdu Qais, dari [Ubay] ia berkata, \"Kami shalat subuh bersama Rasulullah shallallahu 'alaihi wasallam, seusai shalat beliau menghadap ke arah kami dan bersabda: \"Sesungguhnya dua shalat ini adalah shalat yang paling berat bagi orang orang munafik.\""},"3006":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍ أَوْ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ بِمَقُولِ هُوَ اللَّهُ أَحَدٌ فَكَأَنَّمَا قَرَأَ بِثُلُثِ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Husyaim] dari [Hushain] dari [Hilal bin Yasaf] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b] dari salah seorang Lelaki Anshar dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca surat 'QUL HUWALLAAHU AHAD (Katakanlah Dialah Allah yang maha Esa) ', maka sakan akan dia telah membaca sepertiga Al Qur'an.\""},"3007":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ و حَدَّثَنَا عَبْد اللَّهِ قَالَ و حَدَّثَنِي وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ الْوَاسِطِيُّ قَالَ الثَّقَفِيُّ فِي حَدِيثِهِ حَدَّثَنَا أَبُو مَسْعُودٍ الْجُرَيْرِيُّ قَالَ وَهْبٌ أَخْبَرَنَا خَالِدٌ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ قَالَ قَالَ أُبَيُّ بْنُ كَعْبٍالصَّلَاةُ فِي الثَّوْبِ الْوَاحِدِ سُنَّةٌ كُنَّا نَفْعَلُهُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُعَابُ عَلَيْنَافَقَالَ ابْنُ مَسْعُودٍ إِنَّمَا كَانَ ذَاكَ إِذْ كَانَ فِي الثِّيَابِ قِلَّةٌ فَأَمَّا إِذْ وَسَّعَ اللَّهُ فَالصَّلَاةُ فِي الثَّوْبَيْنِ أَزْكَى","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi], telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Wahab bin Baqiyyah] telah mengabarkan kepada kami [Khalid Al Washithi], [Ats Tsaqafi] menyebutkan dalam haditsnya, telah menceritakan kepada kami [Abu Mas'ud Al Jurairi], [Wahab] berkata, telah mengabarkan kepada kami [Khalid] dari [Al Jurairi] dari [Abu Nadlrah] dia berkata, [Ubai bin Ka'b] berkata, \"Shalat dengan menggunakan satu pakaian adalah sunnah yang pernah kami lakukan bersama Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak mencela kami. Kemudian [Ibnu Mas'ud] berkata, \"Hanyasannya yang demikian itu dilakukan ketika pakaian hanya sedikit, adapun ketika Allah memberikan kelapangan maka shalat dengan menggunakan dua pakaian adalah lebih baik.\""},"3008":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَحَسَنُ بْنُ مُوسَى وَعَفَّانُ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ وَقَالَ عَفَّانُ أَخْبَرَنَا ثَابِتٌ عَنْ أَبِي رَافِعٍ عَنْ أُبَيِّ بْنِ كَعْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ فَسَافَرَ سَنَةً فَلَمْ يَعْتَكِفْ فَلَمَّا كَانَ الْعَامُ الْمُقْبِلُ اعْتَكَفَ عِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Hasan bin Musa] dan ['Affan] mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit], ['Affan] berkata, telah mengkabarkan kepada kami [Tsabit] dari [Abu Rafi'] dari [Ubay bin Ka'b] bahwa Rasulullah shallallahu 'alaihi wasallam, dan telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Abu Rafi'] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan I'tikaf pada sepuluh hari terakhir di bulan Ramadan, kemudian beliau pada suatu tahun melakukan safar (bepergian) sehigga tidak melaksanakan I'tikaf, maka ketika tahun berikutnya beliau melaksanakan I'tikaf selama dua puluh hari.\""},"3009":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ عُمَارَةَ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُصَدِّقًا عَلَى بَلِيٍّ وَعُذْرَةَ وَجَمِيعِ بَنِي سَعْدٍ وَهُذَيْمِ بْنِ قُضَاعَةَ قَالَ أَبِي وَقَالَ يَعْقُوبُ فِي مَوْضِعٍ آخَرَ مِنْ قُضَاعَةَ قَالَ فَصَدَّقْتُهُمْ حَتَّى مَرَرْتُ بِآخِرِ رَجُلٍ مِنْهُمْ وَكَانَ مَنْزِلُهُ وَبَلَدُهُ مِنْ أَقْرَبِ مَنَازِلِهِمْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ قَالَ فَلَمَّا جَمَعَ إِلَيَّ مَالَهُ لَمْ أَجِدْ عَلَيْهِ فِيهَا إِلَّا ابْنَةَ مَخَاضٍ يَعْنِي فَأَخْبَرْتُهُ أَنَّهَا صَدَقَتُهُ قَالَ فَقَالَ ذَاكَ مَا لَا لَبَنَ فِيهِ وَلَا ظَهْرَ وَايْمُ اللَّهِ مَا قَامَ فِي مَالِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا رَسُولٌ لَهُ قَطُّ قَبْلَكَ وَمَا كُنْتُ لِأُقْرِضَ اللَّهَ تَبَارَكَ وَتَعَالَى مِنْ مَالِي مَا لَا لَبَنَ فِيهِ وَلَا ظَهْرَ وَلَكِنْ هَذِهِ نَاقَةٌ فَتِيَّةٌ سَمِينَةٌ فَخُذْهَا قَالَ فَقُلْتُ لَهُ مَا أَنَا بِآخِذٍ مَا لَمْ أُومَرْ بِهِ فَهَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْكَ قَرِيبٌ فَإِنْ أَحْبَبْتَ أَنْ تَأْتِيَهُ فَتَعْرِضَ عَلَيْهِ مَا عَرَضْتَ عَلَيَّ فَافْعَلْ فَإِنْ قَبِلَهُ مِنْكَ قَبِلَهُ وَإِنْ رَدَّهُ عَلَيْكَ رَدَّهُ قَالَ فَإِنِّي فَاعِلٌ قَالَ فَخَرَجَ مَعِي وَخَرَجَ بِالنَّاقَةِ الَّتِي عَرَضَ عَلَيَّ حَتَّى قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ لَهُ يَا نَبِيَّ اللَّهِ أَتَانِي رَسُولُكَ لِيَأْخُذَ مِنِّي صَدَقَةَ مَالِي وَايْمُ اللَّهِ مَا قَامَ فِي مَالِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا رَسُولٌ لَهُ قَطُّ قَبْلَهُ فَجَمَعْتُ لَهُ مَالِي فَزَعَمَ أَنَّ عَلَيَّ فِيهِ ابْنَةَ مَخَاضٍ وَذَلِكَ مَا لَا لَبَنَ فِيهِ وَلَا ظَهْرَ وَقَدْ عَرَضْتُ عَلَيْهِ نَاقَةً فَتِيَّةً سَمِينَةً لِيَأْخُذَهَا فَأَبَى عَلَيَّ ذَلِكَ وَقَالَ هَا هِيَ هَذِهِ قَدْ جِئْتُكَ بِهَا يَا رَسُولَ اللَّهِ خُذْهَا قَالَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ الَّذِي عَلَيْكَ فَإِنْ تَطَوَّعْتَ بِخَيْرٍ قَبِلْنَاهُ مِنْكَ وَآجَرَكَ اللَّهُ فِيهِ قَالَ فَهَا هِيَ ذِهْ يَا رَسُولَ اللَّهِ قَدْ جِئْتُكَ بِهَا فَخُذْهَا قَالَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْضِهَا وَدَعَا لَهُ فِي مَالِهِ بِالْبَرَكَةِحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَاقَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ عَنْ عُمَارَةَ بْنِ حَزْمٍ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ مُصَدِّقًا فَذَكَرَ نَحْوَ حَدِيثِ أُبَيٍّ وَزَادَ فِيهِ قَالَ عُمَارَةُ وَقَدْ وُلِّيتُ صَدَقَاتِهِمْ فِي زَمَنِ مُعَاوِيَةَ فَأَخَذْتُ مِنْ ذَلِكَ الرَّجُلِ ثَلَاثِينَ حِقَّةً لِأَلْفٍ وَخَمْسِ مِائَةِ بَعِيرٍ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Abdullah bin Abu Bakar bin Muhammad bin Amru bin Hazam] dari [Yahya bin Abdullah bin Abdurrahman bin Sa'ad bin Zurarah] dari ['Umarah bin Amru bin Hazam] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mengutusku sebagai petugas pengumpul Zakat kepada kabilah Bali, 'Udzrah, seluruh Bani Sa'ad dan Hudzaim bin Qudla'ah.\" Abdullah berkata, Bapakku berkata, \"Dalam riwayat yang lain [Ya'qub] menyebutkan, \"dari Qudla'ah.\" Ubay melanjutkan, \"Maka aku pungut zakat dari mereka semuanya hingga giliran orang yang terakhir dari mereka yang kediamannya paling dekat dengan rumah Rasulullah shallallahu 'alaihi wasallam di Madinah.\" Ubay berkata, \"Maka selesai ia kumpulkan semua hartanya kepadaku, ternyata aku tidak mendapatkan sesuatu yang bisa aku ambil sebagai zakat kecuali unta betina yang masuk umur dua tahun, kemudian aku sampaikan kepadanya bahwa unta tersebutlah yang aku jadikan sebagai zakat.\" Ubay melanjutkan, \"Kemudian orang itu berkata, \"Unta itu tidak mengeluarkan susu dan tidak bisa di tunggangi sebagai kendaraan, demi Allah tidak pernah sama sekali Rasulullah shallallahu 'alaihi wasallam maupun utusannya sebelum kamu memungut zakat dari hartaku, dan aku tidak akan memberikan hartaku kepada Allah Tabaaraka Wa Ta'ala dan Rasul-Nya dengan unta yang tidak mengeluarkan susu dan tidak dapat ditunggangi, akan tetapi ini ada unta yang kekar dan gemuk maka ambillah (sebagai zakat)!\" Lanjut Ubay, \"Kemudian aku berkata, \"Saya tidak akan mengambilnya selama saya tidak diperintahkan untuk memungutnya, Rasulullah tinggal dekat denganmu jika kamu suka menemuinya maka tawarkanlah kepada beliau apa yang kamu tawarkan kepadaku, jika beliau menerima darimu maka akan diterima dan jika beliau menolak maka akan ditolak.\" Ubay berkata, \"Maka aku melakukannya dan dia keluar bersamaku dengan memmbawa unta yang ditawarkan kepadaku sampai kami tiba menemui Rasulullah shallallahu 'alaihi wasallam. Kemudian ia berkata kepada beliau, \"Wahai Nabiyallah, telah datang utusanmu kepadaku untuk memungut zakat dari hartaku, demi Allah tidak pernah sama sekali Rasulullah shallallahu 'alaihi wasallam maupun utusannya sebelum dia yang memungut dari hartaku, maka aku kumpulkan hartaku kepadanya, kemudian dia menganggap bahwa zakat yang harus dikeluarkan dari hartaku adalah anak unta betina yang masuk umur dua tahun, padahal unta tersebut tidak mengeluarkan susu dan tidak dapat ditunggangi sebagai kendaraan. Dan saya telah tawarkan kepadanya agar mengambil seekor unta yang kekar dan gemuk namun dia menolakku.\" Laki-laki itu lalu berkata, \"Wahai Rasulullah, inilah untanya, silahkah engkau ambil, aku membawakannya untukmu.\" Ubay berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Itulah (anak unta betina umur dua tahun) yang wajib bagimu dan jika kamu memberikan tambahan yang lebih baik maka kami menerimanya dan semoga Allah memberimu balasan pahala.\" Laki-laki itu berkata, \"Inilah wahai Rasulullah aku telah datangkan kepadamu maka ambillah dia!\" Ubay berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menerimanya dan beliau mendoakan keberkahan dalam hartanya.\" Telah menceritakan kepada kami Abdullah dia berkata telah menceritakan kepadaku [Muhammad bin Basyysar] dia berkata, telah menceritakan kepada kami [Wahab bin Jarir] dia berkata, telah menceritakan kepada kami [Bapakku] dia berkata, aku mendengar [Muhammad bin Ishaq] menceritakan dari [Abdullah bin Abu Bakar] dari [Yahya bin Abdullah] dari [Umarah bin Hazm] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam mengutusnya sebagai petugas pemungut zakat… kemudian dia menyebutkan hadits yang semakna dengan hadits Ubay. Lalu ia menambahkan di dalamnya, \"Umarah berkata, \"Sungguh aku telah diangkat sebagai petugas zakat pada masa pemerintahan Mu'awiyah, lalu aku mengambil dari laki-laki itu tiga puluh ekor unta betina yang berumur empat tahun dari seribu lima ratus ekor unta yang dia miliki.\""},"3010":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ الْجَارُودِ بْنِ أَبِي سَبْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ الْخُزَاعِيُّ فِي حَدِيثِهِ قَالَ أُبَيُّ بْنُ كَعْبٍ و حَدَّثَنَا عَبْد اللَّهِ بْن أَحْمَد حَدَّثَنَاه إِبْرَاهِيمُ بْنُ الْحَجَّاجِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ الْجَارُودِ بْنِ أَبِي سَبْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِالنَّاسِ فَتَرَكَ آيَةً فَقَالَ أَيُّكُمْ أَخَذَ عَلَيَّ شَيْئًا مِنْ قِرَاءَتِي فَقَالَ أُبَيٌّ أَنَا يَا رَسُولَ اللَّهِ تَرَكْتَ آيَةَ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَلِمْتُ إِنْ كَانَ أَحَدٌ أَخَذَهَا عَلَيَّ فَإِنَّكَ أَنْتَ هُوَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], dan [Abu Salamah Al Khuza'i] keduanya berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Al Jarud bin Abu Sabrah] dari [Ubay bin Ka'b], [Al Khuza'i] menyebutkan dalam haditsnya; [Ubay Abu Isa Ka'b] berkata, dan telah menceritakan kepada kami Abdullah bin Ahmad telah menceritakan kepada kami [Ibrahim bin Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Al Jarud bin Abu Sabrah] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam shalat bersama orang-orang, lalu tertinggalah satu ayat dan beliau bersabda: \"Siapa di antara kalian yang mengambil satu ayat dariku?\" Ubay berkata, \"Wahai Rasulullah, engkau meninggalkan ayat ini dan itu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tahu jika ada seseorang yang mengambilnya dariku, maka kamulah orangnya.\""},"3011":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا يُونُسُ عَنْ الْحَسَنِأَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ أَرَادَ أَنْ يَنْهَى عَنْ مُتْعَةِ الْحَجِّ فَقَالَ لَهُ أُبَيٌّ لَيْسَ ذَاكَ لَكَ قَدْ تَمَتَّعْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَنْهَنَا عَنْ ذَلِكَ فَأَضْرَبَ عَنْ ذَلِكَ عُمَرُ وَأَرَادَ أَنْ يَنْهَى عَنْ حُلَلِ الْحِبَرَةِ لِأَنَّهَا تُصْبَغُ بِالْبَوْلِ فَقَالَ لَهُ أُبَيٌّ لَيْسَ ذَلِكَ لَكَ قَدْ لَبِسَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَبِسْنَاهُنَّ فِي عَهْدِهِ","id":"Telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Yunus] dari [Al Hasan] dia berkata, \"Umar? radliallahu 'anhu hendak melarang dari haji tamattu', maka [Ubay] berkata kepadanya, \"Itu bukan kewenanganmu, sungguh kami telah melakukan haji tamatu' bersama Rasulullah shallallahu 'alaihi wasallam dan beliau tidak melarang hal itu.\" Kemudian Umar berpaling dari hal itu dan dia hendak melarang dari pakaian Al hibrah (kain yang berhias dengan sutera dan wool), sebab ia dicelup dengan menggunakan air seni, maka Ubay pun berkata kepadanya, \"Itu juga bukan hakmu karena Nabi Shallalahu 'Alaihi Wasallam telah memakainya dan kamipun ikut memakainya.\""},"3012":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ صَعْصَعَةَ بْنِ صُوحَانَ قَالَأَقْبَلَ هُوَ وَنَفَرٌ مَعَهُ فَوَجَدُوا سَوْطًا فَأَخَذَهُ صَاحِبُهُ فَلَمْ يَأْمُرُوهُ وَلَمْ يَنْهَوْهُ فَقَدِمْتُ الْمَدِينَةَ فَلَقِيَنَا أُبَيُّ بْنُ كَعْبٍ فَسَأَلْنَاهُ فَقَالَ وَجَدْتُ مِائَةَ دِينَارٍ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا حَوْلًا فَكَرَّرَ عَلَيْهِ حَتَّى ذَكَرَ أَحْوَالًا ثَلَاثَةً فَقُلْتُ يَا رَسُولَ اللَّهِ فَقَالَ شَأْنُكَ بِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] telah menceritakan kepada kami [Umarah bin Ghaziyah] dari [Salamah bin Kuhail] dari [Sha'sha'ah bin Shuhan] berkata, \"Bahwa ia dan beberapa orang bersama berangkat (safar), lalu mereka menemukan sebuah pecut, lantas salah seorang dari mereka mengambilnya, dan mereka tidak menyuruh atau melarangnya. Maka ketika aku tiba di Madinah, kami bertemu dengan [Ubay bin Ka'b] dan kami menanyakan hal itu kepadanya, Ubay pun menjawab, \"Aku menemukan seratus dinar di masa Rasulullah shallallahu 'alaihi wasallam, aku lalu menanyakan hal itu pada beliau, beliau menjawab: 'Umumkanlah setahun', beliau mengulangi kata setahun hingga tiga kali, maka aku pun berkata, 'Wahai Rasulullah'. Beliau memotong: 'Itu urusanmu'.\""},"3013":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي زَكَرِيَّا بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَعِيدٍ الرَّقَاشِيُّ الْخَزَّازُ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ ابْنِ الْفَضْلِ عَنْ أَبِي الْجَوْزَاءِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ اجْعَلْ بَيْنَ أَذَانِكَ وَإِقَامَتِكَ نَفَسًا يَفْرُغُ الْآكِلُ مِنْ طَعَامِهِ فِي مَهَلٍ وَيَقْضِي الْمُتَوَضِّئُ حَاجَتَهُ فِي مَهَلٍحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ أَخْبَرَنَا قُرَّةُ بْنُ حَبِيبٍ أَخْبَرَنَا مُعَارِكُ بْنُ عَبَّادٍ الْعَبْدِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْفَضْلِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْجَوْزَاءِ عَنْ أُبَيِّ بْنِ كَعْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا بِلَالُ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Zakaria bin Yahya bin Abdullah bin Abu Sa'id Ar Raqasyi Al Khazzaz] telah menceritakan kepada kami [Salam bin Qutaibah] telah menceritakan kepada kami [Malik bin Mighwal] dari [Ibnu Fadlal] dari [Abul Jauza`] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Bilal jadikan jarak antara adzan dan iqamatmu seperti seseorang yang sedang makan dengan santai hingga dia selesai dari makannya, dan seperti seseorang yang mengambil wudlu dengan santai sehingga dia selesai dari wudlunya.\" Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepadaku [Muhammad bin Abdurrahim Al Bazzaz] dia berkata, telah mengabarkan kepada kami [Qurrah bin Habib] dia berkata, telah mengabarkan kepada kami [Mu'arik bin Abbad Al 'Abdi] dia berkata, telah mengabarkan kepada kami [Abdullah bin Al Fadlal] dari [Abdullah bin Abul Al Jauza`] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Bilal… kemudian dia menyebutkan hadits yang semisalnya.\""},"3014":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ بْنِ مُحَمَّدٍ الْمُسَيَّبِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ يُونُسَ بْنِ يَزِيدَ قَالَ قَالَ ابْنُ شِهَابٍ قَالَ أَنَسُ بْنُ مَالِكٍ كَانَ أَبُو ذَرٍّ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُرِجَ سَقْفُ بَيْتِي وَأَنَا بِمَكَّةَ فَنَزَلَ جِبْرِيلُ عَلَيْهِ السَّلَام فَفَرَجَ صَدْرِي ثُمَّ غَسَلَهُ مِنْ مَاءِ زَمْزَمَ ثُمَّ جَاءَ بِطَسْتٍ مِنْ ذَهَبٍ مُمْتَلِئٍ حِكْمَةً وَإِيمَانًا فَأَفْرَغَهَا فِي صَدْرِي ثُمَّ أَطْبَقَهُ ثُمَّ أَخَذَ بِيَدِي فَعَرَجَ بِي إِلَى السَّمَاءِ فَلَمَّا جَاءَ السَّمَاءَ الدُّنْيَا فَافْتَتَحَ فَقَالَ مَنْ هَذَا قَالَ جِبْرِيلُ قَالَ هَلْ مَعَكَ أَحَدٌ قَالَ نَعَمْ مَعِي مُحَمَّدٌ قَالَ أُرْسِلَ إِلَيْهِ قَالَ نَعَمْ فَافْتَحْ فَلَمَّا عَلَوْنَا السَّمَاءَ الدُّنْيَا إِذَا رَجُلٌ عَنْ يَمِينِهِ أَسْوِدَةٌ وَعَنْ يَسَارِهِ أَسْوِدَةٌ وَإِذَا نَظَرَ قِبَلَ يَمِينِهِ تَبَسَّمَ وَإِذَا نَظَرَ قِبَلَ يَسَارِهِ بَكَى قَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالِابْنِ الصَّالِحِ قَالَ قُلْتُ لِجِبْرِيلَ عَلَيْهِ السَّلَام مَنْ هَذَا قَالَ هَذَا آدَمُ وَهَذِهِ الْأَسْوِدَةُ عَنْ يَمِينِهِ وَشِمَالِهِ نَسَمُ بَنِيهِ فَأَهْلُ الْيَمِينِ هُمْ أَهْلُ الْجَنَّةِ وَالْأَسْوِدَةُ الَّتِي عَنْ شِمَالِهِ أَهْلُ النَّارِ فَإِذَا نَظَرَ قِبَلَ يَمِينِهِ ضَحِكَ وَإِذَا نَظَرَ قِبَلَ شِمَالِهِ بَكَى قَالَ ثُمَّ عَرَجَ بِي جِبْرِيلُ عَلَيْهِ السَّلَام حَتَّى جَاءَ السَّمَاءَ الثَّانِيَةَ فَقَالَ لِخَازِنِهَا افْتَحْ فَقَالَ لَهُ خَازِنُهَا مِثْلَ مَا قَالَ خَازِنُ السَّمَاءِ الدُّنْيَا فَفَتَحَ لَهُ قَالَ أَنَسُ بْنُ مَالِكٍ فَذَكَرَ أَنَّهُ وَجَدَ فِي السَّمَوَاتِ آدَمَ وَإِدْرِيسَ وَمُوسَى وَعِيسَى وَإِبْرَاهِيمَ عَلَيْهِمْ الصَّلَاةُ وَالسَّلَامُ وَلَمْ يُثْبِتْ لِي كَيْفَ مَنَازِلُهُمْ غَيْرَ أَنَّهُ ذَكَرَ أَنَّهُ وَجَدَ آدَمَ فِي السَّمَاءِ الدُّنْيَا وَإِبْرَاهِيمَ فِي السَّمَاءِ السَّادِسَةِ قَالَ أَنَسٌ فَلَمَّا مَرَّ جِبْرِيلُ عَلَيْهِ السَّلَام وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِدْرِيسَ قَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالْأَخِ الصَّالِحِ قَالَ فَقُلْتُ مَنْ هَذَا قَالَ هَذَا إِدْرِيسُ قَالَ ثُمَّ مَرَرْتُ بِمُوسَى فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالْأَخِ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا مُوسَى ثُمَّ مَرَرْتُ بِعِيسَى فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالْأَخِ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا عِيسَى ابْنُ مَرْيَمَ قَالَ ثُمَّ مَرَرْتُ بِإِبْرَاهِيمَ فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالِابْنِ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا إِبْرَاهِيمُ عَلَيْهِ السَّلَامقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي ابْنُ حَزْمٍ أَنَّ ابْنَ عَبَّاسٍ وَأَبَا حَبَّةَ الْأَنْصَارِيَّ يَقُولَانِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عُرِجَ بِي حَتَّى ظَهَرْتُ بِمُسْتَوًى أَسْمَعُ صَرِيفَ الْأَقْلَامِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Ishaq bin Muhammad Al Musayyibi] telah menceritakan kepada kami [Anas bin Iyadl] dari [Yunus bin Yazid] berkata, [Ibnu Syihab] berkata, [Anas bin Malik] berkata, [Abu Dzar] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Atap rumahku terbuka sementara aku berada di Makkah, Jibril Alaihis Salam lalu turun dan membelah dadaku, kemudian ia mencucinya dengan air zamzam, kemudian ia membawa mangkuk besar dari emas, penuh dengan hikmah dan keimanan, lalu ditumpahkan ke dalam dadaku dan menutupnya kembali. Ia memegang tanganku dan membawaku ke langit dunia. Ketika aku tiba di langit dunia, berkatalah Jibril kepada penjaga langit, 'Bukalah.' Penjaga langit itu bertanya, 'Siapakah ini? ' Jibril menjawab, 'Ini Jibril.' Penjaga langit itu bertanya lagi, 'Apakah anda bersama seseorang? ' Jibril menjawab, 'Ya, aku bersama Muhammad shallallahu 'alaihi wasallam.' Penjaga langit itu bertanya, 'Apakah dia diutus? ' Jibril menjawab, 'Ya.' Ketika penjaga langit itu membuka, kami menaiki langit dunia. Tiba tiba ada seorang laki-laki duduk di sebelah kanannya ada hitam-hitam (banyak orang) dan di sebelah kirinya juga ada hitam-hitam (banyak orang). Jika memandang ke kanan, laki-laki itu tertawa, dan jika memandang ke sebelah kirinya laki-laki itu menangis, lalu ia berkata, 'Selamat datang Nabi yang saleh dan anak laki-laki yang saleh.' Aku lalu bertanya kepada Jibril, 'Siapakah orang ini? ' Jibril menjawab, 'Ini adalah Adam dan hitam-hitam yang di kanan dan kirinya adalah adalah jiwa anak cucunya. Yang di sebelah kanan dari mereka itu adalah penghuni surga, dan hitam-hitam yang di sebelah kirinya adalah penghuni neraka.' Apabila berpaling ke sebelah kanannya ia tertawa, dan apabila melihat ke sebelah kirinya ia menangis, sampai Jibril menaikkan aku ke langit yang ke dua. Kemudian Jibril berkata kepada penjaganya, 'Bukalah.' Berkatalah penjaga itu kepadanya seperti apa yang dikatakan oleh penjaga pertama, lalu penjaga itu membukakannya.\" [Anas bin Malik] berkata, \"Beliau menyebutkan bahwa di beberapa langit itu beliau bertemu dengan Adam, Idris, Musa, Isa, dan Ibrahim shalawatullahi alaihim, namun beliau tidak menetapkan bagaimana kedudukan (posisi) mereka, hanya saja beliau menyebutkan bahwa beliau bertemu dengan Adam di langit dunia dan Ibrahim di langit keenam.\" Anas melanjutkan, \"Ketika Jibril Alaihis Salam dan Nabi Muhammad shallallahu 'alaihi wasallam melewati Idris, Idris berkata, 'Selamat datang Nabi yang saleh dan saudara laki-laki yang saleh.' Aku (Rasulullah) bertanya, 'Siapakah ini? ' Jibril menjawab, 'Ini adalah Idris.' Aku melewati Musa lalu ia berkata, 'Selamat datang Nabi yang saleh dan saudara yang saleh.' Aku bertanya, 'Siapakah ini? ' Jibril menjawab, 'Ini adalah Musa.' Aku lalu melewati Isa dan ia berkata, 'Selamat datang saudara yang saleh dan Nabi yang saleh.' Aku bertanya, 'Siapakah ini? ' Jibril menjawab, 'Ini adalah Isa.' Aku lalu melewati Ibrahim, lalu ia berkata, 'Selamat datang Nabi yang saleh dan anak yang saleh.' Aku bertanya, 'Siapakah ini? ' Jibril menjawab, 'Ini adalah Ibrahim Alaisis Salam'.\" [Ibnu Syihab] berkata, [Ibnu Hazm] memberitahukan kepadaku bahwa [Ibnu Abbas] dan [Abu Habbah al-Anshari] keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku dibawa naik ke langit hingga sampai di Mustawa, dan aku mendengar goresan pena-pena.'"},"3015":{"ar":"قَالَ ابْنُ حَزْمٍ وَأَنَسُ بْنُ مَالِكٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى أُمَّتِي خَمْسِينَ صَلَاةً قَالَ فَرَجَعْتُ بِذَلِكَ حَتَّى أَمُرَّ عَلَى مُوسَى عَلَيْهِ السَّلَام فَقَالَ مَاذَا فَرَضَ رَبُّكَ تَبَارَكَ وَتَعَالَى عَلَى أُمَّتِكَ قُلْتُ فَرَضَ عَلَيْهِمْ خَمْسِينَ صَلَاةً فَقَالَ لِي مُوسَى عَلَيْهِ السَّلَام رَاجِعْ رَبَّكَ تَبَارَكَ وَتَعَالَى فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ قَالَ فَرَاجَعْتُ رَبِّي عَزَّ وَجَلَّ فَوَضَعَ شَطْرَهَا فَرَجَعْتُ إِلَى مُوسَى فَأَخْبَرْتُهُ فَقَالَ رَاجِعْ رَبَّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ قَالَ فَرَاجَعْتُ رَبِّي عَزَّ وَجَلَّ فَقَالَ هِيَ خَمْسٌ وَهِيَ خَمْسُونَ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ قَالَ فَرَجَعْتُ إِلَى مُوسَى عَلَيْهِ السَّلَام فَقَالَ رَاجِعْ رَبَّكَ فَقُلْتُ قَدْ اسْتَحْيَيْتُ مِنْ رَبِّي تَبَارَكَ وَتَعَالَى قَالَ ثُمَّ انْطَلَقَ بِي حَتَّى أَتَى بِي سِدْرَةَ الْمُنْتَهَى قَالَ فَغَشِيَهَا أَلْوَانٌ مَا أَدْرِي مَا هِيَ قَالَ ثُمَّ أُدْخِلْتُ الْجَنَّةَ فَإِذَا فِيهَا جَنَابِذُ اللُّؤْلُؤِ وَإِذَا تُرَابُهَا الْمِسْكُهَذَا آخِرُ مُسْنَدِ أُبَيِّ بْنِ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"[Ibnu Hazm] dan [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Tabaaraka Wa Ta'ala telah mewajibkan kepada ummatku lima puluh kali shalat. Kemudian aku kembali dengan membawa perintah itu sehingga ketika aku melewati Musa 'Alaihis Salam, dia bertanya, 'Apa yang diperintahkan oleh Rabbmu Tabaaraka Wa Ta'ala kepada umatmu?\" Aku menjawab: 'Allah memerintahkan kepada mereka shalat lima puluh kali.' Musa Alaihis Salam berkata kepadaku, 'Kembalilah kepada Rabbmu Tabaaraka Wa Ta'la (untuk minta keringanan) karena umatmu tidak akan mampu mengerjakan sebanyak itu.' Nabi melanjutkan: \"Kemudian aku kembali kepada Rabbku Azza Wa Jalla dan Allah mengurangi separuhnya, ' kemudian aku kembali kepada Musa dan mengabarkan kepadanya, ia pun berkata, 'Kembalilah kepada Rabbmu karena umatmu tidak akan mampu sebanyak itu'.\" Nabi bersabda: \"Kemudian aku kembali kepada Rabbku Azza Wa Jalla, maka Allah pun berfirman: 'Kewajiban itu menjadi lima kali shalat namun pahalanya seperti lima puluh kali shalat dan tidak akan berubah perkataan-Ku.' Nabi bersabda: \"Kemudian aku kembali kepada Musa 'Alaihis Salam dan dia berkata, 'Kembalilah kepada Rabbmu! ' Namun aku menjawab: 'Aku malu kepada Rabbku Tabaaraka Wa Ta'ala.' Nabi kembali bersabda: 'Kemudian aku berjalan sehingga sampailah di Sidratul Muntaha, maka tertutuplah (Sidratul Muntaha) dengan beberapa warna yang aku tidak mengetahui warna apakah itu. Kemudian aku dimasukkan ke dalam Surga yang di dalamnya ada kubah dari mutiara dan debunya dari minyak misik.\" -Ini adalah hadits terakhir dari Musnad Ubai bin Ka'b-."},"3016":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَبُو الْيَمَانِ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حُسَيْنٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي ذَرٍّ قَالَكُنْتُ أَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ آتِي الْمَسْجِدَ إِذَا أَنَا فَرَغْتُ مِنْ عَمَلِي فَأَضْطَجِعُ فِيهِ فَأَتَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا وَأَنَا مُضْطَجِعٌ فَغَمَزَنِي بِرِجْلِهِ فَاسْتَوَيْتُ جَالِسًا فَقَالَ لِي يَا أَبَا ذَرٍّ كَيْفَ تَصْنَعُ إِذَا أُخْرِجْتَ مِنْهَا فَقُلْتُ أَرْجِعُ إِلَى مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَى بَيْتِي قَالَ فَكَيْفَ تَصْنَعُ إِذَا أُخْرِجْتَ فَقُلْتُ إِذَنْ آخُذَ بِسَيْفِي فَأَضْرِبَ بِهِ مَنْ يُخْرِجُنِي فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى مَنْكِبِي فَقَالَ غَفْرًا يَا أَبَا ذَرٍّ ثَلَاثًا بَلْ تَنْقَادُ مَعَهُمْ حَيْثُ قَادُوكَ وَتَنْسَاقُ مَعَهُمْ حَيْثُ سَاقُوكَ وَلَوْ عَبْدًا أَسْوَدَ قَالَ أَبُو ذَرٍّ فَلَمَّا نُفِيتُ إِلَى الرَّبَذَةِ أُقِيمَتْ الصَّلَاةُ فَتَقَدَّمَ رَجُلٌ أَسْوَدُ كَانَ فِيهَا عَلَى نَعَمْ الصَّدَقَةِ فَلَمَّا رَآنِي أَخَذَ لِيَرْجِعَ وَلِيُقَدِّمَنِي فَقُلْتُ كَمَا أَنْتَ بَلْ أَنْقَادُ لِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku Ayahku telah menceritakan kepada kami [Hakam bin Nafi' Abu Yaman] telah mengabarkan kepada kami [Isma'il bin 'Ayyasy] dari [Abdullah bin Abu Husain] dari [Syahr bin Hausyab] dari [Abdurrahman bin Ghanam] dari [Abu Dzar] dia berkata, \"Aku membantu Nabi Shallalahu 'Alaihi Wasallam, seusai dari pekerjaan, aku datang ke Masjid dan berbaring. Suatu kali Nabi Shallalahu 'Alaihi Wasallam mendatangiku namun aku sedang berbaring, beliau mengusik-usikku dengan kakinya sehingga aku bangun dan duduk. Beliau bertanya kepadaku: \"Wahai Abu Dzar, apa yang akan kamu lakukan jika kamu diusir darinya?\" Aku menjawab, \"Aku kembali ke masjid Nabi Shallalahu 'Alaihi Wasallam dan ke rumahku.\" Nabi bertanya lagi: \"Bagaimana jika mereka mengusirmu darinya?\" Abu Dzar menjawab, \"Kalau begitu aku mengangkat senjata dan menebas leher orang-orang yang mengusirku.\" Kemudian Nabi shallallahu 'alaihi wasallam meletakkan tangannya di atas pundakku sambil bersabda: \"Semoga kamu mendapat ampunan wahai Abu Dzar (beliau ucapkan hingga tiga kali), bahkan kamu harus tunduk kepada mereka kemanapun mereka membawamu dan kamu patuh kepada mereka kemanapun mereka memerintahkanmu, sekalipun yang memerintah adalah seorang budak yang hitam.\" Abu Dzar berkata, \"Hingga ketika Rabadzah tak terlihat lagi, shalatpun ditegakkan dan majulah salah seorang lelaki hitam yang menggembala unta hasil zakat, namun ketika melihatku dia kembali ke belakang dan mendorongku ke depan. Maka aku berkata, \"Kamu tetap seperti semula (yaitu maju memimpin shalat) karena aku tunduk kepada perintah Rasulullah shallallahu 'alaihi wasallam.\""},"3017":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ مُعَانِ بْنِ رِفَاعَةَ عَنْ أَبِي خَلَفٍ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْإِسْلَامُ ذَلُولٌ لَا يَرْكَبُ إِلَّا ذَلُولًا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami Ayahku telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Mu'an bin Rifa'ah] dari [Abu Khalaf] dari [Anas bin Malik] dari [Abu Dzar] dari Nabi Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Islam itu lembut dan tidak membawa kecuali kepada yang lembut.\""},"3018":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ الْبَخْتَرِيِّ بْنِ عُبَيْدِ بْنِ سَلْمَانَ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اثْنَانِ خَيْرٌ مِنْ وَاحِدٍ وَثَلَاثٌ خَيْرٌ مِنْ اثْنَيْنِ وَأَرْبَعَةٌ خَيْرٌ مِنْ ثَلَاثَةٍ فَعَلَيْكُمْ بِالْجَمَاعَةِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَنْ يَجْمَعَ أُمَّتِي إِلَّا عَلَى هُدًى","id":"Telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Al Bakhtari bin Ubaid bin Salman] dari [Ayahnya] dari [Abu Dzar] dari Nabi Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Dua orang itu lebih baik ketimbang satu, tiga orang itu lebih baik ketimbang dua dan empat itu lebih baik ketimbang tiga, maka hendaklah kalian berjama'ah, karena sesungguhnya Allah 'azza wajalla tidak mengumpulkan ummatku kecuali di atas petunjuk.\""},"3019":{"ar":"حَدَّثَنَا يُونُسُ وَعَفَّانُ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ بُرْدٍ أَبِي الْعَلَاءِ قَالَ عَفَّانُ قَالَ أَخْبَرَنَا بُرْدٌ أَبُو الْعَلَاءِ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِأَنَّهُ مَرَّ بِعُمَرَ بْنِ الْخَطَّابِ فَقَالَ نِعْمَ الْفَتَى غُضَيْفٌ فَلَقِيَهُ أَبُو ذَرٍّ فَقَالَ أَيْ أُخَيَّ اسْتَغْفِرْ لِي قَالَ أَنْتَ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتَ أَحَقُّ أَنْ تَسْتَغْفِرَ لِي فَقَالَ إِنِّي سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُ نِعْمَ الْفَتَى غُضَيْفٌ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ ضَرَبَ بِالْحَقِّ عَلَى لِسَانِ عُمَرَ وَقَلْبِهِ قَالَ عَفَّانُ عَلَى لِسَانِ عُمَرَ يَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Yunus] dan ['Affan] secara makna, keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Burd Abul A'la] ia berkata, ['Affan] berkata, telah mengabarkan kepada kami [Burd Abul A'la] dari [Ubadah bin Nusayy] dari [Ghudlaif bin Al Harits] bahwa dia melewati Umar bin Al Khattab, kemudian Umar berkata, \"Sebaik-baik pemuda adalah Ghudlaif.\" Maka [Abu Dzar] menemuinya dan berkata, \"Wahai saudaraku, mohonkanlah (ampunan) untukku.\" Ghudlaif menjawab, \"Kamu adalah sahabat Rasulullah shallallahu 'alaihi wasallam dan kamu lebih pantas untuk memohonkan ampun untukku.\" Kemudian Abu Dzar berkata, \"Sesungguhnya aku telah mendengar Umar berkata, 'Sebaik-baik pemuda adalah Ghudlaif.' Dan sungguh Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Sesungguhnya Allah Azza Wa Jalla telah menjadikan permisalan lisan dan hati Umar sebagai tanda kebenaran.\" 'Affan berkata, \"Karena perkataan Umar inilah ia mengatakannya.\""},"3020":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ أَخْبَرَنِي أَبُو تَمِيمٍ الْجَيْشَانِيُّ قَالَ أَخْبَرَنِي أَبُو ذَرٍّ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَغَيْرُ الدَّجَّالِ أَخْوَفُنِي عَلَى أُمَّتِي قَالَهَا ثَلَاثًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا هَذَا الَّذِي غَيْرُ الدَّجَّالِ أَخْوَفُكَ عَلَى أُمَّتِكَ قَالَ أَئِمَّةً مُضِلِّينَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Abdullah bin Hubairah] dia berkata, telah mengkabarkan kepadaku [Abu Tamim Al Jaisyani] dia berkata, telah mengabarkan kepadaku [Abu Dzar] dia berkata, \"Aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Selain Dajjal, ada yang lebih aku takuti atas ummatku, \" beliau mengucapkannya tiga kali, maka aku bertanya, \"Wahai Rasulullah, yang engkau takuti atas umatmu selain Dajjal itu apa? ' beliau menjawab: \"Para pemimpin yang menyesatkan.\""},"3021":{"ar":"حَدَّثَنَا عَمَّارُ بْنُ مُحَمَّدٍ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ أَلَا أَدُلُّكَ عَلَى كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ قُلْ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami ['Ammar bin Muhammad] dari [Al A'masy] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Wahai Abu Dzar, maukah aku tunjukkan simpanan dari simpanan-simpanan Surga? Bacalah 'Laa Haulaa Walaa Quwwata Illaa Billaah (Tidak ada daya dan upaya kecuali dari Allah) '.\""},"3022":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَاقَ حَدَّثَنِي سُلَيْمَانُ الْأَعْمَشُ عَنْ مُجَاهِدِ بْنِ جَبْرٍ أَبِي الْحَجَّاجِ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ اللَّيْثِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُوتِيتُ خَمْسًا لَمْ يُؤْتَهُنَّ نَبِيٌّ كَانَ قَبْلِي نُصِرْتُ بِالرُّعْبِ فَيُرْعَبُ مِنِّي الْعَدُوُّ عَنْ مَسِيرَةِ شَهْرٍ وَجُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا وَأُحِلَّتْ لِي الْغَنَائِمُ وَلَمْ تَحِلَّ لِأَحَدٍ كَانَ قَبْلِي وَبُعِثْتُ إِلَى الْأَحْمَرِ وَالْأَسْوَدِ وَقِيلَ لِي سَلْ تُعْطَهْ فَاخْتَبَأْتُهَا شَفَاعَةً لِأُمَّتِي وَهِيَ نَائِلَةٌ مِنْكُمْ إِنْ شَاءَ اللَّهُ مَنْ لَقِيَ اللَّهَ عَزَّ وَجَلَّ لَا يُشْرِكُ بِهِ شَيْئًاقَالَ الْأَعْمَشُ فَكَانَ مُجَاهِدٌ يَرَى أَنَّ الْأَحْمَرَ الْإِنْسُ وَالْأَسْوَدَ الْجِنُّ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Sulaiman Al A'masy] dari [Mujahid bin Jabr Abul Hajjaj] dari [Ubaid bin Umair Al Laitsi] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diberi empat hal yang tidak diberikan kepada seorang Nabi pun sebelumku; aku ditolong dari rasa takut sehingga musuhku dijadikan takut sepanjang perjalanan satu bulan, bumi seluruhnya di jadikan mesjid dan tempat yang suci bagiku, dihalalkan ghanimah untukku yang tidak pernah dihalalkan kepada seorangpun dari Nabi sebelumku, dan aku diutus kepada orang berkulit merah maupun hitam serta dikatakan kepadaku 'memohonlah pasti kamu akan diberi', maka hal itu aku sembunyikan sebagai syafaat kepada Ummatku dan dia pasti akan kalian dapatkan atas izin Allah bagi siapa yang bertemu dengan Allah 'azza wajalla sedang dia tidak mensekutukan-Nya dengan sesuatu apapun.\" Al A'masy berkata, \"Mujahid berpendapat bahwa yang merah itu adalah golongan manusia dan yang hitam itu adalah golongan Jin.\""},"3023":{"ar":"حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ حَدَّثَنَا يُونُسُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَغِيبُ الشَّمْسُ تَحْتَ الْعَرْشِ فَيُؤْذَنُ لَهَا فَتَرْجِعُ فَإِذَا كَانَتْ تِلْكَ اللَّيْلَةُ الَّتِي تَطْلُعُ صَبِيحَتَهَا مِنْ الْمَغْرِبِ لَمْ يُؤْذَنْ لَهَا فَإِذَا أَصْبَحَتْ قِيلَ لَهَا اطْلُعِي مِنْ مَكَانِكِ ثُمَّ قَرَأَ{ هَلْ يَنْظُرُونَ إِلَّا أَنْ تَأْتِيَهُمْ الْمَلَائِكَةُ أَوْ يَأْتِيَ رَبُّكَ أَوْ يَأْتِيَ بَعْضُ آيَاتِ رَبِّكَ }","id":"Telah menceritakan kepada kami [Mu`amal] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Salamah- telah menceritakan kepada kami [Yunus] dari [Ibrahim At Taimi] dari [Ayahnya] dari [Abu Dzar], bahwa Nabi Shallalahu 'Alaihi Wasallam bersabda: \"Matahari terbenam di bawah 'Arsy kemudian diizinkan untuknya (terbit kembali), maka dia pun kembali terbit (dari arah timur). Jika malam yang pada pagi harinya matahari terbit dari arah barat, sebenarnya (pada malam itu) ia tidak mendapatkan untuk terbit (dari arah timur). Maka di pagi harinya dikatakan padanya: 'Terbitlah kamu dari tempatmu (timur)!\" Kemudian beliau membaca: '(Yang mereka nanti-nanti tidak lain hanyalah kedatangan malaikat kepada mereka untuk mencabut nyawa mereka atau kedatangan siksa Tuhanmu atau kedatangan beberapa ayat Tuhanmu) ' (Qs. Al An'am: 158)."},"3024":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا دَيْلَمٌ عَنْ وَهْبِ بْنِ أَبِي دُبَيٍّ عَنْ أَبِي حَرْبٍ عَنْ مِحْجَنٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَيْنَ لَتُولِعُ بِالرَّجُلِ بِإِذْنِ اللَّهِ حَتَّى يَصْعَدَ حَالِقًا ثُمَّ يَتَرَدَّى مِنْهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Dailam] dari [Wahab bin Abu Dubai] dari [Abu Harb] dari [Mihjan] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penyakit 'ain (penyakit yang bersumber dari mata) itu akan mengenai pada laki-laki, dengan izin Allah sehingga ia mendaki ke tempat tinggi kemudian terjatuh darinya.\""},"3025":{"ar":"حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ عَطَاءٍ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ عَنْ أَبِي ذَرٍّ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَدْرُونَ أَيُّ الْأَعْمَالِ أَحَبُّ إِلَى اللَّهِ عَزَّ وَجَلَّ قَالَ قَائِلٌ الصَّلَا��ُ وَالزَّكَاةُ وَقَالَ قَائِلٌ الْجِهَادُ قَالَ إِنَّ أَحَبَّ الْأَعْمَالِ إِلَى اللَّهِ عَزَّ وَجَلَّ الْحُبُّ فِي اللَّهِ وَالْبُغْضُ فِي اللَّهِ","id":"Telah menceritakan kepada kami [Husain] telah menceritakan kepada kami [Yazid bin Atha`] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Seseorang] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami kemudian bertanya: \"Apakah kalian tahu amalan apakah yang paling dicintai oleh Allah 'azza wajalla?\" Salah seorang sahabat menjawab, \"Shalat dan zakat.\" Yang lain menjawab, \"Berjihad.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya amalan yang paling dicintai oleh Allah 'azza wajalla adalah cinta karena Allah dan benci karena Allah.\""},"3026":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ عَنْ شُرَحْبِيلَ قَالَأَخَذْتُ نُهَسًا بِالْأَسْوَافِ فَأَخَذَهُ مِنِّي زَيْدُ بْنُ ثَابِتٍ فَأَرْسَلَهُ وَقَالَ أَمَا عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ مَا بَيْنَ لَابَتَيْهَا","id":"Telah menceritakan kepada kami [Abu Sa'id] budak bani Hasyim, telah menceritakan kepada kami [Abdurrahman bin Abu Rijal] dari [Syurahbil] berkata, \"Aku mengambil sisa daging yang ada di antara sela-sela gigi (untuk aku makan), namun [Zaid bin Tsabit] mengambil dan membuangnya seraya berkata, 'Tidakkah engkau tahu bahwa Rasulullah Shallalahu 'Alaihi Wasallam telah mengharamkan apa yang ada di antara dua lembah batu (memburu binatang di wilayah Madinah).\""},"3027":{"ar":"حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدٍ أَنَّ زَيْدَ بْنَ ثَابِتٍ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْعِ الْعَرَايَا أَنْ تُبَاعَ بِخَرْصِهَا كَيْلًا","id":"Telah menceritakan kepada kami [Suraij] telah menceritakan kepada kami [Ibnu Abu Zanad] dari [Ayahnya] dari [Kharijah bin Zaid] bahwa [Zaid bin Tsabit] berkata, \"Rasulullah Shallalahu 'Alaihi Wasallam membolehkan jual beli 'Araya sesuai dengan takarannya.\""},"3028":{"ar":"حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنِ الرُّكَيْنِ عَنِ الْقَاسِمِ بْنِ حَسَّانَ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي تَارِكٌ فِيكُمْ خَلِيفَتَيْنِ كِتَابُ اللَّهِ حَبْلٌ مَمْدُودٌ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ أَوْ مَا بَيْنَ السَّمَاءِ إِلَى الْأَرْضِ وَعِتْرَتِي أَهْلُ بَيْتِي وَإِنَّهُمَا لَنْ يَتَفَرَّقَا حَتَّى يَرِدَا عَلَيَّ الْحَوْضَ","id":"Telah menceritakan kepada kami [Al Aswad bin Amir] telah menceritakan kepada kami [Syariik] dari [Rukain] dari [Al Qasim bin Hassan] dari [Zaid bin Tsabit] berkata, \"Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Aku tinggalkan untuk kalian dua pusaka; Kitabullah, tali yang terjulur antara langit dan bumi atau dari langit ke bumi, dan ahli baitku. Keduanya tidak akan terpisah hingga keduanya menemuiku di telaga.\""},"3029":{"ar":"قَالَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ عَنْ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ قَالَ تَمَارَوْا فِي الْقِرَاءَةِ فِي الظُّهْرِ وَالْعَصْرِ فَأَرْسَلُوا إِلَى خَارِجَةَ بْنِ زَيْدٍ فَقَالَ قَالَ أَبِيقَامَ أَوْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطِيلُ الْقِيَامَ وَيُحَرِّكُ شَفَتَيْهِفَقَدْ أَعْلَمُ ذَلِكَ لَمْ يَكُنْ إِلَّا لِقِرَاءَةٍ فَأَنَا أَفْعَلُ","id":"Ia berkata; telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Katsir bin Zaid] dari [Muthalib bin Abdullah] ia berkata, \"Manusia saling meributkan bacaan dalam shalat shalat zhuhur dan asar, lalu mereka mengutus seseorang kepada [Kharijah bin Zaid] ia berkata, [Ayahku] berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam memanjangkan berdiri saat shalat, lalu beliau menggerak-gerakan bibirnya. Dan aku tahu hal itu terjadi karena bacaan, maka aku pun ikut melakukannya.\""},"3030":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنِ الزُّهْرِيِّ عَنْ سَالِمٍ عَنِ ابْنِ عُمَرَ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا أَنْ تُبَاعَ بِخَرْصِهَا وَلَمْ يُرَخِّصْ فِي غَيْرِ ذَلِكَ","id":"Ia berkata; telah menceritakan kepada kami [Muhammad bin Mus'ab] telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dari [Zaid bin Tsabit], bahwa Rasulullah Shallalahu 'Alaihi Wasallam membolehkan jual beli 'Araya dan tidak memberi keringanan untuk selainnya.\""},"3031":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ سَمِعْتُ أَبَا النَّضْرِ يُحَدِّثُ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ حُجْرَةً فِي الْمَسْجِدِ مِنْ حَصِيرٍ فَصَلَّى فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَالِيَ حَتَّى اجْتَمَعَ إِلَيْهِ نَاسٌ ثُمَّ فَقَدُوا صَوْتَهُ فَظَنُّوا أَنَّهُ قَدْ نَامَ فَجَعَلَ بَعْضُهُمْ يَتَنَحْنَحُ لِيَخْرُجَ إِلَيْهِمْ فَقَالَ مَا زَالَ بِكُمْ الَّذِي رَأَيْتُ مِنْ صَنِيعِكُمْ حَتَّى خَشِيتُ أَنْ يُكْتَبَ عَلَيْكُمْ وَلَوْ كُتِبَ عَلَيْكُمْ مَا قُمْتُمْ بِهِ فَصَلُّوا أَيُّهَا النَّاسُ فِي بُيُوتِكُمْ فَإِنَّ أَفْضَلَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَ","id":"Ia berkata; telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa bin Uqbah] ia berkata, Aku mendengar [Abu Nadlar] menceritakan dari [Busr bin Sa'id] dari [Zaid bin Tsabit], bahwa Rasulullah Shallalahu 'Alaihi Wasallam membuat sebuah kamar di masjid dengan tikar, beliau shalat di situ beberapa malam hingga manusia berkumpul. Pada suatu malam orang-orang tidak lagi mendengar suara beliau, lalu mereka menyangka bahwa beliau telah terlelap tidur. Kemudian salah seorang di antara mereka berteriak-teriak agar beliau terbangun dan menemui mereka. Maka beliau pun bersabda: \"Kalian masih saja melakukan hal-hal yang aku takutkan hal itu akan diwajibkan atas kalian, sekiranya hal itu diwajibkan maka kalian tidak akan mampu. Wahai manusia, shalatlah di rumah kalian, karena sebaik-baik shalat adalah yang di kerjakan di rumah kecuali shalat wajib.\""},"3032":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ بِالتَّمْرِ فَأَخْبَرَهُمْ زَيْدُ بْنُ ثَابِتٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya], bahwa Nabi shallallahu 'alaihi wasallam melarang jual beli kurma yang belum matang dengan kurma yang sudag matang. Sementara [Zaid bin Tsabit] mengabarkan kepada mereka bahwa Nabi shallallahu 'alaihi wasallam membolehkannya dalam 'araya (kurma yang telah masak).\""},"3033":{"ar":"حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَتَسَحَّرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجْنَا إِلَى الْمَسْجِدِ فَأُقِيمَتْ الصَّلَاةُ قُلْتُ كَمْ كَانَ بَيْنَهُمَا قَالَ قَدْرُ مَا يَقْرَأُ الرَّجُلُ خَمْسِينَ آيَةً","id":"Telah menceritakan kepada kami [Yahya] dari [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] dari [Zaid bin Tsabit] berkata, \"Kami makan sahur bersama Nabi shallallahu 'alaihi wasallam, lalu kami keluar menuju masjid dan dikumandangkan iqamat. Aku (Anas) bertanya, \"Berapa jarak antara keduanya?\" Zaid menjawab, \"Seperti seseorang membaca lima puluh ayat.\""},"3034":{"ar":"حَدَّثَنَا جَرِيرٌ عَنِ الْأَعْمَشِ عَنْ ثَابِتِ بْنِ عُبَيْدٍ قَالَ قَالَ زَيْدُ بْنُ ثَابِتٍقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُحْسِنُ السُّرْيَانِيَّةَ إِنَّهَا تَأْتِينِي كُتُبٌ قَالَ قُلْتُ لَا قَالَ فَتَعَلَّمْهَا فَتَعَلَّمْتُهَا فِي سَبْعَةَ عَشَرَ يَوْمًا","id":"Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Tsabit bin Ubaid] berkata, [Zaid bin Tsabit] berkata, \"Rasulullah shallallahu 'alaihi wasallam bertanya padaku: 'Apakah engkau bisa bahasa suryani? ' Aku menjawab, 'Tidak bisa.' Beliau bersabda: 'Belajarlah! ' Maka aku mempelajarinya hanya dalam tujuh belas hari.\""},"3035":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارٍ عَنِ الْوَلِيدِ بْنِ أَبِي الْوَلِيدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ قَالَ زَيْدُ بْنُ ثَابِتٍيَغْفِرُ اللَّهُ لِرَافِعِ بْنِ خَدِيجٍ أَنَا وَاللَّهِ أَعْلَمُ بِالْحَدِيثِ مِنْهُ إِنَّمَا أَتَى رَجُلَانِ قَدْ اقْتَتَلَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ هَذَا شَأْنَكُمْ فَلَا تُكْرُوا الْمَزَارِعَ قَالَ فَسَمِعَ رَافِعٌ قَوْلَهُ لَا تُكْرُوا الْمَزَارِعَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Abu Ubaidah bin Muhammad bin 'Ammar] dari [Al Walid bin Abul Walid] dari [Urwah bin Zubair] berkata, [Zaid bin Tsabit] berkata, \"Semoga Allah mengampuni Rafi' bin Khadij -Demi Allah aku lebih tahu tantang hadits dari padanya-, bahwa ada dua orang yang saling membunuh, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah ini sebab pertengkaran kalian, maka janganlah kalian menyewakan tanah.\" Zaid berkata, \"Lalu Rafi mendengar sabda beliau: 'Jangalah menyewakan tanah.'\""},"3036":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الشَّهَادَةِ مَا شَهِدَ بِهَا صَاحِبُهَا قَبْلَ أَنْ يُسْأَلَهَا","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Abu Bakar bin Muhammad bin Amru bin Hazm] dari Bapaknya dari [Abdullah bin Utsman] dari [Zaid bin Khalid Al Juhanni] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik persaksian adalah persaksian pelakunya sebelum diminta untuk bersaksi.\""},"3037":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدِ بْنِ حَيَّانَ عَنْ مُحَمَّدِ بْنِ يَحْيَى عَنْ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا مِنْ أَشْجَعَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُوُفِّيَ يَوْمَ خَيْبَرَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَتَغَيَّرَ وُجُوهُ النَّاسِ مِنْ ذَلِكَ فَقَالَ إِنَّ صَاحِبَكُمْ غَلَّ فِي سَبِيلِاللَّهِ فَفَتَّشْنَا مَتَاعَهُ فَوَجَدْنَا خَرَزًا مِنْ خَرَزِ يَهُودَ مَا يُسَاوِي دِرْهَمَيْنِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id bin Hayyan] dari [Muhammad bin Yahya] dari [Abu Amrah] dari [Zaid bin Khalid Al Juhani], bahwa seorang laki-laki Asyja', seorang sahabat Rasulullah Nabi shallallahu 'alaihi wasallam, wafat pada hari Khaibar. Hal itu kemudian diceritakan kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun berkata: \"Shalatlah kalian untuk sahabat kalian!\", maka berubahkah rona wajah para sahabat dengan ucapan tersebut. Beliau kemudian bersabda: \"Sesungguhnya sahabat kalian telah mencuri harta rampasan perang -di jalan Allah-.\" Kemudian kami memeriksa harta sahabat tersebut dan kami dapati kharajan (sejenis alat pelubang) Yahudi senilai dua dirham.\""},"3038":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْمَلِكِ حَدَّثَنَا عَطَاءٌ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَطَّرَ صَائِمًا كَانَ لَهُ أَوْ كُتِبَ لَهُ مِثْلُ أَجْرِ الصَّائِمِ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أَجْرِ الصَّائِمِ شَيْئًا وَمَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ كَ��نَ لَهُ أَوْ كُتِبَ لَهُ مِثْلُ أَجْرِ الْغَازِي فِي أَنَّهُ لَا يَنْقُصُ مِنْ أَجْرِ الْغَازِي شَيْئًا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdul Malik] berkata, telah menceritakan kepada kami ['Atha] dari [Zaid bin Khalid Al Juhanni] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa saja yang menjamu orang yang berpuasa, maka ditulis untuknya pahala orang yang berpuasa tersebut tanpa mengurangi sedikit pun pahala puasanya. Dan siapa saja yang menyiapkan kelengkapan orang yang berperang di jalan Allah, maka baginya pahala seperti orang yang berperang itu tanpa mengurangi sedikit pun pahalanya.\""},"3039":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنِ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ عَنْ خَلَّادِ بْنِ السَّائِبِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَنِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ يَا مُحَمَّدُ مُرْ أَصْحَابَكَ فَلْيَرْفَعُوا أَصْوَاتَهُمْ بِالتَّلْبِيَةِ فَإِنَّهَا مِنْ شَعَائِرِ الْحَجِّ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Abu Labid] dari [Al Muthallib bin Abdullah bin Hanthab] dari [Khallad bin Sa`ib] dari [Zaid bin Khalid Al Juhanni] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril datang kepadaku dan berkata, 'Wahai Muhammad, suruh para sahabatmu mengeraskan suara talbiyah karena ia adalah syi'ar haji.\""},"3040":{"ar":"حَدَّثَنَا يَزِيدُ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ حَدَّثَنَا صَالِحُ بْنُ كَيْسَانَ وَأَبُو النَّضْرِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الدِّيكَ فَإِنَّهُ يَدْعُو إِلَى الصَّلَاةِقَالَ أَبِي قَالَ أَبُو النَّضْرِ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ سَبِّ الدِّيكِ وَقَالَ إِنَّهُ يُؤَذِّنُ بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Yazid] dari [Abdul Aziz bin Abdullah bin Abu Salamah] telah menceritakan kepada kami [Shalih bin Kaisan] dan [Abu Nadlr] ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] dari [Shalih bin Kaisan] dari [Ubaidullah bin Abdullah bin Utbah] dari [Zaid bin Khalid Al Juhanni] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencaci ayam jago, karena ia menyeru kalian melaksanakan shalat.\" Ayahku berkata; [Abu Nadlr] berkata, \"Rasululllah shallallahu 'alaihi wasallam melarang menghina ayam jago, Beliau mengatakan: \"Sesungguhnya ia menyerukan pada kalian untuk (bersegera melaksanakan) shalat.\""},"3041":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّ عَبْدَ اللَّهِ بْنَ قَيْسٍ أَخْبَرَهُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُقَالَ لَأَرْمُقَنَّ اللَّيْلَةَ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَسَّدْتُ عَتَبَتَهُ أَوْ فُسْطَاطَهُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ طَوِيلَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ أَوْتَرَ فَذَلِكَ ثَلَاثَ عَشْرَةَقَالَ عَبْد اللَّهِ و حَدَّثَنَا مُصْعَبٌ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ أَنَّ عَبْدَ اللَّهِ بْنَ قَيْسِ بْنِ مَخْرَمَةَ أَخْبَرَهُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ فَذَكَرَ الْحَدِيثَ وَلَمْ يَذْكُرْ عَبْدَ الرَّحْمَنِ فِي حَدِيثِ مَالِكٍ عَنْ أَبِيهِ وَالصَّوَابُ مَا رَوَى مُصْعَبٌ عَنْ أَبِيهِ وَكَذَا حَدَّثَنَا أَبُو مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ أَنَّ عَبْدَ اللَّهِ بْنَ قَيْسِ بْنِ مَخْرَمَةَ أَخْبَرَهُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ وَالصَّوَابُ مَا قَالَ مُصْعَبٌ ومَعْنٌ عَنْ أَبِيهِ وَلَمْ يَذْكُرْ عَبْدُ الرَّحْمَنِ فِيهِ عَنْ أَبِيهِ وَهِمَ فِيهِ","id":"Ia Abu Nadlar berkata, \"Aku membacakannya dihadapan [Abdurrahman]; [Malik] dari [Abdullah bin Abu Bakar] bahwa [Abdullah bin Qais] mengabarkan kepadanya dari [Zaid bin Khalid Al Juhanni] bahwa ia berkata; \"Sungguh aku mendapatkan suatu malam untuk menyaksikan shalat Rasulullah shallallahu 'alaihi wasallam, aku duduk di kemah beliau, lalu beliau melakukan shalat dua rakaat ringan, kemudian shalat dengan dua rakaat panjang, lalu shalat dengan dua rakaat yang tidak sama dengan yang dua shalat sebelumnya, kemudian beliau shalat lagi dengan dua rakaat yang juga tidak sama dengan sebelumnya, lalu dua rakaat lagi ditambah dua rakaat lagi yang tidak sama dengan shalat-shalat sebelumnya. Setelah itu beliau melakukan witir dan semuanya ada tiga belas rakaat.\" Abdullah berkata; telah menceritakan kepada kami [Mus'ab] telah menceritakan kepadaku [Malik] dari [Abdullah bin Abu Bakar] dari [Ayahnya] bahwa [Abdullah bin Qais bin Makhramah] ia mengabarkan kepadanya dari [Zaid bin Khalid Al Juhanni], lalu ia sebutkan hadits tanpa menyebutkan nama Abdurrahman dalam hadits Malik dari bapaknya. Dan yang benar adalah apa yang telah diriwayatkan Mush'ab dari bapaknya. Demikian juga telah menceritakan kepada kami [Abu Musa Al Anshari] telah menceritakan kepada kami [Ma'nun] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakar] dari [Ayahnya] bahwa [Abdullah bin Qais bin Makhramah] ia mengabarkan kepadanya dari [Zaid bin Khalid Al Juhanni], dan yang benar adalah apa yang disebutkan oleh Mush'ab dan Ma'n dari bapaknya, tanpa menyebutkan Abdurrahman di dalamnya dari bapaknya, sedang mereka termasuk di dalamnya.\""},"3042":{"ar":"حَدَّثَنَا رِبْعِيٌّ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْن�� إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ هِشَامٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَمْنَعُوا إِمَاءَ اللَّهِ الْمَسَاجِدَ وَلْيَخْرُجْنَ تَفِلَاتٍ","id":"Telah menceritakan kepada kami [Rib'i bin Ibrahim] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Muhammad bin Abdullah bin Amru bin Hisyam] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhanni] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menghalangi para wanita pergi ke masjid, dan suruhlah mereka menghilangkan wewangian yang mereka kenakan.\""},"3043":{"ar":"حَدَّثَنَا أَبُو نُوحٍ قُرَادٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ بْنِ عَفَّانَ عَنِ ابْنِ أَبِي عَمْرَةَ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ الشُّهَدَاءِ الَّذِي يَأْتِي بِشَهَادَتِهِ قَبْلَ أَنْ يُسْأَلَهَا أَوْ يُخْبِرُ بِشَهَادَتِهِ قَبْلَ أَنْ يُسْأَلَهَا","id":"Telah menceritakan kepada kami [Abu Nuh qurad] telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah bin Abu Bakar] dari [Ayahnya] dari [Abdullah bin Amru bin Utsman bin Affan] dari [Ibnu Abu Amrah Al Anshari] dari [Zaid bin Khalid Al Juhanni] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perhatikanlah, aku kabarkan pada kalian bahwa sebaik-baik para saksi adalah yang datang dengan kesaksiannya sebelum diminta atau ia mengkabarkan kesaksiannya sebelum diminta untuk bersaksi.\""},"3044":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍقَالَ فَكَانَ زَيْدٌ يَرُوحُ إِلَى الْمَسْجِدِ وَسِوَاكُهُ عَلَى أُذُنِهِ بِمَوْضِعِ قَلَمِ الْكَاتِبِ مَا تُقَامُ صَلَاةٌ إِلَّا اسْتَاكَ قَبْلَ أَنْ يُصَلِّيَ","id":"Telah menceritakan kepada kami [Ali bin Tsabit] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim bin Harits At Taimi] dari [Abu Salamah bin Abdurrahman bin Auf] dari [Zaid bin Khalid Al Juhanni] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya tidak memberatkan atas umatku niscaya aku perintahkan mereka bersiwak (menggosok gigi) pada setiap kali shalat.\" Ia (perawi) Berkata, \"Zaid biasa melenggang ke masjid sedang siwaknya berada di atas telinganya, tepatnya seperti pulpen seorang penulis, ia tidak melakukan shalat kecuali ia telah bersiwak sebelum mengerjakan shalat.\""},"3045":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَاعِيلَ بْنِ أَبِي فُدَيْكٍ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَن أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ بَاغِيهَا فَأَدِّهَا إِلَيْهِ وَإِلَّا فَاعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ كُلْهَا فَإِنْ جَاءَ بَاغِيهَا فَأَدِّهَا إِلَيْهِ","id":"Telah menceritakan kepadaku [Muhammad bin Isma'il bin Abu Fudaik] telah menceritakan kepadaku [Adl Dlahak bin Utsman] dari [Abu Nadlr] budak Umar bin Ubaidullah, dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhanni], bahwa Rasulullah shallallahu 'alaihi wasallam ditanya tentang luqathah (barang temuan), beliau bersabda: \"Umumkan dia hingga setahun, bila datang pemiliknya maka berikanlah, jika tidak maka sebutkanlah sifat dan bentuknya, jika (makanan yang mudah busuk) maka makanlah dan jika datang pemiliknya maka gantilah!\""},"3046":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هُشَيْمٌ أَنَا دَاوُدُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ أَبِي زَكَرِيَّا الْخُزَاعِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ تُدْعَوْنَ يَوْمَ الْقِيَامَةِ بِأَسْمَائِكُمْ وَأَسْمَاءِ آبَائِكُمْ فَحَسِّنُوا أَسْمَاءَكُمْ","id":"Telah menceritakan kepada kami [Afan], telah menceritakan kepada kami [Husyaim], telah menceritakan kepadaku [Dawud bin 'Amru] dari [Abdullah bin Abu Zakariya Al khuza'i] dari [Abu Darda`] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian semua akan dipanggil pada hari kiamat dengan nama-nama kalian dan bapak-bapak kalian saat ini, maka perbaguslah nama-nama kalian.\""},"3047":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي مَرْيَمَ الْغَسَّانِيُّ عَنْ خَالِدِ بْنِ مُحَمَّدٍ الثَّقَفِيِّ عَنْ بِلَالِ بْنِ أَبِي الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُبُّكَ الشَّيْءَ يُعْمِي وَيُصِمُّقَالَ و حَدَّثَنَاه أَبُو الْيَمَانِ لَمْ يَرْفَعْهُ وَرَفَعَهُ الْقُرْقُسَانِيُّ مُحَمَّدُ بْنُ مُصْعَبٍ","id":"Telah menceritakan kepada kami ['Isham bin Khalid], telah menceritakan kepada kami [Abu Bakar bin Abdullah bin Abu Maryam Al Ghasani] dari [Khalid bin Muhammad Ats Tsaqafi] dari [Bilal bin Abu Darda`] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kecintaanmu terhadap sesuatu akan membuatmu buta dan tuli.\" Telah menceritakan kepada kami [Abu Yaman] namun dia tidak merafa'kannya, namun [Al Qursani Muhammd bin Mush'ab] merafa'kan hadits tersebut.\""},"3048":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ اللَّهِ عَنْ ضَمْرَةَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مِنْ فِقْهِ الرَّجُلِ رِفْقُهُ فِي مَعِيشَتِهِ","id":"Telah menceritakan kepada kami ['Isham bin Khalid], telah menceritakan kepadaku [Abu Bakar bin Abdullah] dari [Dhamrah] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Diantara tanda dari kefaqihan seseorang adalah memiliki budipekerti yang baik dalam bergaul.\""},"3049":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ ثَابِتٍ أَوْ عَنْ أَبِي ثَابِتٍأَنَّ رَجُلًا دَخَلَ مَسْجِدَ دِمَشْقَ فَقَالَ اللَّهُمَّ آنِسْ وَحْشَتِي وَارْحَمْ غُرْبَتِي وَارْزُقْنِي جَلِيسًا صَالِحًا فَسَمِعَهُ أَبُو الدَّرْدَاءِ فَقَالَ لَئِنْ كُنْتَ صَادِقًا لَأَنَا أَسْعَدُ بِمَا قُلْتَ مِنْكَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ{ فَمِنْهُمْ ظَالِمٌ لِنَفْسِهِ }يَعْنِي الظَّالِمَ يُؤْخَذُ مِنْهُ فِي مَقَامِهِ ذَلِكَ فَذَلِكَ الْهَمُّ وَالْحَزَنُ{ وَمِنْهُمْ مُقْتَصِدٌ }قَالَ يُحَاسَبُ حِسَابًا يَسِيرًا{ وَمِنْهُمْ سَابِقٌ بِالْخَيْرَاتِ بِإِذْنِ اللَّهِ }قَالَ الَّذِينَ يَدْخُلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ","id":"Telah berceritak kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Tsabit] atau dari Abu Tsabit bahwa seseorang masuk masjid Damaskus, kemudian ia berdo'a; \"Ya Allah hilangkanlah kesedihanku, rahmatilah kepergianku dan berikanlah aku teman yang shaleh.\" [Abu Darda`] mendengar do'anya dan berkata; \"Jika sekiranya kamu jujur dengan do'amu, sungguh aku senang mendengar apa yang kamu katakan, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka diantara mereka ada yang menzhalimi diri mereka sendiri, \" beliau bersabda: \"Zhalim adalah sesuatu yang diambil (dihisab) ditempatnya, maka itulah perasaan sedih dan susah, dan diantara mereka ada yang dipertengahan yaitu yang dipermudah hisabnya, dan diantara mereka ada yang berlomba-lomba dalam kebaikan dengan izin Allah, mereka itulah orang-orang yang masuk syurga tanpa hisab.\""},"3050":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا هِشَامٌ يَعْنِي ابْنَ سَعْدٍ عَنْ عُثْمَانَ بْنِ حَيَّانَ الدِّمَشْقِيِّ أَخْبَرَتْنِي أُمُّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَلَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فِي الْيَوْمِ الْحَارِّ الشَّدِيدِ الْحَرِّ حَتَّى إِنَّ الرَّجُلَ لَيَضَعُ يَدَهُ عَلَى رَأْسِهِ فِي شِدَّةِ الْحَرِّ وَمَا فِي الْقَوْمِ صَائِمٌ إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ","id":"Telah menceritakan kepada kami [Abu 'Amir], telah menceritakan kepada kami [Hisyam yaitu Ibnu Sa'ad] dari [Utsman bin Hayan Ad Damasqi], telah mengabarkan kepadaku [Ummu Darda`] dari [Abu Darda`] ia berkata; \"Sungguh aku pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, ketika itu cuaca sangat panas, sehingga seseorang meletakkan tangannya di atas kepala berlindung dari panasnya terik matahari, dan tak ada seorangpun dari mereka yang berpuasa kecuali Rasulullah shallallahu 'alaihi wasallam dan Abdullah bin Rawahah.\""},"3051":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمٍ عَنْ أُمِّ الدَّرْدَاءِ قَالَتْدَخَلَ عَلَيْهَا يَوْمًا أَبُو الدَّرْدَاءِ مُغْضَبًا فَقَالَتْ مَا لَكَ قَالَ وَاللَّهِ مَا أَعْرِفُ فِيهِمْ شَيْئًا مِنْ أَمْرِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا أَنَّهُمْ يُصَلُّونَ جَمِيعًا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy] dari [Salim] dari [Ummu Darda`] ia berkata; \"Suatu hari [Abu Darda`] datang menemuinya dalam keadaan marah, Ummu Darda` berkata; \"Ada apa denganmu?, Abu Darda` menjawab; \"Demi Allah, aku tidak tahu sedikitpun dari perkara Muhammad shallallahu 'alaihi wasallam, kecuali mereka hanya melaksanakan shalat.\""},"3052":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ يَعِيشَ بْنِ الْوَلِيدِ بْنِ هِشَامٍ عَنْ مَعْدَانَ أَوْ مَعْدَانَ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَقَالَ فَلَقِيتُ ثَوْبَانَ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ أَنَا صَبَبْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضُوءَهُ","id":"Telah menceritakan kepada kami [Ismail], telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Ya`is bin Walid bin Hisyam] dari [Ma'dan] dari [Abu Darda`] bahwa Rasulullah shallallahu 'alaihi wasallam pernah muntah, kemudian beliau berbuka. [Abu Darda`] berkata; 'Aku menemui [Tsauban] di masjid Rasulullah shallallahu 'alaihi wasallam dan bertanya tentang hal ini kepadanya, dia menjawab, \"Akulah orang yang menuangkan air wudhu Rasulullah shallallahu 'alaihi wasallam.\""},"3053":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ حَدَّثَنِي مَوْلَى ابْنِ عَيَّاشٍ عَنْ أَبِي بَحْرِيَّةَ و حَدَّثَنَا أَبِي حَدَّثَنَا مَكِّيٌّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ زِيَادِ بْنِ أَبِي زِيَادٍ عَنْ أَبِي بَحْرِيَّةَ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُنَبِّئُكُمْ بِخَيْرِ أَعْمَالِكُمْ قَالَ مَكِّيٌّ وَأَزْكَاهَا عِنْدَ مَلِيكِكُمْ وَأَرْفَعِهَا فِي دَرَجَاتِكُمْ وَخَيْرٍ لَكُمْ مِنْ إِعْطَاءِ الذَّهَبِ وَالْوَرِقِ وَخَيْرٍ لَكُمْ مِنْ أَنْ تَلْقَوْا عَدُوَّكُمْ فَتَضْرِبُوا أَعْنَاقَهُمْ وَيَضْرِبُوا أَعْنَاقَكُمْ قَالُوا وَذَلِكَ مَا هُوَ يَا رَسُولَ اللَّهِ قَالَ ذِكْرُ اللَّهِ عَزَّ وَجَلَّ","id":"Telah becerita kapada kami [Yahya bin Sa`id] dari [Abdullah bin Sa`id], telah menceritakan kepada kami [mantan budak Ibnu Abbas] dari [Abu Bahriyah] -(diriwayatkan dari jalur lain) Telah menceritakan kepada kami Ayahku, telah menceritakan kepada kami [Maki], telah menceritakan kepada kami [Abdullah bin Sa`id] dari [Ziyad bin Abu Ziyad] dari [Abu Bahriyah] - dari [Abu Darda`] ia berkata; 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian amalan yang paling baik untuk kelian kerjakan?\" [Makky] mengatakan; \"(amalan) yang paling suci di sisi Rab kalian, lebih tinggi dari derajat kalian, lebih baik dari emas dan uang yang kalian berikan, dan lebih baik daripada kalian menemui musuh dan memenggal leher mereka, begitupula sebaliknya, mereka memenggal leher kalian?\" Para sahabat bertanya, \"Amalan apakah itu Wahai Rasulullah?\" Beliau menjawab: \"Dzikir kepada Allah 'azza wajalla.\""},"3054":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَعْجَبُ أَحَدُكُمْ أَنْ يَقْرَأَ ثُلُثَ الْقُرْآنِ فِي لَيْلَةٍ قَالُوا كَيْفَ يُطِيقُ ذَلِكَ أَوْ مَنْ يُطِيقُ ذَلِكَ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah], telah menceritakan kepada kami [Qatadah] dari [Salim bin Abu Ja'd] dari [Ma'dan] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam, beiau bersabda: \"Tidakkah kalian heran terharap seseorang yang membaca sepertiga Al Qur`an pada satu malam?\" para sahabat bertanya; \"Bagaimana ia mampu membacanya atau siapa yang mampu melakukannya? Beliau menjawab: \"Katakanlah qul huwallahu ahad.\""},"3055":{"ar":"حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ سَأَلْتُ سَعِيدَ بْنَ الْمُسَيَّبِ عَنْ الضَّبُعِ فَكَرِهَهَا فَقُلْتُ لَهُ إِنَّ قَوْمَكَ يَأْكُلُونَهُ قَالَ لَا يَعْلَمُونَ فَقَالَ رَجُلٌ عِنْدَهُ سَمِعْتُ أَبَا الدَّرْدَاءِ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ كُلِّ ذِي نُهْبَةٍ وَكُلِّ ذِي خَطْفَةٍ وَكُلِّ ذِي نَابٍ مِنْ السِّبَاعِقَالَ سَعِيدٌ صَدَقَ","id":"Telah menceritakan kepada kami [Yahya] dari [Sufyan], telah menceritakan kepadaku [Suhail bin Abu Shalah] dari [Abdullah bin Yazid] ia berkata; 'Aku bertanya kepada [Sa'id bin Musayab] mengenai hukum memakan anjing hutan?, Beliau membenci anjing hutan. Aku katakan kepada beliau, \"Ketahuilah bahwa kaummu memakan anjing hutan.\" beliau menjawab; \"barangkali mereka belum tahu.\" Lantas [seseorang] yang berada di sisinya berkata; \"Aku mendengar [Aba Darda`] menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau melarang memakan setiap hewan yang memiliki sifat merampas, setiap hewan yang menerkam, dan setiap hewan buas yang bertaring.\" [Sa`id] berkata; \"Abu Darda` benar.\""},"3056":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ أَنَّهُ سَأَلَ أُسَامَةَ بْنَ زَيْدٍ قَالَقُلْتُ أَخْبِرْنِي كَيْفَ صَنَعْتُمْ عَشِيَّةَ رَدِفْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جِئْنَا الشِّعْبَ الَّذِي يُنِيخُ فِيهِ النَّاسُ لِلْمَغْرِبِ فَأَنَاخَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَتَهُ ثُمَّ بَالَ مَاءً قَالَ أَهْرَاقَ الْمَاءَ ثُمَّ دَعَا بِالْوَضُوءِ فَتَوَضَّأَ وُضُوءًا لَيْسَ بِالْبَالِغِ جِدًّا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ الصَّلَاةَ قَالَ الصَّلَاةُ أَمَامَكَ قَالَ فَرَكِبَ حَتَّى قَدِمَ الْمُزْدَلِفَةَ فَأَقَامَ الْمَغْرِبَ ثُمَّ أَنَاخَ النَّاسُ فِي مَنَازِلِهِمْ وَلَمْ يَحُلُّوا حَتَّى أَقَامَ الْعِشَاءَ فَصَلَّى ثُمَّ حَلَّ النَّاسُ قَالَ فَقُلْتُ كَيْفَ فَعَلْتُمْ حِينَ أَصْبَحْتُمْ قَالَ رَدِفَهُ الْفَضْلُ بْنُ عَبَّاسٍ وَانْطَلَقْتُ أَنَا فِي سُبَّاقِ قُرَيْشٍ عَلَى رِجْلَيَّ","id":"Telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Ibrahim bin 'Uqbah], telah mengabarkan kepada kami [Kuraib] ia bertanya kepada [Usamah bin Zaid] katanya; aku berkata; \"Beritahukanlah kepadaku apa yang kalian lakukan pada waktu petang, ketika kamu membonceng Rasulullah shallallahu 'alaihi wasallam!.\" Usamah menjawab; \"Kami mendatangi suatu lembah, yang biasa digunakan orang-orang untuk menderumkan unta pada waktu maghrib, maka Rasulullah shallallahu 'alaihi wasallam menderumkan untanya di tempat tersebut, lalu beliau menuangkan air, beliau besabda: \"Tuangkanlah air.\" lalu beliau memerintahkan orang-orang untuk berwudhu, dan beliau pun berwudhu dengan wudhu yang tidak basah sekali. Usamah berkata; \"Aku bertanya; 'Wahai Rasulullah, apakah anda hendak mengerjakan shalat?.' Beliau menjawab: 'Shalat ada di hadapanmu.\" Usamah melanjutkan; \"Lalu beliau menaiki kendaraannya hingga sampai di Muzdalifah dan menunaikan shalat Maghrib, setelah itu orang-orang singgah di persinggahan mereka masing-masing, mereka belum mengerjakan tahalullul, seusai mengerjakan shalat isya`, orang-orang pun mengerjakan tahallul, \" Kuraib berkata; aku bertanya; \"Lantas apa yang kalian kerjakan di pagi harinya?\" Usamah menjawab; \"Al Fadl bin 'Abbas membonceng beliau, sementara aku bersama rombongan orang-orang Qurasiy pergi dengan berjalan kaki.\""},"3057":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ وَعَفَّانُ قَالَا ثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رِبَا فِيمَا كَانَ يَدًا بِيَدٍ قَالَ يَعْنِي إِنَّمَا الرِّبَا فِي النَّسِيئَةِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami [Abdullah bin Thawus] dari [Ayahnya] dari [Ibnu Abbas] dari [Usamah bin Zaid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah termasuk riba jual beli secara kontan, hanyasanya riba itu bisa terjadi dalam jual beli dengan pembayaran yang di tangguhkan.\""},"3058":{"ar":"حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ حَدَّثَنَا حُصَيْنٌ عَنْ أَبِي ظِبْيَانَ قَالَ سَمِعْتُ أُسَامَةَ بْنَ زَيْدٍ يُحَدِّثُ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْحُرَقَةِ مِنْ جُهَيْنَةَ قَالَ فَصَبَّحْنَاهُمْ فَقَاتَلْنَاهُمْ فَكَانَ مِنْهُمْ رَجُلٌ إِذَا أَقْبَلَ الْقَوْمُ كَانَ مِنْ أَشَدِّهِمْ عَلَيْنَا وَإِذَا أَدْبَرُوا كَانَ حَامِيَتَهُمْ قَالَ فَغَشِيتُهُ أَنَا وَرَجُلٌ مِنْ الْأَنْصَارِ قَالَ فَلَمَّا غَشِينَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَكَفَّ عَنْهُ الْأَنْصَارِيُّ وَقَتَلْتُهُ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أُسَامَةُ أَقَتَلْتَهُ بَعْدَمَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا كَانَ مُتَعَوِّذًا مِنْ الْقَتْلِ فَكَرَّرَهَا عَلَيَّ حَتَّى تَمَنَّيْتُ أَنِّي لَمْ أَكُنْ أَسْلَمْتُ إِلَّا يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Husyaim bin Basyir], telah menceritakan kepada kami [Hushain], dari [Abu Dzibyan] ia berkata; aku mendengar [Usamah bin Zaid] bercerita, ia berkata; Rasulullah shallallahu 'alaihi wasallam telah mengutus kami ke Huraqah, yaitu wilayah bagian Juhainah, Usamah berkata; \"Lalu kami memerangi mereka di waktu pagi, sementara diantara mereka ada seeorang apabila bertemu dengan kaumnya mereka menggencarkan permusuhannya dengan kami, namun bila kaumnya mundur ia berbuat baik pada kami.\" Usamah melanjutkan; \"Maka aku dan seorang Anshar berhasil mendekatinya, ketika kami telah dekat dengannya, serta merta ia mengucapkan; 'Laa ilaaha Illallah', maka sahabat Anshar mengurungkan niatnya, sementara aku telah membunuhnya, ketika hal ini diberitahukan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: 'Wahai Usamah, apakah kamu membunuhnya padahal ia telah mengucapkan 'La ilaaha illallalah?.' Aku menjawab; 'Wahai Rasulullah, ia mengcapkan hal itu karena hendak berlindung dari pembunuhan?.' Beliau mengulangi pertanyaan tersebut berkali-kali seakan saya baru masuk Islam.\""},"3059":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَرَكْتُ بَعْدِي فِتْنَةً أَضَرَّ عَلَى أُمَّتِي مِنْ النِّسَاءِ عَلَى الرِّجَالِ","id":"Telah menceritakan kepada kami [Husyaim], telah mengabarkan kepadaku [Sulaiman At Taimi] dari [Abu 'Utsman An Nahdi] dari [Usamah bin Zaid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah aku meninggalkan suatu fitnah yang lebih dahsyat bagi kaum laki-laki melebihi fitnah wanita.\""},"3060":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْرَفَ عَلَى أُطُمٍ مِنْ آطَامِ الْمَدِينَةِ فَقَالَ هَلْ تَرَوْنَ مَا أَرَى إِنِّي لَأَرَى مَوَاقِعَ الْفِتَنِ خِلَالَ بُيُوتِكُمْ كَمَوَاقِعِ الْقَطْرِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Usamah bin Zaid] bahwa Nabi shallallahu 'alaihi wasallam pernah naik ke atas salah satu dari benteng-benteng Madinah, lalu bersabda: \"Apakah kalian melihat sebagaimana aku melihat?, Sungguh aku melihat tempat-tempat terjadinya fitnah di sela-sela rumah kalian seperti tempat jatuhnya tetesan (air hujan) \"."},"3061":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ كُرَيْبٍ عَنِ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْدَفَهُ مِنْ عَرَفَةَ فَلَمَّا أَتَى الشِّعْبَ نَزَلَ فَبَالَ وَلَمْ يَقُلْ أَهْرَاقَ الْمَاءَ فَصَبَبْتُ عَلَيْهِ فَتَوَضَّأَ وُضُوءًا خَفِيفًا فَقُلْتُ الصَّلَاةَ فَقَالَ الصَّلَاةُ أَمَامَكَ قَالَ ثُمَّ أَتَى الْمُزْدَلِفَةَ فَصَلَّى الْمَغْرِبَ ثُمَّ حَلُّوا رِحَالَهُمْ وَأَعَنْتُهُ ثُمَّ صَلَّى الْعِشَاءَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin 'Uqbah] dari [Kuraib] dari [Ibnu Abbas] ia berkata; telah mengabarkan kepadaku [Usamah bin Zaid] bahwa suatu hari ia membonceng Nabi shallallahu 'alaihi wasallam dari Arafah. Ketika tiba disuatu lembah, beliau turun untuk buang air kecil. -namun Usamah tidak mengatakan; \"lalu beliau menyuruh untuk menuangkan air\"- Maka akupun menuangkan air untuk beliau, lalu beliau berwudlu. Aku berkata; \"Apakah anda hendak mengerjakan shalat?.\" Beliau menjawab: \"Shalat ada di hadapanmu.\" Usamah bin Zaid berkata; Setibanya di Muzdalifah, beliau mengerjakan shalat Maghrib, lalu orang-orang melepas hewan kendaraan mereka, sementara aku membantu beliau melepas kendaraannya, setelah itu beliau mengerjakan shalat Isya.\""},"3062":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا عَمْرٌو يَعْنِي ابْنَ دِينَارٍ عَنْ أَبِي صَالِحٍ قَالَسَمِعْتُ أَبَا سَعِيدٍ يَقُولُ الذَّهَبُ بِالذَّهَبِ وَزْنًا بِوَزْنٍ قَالَ فَلَقِيتُ ابْنَ عَبَّاسٍ فَقُلْتُ أَرَأَيْتَ مَا تَقُولُ أَشَيْئًا وَجَدْتَهُ فِي كِتَابِ اللَّهِ أَوْ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ بِشَيْءٍ وَجَدْتُهُ فِي كِتَابِ اللَّهِ أَوْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرِّبَا فِي النَّسِيئَةِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah], telah menceritakan kepada kami ['Amru bin Dinar] dari [Abu Shalih] ia berkata; aku mendengar Abu Sa`id berkata; \"Emas dengan emas dengan kadar yang sama, \" lalu aku menemui [Ibnu Abbas] seraya bertanya kepadanya; \"Apakah anda mendapatkan perkara ini di dalam Al-Qur'an atau anda pernah mendengarnya dari Rasulullah shallallahu 'alaihi wasallam? Ibnu Abbas menjawab; \"Aku tidak mendapatkannya dalam Al-Qur'an atau mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, namun [Usamah bin Zaid] pernah mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Riba itu dapat terjadi dalam jual beli dengan pembayaran yang di tangguhkan.\""},"3063":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ غَدًا إِنْ شَاءَ اللَّهُ وَذَلِكَ زَمَنَ الْفَتْحِ فَقَالَ هَلْ تَرَكَ لَنَا عَقِيلٌ مِنْ مَنْزِلٍ ثُمَّ قَالَ لَا يَرِثُ الْكَافِرُ الْمُؤْمِنَ وَلَا الْمُؤْمِنُ الْكَافِرَ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami [Muhammad bin Abu Hafshah], telah menceritakan kepada kami [Az-Zuhri] dari [Ali bin Husain] dari ['Amru bin 'Utsman] dari [Usamah bin Zaid] ia bertanya; \"Wahai Rasulullah, Insya Allah dimanakah besok anda menginap?\" -Ketika itu adalah hari penaklukan kota Makkah- Beliau bersabda; \"Apakah 'Aqil meninggalkan kita tempat untuk tinggal?.\" Kemudian beliau melanjutkan: \"Orang kafir tidak mewarisi orang mukmin, dan orang mukmin tidak mewarisi orang kafir.\""},"3064":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا ثَابِتُ بْنُ قَيْسٍ أَبُو غُصْنٍ حَدَّثَنِي أَبُو سَعِيدٍ الْمَقْبُرِيُّ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ الْأَيَّامَ يَسْرُدُ حَتَّى يُقَالَ لَا يُفْطِرُ وَيُفْطِرُ الْأَيَّامَ حَتَّى لَا يَكَادَ أَنْ يَصُومَ إِلَّا يَوْمَيْنِ مِنْ الْجُمُعَةِ إِنْ كَانَا فِي صِيَامِهِ وَإِلَّا صَامَهُمَا وَلَمْ يَكُنْ يَصُومُ مِنْ شَهْرٍ مِنْ الشُّهُورِ مَا يَصُومُ مِنْ شَعْبَانَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ تَصُومُ لَا تَكَادُ أَنْ تُفْطِرَ وَتُفْطِرَ حَتَّى لَا تَكَادَ أَنْ تَصُومَ إِلَّا يَوْمَيْنِ إِنْ دَخَلَا فِي صِيَامِكَ وَإِلَّا صُمْتَهُمَا قَالَ أَيُّ يَوْمَيْنِ قَالَ قُلْتُ يَوْمُ الِاثْنَيْنِ وَيَوْمُ الْخَمِيسِ قَالَ ذَانِكَ يَوْمَانِ تُعْرَضُ فِيهِمَا الْأَعْمَالُ عَلَى رَبِّ الْعَالَمِينَ وَأُحِبُّ أَنْ يُعْرَضَ عَمَلِي وَأَنَا صَائِمٌ قَالَ قُلْتُ وَلَمْ أَرَكَ تَصُومُ مِنْ شَهْرٍ مِنْ الشُّهُورِ مَا تَصُومُ مِنْ شَعْبَانَ قَالَ ذَاكَ شَهْرٌ يَغْفُلُ النَّاسُ عَنْهُ بَيْنَ رَجَبٍ وَرَمَضَانَ وَهُوَ شَهْرٌ يُرْفَعُ فِيهِ الْأَعْمَالُ إِلَى رَبِّ الْعَالَمِينَ فَأُحِبُّ أَنْ يُرْفَعَ عَمَلِي وَأَنَا صَائِمٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Tsabit bin Qais Abu Ghushn], telah menceritakan kepadaku [Abu Sa`id Al Maqburi], telah menceritakan kepadaku [Usamah bin Zaid] ia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa beberapa hari berturut-turut, sampai-sampai dikatakan, beliau tidak pernah berbuka. Dan beliau juga berbuka beberapa hari hingga hamir beliau tidak puasa kecuali dua hari dalam sepekan, yaitu dua hari yang biasa beliau gunakan untuk berpuasa, jika tidak (berpuasa terus menerus), maka beliau akan berpuasa dua hari itu. Dan tidaklah beliau banyak berpuasa kecuali di bulan Sya'ban, Aku bertanya; 'Wahai Rasulullah, engkau berpuasa seakan-akan engkau tidak pernah berbuka dan engkau berbuka seakan engkau tidak berpuasa kecuali dua hari saja, yaitu Senin dan Kamis.\" Beliau bersabda: \"Itulah dua hari yang amalan seorang hamba ditampakkan di hadapan Rabb semesta alam, aku senang ketika amalanku ditampakkan, diriku sedang berpuasa.\" Usamah melanjutkan; kataku selanjutnya; \"Dan kami tidak melihat engkau banyak berpusa kecuali di bulan Sya'ban?.\" Beliau bersabda: \"Itulah bulan yang orang-orang banyak yang lalai antara bulan Rajab dan Ramadhan, yaitu bulan ditampakkannya amalan-amalan, dan aku suka ketika amalanku diperlihatkan dihadapan Rabbku, sedangkan aku dalam keadaan berpuasa.\""},"3065":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي سَعِيدُ بْنُ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ مُحَمَّدِ بْنِ أُسَامَةَ بْنِ زَيْدٍ عَنْ أَبِيهِ أُسَامَةَ بْنِ زَيْدٍ قَالَلَمَّا ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَبَطْتُ وَهَبَطَ النَّاسُ مَعِي إِلَى الْمَدِينَةِ فَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَصْمَتَ فَلَا يَتَكَلَّمُ فَجَعَلَ يَرْفَعُ يَدَيْهِ إِلَى السَّمَاءِ ثُمَّ يَصُبُّهَا عَلَيَّ أَعْرِفُ أَنَّهُ يَدْعُو لِي","id":"Telah menceritakan kepada kami [Ya'qub], telah menceritakan kepada kami [Ayahku] dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Sa`id bin Ubaidillah bin As Sabaq] dari [Muhammad bin Usamah bin Zaid] dari ayahnya yaitu [Usamah bin Zaid], ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam sakit keras, aku bersama orang-orang pergi menuju Madinah, lalu aku menemui Rasulullah shallallahu 'alaihi wasallam, beliau diam dan tidak berbicara, setelah itu beliau mengangkat kedua tangannya ke langit dan menunjuk kepadaku, aku tahu bahwasannya beliau mendoakanku.\""},"3066":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ زَكَرِيَّا وَوَكِيعٌ حَدَّثَنَا زَكَرِيَّا عَنْ يَحْيَى فِي حَدِيثِهِ حَدَّثَنِي عَامِرٌ عَنْ خَارِجَةَ بْنِ الصَّلْتِ قَالَ يَحْيَى التَّمِيمِيُّ عَنْ عَمِّهِ أَنَّهُأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَقْبَلَ رَاجِعًا مِنْ عِنْدِهِ فَمَرَّ عَلَى قَوْمٍ عِنْدَهُمْ رَجُلٌ مَجْنُونٌ مُوثَقٌ بِالْحَدِيدِ فَقَالَ أَهْلُهُ إِنَّا قَدْ حُدِّثْنَا أَنَّ صَاحِبَكُمْ هَذَا قَدْ جَاءَ بِخَيْرٍ فَهَلْ عِنْدَهُ شَيْءٌ يُدَاوِيهِ قَالَ فَرَقَيْتُهُ بِفَاتِحَةِ الْكِتَابِ قَالَ وَكِيعٌ ثَلَاثَةَ أَيَّامٍ كُلَّ يَوْمٍ مَرَّتَيْنِ فَبَرَأَ فَأَعْطَوْنِي مِائَةَ شَاةٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ خُذْهَا فَلَعَمْرِي مَنْ أَكَلَ بِرُقْيَةِ بَاطِلٍ لَقَدْ أَكَلْتَ بِرُقْيَةِ حَقٍّ","id":"Telah bercerita kepada kami [Yahya bin Sa'id] dari [Zakariya]. Dan [Waki'] (juga berkata) Telah bercerita kepada kami [Zakariya] dari [Yahya] tentang haditsnya: telah bercerita kepadaku [Amir] dari [Kharijah bin Ash Sahlt], ia berkata: Yahya dari [pamannya], ia mendatangi Rasulullah Shallallahu'alaihiwasallam kemudian pergi meninggalkan beliau. Ia melintasi suatu kaum, ditengah-tengah mereka ada seorang gila yang diikat dengan rantai. Para penduduknya berkata: Kami diberitahu bahwa teman kalian itu datang membawa kebaikan, lalu apakah ia punya sesuatu untuk mengobatinya? Ia (pamannya Yahya) berkata: kemudian saya meruqyahnya dengan surat Al Faatihah. [Waki'] berkata: Selama tiga hari, dua kali sehari hingga orang itu sembuh lalu mereka memberiku seratus ekor kambing. Setelah itu saya mendatangi Rasulullah Shallallahu'alaihiwasallam lalu saya mengabarkan kepada beliau tentang hal itu lalu beliau bersabda: \"Sungguh ada orang yang makan dari hasil ruqyah batil sementara kau memakan dari hasil ruqyah yang benar.\""},"3067":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنِ الشَّعْبِيِّ عَنْ خَارِجَةَ بْنِ الصَّلْتِ عَنْ عَمِّهِ قَالَأَقْبَلْنَا مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْنَا عَلَى حَيٍّ مِنْ الْعَرَبِ فَقَالُوا أُنْبِئْنَا أَنَّكُمْ جِئْتُمْ مِنْ عِنْدِ هَذَا الرَّجُلِ بِخَيْرٍ فَهَلْ عِنْدَكُمْ دَوَاءٌ أَوْ رُقْيَةٌ فَإِنَّ عِنْدَنَا مَعْتُوهًا فِي الْقُيُودِ قَالَ فَقُلْنَا نَعَمْ قَالَ فَجَاءُوا بِالْمَعْتُوهِ فِي الْقُيُودِ قَالَ فَقَرَأْتُ بِفَاتِحَةِ الْكِتَابِ ثَلَاثَةَ أَيَّامٍ غُدْوَةً وَعَشِيَّةً أَجْمَعُ بُزَاقِي ثُمَّ أَتْفُلُ قَالَ فَكَأَنَّمَا نَشِطَ مِنْ عِقَالٍ قَالَ فَأَعْطَوْنِي جُعْلًا فَقُلْتُ لَا حَتَّى أَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَقَالَ كُلْ لَعَمْرِي مَنْ أَكَلَ بِرُقْيَةِ بَاطِلٍ لَقَدْ أَكَلْتَ بِرُقْيَةِ حَقٍّ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Abdulah bin Abu As Safar] dari [Sya'bi] dari [Kharijah bin Ash Shalt] dari [pamannya], ia berkata: kami pulang dari majlis Nabi Shallallahu'alaihiwasallam, kemudian kami mendatangi sebuah perkampungan arab, mereka berkata: kami diberitahu bahwa kalian baru saja mendatangi orang itu dengan membawa kebaikan, lalu apa kalian punya doa atau ruqyah, kami punya orang gila yang tengah dirantai. Aku berkata: 'Ya.' Mereka pun membawa orang gila yang dirantai itu di hadapannya. Kemudian saya membaca surat Al Fatihah selama tiga hari di pagi dan sore hari, saya kumpulkan ludah saya kemudian saya meludahkannya lalu seolah-olah ia sembuh dari penyakit gila. Kemudian mereka memberi saya hadiah, saya berkata: 'Nanti dulu, hingga saya bertanya kepada Nabi Shallallahu'alaihiwasallam.' Saya pun bertanya kepada beliau lalu beliau bersabda: \" Sungguh ada orang yang memakan dari hasil ruqyah batil, tapi engkau memakan dari hasil ruqyah yang benar.\""},"3068":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ هُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ فَقَالَ الْأَشْعَثُ فِيَّ كَانَ وَاللَّهِ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا فَقَالَ لِلْيَهُودِيِّ احْلِفْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِذَنْ يَحْلِفَ فَذَهَبَ بِمَالِي فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah bercerita kepada kami [Abu Mu'awiyah] telah bercerita kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah], ia berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah namun dusta untuk mendapatkan harta seorang muslim, ia bertemu Allah Azza wa jalla dalam keadaan murka padanya.\" [Al Asy'ats] berkata: Demi Allah itu berkenaan denganku. Dulu saya dan seorang Yahudi memiliki sebidang tanah kemudian si Yahudi mengingkari saya, kemudian saya membawanya ke hadapan Nabi Shallallahu'alaihiwasallam, beliau bertanya: \"Apa kau punya bukti?\" saya menjawab: 'Tidak.' Kemudian beliau bertanya kepada si Yahudi: \"Bersumpahlah.\" Saya berkata: Wahai Rasulullah! kalau begitu ia pasti bersumpah lalu melenyapkan harta saya.\" Kemudian Allah Subhanahu wata`ala menurunkan ayat: \"Sesungguhnya orang-orang yang membeli janji Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\" hingga akhir ayat."},"3069":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلْمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ زِيَادِ بْنِ كُلَيْبٍ عَنِ الْأَشْعَثِ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَشْكُرُ اللَّهَ مَنْ لَا يَشْكُرُ النَّاسَ","id":"Telah bercerita kepada kami [Waki'] dari [Sufyan] dari [Salam bin 'Abdur Rahman] dari [Ziyad bin Kulaib] dari [Al Asy'ats bin Qais], ia berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah bersyukur kepada Allah orang yang tidak berterima kasih kepada sesama.\""},"3070":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا مُجَالِدٌ عَنِ الشَّعْبِيِّ حَدَّثَنَا الْأَشْعَثُ بْنُ قَيْسٍ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ كِنْدَةَ فَقَالَ لِي هَلْ لَكَ مِنْ وَلَدٍ قُلْتُ غُلَامٌ وُلِدَ لِي فِي مَخْرَجِي إِلَيْكَ مِنْ ابْنَةِ جَدٍّ وَلَوَدِدْتُ أَنَّ مَكَانَهُ شَبِعَ الْقَوْمُ قَالَ لَا تَقُولَنَّ ذَلِكَ فَإِنَّ فِيهِمْ قُرَّةَ عَيْنٍ وَأَجْرًا إِذَا قُبِضُوا ثُمَّ وَلَئِنْ قُلْتَ ذَاكَ إِنَّهُمْ لَمَجْبَنَةٌ مَحْزَنَةٌ إِنَّهُمْ لَمَجْبَنَةٌ مَحْزَنَةٌ","id":"Telah bercerita kepada kami [Suraij bin An Nu'man] telah bercerita kepada kami [Husyaim] telah memberitakan kepada kami [Mujalid] dari [Asy Sya'bi] telah bercerita kepada kami [Al Asy'ats bin Qais], ia berkata: Saya mendatangi Nabi Shallallahu'alaihiwasallam bersama rombongan, lalu beliau bertanya: Apa kau punya putra? Saya menjawab: Saat saya pergi untuk menemui baginda, saya memperoleh bayi laki-laki dari bibi (keponakan laki-laki), saya mengimpikan kaum saya bangga dengan posisinya. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jangan kau katakan seperti itu, karena bisa jadi ia sebagai penyejuk hati, namun jika meninggal pun kau memperoleh ganjaran, namun jika hanya kau katakan akan menjadi kebanggaan kaummu, nanti hanyalah mendatangkan kekecewaan dan kesedihan, kekecewaan dan kesedihan'."},"3071":{"ar":"حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ بْنِ الطُّفَيْلِ الْبَكَّائِيُّ حَدَّثَنَا مَنْصُورٌ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَمَنْ حَلَفَ عَلَى يَمِينٍ صَبْرًا يَسْتَحِقُّ بِهَا مَالًا وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ وَإِنَّ تَصْدِيقَهَا لَفِي الْقُرْآنِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ قَالَ فَخَرَجَ الْأَشْعَثُ وَهُوَ يَقْرَؤُهَا قَالَ فِيَّ أُنْزِلَتْ هَذِهِ الْآيَةُ إِنَّ رَجُلًا ادَّعَى رَكِيًّا لِي فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَاهِدَاكَ أَوْ يَمِينُهُ فَقُلْتُ أَمَا إِنَّهُ إِنْ حَلَفَ حَلَفَ فَاجِرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ صَبْرًا يَسْتَحِقُّ بِهَا مَالًا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ","id":"Telah bercerita kepada kami [Ziyad bin Abdullah bin Ath Thufail Al Bakka`i] telah bercerita kepada kami [Manshur] dari [Syaqiq] dari [Abdullah bin Mas'ud], ia berkata: 'Barangsiapa bersumpah dengan memaksa untuk mendapatkan harta sementara ia dusta, akan bertemu Allah dalam keadaan murka kepadanya. Pembenar hal itu ada dalam Al Qur`an: \"Sesungguhnya orang-orang yang membeli janji Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\" hingga akhir ayat. Kemudian [Al Asy'ats] keluar dan ia membacanya, ia berkata: Berkenaan dengan dirikulah ayat ini turun. Dulu ada seseorang yang mengakui sumur saya, kami lalu mempersengketakannya di hadapan Rasulullah Shallallahu'alaihiwasallam, beliau bertanya: Yang menjadi buktimu adalah dua orang saksimu atau sumpahnya. Saya berkata: Bila ia bersumpah pasti dusta. Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah dengan memaksa untuk mendapatkan suatu harta, maka akan bertemu Allah dalam keadaan murka kepadanya.\""},"3072":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ قَالَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَأَخْبَرُوهُ فَقَالَ أَشْعَثُ صَدَقَ فِيَّ نَزَلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي أَرْضٍ فَخَاصَمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ فَيَمِينُهُ قَالَ قُلْتُ إِذَنْ يَحْلِفَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ صَبْرًا لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Al A'masy] dari [Abu Wa`il], ia berkata: [Al Asy'ats] masuk dan bertanya: Apa yang disampaikan [Abu 'Abdur Rahman] kepada kalian? Mereka memberitahukan kepadanya lalu Al Asy'ats berkata: Ia benar, berkenaan dengan sayalah ayat itu turun. Dulu antara saya dan seseorang mempersengketakan sebidang tanah. Saya mempersengketakannya di hadapan Nabi Shallallahu'alaihiwasallam Kemudian beliau bertanya: 'Apa kau punya bukti.' Saya menjawab: Tidak. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berarti sumpahnya.\" Saya berkata: Kalau begitu ia pasti bersumpah. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa bersumpah dengan memaksa untuk mendapatkan harta seorang muslim sementara ia dusta, ia bertemu Allah Azza wa Jalla dalam keadaan murka padanya.\" Kemudian turunlah ayat: \"Orang-orang yang membeli janji Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\""},"3073":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبًا لِيَقْتَطِعَ بِهَا مَالَ رَجُلٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ وَأُنْزِلَ تَصْدِيقُ ذَلِكَ فِي الْقُرْآنِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا أُولَئِكَ لَا خَلَاقَ لَهُمْ فِي الْآخِرَةِ إِلَى عَذَابٌ أَلِيمٌ }قَالَ فَلَقِيَنِي الْأَشْعَثُ فَقَالَ مَا حَدَّثَكُمْ عَبْدُ اللَّهِ الْيَوْمَ قَالَ قُلْتُ لَهُ كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa`il] dari [Abdullah] dari Nabi Shallallahu'alaihiwasallam, bahwa beliau bersabda: \"Barangsiapa bersumpah dengan bohong untuk mendapatkan harta seseorang -atau bersabda: saudaranya- maka akan bertemu Allah AzzaWaJalla dalam keadaan murka kepadanya.\" Kemudian turunlah ayat sebagai pembenar hal itu: \"Orang-orang yang membeli janji Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapatkan bagian diakhirat..\" hingga \"Adzab yang pedih.\" Ia (Abu Wa`il) Berkata: kemudian Al Asy'ats menemuiku dan bertanya: Apa yang disampaikan Abdullah hari ini? ia menjawab: Seperti ini dan itu. Ia ([Al Asy'ats]) Berkata: Berkenaan dengankulah ayat itu diturunkan."},"3074":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنِي عَقِيلُ بْنُ طَلْحَةَ قَالَ عَفَّانُ فِي حَدِيثِهِ أَنَا عَقِيلُ بْنُ طَلْحَةَ السُّلَمِيُّ عَنْ مُسْلِمِ بْنِ هَيْضَمٍ عَنِ الْأَشْعَثِ بْنِ قَيْسٍ أَنَّهُ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدٍ مِنْ كِنْدَةَ قَالَ عَفَّانُ لَا يَرَوْنِي إِلَّا أَفْضَلَهُمْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَزْعُمُ أَنَّكُمْ مِنَّا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ بَنُو النَّضْرِ بْنُ كِنَانَةَ لَا نَقْفُو أُمَّنَا وَلَا نَنْتَفِي مِنْ أَبِينَاقَالَ قَالَ الْأَشْعَثُ فَوَاللَّهِ لَا أَسْمَعُ أَحَدًا نَفَى قُرَيْشًا مِنْ النَّضْرِ بْنِ كِنَانَةَ إِلَّا جَلَدْتُهُ الْحَدَّ","id":"Telah bercerita kepada kami [Bahz] dan [Affan] keduanya berkata: Telah bercerita kepada kami [Hammad bin Salamah] telah bercerita kepada kami [Aqil bin Thalhah], -dalam hadits Affan: Telah mengabarkan kepada kami Aqil bin Thalhah Al Sulami- dari [Muslim bin Haidham] dari [Al Asy'ats bin Qais], ia berkata: Saya mendatangi Rasulullah Shallallahu'alaihi wasallam bersama rombongan dari Kindah. Mereka menilaiku sebagai orang terhormat diantara mereka. Saya berkata: Wahai Rasulullah! kami yakin bahwa engkau termasuk golongan kami. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kami adalah keturunan Bani An Nadhr bin Kinanah, kami tidak mengikuti ibu kami tapi tidak menafikan ayah kami. Al Asy'ats berkata: Tidaklah seseorang didatangkan kepadaku yang menafikan Quraisy dari An Nadhr bin Kinanah melainkan pasti saya mencambuknya."},"3075":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنِ ابْنِ شُبْرُمَةَ عَنْ أَبِي مَعْشَرٍ عَنِ الْأَشْعَثِ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَشْكُرُ اللَّهَ مَنْ لَا يَشْكُرُ النَّاسَ","id":"Telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Ibnu Syubrumah] dari [Abu Ma'syar] dari [Al Asy'ats bin Qais] ia berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan bersyukur kepada Allah orang yang tidak berterima kasih kepada manusia.\""},"3076":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ ثَلَاثَةَ أَحَادِيثَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَطَعَ مَالَ امْرِئٍ مُسْلِمٍ بِغَيْرِ حَقٍّ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ فَجَاءَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قَالَ فَحَدَّثْنَاهُ قَالَ فِيَّ كَانَ هَذَا الْحَدِيثُ خَاصَمْتُ ابْنَ عَمٍّ لِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بِئْرٍ كَانَتْ لِي فِي يَدِهِ فَجَحَدَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيِّنَتُكَ أَنَّهَا بِئْرُكَ وَإِلَّا فَيَمِينُهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا لِي بِيَمِينِهِ وَإِنْ تَجْعَلْهَا بِيَمِينِهِ تَذْهَبْ بِئْرِي إِنَّ خَصْمِي امْرُؤٌ فَاجِرٌ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَطَعَ مَالَ امْرِئٍ مُسْلِمٍ بِغَيْرِ حَقٍّ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }الْآيَةَ","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Abu Bakar bin 'Ayyasy] dari ['Ashim bin Abu An Najud] dari [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud], tiga hadits, ia berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mengambil harta seorang muslim secara tidak benar, ia bertemu Allah AzzaWaJalla dalam keadaan murka padanya.\" [Al Asy'ats] datang dan berkata: Apa yang disampaikan Abu 'Abdur Rahman kepada kalian? Ia (Ibnu Mas'ud) berkata: Kami memberitahukannya. Ia (Al Asy'ats) berkata: Hadits ini berkenaan denganku. Saya bersengketa dengan sepupu saya di hadapan Rasulullah Shallallahu'alaihiwasallam tentang sebuah sumur milik saya yang ia miliki, ia mengingkariku kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mana buktimu bahwa itu adalah sumurmu, bila tidak maka sumpahnya.\" Ia (Al Asy'ats) berkata: wahai Rasulullah! apa urusan saya dengan sumpahnya, bila Tuan putuskan berdasarkan sumpahnya, sumurku akan lenyap, sesungguhnya sekutuku adalah orang pendusta. Ia (Al Asy'ats) berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mengambil harta seorang muslim secara tidak benar, ia bertemu Allah AzzaWaJalla dalam keadaan murka padanya.\" Kemudian Rasulullah Shallallahu'alaihiwasallam membaca ayat: \"Sesungguhnya orang-orang yang membeli janji Allah…\" dan seterusnya."},"3077":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْحَارِثُ بْنُ سُلَيْمَانَ حَدَّثَنَا كُرْدُوسٌ عَنِ الْأَشْعَثِ بْنِ قَيْسٍأَنَّ رَجُلًا مِنْ كِنْدَةَ وَرَجُلًا مِنْ حَضْرَمَوْتَ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضٍ بِالْيَمَنِ فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ أَرْضِي اغْتَصَبَهَا هَذَا وَأَبُوهُ فَقَالَ الْكِنْدِيُّ يَا رَسُولَ اللَّهِ أَرْضِي وَرِثْتُهَا مِنْ أَبِي فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ اسْتَحْلِفْهُ أَنَّهُ مَا يَعْلَمُ أَنَّهَا أَرْضِي وَأَرْضُ وَالِدِي وَالَّذِي اغْتَصَبَهَا أَبُوهُ فَتَهَيَّأَ الْكِنْدِيُّ لِلْيَمِينِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَا يَقْتَطِعُ عَبْدٌ أَوْ رَجُلٌ بِيَمِينِهِ مَالًا إِلَّا لَقِيَ اللَّهَ يَوْمَ يَلْقَاهُ وَهُوَ أَجْذَمُ فَقَالَ الْكِنْدِيُّ هِيَ أَرْضُهُ وَأَرْضُ وَالِدِهِ","id":"Telah bercerita kepada kami [Abdullah bin Numair] telah bercerita kepada kami [Al Harits bin Sulaiman] telah bercerita kepada kami [Kurdus] dari [Al Asy'ats bin Qais] bahwa seseorang dari Kindah dan orang lain dari Hadhramaut mempersengketakan sebuah tanah di Yaman di hadapan Rasulullah Shallallahu'alaihiwasallam Orang Hadhramaut berkata: Wahai Rasulullah! tanah saya diserobot oleh orang ini dan ayahnya. Orang Kindah berkata: Wahai Rasulullah! Ini tanah saya yang saya warisi dari ayah saya. Orang Hadhramaut berkata: Wahai Rasulullah! mintalah ia bersumpah bahwa ia tidak tahu itu adalah tanah saya dan tanah ayah saya yang diserobot oleh ayahnya. Orang Kindah bersiap-siap untuk bersumpah kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang hamba atau seseorang mendapatkan suatu harta dengan sumpahnya, kecuali ia bertemu Allah pada hari ia bertemu denganNya dalam keadaan terpotong tangannya.\" Kemudian orang Kindah berkata: Itu tanahnya dan tanah ayahnya."},"3078":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ حَدَّثَنَا حَمَّادٌ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ يَمْسَحُ الْمُسَافِرُ عَلَى الْخُفَّيْنِ ثَلَاثَ لَيَالٍ وَالْمُقِيمُ يَوْمًا وَلَيْلَةً","id":"Telah bercerita kepada kami [Isma'il] telah bercerita kepada kami [Hisyam Ad-Dustuwa`i] telah bercerita kepada kami [Hammad] dari [Ibrahim] dari [Abu Abdullah Al Jadali] dari [Khuzaimah bin Tsabit] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang bepergian mengusap sepatunya selama tiga malam dan orang yang bermukim mengusap sepatunya selama sehari semalam.\""},"3079":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ مَهْدِيٍّ قَالَا ثَنَا شُعْبَةُ عَنِ الْحَكَمِ وَحَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الْمَسْحِ عَلَى الْخُفَّيْنِ يَوْمٌ وَلَيْلَةٌ لِلْمُقِيمِ وَثَلَاثَةُ أَيَّامٍ وَلَيَالِيهُنَّ لِلْمُسَافِرِ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] dan [Ibnu Mahdi], keduanya berkata: Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dan [Hammad] dari [Ibrahim] dari [Abu Abdullah Al Jadali] dari [Khuzaimah bin Tsabit] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda tentang membasuh sepatu: \"Sehari semalam untuk yang bermukim dan tiga hari tiga malam bagi yang bepergian.\""},"3080":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْحَجَّاجُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ هَرَمِيِّ بْنِ عَبْدِ اللَّهِ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ الْعَبْسِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَسْتَحِي اللَّهُ مِنْ الْحَقِّ لَا تَأْتُوا النِّسَاءَ فِي أَعْجَازِهِنَّحَدَّثَنَا ابْنُ أَبِي زَائِدَةَ أَنَا الْحَجَّاحُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ هَرَمِيِّ بْنِ عَبْدِ اللَّهِ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah bercerita kepada kami [Abu Mu'awiyah] telah bercerita kepada kami [Al Hajjaj] dari [Amr bin Syu'aib] dari [Harami bin Abdullah] dari [Khuzaimah bin Tsabit Al Absi], ia berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah tidak malu dari kebenaran, janganlah kalian menggauli istri-istri kalian di dubur mereka.\" Telah bercerita kepada kami [Ibnu Abi Za`idah] telah mengabarkan kepada kami [Al Hajjaj] dari [Amr bin Syu'aib] dari [Harami bin Abdullah] dari [Khuzaimah bin Tsabit] dari Nabi Shallallahu'alaihiwasallam, hadits yang serupa."},"3081":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عَمْرِو بْنِ خُزَيْمَةَ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الِاسْتِطَابَةَ فَقَالَ ثَلَاثَةُ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ","id":"Telah bercerita kepada kami [Muhammad bin Bisyr] telah bercerita kepada kami [Hisyam bin Urwah] dari [Amr bin Khuzaimah] dari [Umaroh bin Khuzaimah] dari [Khuzaimah bin Tsabit Al Anshari] bahwa Nabi Shallallahu'alaihiwasallam menyebutkan tentang membersihkan diri setelah buang hajat lalu bersabda: \"Tiga batu yang tidak ada kotorannya.\""},"3082":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ الْعَمِّيُّ حَدَّثَنَا مَنْصُورٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ التَّيْمِيُّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ امْسَحُوا عَلَى الْخِفَافِ ثَلَاثَةَ أَيَّامٍ وَلَوْ اسْتَزَدْنَاهُ لَزَادَنَا","id":"Telah bercerita kepada kami [Abu Abdush Shamad Al Ammi] telah bercerita kepada kami [Manshur] telah bercerita kepada kami [Ibrahim bin Yazid Al Taimi] dari [Amr bin Maimun] dari [Abu Abdullah Al Jadali] dari [Khuzaimah bin Tsabit Al Anshari] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Basuhlah sepatu selama tiga hari dan bila kita meminta tambahan padaNya niscaya Ia memberinya.\""},"3083":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ سَمِعَهُ يُحَدِّثُ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَرَخَّصَ لِلْمُسَافِرِ ثَلَاثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ وَالْمُقِيمِ يَوْمًا وَلَيْلَةًقَالَ عَبْد اللَّهِ قَالَ أَبِي سَمِعْتُهُ مِنْ سُفْيَانَ مَرَّتَيْنِ يَذْكُرُ لِلْمُقِيمِ وَلَوْ أَطْنَبَ السَّائِلُ فِي مَسْأَلَتِهِ لَزَادَهُمْ","id":"Telah bercerita kepada kami [Sufyan] dari [Manshur] dari [Ibrahim At Taimi] dari [Amr bin Maimun] dari [Abu Abdullah Al Jadali], ia mendengarnya menceritakan dari [Khuzaimah bin Tsabit]: Kami bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang membasuh sepatu kemudian beliau memberi keringanan bagi musafir selama tiga hari tiga malam, dan bagi yang bermukim selama sehari semalam. Berkata Abdullah: ayah saya berkata: Saya mendengarnya dari Sufyan sebanyak dua kali menyebutkan bagi orang yang bermukim. Andai si penanya memperpanjang pertanyaannya, pastilah beliau menambahi mereka."},"3084":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ ثَابِتٍ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ مَالِكٍ وَخُزَيْمَةَ بْنِ ثَابِتٍ وَأُسَامَةَ بْنِ زَيْدٍ قَالُواقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّاعُونُ رِجْزٌ أَوْ عَذَابٌ عُذِّبَ بِهِ قَوْمٌ فَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا مِنْهَا وَإِذَا سَمِعْتُمْ بِهِ بِأَرْضٍ فَلَا تَدْخُلُوا عَلَيْهِ","id":"Telah bercerita kepada kami [Waki'] dari [Sufyan] dari [Habib bin Tsabit] dari [Ibrahim bin Sa'ad] dari [Sa'ad bin Malik], [Khuzaimah bin Tsabit] dan [Usamah bin Zaid], mereka berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tha'un adalah kotoran atau adzab, dengannya sekelompok kaum disiksa, bila terjadi disuatu tempat sementara kalian ada disana maka kalian jangan keluar meninggalkannya dan bila kalian mendengar terjadi disuatu tempat maka kalian jangan memasukinya.\""},"3085":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَمَّادٍ وَمَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسَافِرِ ثَلَاثًا وَلِلْمُقِيمِ يَوْمًا وَلَيْلَةً","id":"Telah bercerita kepada kami [Waki'] dari [Sufyan] dari [Hammad] dan [Manshur] dari [Ibrahim] dari [Abu Abdullah Al Jadali] dari [Khuzaimah bin Tsabit], ia berkata: Rasulullah Shallallahu'alaihiwasallam memberi waktu tiga hari bagi musafir dan satu hari satu malam bagi orang yang bermukim (perihal mengusap sepatu)."},"3086":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي أَبُو جَعْفَرٍ الْمَدِينِيُّ يَعْنِي الْخَطْمِيَّ قَالَ سَمِعْتُ عُمَارَةَ بْنَ عُثْمَانَ بْنِ سَهْلِ بْنِ حُنَيْفٍ يُحَدِّثُ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍأَنَّهُ رَأَى فِي مَنَامِهِ أَنَّهُ يُقَبِّلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِذَلِكَ فَنَاوَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَّلَ جَبْهَتَهُ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] telah bercerita kepadaku [Abu Ja'far Al Madini Al Khathmi], ia berkata: Saya mendengar [Umaroh bin 'Utsman bin Sahal bin Hunaif] menceritakan dari [Khuzaimah bin Tsabit] bahwa ia bermimpi mencium Nabi Shallallahu'alaihiwasallam kemudian ia mendatangi Nabi Shallallahu'alaihiwasallam dan memberitahukan mimpi itu, kemudian Nabi Shallallahu'alaihiwasallam memberikan dahi beliau kemudian ia menciumnya."},"3087":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ بْنِ ثَابِتٍ أَنَّ أَبَاهُ قَالَرَأَيْتُ فِي الْمَنَامِ أَنِّي أَسْجُدُ عَلَى جَبْهَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُ بِذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الرُّوحَ لَا تَلْقَى الرُّوحَ وَأَقْنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ هَكَذَا فَوَضَعَ جَبْهَتَهُ عَلَى جَبْهَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami [Affan] telah bercerita kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Abu Ja'far Al Hathmi] dari [Umarah bin Khuzaimah bin Tsabit] bahwa [ayahnya] berkata: Saya bermimpi bersujud diatas dahi Nabi Shallallahu'alaihiwasallam, kemudian saya memberitahukan hal itu kepada Rasulullah Shallallahu'alaihiwasallam. Kemudian beliau bersabda: \"Sesungguhnya ruh itu tidak bertemu dengan ruh.\" Kemudian Nabi Shallallahu'alaihiwasallam memasukkan wajah beliau ke baju beliau seperti ini lalu Umaroh meletakkan dahinya diatas dahi Nabi Shallallahu'alaihiwasallam"},"3088":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ الْأَنْصَارِيِّ قَالَ سَمِعْتُ ابْنَ أَبِي بَشِيرٍ وَابْنَةَ أَبِي بَشِيرٍ يُحَدِّثَانِ عَنْ أَبِيهِمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الْحُمَّى أَبْرِدُوهَا بِالْمَاءِ فَإِنَّهَا مِنْ فَيْحِ جَهَنَّمَ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Habib Al Anshori], ia berkata: Saya mendengar [Ibnu Abi Basyir] dan [putri Abu Basyir] menceritakan dari [ayah] mereka dari Nabi Shallallahu'alaihiwasallam, beliau bersabda tentang sakit demam: \"Dinginkan dengan air dan sesungguhnya ia dari hembusan neraka Jahannam.\""},"3089":{"ar":"حَدَّثَنَا رَوْحٌ وَإِسْمَاعِيلُ بْنُ عُمَرَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّ أَبَا بَشِيرٍ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا لَا يَبْقَيَنَّ فِي رَقَبَةِ بَعِيرٍ قِلَادَةٌ مِنْ وَتَرٍ وَلَا قِلَادَةٌ إِلَّا قُطِعَتْ قَالَ إِسْمَاعِيلُ قَالَ وَأَحْسِبُهُ قَالَ وَالنَّاسُ فِي صِيَامِهِمْ","id":"Telah bercerita kepada kami [Rouh] dan [Isma'il bin Umar] dari [Malik] dari [Abdullah bin Abu Bakar] dari ['Abbad bin Tamim] bahwa [Abu Basyir Al Anshari] mengabarkan kepadanya, bahwasanya ia pernah bersama Rasulullah Shallallahu'alaihiwasallam dalam salah satu perjalanan beliau, kemudian Rasulullah Shallallahu'alaihiwasallam mengirim seorang utusan untuk menyampaikan tidaklah dileher unta masih ada kalung dari tali busur dan tidak juga kalung lain kecuali harus diputus. Berkata Isma'il: -Saya kira- perawi berkata: Dan orang-orang tengah berpuasa."},"3090":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنِي حَبَّانُ بْنُ وَاسِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ وَأَبِي بَشِيرٍ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ ذَاتَ يَوْمٍ فَمَرَّتْ امْرَأَةٌ بِالْبَطْحَاءِ فَأَشَارَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَأَخَّرِي فَرَجَعَتْ حَتَّى صَلَّى ثُمَّ مَرَّتْ","id":"Telah bercerita kepada kami [Ali bin Ishak] telah bercerita kepada kami [Abdullah] telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepadaku [Habban bin Wasi] dari [ayahnya] dari [Abdullah bin Zaid] dan [Abu Basyir Al Anshari] bahwa Rasulullah Shallallahu'alaihiwasallam pernah shalat bersama mereka pada suatu malam, kemudian seorang wanita melintas di Batha', kemudian Rasulullah Shallallahu'alaihiwasallam memberi isyarat kepada si wanita untuk menghentikan jalannya. Wanita itu pun menghentikan jalannya, hingga Rasulullah Shallallahu'alaihiwasallam selesai shalat. Setelah itu ia meneruskan perjalanannya."},"3091":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ نَافِعٍ قَالَرَآنِي أَبُو بَشِيرٍ الْأَنْصَارِيُّ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أُصَلِّي صَلَاةَ الضُّحَى حِينَ طَلَعَتْ الشَّمْسُ فَعَابَ عَلَيَّ ذَلِكَ وَنَهَانِي ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُصَلُّوا حَتَّى تَرْتَفِعَ الشَّمْسُ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ الشَّيْطَانِ","id":"Telah bercerita kepada kami Harun bin Ma'ruf. Berkata Abdullah: Saya mendengarnya dari [Harun], ia berkata: Telah bercerita kepada kami [Abdullah] telah bercerita kepadaku [Mahramah] dari [ayahnya] dari [Sa'id bin Nafi'], ia berkata: [Abu Basyir], sahabat Rasulullah Shallallahu'alaihiwasallam melihatku saat shalat dhuhaa saat matahari terbit, lalu ia mencelaku karenanya kemudian berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian shalat hingga matahari terangkat karena matahari terbit diantara dua tanduk setan.\""},"3092":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ أَخْبَرَنِي يَزِيدُ بْنُ نُعَيْمِ بنِ هَزَّالٍ عَنْ أَبِيهِ قَالَكَانَ مَاعِزُ بْنُ مَالِكٍ فِي حِجْرِ أَبِي فَأَصَابَ جَارِيَةً مِنْ الْحَيِّ فَقَالَ لَهُ أَبِي ائْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ بِمَا صَنَعْتَ لَعَلَّهُ يَسْتَغْفِرُ لَكَ وَإِنَّمَا يُرِيدُ بِذَلِكَ رَجَاءَ أَنْ يَكُونَ لَهُ مَخْرَجٌ فَأَتَاهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ فَأَعْرَضَ عَنْهُ ثُمَّ أَتَاهُ الثَّانِيَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ ثُمَّ أَتَاهُ الثَّالِثَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ ثُمَّ أَتَاهُ الرَّابِعَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَقِمْ عَلَيَّ كِتَابَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ قَدْ قُلْتَهَا أَرْبَعَ مَرَّاتٍ فَبِمَنْ قَالَ بِفُلَانَةَ قَالَ هَلْ ضَاجَعْتَهَا قَالَ نَعَمْ قَالَ هَلْ بَاشَرْتَهَا قَالَ نَعَمْ قَالَ هَلْ جَامَعْتَهَا قَالَ نَعَمْ قَالَ فَأَمَرَ بِهِ أَنْ يُرْجَمَ قَالَ فَأُخْرِجَ بِهِ إِلَى الْحَرَّةِ فَلَمَّا رُجِمَ فَوَجَدَ مَسَّ الْحِجَارَةِ جَزَعَ فَخَرَجَ يَشْتَدُّ فَلَقِيَهُ عَبْدُ اللَّهِ بْنُ أُنَيْسٍ وَقَدْ أَعْجَزَ أَصْحَابَهُ فَنَزَعَ لَهُ بِوَظِيفِ بَعِيرٍ فَرَمَاهُ بِهِ فَقَتَلَهُ قَالَ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ هَلَّا تَرَكْتُمُوهُ لَعَلَّهُ يَتُوبُ فَيَتُوبَ اللَّهُ عَلَيْهِقَالَ هِشَامٌ فَحَدَّثَنِي يَزِيدُ بْنُ نُعَيْمِ بْنِ هَزَّالٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي حِينَ رَآهُ وَاللَّهِ يَا هَزَّالُ لَوْ كُنْتَ سَتَرْتَهُ بِثَوْبِكَ كَانَ خَيْرًا مِمَّا صَنَعْتَ بِهِ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Hisyam bin Sa'ad] telah bercerita kepadaku [Yazid bin Nu'aim bin Hazzal] dari [ayahnya], ia berkata: Ma'iz bin Malik pernah ada dalam didikanku kemudian ia menggauli seorang budak wanita kampung, ayah saya kemudian berkata padanya: Datangilah Rasulullah Shallallahu'alaihiwasallam, dan beritahukan kepada beliau apa yang telah kau perbuat mudah-mudahan beliau memintakan ampunan untukmu. Ayah saya menginginkan hal itu karena berharap ada jalan keluarnya. Ma'iz mendatangi Rasulullah Shallallahu'alaihiwasallam lalu berkata: Wahai Rasulullah! aku telah berzina, maka tegakkan putusan Allah padaku. Rasulullah Shallallahu'alaihiwasallam berpaling darinya kemudian Ma'iz mendatangi beliau lagi dan berkata: Wahai Rasulullah! aku telah berzina, maka tegakkan putusan Allah padaku. Kemudian Ma'iz mendatangi beliau untuk ketiga kalinya. Kemudian Ma'iz datang lagi untuk keempat kalinya dan berkata: Wahai Rasulullah! aku telah berzina, maka tegakkan putusan Allah padaku. Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \" kau telah mengatakannya empat kali, lalu dengan siapa?\" Ma'iz menjawab: Dengan Fulanah. Rasulullah Shallallahu'alaihiwasallam bertanya: \"Apa kau menidurinya?\" Ma'iz menjawab: Ya. Rasulullah Shallallahu'alaihiwasallam bertanya: \"Apa kau menggaulinya?\" Ma'iz menjawab: Ya. Rasulullah Shallallahu'alaihiwasallam bertanya: \"Apa kau menyetubuhinya?\" Ma'iz menjawab: Ya. Kemudian Rasulullah Shallallahu'alaihiwasallam memerintahkan Ma'iz dihukum rajam. Ma'iz pun dikeluarkan ke tanah tak berpasir. Saat dihukum rajam dan merasakan hantaman batu, Ma'iz takut kemudian keluar melarikan diri lalu ditangkap Abdullah bin Unais, ia telah melelahkan para sahabat-sahabatnya, kemudian Abdullah melepaskan alas kaki onta dan melemparkannya ke Ma'iz hingga membunuhnya. Setelah itu ia mendatangi Nabi Shallallahu'alaihiwasallam dan memberitahukan hal itu, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kenapa tidak kalian biarkan dia, mudah-mudahan ia bertaubat sehingga Allah menerima taubatnya.\" Berkata Hisyam: Telah bercerita kepadaku Yazid bin Nu'aim bin Hazzal dari ayahnya, bahwa Rasulullah Shallallahu'alaihiwasallam bersabda kepada ayah saya saat melihat beliau: \"Demi Allah wahai Hazzal, andai kau menutupinya dengan bajumu, tentu lebih baik dari apa yang kau perbuat terhadapnya.\""},"3093":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ يَعْنِي ابْنَ يَزِيدَ الْعَطَّارَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نُعَيْمِ بْنِ هَزَّالٍأَنَّ هَزَّالًا كَانَ اسْتَأْجَرَ مَاعِزَ بْنَ مَالِكٍ وَكَانَتْ لَهُ جَارِيَةٌ يُقَالُ لَهَا فَاطِمَةُ قَدْ أُمْلِكَتْ وَكَانَتْ تَرْعَى غَنَمًا لَهُمْ وَإِنَّ مَاعِزًا وَقَعَ عَلَيْهَا فَأَخْبَرَ هَزَّالًا فَخَدَعَهُ فَقَالَ انْطَلِقْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ عَسَى أَنْ يَنْزِلَ فِيكَ قُرْآنٌ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ فَلَمَّا عَضَّتْهُ مَسُّ الْحِجَارَةِ انْطَلَقَ يَسْعَى فَاسْتَقْبَلَهُ رَجُلٌ بِلَحْيِ جَزُورٍ أَوْ سَاقِ بَعِيرٍ فَضَرَبَهُ بِهِ فَصَرَعَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلَكَ يَا هَزَّالُ لَوْ كُنْتَ سَتَرْتَهُ بِثَوْبِكَ كَانَ خَيْرًا لَكَ","id":"Telah bercerita kepada kami [Affan] telah bercerita kepada kami [Aban bin Yazid Al 'Atthar] telah bercerita kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdur Rahman] dari [Nu'aim bin Hazzal]; Hazzal pernah menyewa Ma'iz bin Malik dan ia memiliki seorang budak wanita bernama Fathimah yang ia miliki, budak wanita ini bertugas menggembala kambing milik mereka dan Ma'iz menyetubuhinya. Ma'iz memberitahukan hal itu kepada Hazzal kemudian Hazzal mengelabuhinya dan berkata: Pergilah ke Nabi Shallallahu'alaihiwasallam dan beritahukan pada beliau, mudah-mudahan turun Al Qur`an berkenaan denganmu. Kemudian Nabi Shallallahu'alaihiwasallam memerintahkan agar dirajam. Saat dirajam dan terkena hantaman batu, Ma'iz berusaha kabur kemudian seseorang mengejarnya dengan membawa tulang dagu unta atau tulang betis unta kemudian dipukulkan ke Ma'iz hingga mati. Setelah itu Nabi Shallallahu'alaihiwasallam bersabda: \"Celaka kau hai Hazzal, andai kau tutupi dengan bajumu tentu lebih baik bagimu.\""},"3094":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ يَزِيدَ بْنِ نُعَيْمٍ عَنْ أَبِيهِأَنَّ مَاعِزَ بْنَ مَالِكٍ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَقِمْ عَلَيَّ كِتَابَ اللَّهِ فَأَعْرَضَ عَنْهُ أَرْبَعَ مَرَّاتٍ ثُمَّ أَمَرَ بِرَجْمِهِ فَلَمَّا مَسَّتْهُ الْحِجَارَةُ قَالَ عَبْدُ الرَّحْمَنِ وَقَالَ مَرَّةً فَلَمَّا عَضَّتْهُ الْحِجَارَةُ أَجْزَعَ فَخَرَجَ يَشْتَدُّ وَخَرَجَ عَبْدُ اللَّهِ بْنُ أُنَيْسٍ أَوْ أَنَسُ بْنُ نَادِيَةَ فَرَمَاهُ بِوَظِيفِ حِمَارٍ فَصَرَعَهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَهُ بِأَمْرِهِ فَقَالَ هَلَّا تَرَكْتُمُوهُ لَعَلَّهُ أَنْ يَتُوبَ فَيَتُوبَ اللَّهُ عَلَيْهِ ثُمَّ قَالَ يَا هَزَّالُ لَوْ سَتَرْتَهُ بِثَوْبِكَ كَانَ خَيْرًا لَكَ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Sufyan] dari [Zaid bin Aslam] dari [Yazid bin Nu'aim] dari [ayahnya] bahwa Ma'iz bin Malik mendatangi Nabi Shallallahu'alaihiwasallam dan berkata: \"Tegakkan putusan Allah padaku.\" Nabi Shallallahu'alaihiwasallam berpaling darinya empat kali kemudian setelah itu beliau memerintahkan agar Ma'iz dihukum rajam. Saat Malik terkena hantaman batu -'Abdur Rahman kadang berkata- dan saat batu menghantamnya, ia takut kemudian melarikan diri. Abdullah bin Unais atau Unais bin Nadiyah mengejarnya kemudian melemparnya dengan kaki keledai hingga roboh. Kemudian ia mendatangi Nabi Shallallahu'alaihiwasallam dan menceritakan perihalnya, Nabi Shallallahu'alaihiwasallam bersabda: \"Kenapa tidak kau biarkan saja dia, mudah-mudahan ia bertaubat lalu Allah menerima taubatnya?.\" Setelah itu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hai Hazzal! Andai kau menutupinya dengan bajumu tentu lebih baik bagimu.\""},"3095":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ أَخْبَرَنِي يَزِيدُ بْنُ نُعَيْمِ بْنِ هَزَّالٍ عَنْ أَبِيهِأَنَّ مَاعِزَ بْنَ مَالِكٍ كَانَ فِي حِجْرِهِ قَالَ فَلَمَّا فَجَرَ قَالَ لَهُ ائْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ وَلَقِيَهُ يَا هَزَّالُ أَمَا لَوْ كُنْتَ سَتَرْتَهُ بِثَوْبِكَ لَكَانَ خَيْرًا مِمَّا صَنَعْتَ بِهِ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Hisyam bin Sa'id] telah bercerita kepadaku [Yazid bin Nuaim bin Hazzal] dari [ayahnya] bahwa Ma'iz bin Malik ada dalam didikannya. Saat Ma'iz bin Malik melakukan kekejian, Hazzal berkata padanya: Datangilah Rasulullah Shallallahu'alaihiwasallam dan beritahukan kepada beliau. Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda kepadanya dan menemuinya: \"Hai Hazzal! Andai kau menutupinya dengan bajumu tentu lebih baik dari apa yang kau lakukan terhadapnya.\""},"3096":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ يُحَدِّثُ عَنِ ابْنِ هَزَّالٍ عَنْ أَبِيهِأَنَّهُ ذَكَرَ شَيْئًا مِنْ أَمْرِ مَاعِزٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتَ سَتَرْتَهُ بِثَوْبِكَ كَانَ خَيْرًا لَكَ","id":"Telah bercerita kepada kami ['Abdush Shamad] telah bercerita kepada kami [Syu'bah] telah bercerita kepada kami [Yahya bin Sa'id], ia berkata: Saya mendengar [Muhammad bin Al Munkadir] meriwayatkan dari [Ibnu Hazzal] dari [ayahnya], ia menyebutkan sesuatu tentang Ma'iz kepada Nabi Shallallahu'alaihiwasallam. Kemudian Nabi Shallallahu'alaihiwasallam bersabda: \"Andai kau menutupinya dengan bajumu niscaya lebih baik bagimu.\""},"3097":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ يُحَدِّثُ عَنِ ابْنِ هَزَّالٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ وَيْحَكَ يَا هَزَّالُ لَوْ سَتَرْتَهُ يَعْنِي مَاعِزًا بِثَوْبِكَ كَانَ خَيْرًا لَكَ","id":"Telah bercerita kepada kami [Sulaiman bin Dawud Ath Thayalisi] telah bercerita kepada kami [Syu'bah] dari [Yahya bin Sa'id], ia berkata: Saya mendengar [Muhammad bin Al Munkadir] menceritakan dari [Ibnu Hazzal] dari [ayahnya] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda kepadanya: \"Celaka kau hai Hazzal! Andai kau menutupinya -maksud beliau Ma'iz- dengan bajumu niscaya lebih baik bagimu.\""},"3098":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَالِكٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ بِمَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدِ قَالَ كَانَ يَقْرَأُ بِقَافْ وَ اقْتَرَبَتْ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] telah bercerita kepada kami [Malik] dari [Dhamrah bin Sa'id] dari [Ubaidillah bin Abdullah] bahwa Umar bin Al Khaththab Radliyallahu'anhu bertanya kepada [Abu Waqid Al Laitsi] apa yang dibaca Rasulullah Shallallahu'alaihiwasallam saat shalat 'id. Ia menjawab: Beliau membaca surat qaaf dan iqtarabat (Alqamar)."},"3099":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ عَنِ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ تُصِيبُنَا بِهَا مَخْمَصَةٌ فَمَا يَحِلُّ لَنَا مِنْ الْمَيْتَةِ قَالَ إِذَا لَمْ تَصْطَبِحُوا وَلَمْ تَغْتَبِقُوا وَلَمْ تَحْتَفِئُوا بَقْلًا فَشَأْنُكُمْ بِهَا","id":"Telah bercerita kepada kami [Muhammad bin Al Qasim] dari [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Abu Waqid Al Laitsi], ia berkata: saya berkata: Wahai Rasulullah! disuatu tempat kami tertimpa kelaparan, bangkai apa yang halal bagi kami? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bila kalian tidak makan di pagi hari, di sore hari dan tidak mencabut sayuran, maka terserah kalian.\""},"3100":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ سِنَانِ بْنِ أَبِي سِنَانٍ الدِّيْلِيِّ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَخَرَجَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ حُنَيْنٍ فَمَرَرْنَا بِسِدْرَةٍ فَقُلْتُ يَا نَبِيَّ اللَّهِ اجْعَلْ لَنَا هَذِهِ ذَاتَ أَنْوَاطٍ كَمَا لِلْكُفَّارِ ذَاتُ أَنْوَاطٍ وَكَانَ الْكُفَّارُ يَنُوطُونَ بِسِلَاحِهِمْ بِسِدْرَةٍ وَيَعْكُفُونَ حَوْلَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْبَرُ هَذَا كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى{ اجْعَلْ لَنَا إِلَهًا كَمَا لَهُمْ آلِهَةً }إِنَّكُمْ تَرْكَبُونَ سُنَنَ الَّذِينَ مِنْ قَبْلِكُمْ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sinan bin Abu Sinan Ad Dili] dari [Abu Waqid Al Laitsi], ia berkata: Kami pergi bersama Rasulullah Shallallahu'alaihiwasallam ke arah Hunain, lalu kami melintasi sebuah pohon bidara lalu saya berkata: 'Wahai Nabi Allah! buatkan kami Dzat Al Anwath seperti orang-orang kafir juga punya Dzat Al Anwath. Orang-orang kafir biasa menggantungkan senjata mereka dipohon bidara dan beri'tikaf disekitarnya. Kemudian Nabi Shallallahu'alaihiwasallam bersabda: \"Allahu Akbar! Ini seperti yang dikatakan Bani Isra`il kepada Musa: Buatkan kami Tuhan seperti tuhan-tuhan milik mereka. sesungguhnya kalian melakukan perilaku-perilaku orang-orang sebelum kalian.\""},"3101":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٌ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا حَسَّانُ بْنُ عَطِيَّةَ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ تُصِيبُنَا بِهَا الْمَخْمَصَةُ فَمَتَى تَحِلُّ لَنَا الْمَيْتَةُ قَالَ إِذَا لَمْ تَصْطَبِحُوا وَلَمْ تَغْتَبِقُوا وَلَمْ تَحْتَفِئُوا فَشَأْنُكُمْ بِهَاحَدَّثَنَا إِسْحَاقُ بْنُ سُلَيْمَانَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنِ الزُّهْرِيِّ عَنْ سِنَانِ بْنِ أَبِي سِنَانٍ الدُّؤَلِيِّ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى حُنَيْنٍ فَذَكَرَ مَعْنَى حَدِيثِ مَعْمَرٍ وَمَعْمَرٌ أَتَمُّ حَدِيثًا","id":"Telah bercerita kepada kami [Al Walid bin Muslim] telah bercerita kepada kami [Al Auza'i] telah bercerita kepada kami [Hassan bin 'Athiyyah] dari [Abu Waqid Al Laitsi], mereka berkata: 'Wahai Rasulullah! sesungguhnya kami berada di kawasan yang tertimpa kelaparan, kapankah bangkai halal bagi kami? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bila kalian tidak sarapan, tidak makan sore dan tidak mencabut tanaman, terserah kalian.\" Telah bercerita kepada kami [Ishak bin Sulaiman] telah bercerita kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Sinan bin Abu Sinan Ad-Du`ali] dari [Abu Waqid Al Laitsi], ia berkata: Kami pergi bersama Rasulullah Shallallahu'alaihiwasallam ke Hunain. Kemudian ia menyebutkan makna hadits Ma'mar, dan hadits Ma'mar lebih lengkap."},"3102":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَحَمَّادُ بْنُ خَالِدٍ الْمَعْنَى قَالَا ثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ عَبْدُ الصَّمَدِ فِي حَدِيثِهِ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَبِهَا نَاسٌ يَعْمِدُونَ إِلَى أَلْيَاتِ الْغَنَمِ وَأَسْنِمَةِ الْإِبِلِ فَيَجُبُّونَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُطِعَ مِنْ الْبَهِيمَةِ وَهِيَ حَيَّةٌ فَهِيَ مَيْتَةٌ","id":"Telah bercerita kepada kami ['Abdush Shamad] dan [Hammad bin Kholid Al Ma'na], keduanya berkata: Telah bercerita kepada kami ['Abdur Rahman bin 'Abdullah bin Dinar], - 'Abdush Shamad menyebutkan dalam haditsnya-: Telah bercerita kepada kami [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Waqid Al Laitsi], ia berkata: Rasulullah Shallallahu'alaihiwasallam tiba di Madinah, disana ada orang-orang mendatangi ekor kambing gibas dan punuk unta kemudian mereka memotongnya. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bagian binatang hidup yang dipotong adalah bangkai.\""},"3103":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ وَاقِدٍ بْنِ أَبِي وَاقِدٍ اللَّيْثِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِنِسَائِهِ فِي حَجَّتِهِ هَذِهِ ثُمَّ ظُهُورَ الْحُصُرِ","id":"Telah bercerita kepada kami [Sa'id bin Manshur] telah bercerita kepada kami ['Abdul 'Aziz bin Muhammad] dari [Zaid bin Aslam] dari [Waqid bin Abu Waqid Al Laitsi] dari [ayahnya] bahwa Nabi Shallallahu'alaihiwasallam bersabda kepada istri-istri beliau saat berhaji kemudian muncul pengepungan."},"3104":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَكُنَّا نَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُنْزِلَ عَلَيْهِ فَيُحَدِّثُنَا فَقَالَ لَنَا ذَاتَ يَوْمٍ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَ إِنَّا أَنْزَلْنَا الْمَالَ لِإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَلَوْ كَانَ لِابْنِ آدَمَ وَادٍ لَأَحَبَّ أَنْ يَكُونَ إِلَيْهِ ثَانٍ وَلَوْ كَانَ لَهُ وَادِيَانِ لَأَحَبَّ أَنْ يَكُونَ إِلَيْهِمَا ثَالِثٌ وَلَا يَمْلَأُ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ ثُمَّ يَتُوبُ اللَّهُ عَلَى مَنْ تَابَ","id":"Telah bercerita kepada kami [Abu 'Amir] telah bercerita kepada kami [Hisyam bin Sa'ad] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Waqid Al Laitsi], ia berkata: Kami mendatangi Nabi Shallallahu'alaihiwasallam. Bila turun wahyu pada beliau kemudian beliau bercerita kepada kami. Pada suatu hari beliau bersabda kepada kami: \"Allah AzzaWaJalla berfirman, 'Kami menurunkan harta untuk (digunakan) mendirikan shalat dan menunaikan zakat. Andai anak cucu Adam memiliki lembah, pasti ia ingin lembah yang lain, andai ia punya dua lembah pasti ingin punya lembah ketiga dan tidak ada yang memenuhi perut anak cucu Adam kecuali tanah, kemudian Allah menerima taubat orang yang bertaubat.\""},"3105":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ نَافِعِ بْنِ سَرْجِسَ قَالَ عُدْنَا أَبَا وَاقِدٍ الْكِنْدِيَّ فِي مَرَضِهِ الَّذِي تُوُفِّيَ فِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَفَّ النَّاسِ صَلَاةً بِالنَّاسِ وَأَطْوَلَ النَّاسِ صَلَاةً لِنَفْسِهِحَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ نَافِعِ بْنِ سَرْجِسَ قَالَ عُدْنَا أَبَا وَاقِدٍ الْكِنْدِيَّ قَالَ ابْنُ بَكْرٍ الْبَدْرِيَّ فِي وَجَعِهِ الَّذِي مَاتَ فِيهِ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Abdullah bin 'Utsman bin Khutsaim] dari [Nafi' bin Sarjis] ia berkata; Kami menjenguk [Abu Waqid Al Kindi] saat sakit yang membuatnya meninggal dunia, ia berkata; Rasulullah Shallallahu'alaihi wasallam adalah orang yang shalatnya paling ringan bersama orang lain, namun paling lama shalatnya saat shalat sendiri. Telah menceritakan kepada kami ['Abdur Razzaq] dan [Ibnu Bakr], keduanya berkata; telah memberitakan kepada kami [Ibnu Juraij], ia berkata; telah memberitakan kepada kami ['Abdullah bin 'Utsman bin Khutsaim] dari [Nafi' bin Sarjas] ia berkata; Kami menjenguk [Abu Waqid Al Kindi], berkata Ibnu Bakr Al Badri saat sakit yang menyebabkannya meninggal dunia, kemudian ia menyebutkan hadits tersebut."},"3106":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ النُّوشَجَانِ وَهُوَ أَبُو جَعْفَرٍ السُّوَيْدِيُّ حَدَّثَنَا الدَّرَاوَرْدِيُّ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنِ ابْنِ أَبِي وَاقِدٍ اللَّيْثِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَزْوَاجِهِ فِي حَجَّةِ الْوَدَاعِ هَذِهِ ثُمَّ ظُهُورَ الْحُصُرِ","id":"Telah menceritakan kepada kami [Muhammad bin An Nusyajan Abu Ja'far As Suwaidi] telah menceritakan kepada kami [Ad Darowardi] telah menceritakan kepada kami [Zaid bin Aslam] dari [Ibnu Abi Waqid Al Laitsi] dari [ayahnya], Nabi Shallallahu'alaihi wasallam bersabda kepada istri-istri beliau saat haji wada' \"ini\" kemudian beliau mengemukakan kewajiban isteri untuk berdiam di rumah."},"3107":{"ar":"حَدَّثَنَا يُونُسُ وَسُرَيْجٌ قَالَا ثَنَا فُلَيْحٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَسَأَلَنِي عُمَرُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ عَمَّا قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْعِيدَيْنِ قَالَ سُرَيْجٌ بِمَ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْخُرُوجِ قَالَ فَقُلْتُ قَرَأَ اقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُ وَ ق وَالْقُرْآنِ الْمَجِيدِ","id":"Telah menceritakan kepada kami [Yunus] dan [Suraij] keduanya berkata; telah menceritakan kepada kami [Fulaih] dari [Dhamrah bin Sa'id] dari ['Ubadillah bin 'Abdullah bin 'Utbah bin Mas'ud] dari [Abu Waqid Al Laitsi] ia berkata; 'Umar Radliyallahu'anhu bertanya kepadaku bacaan yang dibaca Rasulullah Shallallahu'alaihi wasallam saat shalat dua hari raya. Sedang Suraij berkata dengan redaksi; apa yang dibaca Rasulullah Shallallahu'alaihi wasallam saat shalat keluar (ke tanah lapang). Aku menjawab; beliau membaca iqtarabatis saa'atu wansyaqqal qamar dan qaaf wal qur`aanil majiid (Surat Alqamar dan Qaaf)."},"3108":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ حَدَّثَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنِ السَّائِبِ بْنِ يَزِيدَ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي مِنْ زَرْعٍ أَوْ ضَرْعٍ نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ قَالَ السَّائِبُ فَقُلْتُ لِسُفْيَانَ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Hammad bin Khalid] telah menceritakan kepada kami [Malik] dari [Yazid bin Khushaifah] dari [As Sa`ib bin Yazid] dari [Sufyan bin Abu Zuhair] dari Nabi Shallallahu'alaihi wasallam, sesungguhnya beliau bersabda; \"Barangsiapa memelihara anjing bukan untuk keperluan menjaga tanaman atau menjaga binatang yang diperah, amalnya berkurang satu qirath setiap hari.\" Berkata As Sa`ib; kemudian saya berkata kepada Sofyan; engkau mendengar hadits ini dari Rasulullah Shallallahu'alaihi wasallam? Ia menjawab; ya, demi Rabb masjid ini."},"3109":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ أَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ جَعْفَرٍ أَخْبَرَنِي يَزِيدُ بْنُ خُصَيْفَةَ أَنَّ بُسْرَ بْنَ سَعِيدٍ أَخْبَرَهُأَنَّهُ سَمِعَ فِي مَجْلِسِ اللَّيْثِيِّينَ يَذْكُرُونَ أَنَّ سُفْيَانَ أَخْبَرَهُمْ أَنَّ فَرَسَهُ أَعْيَتْ بِالْعَقِيقِ وَهُوَ فِي بَعْثٍ بَعَثَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعَ إِلَيْهِ يَسْتَحْمِلُهُ فَزَعَمَ سُفْيَانُ كَمَا ذَكَرُوا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مَعَهُ يَبْ��َغِي لَهُ بَعِيرًا فَلَمْ يَجِدْ إِلَّا عِنْدَ أَبِي جَهْمِ بْنِ حُذَيْفَةَ الْعَدَوِيِّ فَسَامَهُ لَهُ فَقَالَ لَهُ أَبُو جَهْمٍ لَا أَبِيعُكَهُ يَا رَسُولَ اللَّهِ وَلَكِنْ خُذْهُ فَاحْمِلْ عَلَيْهِ مَنْ شِئْتَ فَزَعَمَ أَنَّهُ أَخَذَهُ مِنْهُ ثُمَّ خَرَجَ حَتَّى إِذَا بَلَغَ بِئْرَ الْإِهَابِ زَعَمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُوشِكُ الْبُنْيَانُ أَنْ يَأْتِيَ هَذَا الْمَكَانَ وَيُوشِكُ الشَّامُ أَنْ يُفْتَتَحَ فَيَأْتِيَهُ رِجَالٌ مِنْ أَهْلِ هَذَا الْبَلَدِ فَيُعْجِبَهُمْ رِيفُهُ وَرَخَاؤُهُ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ ثُمَّ يُفْتَحُ الْعِرَاقُ فَيَأْتِي قَوْمٌ يَبُسُّونَ فَيَتَحَمَّلُونَ بِأَهْلِيهِمْ وَمَنْ أَطَاعَهُمْ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ إِنَّ إِبْرَاهِيمَ دَعَا لِأَهْلِ مَكَّةَ وَإِنِّي أَسْأَلُ اللَّهَ تَبَارَكَ وَتَعَالَى أَنْ يُبَارِكَ لَنَا فِي صَاعِنَا وَأَنْ يُبَارِكَ لَنَا فِي مُدِّنَا مِثْلَ مَا بَارَكَ لِأَهْلِ مَكَّةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Al Hasyimi] telah memberitakan kepada kami [Isma'il bin Ja'far] telah mengabarkan kepadaku [Yazid bin Khushaifah] bahwa [Busr bin Sa'id] memberitakan padanya, ia mendengar [di majlis Al Laitsain], mereka menyebutkan bahwa [Sufyan] memberitakan kepada mereka bahwa kudanya lemah saat berada di 'Aqiq saat ia tengah diutus Rasulullah Shallallahu'alaihi wasallam, kemudian ia kembali kepada beliau seraya meminta agar dibawa serta. Kemudian Sufyan mengira seperti yang mereka sebutkan bahwa Nabi Shallallahu'alaihi wasallam keluar bersamanya untuk mencari unta milik beliau tapi tidak menemukannya kecuali ditempat Abu Jahm bin Hudzaifah Al 'Adawi. Kemudian Abu Jahm berkata kepadanya; Aku tidak menjualnya kepada tuan wahai Rasulullah Shallallahu'alaihi wasallam! Tapi silahkan tuan ambil dan silahkan perintahkan siapa saja yang tuan kehendaki untuk membawanya. Sufyan mengira Rasulullah Shallallahu'alaihi wasallam mengambila unta itu dari Abu Jahm. Kemudian ia pergi hingga tiba di sumur Ihab, ia mengira Rasulullah Shallallahu'alaihi wasallam bersabda: \"Hampir saja bangunan-bangunan mendatangi tempat ini dan hampir saja Syam akan ditaklukkan.\" Kemudian beberapa penduduk tempat itu mendatangi beliau, kesederhanaan dan keleluasaan Rasulullah Shallallahu'alaihi wasallam membuat mereka kagum dan Madinah lebih baik bagi mereka, andai saja mereka mengetahui. Selanjutnya Irak ditaklukkan lalu sekelompok kaum datang seraya membujuk manusia untuk meninggalkan MAdinah dengan membawa serta keluarga mereka, juga orang-orang yang menaati mereka, padahal Madinah lebih baik bagi mereka andai saja mereka mengetahui, karena Ibrahim telah mendoakan kebaikan penduduk Makkah sedang aku memohon kepada Allah untuk memberkahi kami dalam sha' kami serta memberkahi mud kami (Sha' dan Mud Madinah) seperti berkah yang diberikan kepada penduduk Makkah."},"3110":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍ الْبَهْزِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُفْتَحُ الْيَمَنُ فَيَأْتِي قَوْمٌ يَبُسُّونَ فَيَتَحَمَّلُونَ بِأَهْلِيهِمْ وَمَنْ أَطَاعَهُمْ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَحَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى أَخْبَرَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُفْتَحُ الْيَمَنُ فَيَأْتِي قَوْمٌ يَبُسُّونَ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍ قَالَ ابْنُ الزُّبَيْرِ أُخْبِرْتُ أَنَّهُ بِالْمَوْسِمِ فَأَتَيْتُهُ فَسَأَلْتُهُ فَأَخْبَرَنِي فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَفْتَحُونَ الشَّامَ فَيَجِيءُ أَقْوَامٌ يَبُسُّونَ قَالَ كُلُّهَا فَتَحُوا وَقَالَ يَبُسُّونَ","id":"Telah menceritakan kepada kami ['Abdur Rozzaq] telah memberitakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Hisyam bin 'Urwah] dari [ayahnya] dari ['Abdullah bin Az Zubair] dari [Sufyan bin Abu Zuhair Al Bahzi], ia berkata; aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda; \"Yaman ditaklukkan kemudian datanglah suatu kaum yang mereka membujuk manusia untuk meninggalkan Madinah dan membawa serta keluarga mereka, juga siapapun yang menaati mereka padahal Madinah lebih baik bagi mereka, andai mereka tahu.\" Telah menceritakan kepada kami [Ishaq bin 'Isa] telah mengabarkan kepadaku [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari ['Abdullah bin Az Zubair] dari [Sufyan bin Abu Zuhair], ia berkata; aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Yaman ditaklukkan kemudian datanglah suatu kaum yang membujuk manusia untuk meninggalkan Madinah dengan membawa serta keluarga mereka.\" Lantas Ia menyebutkan hadits. Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin 'Urwah] dari [ayahnya] dari ['Abdullah bin Az Zubair] dari [Sufyan bin Abu Zuhair]. Berkata Ibnu Az Zubair; saya dikhabari bahwa Sufyan tengah menunaikan haji kemudian saya mendatanginya dan bertanya kepadanya, ia mengabarkan kepada saya lalu berkata; saya mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Kalian akan menaklukkan Syam kemudian beberapa kaum membujuk keluarganya untuk meninggalkan Madinah.\" Sofyan berkata; semua hadis dengan redaksi: \"Mereka menaklukkan.\" Dan ia berkata: \"Mereka membujuk.\""},"3111":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنِ السَّائِبِ بْنِ يَزِيدَ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَمِعَ سُفْيَانَ بْنَ أَبِي زُهَيْرٍ وَهُوَ رَجُلٌ مِنْ شَنُوءَةَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ نَاسًا مَعَهُ عِنْدَ بَابِ الْمَسْجِدِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ قَالَ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِي وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Rouh] telah menceritakan kepada kami [Malik bin Anas] dari [Yazid bin Khushaifah] dari [As Sa`ib bin Yazid] bahwa ia memberitahukan padanya, ia mendengar [Sufyan bin Abu Zuhair] -ia adalah sahabat Nabi Shallallahu'alaihi wasallam dari Syanu`ah- bercerita kepada orang-orang yang ada bersamanya didekat pintu masjid, ia berkata; saya mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing yang bukan untuk keperluan tanaman atau susu binatang, maka amalnya berkurang satu qirath setiap hari.\" Ia ditanya; Kau mendengar hadits ini dari Rasulullah Shallallahu'alaihi wasallam? Sufyan menjawab; Ya, demi Rabb masjid ini."},"3112":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ ح وَعَبْدُ الصَّمَدِ حَدَّثَنِي سَعِيدُ بْنُ جُمْهَانَ عَنْ سَفِينَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخِلَافَةُ ثَلَاثُونَ عَامًا ثُمَّ يَكُونُ بَعْدَ ذَلِكَ الْمُلْكُقَالَ سَفِينَةُ أَمْسِكْ خِلَافَةَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ سَنَتَيْنِ وَخِلَافَةَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَشْرَ سِنِينَ وَخِلَافَةَ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ اثْنَيْ عَشْرَ سَنَةً وَخِلَافَةَ عَلِيٍّ سِتَّ سِنِينَ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Sa'id bin Jumhan]. Dan ['Abdush Shamad] berkata, telah menceritakan kepadaku [Sa'id bin Jumhan] dari [Safinah], ia berkata; aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"(Masa) khilafah selama tigapuluh tahun, kemudian setelah itu kerajaan.\" Berkata Safinah; peganglah khilafah Abu Bakar Radliyallahu'anhu selama dua tahun, khilafah 'Umar Radliyallahu'anhu sepuluh tahun, khilafah 'Utsman Radliyallahu'anhu duabelas tahun dan khilafah 'Ali Radliyallahu'anhu enam tahun."},"3113":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ عَلِيٍّ يَعْنِي ابْنَ مُبَارَكٍ عَنْ يَحْيَى عَنْ سَفِينَةَأَنَّ رَجُلًا سَاطَ نَاقَتَهُ بِجِذْلٍ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُمْ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Waki'] dari ['Ali bin Mubarak] dari [Yahya] dari [Safinah] bahwa pernah ada seorang laki-laki mencambuk untanya dengan pangkal pohon, unta itu membawa bawaan yang banyak, kemudian Rasulullah Shallallahu'alaihi wasallam menanyakannya kemudian memerintahkan mereka untuk memakan pangkal pohon tersebut."},"3114":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ سَعِيدِ بْنِ جُمْهَانَ قَالَ سَمِعْتُ سَفِينَةَيُحَدِّثُ أَنَّ رَجُلًا ضَافَ عَلِيَّ بْنَ أَبِي طَالِبٍ فَصَنَعُوا لَهُ طَعَامًا فَقَالَتْ فَاطِمَةُ رَضِيَ اللَّهُ عَنْهَا لَوْ دَعْونَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ مَعَنَا فَأَرْسَلُوا إِلَيْهِ فَجَاءَ فَأَخَذَ بِعِضَادَتَيْ الْبَابِ فَإِذَا قِرَامٌ قَدْ ضُرِبَ بِهِ فِي نَاحِيَةِ الْبَيْتِ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَعَ فَقَالَتْ فَاطِمَةُ لِعَلِيٍّ اتْبَعْهُ فَقُلْ لَهُ مَا رَجَعَكَ قَالَ فَتَبِعَهُ فَقَالَ مَا رَجَعَكَ يَا رَسُولَ اللَّهِ قَالَ إِنَّهُ لَيْسَ لِي أَوْ لَيْسَ لِنَبِيٍّ أَنْ يَدْخُلَ بَيْتًا مُزَوَّقًاحَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ سَعِيدِ بْنِ جُمْهَانَ حَدَّثَنِي سَفِينَةُ أَبُو عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخِلَافَةُ ثَلَاثُونَ عَامًا ثُمَّ الْمُلْكُ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad bin Salamah] dari [Sa'id bin Jumhan] ia berkata; aku mendengar [Safinah] bercerita, bahwa seseorang menjamu 'Ali bin Abi Thalib, mereka membuatkan makanan untuknya kemudian Fathimah Radliyallahu'anha berkata; Andai saja kita mengajak Rasulullah Shallallahu'alaihi wasallam kemudian beliau makan bersama kami. Kemudian mereka mendatangi Rasulullah Shallallahu'alaihi wasallam dan beliau pun datang. Rasulullah Shallallahu'alaihi wasallam kemudian menarik dua sisi pintu, ternyata di salah satu sisi rumah ada kain tipis berbordir beraneka warna. Begitu melihatnya, Rasulullah Shallallahu'alaihi wasallam langsung balik. Kemudian Fathimah berkata kepada 'Ali; Ikutilah beliau dan tanyakan kenapa beliau balik. 'Ali pun mengikuti beliau dan bertanya; Apa yang membuat Tuan balik wahai Rasulullah Shallallahu'alaihi wasallam? Rasulullah Shallallahu'alaihi wasallam bersabda: \"Sesungguhnya saya atau nabi tidak boleh masuk rumah yang disana ada gambar bordir beraneka warni.\" Telah menceritakan kepadaku [Zaid bin Al Hubab], telah menceritakan kepada kami [Hammad bin Salamah] dari [Sa'id bin Jumhan], telah menceritakan kepada kami [Safinah Abu 'Abdur Rahman], ia berkata; saya mendengar Nabi Shallallahu'alaihi wasallam bersabda; \"(Masa) khilafah tiga puluh tahun kemudian (setelah itu) kerajaan.\" Maka Safinah menyebutkan hadits."},"3115":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ عِمْرَانَ النَّخْلِيِّ عَنْ مَوْلًى لِأُمِّ سَلَمَةَ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَانْتَهَيْنَا إِلَى وَادٍ قَالَ فَجَعَلْتُ أَعْبُرُ النَّاسَ أَوْ أَحْمِلُهُمْ قَالَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كُنْتَ الْيَوْمَ إِلَّا سَفِينَةً أَوْ مَا أَنْتَ إِلَّا سَفِينَةٌقِيلَ لِشَرِيكٍ هُوَ سَفِينَةُ مَوْلَى أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Syarik] dari ['Imron An Nakhli] dari [budak milik Ummu Salamah] ia berkata; saya pernah bersama Nabi Shallallahu'alaihi wasallam dalam suatu perjalanan hingga kami tiba disebuah lembah. Saya kemudian saya melintasi orang-orang atau membawa mereka kemudian Rasulullah Shallallahu'alaihi wasallam bersabda kepadaku; \"Engkau hari ini tidak lain adalah Safinah, \" atau \"Engkau tidak lain adalah Safinah.\" Dikatakan kepada Syarik; Dia adalah Safinah, budak milik Ummu Salamah Radliyallahu'anha."},"3116":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ حَدَّثَنَا سَفِينَةُ أَبُو عَبْدِ الرَّحْمَنِأَنَّ رَجُلًا أَضَافَهُ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ فَصَنَعَ لَهُ طَعَامًا فَقَالَتْ فَاطِمَةُ لَوْ دَعَوْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ حَدِيثِ أَبِي كَامِلٍ فَدَعَوْهُ فَجَاءَ فَوَضَعَ يَدَهُ عَلَى عِضَادَتَيْ الْبَابِ فَرَأَى قِرَامًا فِي نَاحِيَةِ الْبَيْتِ فَرَجَعَ فَقَالَتْ فَاطِمَةُ لِعَلِيٍّ الْحَقْهُ فَقُلْ لَهُ لِمَ رَجَعْتَ يَا رَسُولَ اللَّهِ فَقَالَ إِنَّهُ لَيْسَ لِي أَنْ أَدْخُلَ بَيْتًا مُزَوَّقًا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Sa'id bin Jumhan] telah menceritakan kepada kami [Safinah Abu 'Abdur Rahman]; Bahwa 'Ali bin Abi Thalib menjamu seseorang kemudian ia membuatkan makanan untuknya kemudian Fathimah berkata; Andai kita mengajak Rasulullah Shallallahu'alaihi wasallam, kemudian ia menyebutkan yang sama seperti hadits Abu Kamil; kemudian mereka mengajak beliau lalu beliau datang. Beliau meletakkan tangan beliau diatas dua sisi pintu kemudian melihat kain tipis disalah satu sisi rumah kemudian beliau kembali. Fathimah berkata kepada 'Ali; Susullah beliau dan tanyakan kenapa engkau kembali wahai Rasulullah Shallallahu'alaihi wasallam? Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Saya tidak boleh masuk rumah yang disana terdapat pahatan beraneka-warni.\""},"3117":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ عَنْ سَفِينَةَ أَبِي عَبْدِ الرَّحْمَنِ قَالَأَعْتَقَتْنِي أُمُّ سَلَمَةَ وَاشْتَرَطَتْ عَلَيَّ أَنْ أَخْدُمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَاشَ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Sa'id bin Jumhan] dari [Safinah Abu 'Abdur Rahman] ia berkata; Ummu Salamah memerdekakanku dan mensyaratkan kepadaku agar melayani Nabi Shallallahu'alaihi wasallam selama hidup beliau."},"3118":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا حَشْرَجُ ابْنُ نُبَاتَةَ الْعَبْسِيُّ كُوفِيٌّ حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ حَدَّثَنِي سَفِينَةُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخِلَافَةُ فِي أُمَّتِي ثَلَاثُونَ سَنَةً ثُمَّ مُلْكًا بَعْدَ ذَلِكَ ثُمَّ قَالَ لِي سَفِينَةُ أَمْسِكْ خِلَافَةَ أَبِي بَكْرٍ وَخِلَافَةَ عُمَرَ وَخِلَافَةَ عُثْمَانَ وَأَمْسِكْ خِلَافَةَ عَلِيٍّ رَضِيَ اللَّهُ تَعَالَى عَنْهُمْ قَالَ فَوَجَدْنَاهَا ثَلَاثِينَ سَنَةً ثُمَّ نَظَرْتُ بَعْدَ ذَلِكَ فِي الْخُلَفَاءِ فَلَمْ أَجِدْهُ يَتَّفِقُ لَهُمْ ثَلَاثُونَ فَقُلْتُ لِسَعِيدٍ أَيْنَ لَقِيتَ سَفِينَةَ قَالَ لَقِيتُهُ بِبَطْنِ نَخْلٍ فِي زَمَنِ الْحَجَّاجِ فَأَقَمْتُ عِنْدَهُ ثَمَانِ لَيَالٍ أَسْأَلُهُ عَنْ أَحَادِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ لَهُ مَا اسْمُكَ قَالَ مَا أَنَا بِمُخْبِرِكَ سَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَفِينَةَ قُلْتُ وَلِمَ سَمَّاكَ سَفِينَةَ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ أَصْحَابُهُ فَثَقُلَ عَلَيْهِمْ مَتَاعُهُمْ فَقَالَ لِي ابْسُطْ كِسَاءَكَ فَبَسَطْتُهُ فَجَعَلُوا فِيهِ مَتَاعَهُمْ ثُمَّ حَمَلُوهُ عَلَيَّ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْمِلْ فَإِنَّمَا أَنْتَ سَفِينَةُ فَلَوْ حَمَلْتُ يَوْمَئِذٍ وِقْرَ بَعِيرٍ أَوْ بَعِيرَيْنِ أَوْ ثَلَاثَةٍ أَوْ أَرْبَعَةٍ أَوْ خَمْسَةٍ أَوْ سِتَّةٍ أَوْ سَبْعَةٍ مَا ثَقُلَ عَلَيَّ إِلَّا أَنْ يَجْفُوا","id":"Telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Hasyraj bin Nubatah Al 'Absi Kufi] telah menceritakan kepada kami [Sa'id bin Jumhan] telah menceritakan kepadaku [Safinah], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Masa khilafah dalam ummatku tiga puluh tahun kemudian setelah itu kerajaan.\" Kemudian Safinah berkata kepadaku; Peganglah khilafah Abu Bakar, 'Umar, 'Utsman dan Ali Radliyallahu'anhum. Kemudian kami menghitungnya tepat tigapuluh tahun dan setelah itu saya memperhatikan pada khalifah tapi saya tidak menemukannya sesuai selama tiga puluh tahun lalu saya bertanya kepada Sa'id; Dimana kau temui Safinah? Ia menjawab; Saya bertemu dengannya di Bathn Nakhl dimasa Al Hajjaj, kemudian saya tinggal disana selama delapan hari untuk menanyakan hadits-hadits Rasulullah Shallallahu'alaihi wasallam padanya. Saya bertanya padanya; Siapa namamu? Ia menjawab; Bukankah telah kuberitahukan kepadamu? Rasulullah Shallallahu'alaihi wasallam memberiku nama Safinah. Saya bertanya; 'Kenapa beliau memberimu nama Safinah? ' Ia menjawab; Rasulullah Shallallahu'alaihi wasallam bepergian bersama sahabat-sahabat beliau, barang bawaan mereka memberatkan mereka kemudian Rasulullah Shallallahu'alaihi wasallam bersabda kepadaku; \"Bentangkan selendangmu.\" Saya pun membentangkan selendangku, kemudian mereka meletakkan barang-barang mereka diselendangku. Mereka menyuruhku membawanya kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bawalah, engkau adalah Safinah.\" Andai saat ini aku membawa bawaan satu unta, dua unta, tiga unta, tiga unta, empat unta, lima unta, enam unta atau tujuh unta pastilah tidak memberatkanku kecuali bila mereka membanting ke tanah."},"3119":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ حَدَّثَنِي أَبُو رَيْحَانَةَ قَالَ أَبِي وَسَمَّاهُ عَلِيٌّ عَبْدَ اللَّهِ بْنَ مَطَرٍ قَالَ أَخْبَرَنِي سَفِينَةُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوَضِّئُهُ الْمُدُّ وَيَغْسِلُهُ الصَّاعُ مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Ashim] telah menceritakan kepadaku [Abu Raihanah]. -Berkata ayah saya; Dan Ali menamainya Abdullah bin Mathar- ia berkata; [Safinah] -pelayan Rasulullah Shallallahu'alaihi wasallam- telah mengabarkan kepadaku bahwa Rasulullah Shallallahu'alaihi wasallam memberinya air untuk wudhu sebanyak satu mud dan memandikannya dengan satu sha' air karena janabat."},"3120":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو رَيْحَانَةَ عَنْ سَفِينَةَ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ بِالصَّاعِ وَيَتَطَهَّرُ بِالْمُدِّ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Abu Raihanah] dari [Safinah] sahabat Rasulullah Shallallahu'alaihi wasallam, ia berkata; Rasulullah Shallallahu'alaihi wasallam mandi dengan satu sha' air dan bersuci dengan satu mud air."},"3121":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادٌ أَنَا سَعِيدُ بْنُ جُمْهَانَ حَدَّثَنِي سَفِينَةُأَنَّ رَجُلًا ضَافَ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ فَصَنَعَ لَهُ طَعَامًا فَقَالَتْ فَاطِمَةُ لِعَلِيٍّ لَوْ دَعَوْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ مَعَنَا فَدَعَوْنَاهُ فَجَاءَ فَأَخَذَ بِعِضَادَتَيْ الْبَابِ وَقَدْ ضَرَبْنَا قِرَامًا فِي نَاحِيَةِ الْبَيْتِ فَلَمَّا رَآهُ رَجَعَ قَالَتْ فَاطِمَةُ لِعَلِيٍّ الْحَقْهُ فَانْظُرْ مَا رَجَعَهُ قَالَ مَا رَدَّكَ يَا نَبِيَّ اللَّهِ قَالَ لَيْسَ لِنَبِيٍّ أَنْ يَدْخُلَ بَيْتًا مُزَوَّقًاحَدَّثَنَا أَبُو كَامِلٍ بِمَعْنَاهُ قَالَ إِنَّهُ لَيْسَ لِي أَوْ قَالَ لَيْسَ لِنَبِيٍّ أَنْ يَدْخُلَ بَيْتًا مُزَوَّقًا","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad] telah memberitakan kepada kami [Sa'id bin Jumhan] telah menceritakan kepadaku [Safinah] bahwa seseorang menjamu 'Ali Radliyallahu'anhu kemudian ia membuatkan makanan untuknya, lalu Fathimah berkata kepada 'Ali; Andai engkau memanggail Rasulullah Shallallahu'alaihi wasallam untuk makan bersama kita. Kemudian kami memanggil beliau, beliau datang kemudian meraih dua sisi pintu, kami memasang kain tipis disudut rumah. Saat Rasulullah Shallallahu'alaihi wasallam melihatnya, beliau langsung membalikkan tubuhnya. Fathimah berkata kepada 'Ali; Susullah beliau dan tanyakan apa yang membuat beliau berbalik. Bertanya 'Ali; Apa yang membuat tuan kembali wahai nabi Allah? Beliau menjawab; \"Seorang nabi tidak boleh masuk rumah yang disana terdapat gambar beraneka warni.\" Telah menceritakan kepada kami [Abu Kamil] dengan maknanya, Rasulullah Shallallahu'alaihi wasallam bersabda: \"Sesungguhnya tidak boleh bagi seorang nabi untuk memasuki rumah yang disana terdapat gambar beraneka warni.\""},"3122":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَاقَ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ عَنْ جَبَلَةَ بْنِ حَارِثَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي شَيْئًا أَقُولُهُ عِنْدَ مَنَامِي قَالَ إِذَا أَخَذْتَ مَضْجَعَكَ فَقُلْ يَا أَيُّهَا الْكَافِرُونَ حَتَّى تَخْتِمَهَا فَإِنَّهَا بَرَاءَةٌ مِنْ الشِّرْكِحَدَّثَنَا أَسْوَدُ قَالَ حَدَّثَنَا شَرِيكٌ قَالَ جَبَلَةُ وَلَمْ يَشُكَّ وَقَالَ عَلِيٌّ يَعْنِي ابْنَ الْمَدِينِيِّ جَبَلَةُ بْنُ حَارِثَةَ الْكلْبِيُّ قَالَ عَلِيٌّ سَمِعْتُهُ مِنْ ابْنِ أَبِي الْوَزِيرِ قَالَ عَبْد اللَّهِ و حَدَّثَنَاه أَبِي عَنْ عَلِيٍّ قَبْلَ أَنْ يُمْتَحَنَ بِالْقُرْآنِ","id":"Telah menceritakan kepada kami [Hajjaj] ia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishak] dari [Farwah bin Naufal] dari [Jabalah bin Haritsah] ia berkata; aku berkata; Wahai Rasulullah! Ajarkanlah sesuatu padaku yang aku ucapkan saat hendak tidur. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila kau hendak tidur, bacalah qul yaa `ayyuhal kaafirun hingga usai, karena itu membebaskan dari kesyirikan'.\" Telah menceritakan kepada kami [Aswad], ia berkata; telah menceritakan kepada kami [Syarik], -ia menyebutkan Jabalah dan ia tidak ragu. Sedang 'Ali bin Al Madini berkata Jabalah bin Haritsah Al Kalbi-. Berkata ['Ali]; saya mendengarnya dari [Ibnu Abi Al Wazir], berkata 'Abdullah dan kami bercerita kepadanya dari 'Ali sebelum diuji dengan Al Qur`an."},"3123":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَاقَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ سَعِيدِ بْنِ سَعْدِ بْنِ عُبَادَةَ قَالَكَانَ بَيْنَ أَبْيَاتِنَا إِنْسَانٌ مُخْدَجٌ ضَعِيفٌ لَمْ يُرَعْ أَهْلُ الدَّارِ إِلَّا وَهُوَ عَلَى أَمَةٍ مِنْ إِمَاءِ الدَّارِ يَخْبُثُ بِهَا وَكَانَ مُسْلِمًا فَرَفَعَ شَأْنَهُ سَعْدٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اضْرِبُوهُ حَدَّهُ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ أَضْعَفُ مِنْ ذَلِكَ إِنْ ضَرَبْنَاهُ مِائَةً قَتَلْنَاهُ قَالَ فَخُذُوا لَهُ عِثْكَالًا فِيهِ مِائَةُ شِمْرَاخٍ فَاضْرِبُوهُ بِهِ ضَرْبَةً وَاحِدَةً وَخَلُّوا سَبِيلَهُ","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Muhammad bin Ishak] dari [Ya'qub bin 'Abdullah bin Al Asyuj] dari [Abu Umamah bin Sahl] dari [Sa'id bin Sa'ad bin 'Ubadah], ia berkata; Kami memiliki seorang tetangga yang pendek dan lemah, penghuni rumah tidak memperhatikannya hingga ia bercumbu rayu dengan budak wanita dirumah itu dan melakukan kekejian terhadapnya, padahal ia adalah muslim. Kemudian Sa'ad melaporkannya kepada Rasulullah Shallallahu'alaihi wasallam kemudian beliau bersabda; \"Cambuklah dia sebagai hukumannya.\" Mereka berkata; Wahai Rasulullah! Ia lebih lemah dari hal itu, bila kami mencambuknya seratus kali pasti dia mati. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Ambillah rumbai sebanyak seratus tangkai lalu cambukkan padanya sekali saja kemudian lepaskan dia.\""},"3124":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ سَعِيدٍ قَالَمَرَّ عُمَرُ رَضِيَ اللَّهُ عَنْهُ بِحَسَّانَ وَهُوَ يُنْشِدُ فِي الْمَسْجِدِ فَلَحَظَ إِلَيْهِ قَالَ كُنْتُ أُنْشِدُ وَفِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ ثُمَّ الْتَفَتَ إِلَى أَبِي هُرَيْرَةَ فَقَالَ سَمِعْتَ رَسُولَ اللَّهِ صَ��َّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَجِبْ عَنِّي اللَّهُمَّ أَيِّدْهُ بِرُوحِ الْقُدُسِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id] ia berkata; Umar Radliyallahu'anhu melintasi Hassan yang tengah bersyair di masjid, Umar meliriknya, lalu [Hassan] berkata; Disini orang yang lebih baik darimu pernah bersyair. Kemudian Umar melirik [Abu Hurairah] dan bertanya; \"Kau pernah mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Kabulkanlah aku ya Allah! Teguhkanlah ia dengan Jibril. Ia menjawab; Ya."},"3125":{"ar":"حَدَّثَنَا يَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ قَالَمَرَّ عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَلَى حَسَّانَ وَهُوَ يُنْشِدُ الشِّعْرَ فِي الْمَسْجِدِ فَقَالَ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُنْشِدُ الشِّعْرَ قَالَ كُنْتُ أُنْشِدُ وَفِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ أَوْ كُنْتُ أُنْشِدُ فِيهِ وَفِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Yahya bin 'Abdur Rahman], ia berkata; 'Umar Radliyallahu'anhu melawati Hassan saat tengah bersyair di masjid kemudian 'Umar berkata; Di masjid Rasulullah Shallallahu'alaihi wasallam syair disenandungkan? [Hassan] berkata; 'Saya pernah bersyair dan di dalam masjid ada orang yang lebih baik darimu (yaitu Nabi Shallallahu 'alaihi wa Salam).'"},"3126":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَمَرَّ عُمَرُ عَلَى حَسَّانَ وَهُوَ يُنْشِدُ فِي الْمَسْجِدِ فَقَالَ مَهْ قَالَ لَهُ حَسَّانُ قَدْ كُنْتُ أُنْشِدُ وَفِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ قَالَ فَانْصَرَفَ عُمَرُ وَهُوَ يَعْرِفُ أَنَّهُ يُرِيدُ رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Ibrahim bin Sa'ad] telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Al Musayyib], ia berkata; 'Umar melintasi Hassan saat ia tengah bersyair di masjid kemudian 'Umar berkata; 'Heih'. Kemudian [Hassan] berkata padanya; 'Saya pernah bersyair dan dimasjid ada orang yang lebih baik darimu'. Sa'id melanjutkan; 'Umar pun pergi dan ia tahu bahwa yang dimaksudkan Hassan adalah Rasulullah Shallallahu'alaihi wasallam."},"3127":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنِ ابْنِ الْمُسَيَّبِ قَالَأَنْشَدَ حَسَّانُ بْنُ ثَابِتٍ وَهُوَ فِي الْمَسْجِدِ فَمَرَّ عُمَرُ بِهِ فَلَحَظَهُ فَقَالَ حَسَّانُ وَاللَّهِ لَقَدْ أَنْشَدْتُ فِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ فَخَشِيَ أَنْ يَرْمِيَهُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَازَ وَتَرَكَهُ","id":"Telah menceritakan kepada kami ['Abdur Rozzaq] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyib], ia berkata; Hassan bin Tsabit bersyair dimasjid kemudian 'Umar lewat dan meliriknya, [Hassan] berkata; Demi Allah, saya pernah bersyair dimasjid dan didalamnya ada orang yang lebih baik darimu. 'Umar khawatir bahwa yang dimaksudkan adalah Rasulullah Shallallahu'alaihi wasallam kemudian 'Umar membolehkan dan membiarkannya."},"3128":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ أَبِي بَكْرِ بْنِ حَزْمٍ أَنَّ النَّضْرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ عَنْ عَمْرِو بْنِ حَزْمٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقْعُدُوا عَلَى الْقُبُورِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] telah menceritakan kepada kami ['Abdullah bin Wahb] dari [Sa'id bin Abu Hilal] dari [Abu Bakr bin Hazm] bahwa [An Nadhr bin 'Abdullah] memberi khabar padanya dari ['Amr bin Hazm] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda; \"Janganlah kalian duduk diatas kuburan.\""},"3129":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ وَحَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ زِيَادِ بْنِ نُعَيْمٍ عَنْ عَمْرِو بْنِ حَزْمٍقَالَ رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا عَلَى قَبْرٍ فَقَالَ لَا تُؤْذِ صَاحِبَ هَذَا الْقَبْرِ أَوْ لَا تُؤْذِهِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Ibnu Wahb] telah memberitakan kepada kami ['Amr bin Al Harits]. Dan telah menceritakan kepada kami [Yahya bin Ishaq] telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Bakr bin Sawadah] dari [Ziyad bin Nu'aim] dari ['Amr bin Hazm], ia berkata; Rasulullah Shallallahu'alaihi wasallam melihatku bersandar diatas kuburan kemudian beliau bersabda; \"Jangan ganggu penghuni kubur ini, \" atau, \"Jangan ganggu dia.\""},"3130":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرِو بْنِ حَزْمٍ قَالَعُرِضَتْ النَّهْشَةُ مِنْ الْحَيَّةِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] telah menceritakan kepada kami ['Utsman bin Hakim] telah menceritakan kepadaku [Abu Bakr bin 'Amr bin Hazm] dari ['Amr bin Hazm], ia berkata; Seekor ular mematikan diperlihatkan dihadapan Rasulullah Shallallahu'alaihi wasallam kemudian beliau memerintahkan agar dibunuh."},"3131":{"ar":"حَدَّثَنَا يَعْقُوبُ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ عَنْ سَعِيدِ بْنِ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ جَدِّهِ أَنَّهُ قَالَ وَجَدْتُ فِي كُتُبِ سِعِيدِ بْنِ سَعْدِ بْنِ عُبَادَةَ أَنَّ عُمَارَةَ بْنَ حَزْمٍ شَهِدَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ مَعَ الشَّاهِدِ","id":"Telah menceritakan kepada kami [Ya'qub] telah memberitakan kepada kami ['Abdul 'Aziz bin Al Muthallib] dari [Sa'id bin 'Amr bin Syurahbil] dari [kakeknya], ia berkata; saya temukan dalam kitab-kitab milik Sa'id bin Sa'ad bin 'Ubadah bahwa ['Umarah bin Hazm] menyaksikan bahwa Rasulullah Shallallahu'alaihi wasallam memutuskan sumpah harus disaksikan seorang saksi."},"3132":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا بَكْرُ بْنُ سَوَادَةَ عَنْ زِيَادِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ أَنَّ ابْنَ حَزْمٍ إِمَّا عَمْرٌو وَإِمَّا عُمَارَةُ قَالَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مُتَّكِئٌ عَلَى قَبْرٍ فَقَالَ انْزِلْ عَنْ الْقَبْرِ لَا تُؤْذِ صَاحِبَ الْقَبْرِ وَلَا يُؤْذِيكَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Bakr bin Sawadah] dari [Ziyad bin Nu'aim Al Hadhrami] bahwa [Ibnu Hazm], kemungkinan 'Amr atau ['Umaroh], berkata; Rasulullah Shallallahu'alaihi wasallam melihatku saat aku bersandar diatas makam, kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Turunlah, jangan engkau ganggu penghuni kubur ini dan ia tidak mengganggumu.\""},"3133":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ مُحَمَّدِ بْنِ زَيْدٍ حَدَّثَنِي عُمَيْرٌ مَوْلَى آبِي اللَّحْمِ قَالَشَهِدْتُ خَيْبَرَ مَعَ سَادَتِي فَكَلَّمُوا فِيَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي فَقُلِّدْتُ سَيْفًا فَإِذَا أَنَا أَجُرُّهُ فَأُخْبِرَ أَنِّي مَمْلُوكٌ فَأَمَرَ لِي بِشَيْءٍ مِنْ خُرْثِيِّ الْمَتَاعِ","id":"Telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Muhammad bin Zaid] telah menceritakan kepadaku ['Umair] budak Abu Al Lahm, ia berkata; Saya turut serta dalam perang Khaibar bersama para pemimpinku, mereka berbicara kepadaku tentang Rasulullah Shallallahu'alaihi wasallam, kemudian aku mengaitkan pedang dan ternyata aku menyeretnya kemudian aku diberitahu bahwa aku adalah budak, kemudian saya diperintahkan untuk membawa perkakas."},"3134":{"ar":"حَدَّثَنَا رِبْعِيُّ بْنُ إِبْرَاهِيمَ أَخُو إِسْمَاعِيلَ ابْنِ عُلَيَّةَ وَأَثْنَى عَلَيْهِ خَيْرًا قَالَ وَكَانَ يَفْضُلُ عَلَى إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ الْمُهَاجِرِ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ قَالَشَهِدْتُ مَعَ سَادَتِي خَيْبَرَ فَأَمَرَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلِّدْتُ سَيْفًا فَإِذَا أَنَا أَجُرُّهُ قَالَ فَقِيلَ لَهُ إِنَّهُ عَبْدٌ مَمْلُوكٌ قَالَ فَأَمَرَ لِي بِشَيْءٍ مِنْ خُرْثِيِّ الْمَتَاعِ قَالَ وَعَرَضْتُ عَلَيْهِ رُقْيَةً كُنْتُ أَرْقِي بِهَا الْمَجَانِينَ فِي الْجَاهِلِيَّةِ قَالَ اطْرَحْ مِنْهَا كَذَا وَكَذَا وَارْقِ بِمَا بَقِيَقَالَ مُحَمَّدُ بْنُ زَيْدٍ وَأَدْرَكْتُهُ وَهُوَ يَرْقِي بِهَا الْمَجَانِينَ","id":"Telah menceritakan kepada kami [Rib'iy bin Ibrahim] -saudara Isma'il bin 'Ulaiyyah, ia memujinya dengan baik, ia berkata; Ia lebih mulia dari Isma'il- telah menceritakan kepada kami ['Abdur Rahman bin Ishak] dari [Muhammad bin Zaid bin Al Muhajir] dari ['Umair] budak Abu Al Lahm, ia berkata; saya bersama para pemimpin-pemimpin saya turut serta dalam perang Khaibar, kemudian Rasulullah Shallallahu'alaihi wasallam memerintahkanku, lalu aku mengaitkan pedang dan ternyata aku menyeretnya. Kemudian ada yang berkata padanya; 'Ia adalah budak. Kemudian Rasulullah Shallallahu'alaihi wasallam memerintahkanku membawa beberapa perkakas. Kemudian saya memperlihatkan ruqyah kepada beliau yang pernah aku pakai untuk meruqyah orang-orang gila dimasa jahiliyah, Rasulullah Shallallahu'alaihi wasallam bersabda: \"Buanglah ini dan itu, dan selebihnya pakailah untuk meruqyah.\" Berkata Muhammad bin Zaid; saya bertemu dengannya saat ia meruqyah orang-orang gila dengan bacaan-bacaan itu."},"3135":{"ar":"حَدَّثَنَا رِبْعِيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ إِسْحَاقَ حَدَّثَنِي أَبِي عَنْ عَمِّهِ وَعَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ الْمُهَاجِرِ أَنَّهُمَا سَمِعَا عُمَيْرًا مَوْلَى آبِي اللَّحْمِ قَالَأَقْبَلْتُ مَعَ سَادَتِي نُرِيدُ الْهِجْرَةَ حَتَّى أَنْ دَنَوْنَا مِنْ الْمَدِينَةِ قَالَ فَدَخَلُوا الْمَدِينَةَ وَخَلَّفُونِي فِي ظَهْرِهِمْ قَالَ قَالَ فَأَصَابَنِي مَجَاعَةٌ شَدِيدَةٌ قَالَ فَمَرَّ بِي بَعْضُ مَنْ يَخْرُجُ مِنْ الْمَدِينَةِ فَقَالُوا لِي لَوْ دَخَلْتَ الْمَدِينَةَ فَأَصَبْتَ مِنْ ثَمَرِ حَوَائِطِهَا فَدَخَلْتُ حَائِطًا فَقَطَعْتُ مِنْهُ قِنْوَيْنِ فَأَتَانِي صَاحِبُ الْحَائِطِ فَأَتَى بِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرَهُ خَبَرِي وَعَلَيَّ ثَوْبَانِ فَقَالَ لِي أَيُّهُمَا أَفْضَلُ فَأَشَرْتُ لَهُ إِلَى أَحَدِهِمَا فَقَالَ خُذْهُ وَأَعْطِي صَاحِبَ الْحَائِطِ الْآخَرَ وَخَلَّى سَبِيلِي","id":"Telah menceritakan kepada kami [Rib'i bin Ibrahim] telah menceritakan kepada kami ['Abdur Rahman bin Ishak] telah menceritakan kepadaku [ayahku] dari [pamannya] dan dari [Muhammad bin Zaid bin Al Muhajir], keduanya mendengar ['Umair] budak Abu Al Lahm berkata; Saya pergi bersama para pemimpinku, kami hendak berhijrah hingga kami mendekati Madinah. Mereka pun masuk Madinah sementara aku ditinggal dibelakang mereka. Kemudian saya kelaparan. Lalu sebagian orang yang meninggalkan Madinah melewatiku, dan berujar; 'Oh,,, andai saja engkau masuk ke Madinah lalu memakan buah-buahan kebunnya'. Kemudian saya masuk ke salah satu kebun, aku memetik dua tandan. Namun pemilik kebun mendatangiku dan membawaku ke hadapan Rasulullah Shallallahu'alaihi wasallam, ia mengutarakan masalahku kepada beliau. Saat itu aku mengenakan dua pakaian, kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Mana diantara keduanya yang lebih baik?\" kemudian saya menunjukkan salah satunya, lalu Rasulullah Shallallahu'alaihi wasallam bersabda: \"Ambillah dan berikan pada pemilik kebun.\" Setelah itu saya dilepaskan."},"3136":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ عَنْ آبِي اللَّحْمِ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أَحْجَارِ الزَّيْتِ يَسْتَسْقِي وَهُوَ مُقْنِعٌ بِكَفَّيْهِ يَدْعُو","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Kholid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Yazid bin 'Abdullah] dari ['Umair] budak Abu Al Lahm, dari [Abu Al Lahm]; ia melihat Rasulullah Shallallahu'alaihi wasallam di dekat Ahjar Zait seraya meminta hujan, beliau mengangkat kedua tangan dengan telapak tangan ditelungkupkan, dan beliau berdoa."},"3137":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ قَالَ حَيْوَةُ عَنِ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي عِنْدَ أَحْجَارِ الزَّيْتِ قَرِيبًا مِنْ الزَّوْرَاءِ قَائِمًا يَدْعُو يَسْتَسْقِي رَافِعًا كَفَّيْهِ لَا يُجَاوِزُ بِهِمَا رَأْسَهُ مُقْبِلٌ بِبَاطِنِ كَفَّيْهِ إِلَى وَجْهِهِحَدَّثَنَا هَارُونُ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ وَأَخْبَرَنِي حَيْوَةُ عَنْ عُمَرَ بْنِ مَالِكٍ عَنِ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf], ia berkata; telah menceritakan kepada kami [Ibnu Wahab], ia berkata; berkata [Haiwah] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim At Taimi] dari ['Umair] budak Abu Al Lahm; Bahwasanya ia melihat Rasulullah Shallallahu'alaihi wasallam di Ahjar Zait didekat Zarwa`, beliau berdiri berdoa meminta hujan seraya mengangkat kedua tangan tidak sampai sebatas kepala, telapak tangan beliau dihadapkan ke wajah. Telah menceritakan kepada kami [Harun] dari [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Haiwah] dari ['Umar bin Malik] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari ['Umair] budak Abu Al Lahm; ia melihat Rasulullah Shallallahu'alaihi wasallam, ia menyebut hadis serupa."},"3138":{"ar":"حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِفَاعَةَ بْنِ شَدَّادٍ قَالَكُنْتُ أَقُومُ عَلَى رَأْسِ الْمُخْتَارِ فَلَمَّا تَبَيَّنْتُ كِذَابَتَهُ هَمَمْتُ وَايْمُ اللَّهِ أَنْ أَسُلَّ سَيْفِي فَأَضْرِبَ عُنُقَهُ حَتَّى ذَكَرْتُ حَدِيثًا حَدَّثَنِيهِ عَمْرُو بْنُ الْحَمِقِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَمَّنَ رَجُلًا عَلَى نَفْسِهِ فَقَتَلَهُ أُعْطِيَ لِوَاءَ الْغَدْرِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Bahz bin Asad] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Abdul Malik bin 'Umair] dari [Rifa'ah bin Syaddad], ia berkata; Saya pernah berdiri diatas kepala Al Mukhtar, saat saya mengetahui kebohongannya, saya ingin -demi Allah- menghunuskan pedang lalu saya tebaskan ke lehernya hingga saya teringat hadits yang diceritakan ['Amr bin Al Hamiq] kepadaku, ia berkata; saya mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa yang memberi jaminan keamanan kepada seseorang kemudian membunuhnya, aku memberinya bendera pengkhianatan pada hari kiamat.\""},"3139":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا عِيسَى الْقَارِئُ أَبُو عُمَرَ بْنُ عُمَرَ حَدَّثَنَا السُّدِّيُّ عَنْ رِفَاعَةَ الْقِتْبَانِيِّ قَالَدَخَلْتُ عَلَى الْمُخْتَارِ فَأَلْقَى لِي وِسَادَةً وَقَالَ لَوْلَا أَنَّ أَخِي جِبْرِيلَ قَامَ عَنْ هَذِهِ لَأَلْقَيْتُهَا لَكَ قَالَ فَأَرَدْتُ أَنْ أَضْرِبَ عُنُقَهُ فَذَكَرْتُ حَدِيثًا حَدَّثَنِيهِ أَخِي عَمْرُو بْنُ الْحَمِقِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُؤْمِنٍ أَمَّنَ مُؤْمِنًا عَلَى دَمِهِ فَقَتَلَهُ فَأَنَا مِنْ الْقَاتِلِ بَرِيءٌ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami ['Isa Al Qori` Abu Umar bin Umar] telah menceritakan kepada kami [As Suddi] dari [Rifa'ah Al Qibtani], ia berkata; 'Saya memasuki kediaman Al Mukhtar kemudian ia memberiku bantal dan berkata; 'Andaikan saudaraku Jibril, tidak berdiri dari bantal ini, pastilah aku tetapkan memberikan bantal itu untukmu.' Saya ingin menebas lehernya, hanya saya ingat hadits yang diceritakan saudaraku ['Amr bin Al Hamiq], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Siapapun mukmin yang telah memberi jaminan keamanan kepada orang mukmin lain atas nyawanya kemudian ia membunuhnya, maka saya terbebas dari si pembunuh itu.\""},"3140":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ حَمَّادِ بْنِ سَلَمَةَ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ رِفَاعَةَ بْنِ شَدَّادٍ قَالَكُنْتُ أَقُومُ عَلَى رَأْسِ الْمُخْتَارِ فَلَمَّا عَرَفْتُ كَذِبَهُ هَمَمْتُ أَنْ أَسُلَّ سَيْفِي فَأَضْرِبَ عُنُقَهُ فَذَكَرْتُ حَدِيثًا حَدَّثَنَاهُ عَمْرُو بْنُ الْحَمِقِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَمَّنَ رَجُلًا عَلَى نَفْسِهِ فَقَتَلَهُ أُعْطِيَ لِوَاءَ الْغَدْرِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id Al Qhoththon] dari [Hammad bin Salamah] telah menceritakan kepadaku ['Abdul Malik bin 'Umair] dari [Rifa'ah bin Syaddad], ia berkata; Aku pernah berdiri diatas kepala Al Mukhtar, saat saya mengetahui kebohongannya, saya ingin menghunuskan pedangku lalu aku tebaskan ke lehernya, kemudian saya teringat hadits yang diceritakan ['Amr bin Al Hamiq], ia berkata; Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa memberi jaminan keamanan kepada seseorang atas nama dirinya, kemudian ia membunuhnya, aku memberinya bendera pengkhianatan pada hari kiamat.\""},"3141":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ الْحَمِقِ الْخُزَاعِيِّ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَرَادَ اللَّهُ بِعَبْدٍ خَيْرًا اسْتَعْمَلَهُ قِيلَ وَمَا اسْتَعْمَلَهُ قَالَ يُفْتَحُ لَهُ عَمَلٌ صَالِحٌ بَيْنَ يَدَيْ مَوْتِهِ حَتَّى يَرْضَى عَنْهُ مَنْ حَوْلَهُ","id":"Telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepada kami [Mu'awiyah bin Shalih] telah menceritakan kepada kami ['Abdur Rahman bin Jubair bin Nufair] dari [ayahnya] dari ['Amr bin Al Hamiq Al Khuza'i], bahwa ia mendengar Nabi Shallallahu'alaihi wasallam bersabda; \"BIla Allah menghendaki kebaikan kepada seorang hamba, Allah akan menggunakannya.\" Ada yang bertanya; Digunakan untuk apa? Rasulullah Shallallahu'alaihi wasallam bersabda: \"Dibukakan baginya amal shalih dihadapan kematiannya hingga orang-orang sekelilingnya meridhainya.\""},"3142":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ مَسْعُودِ بْنِ الْحَكَمِ الْأَنْصَارِيِّ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ حُذَافَةَ السَّهْمِيَّ أَنْ يَرْكَبَ رَاحِلَتَهُ أَيَّامَ مِنًى فَيَصِيحَ فِي النَّاسِ لَا يَصُومَنَّ أَحَدٌ فَإِنَّهَا أَيَّامُ أَكْلٍ وَشُرْبٍقَالَ فَلَقَدْ رَأَيْتُهُ عَلَى رَاحِلَتِهِ يُنَادِي بِذَلِكَ","id":"Telah menceritakan kepada kami ['Abdur Rozzaq] telah memberitakan kepada kami [Ma'mar], dari [Az Zuhri] dari [Mas'ud bin Al Hakam Al Anshori] dari [seseorang sahabat Nabi Shallallahu'alaihi wasallam], ia berkata; Rasulullah Shallallahu'alaihi wasallam memerintahkan 'Abdullah bin Hudzafah As Sahmi untuk naik kendaraan beliau saat di Mina, kemudian ia berkata lantang ditengah-tengah kerumunan orang; 'Jangan ada seorang pun puasa, karena sesungguhnya ini adalah hari-hari makan dan minum. Saya melihatnya berada diatas kendaraan Rasulullah Shallallahu'alaihi wasallam menyerukan hal itu."},"3143":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ قَالَ قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ كَعْبِ بْنِ مَالِكٍ وَكَانَ أَبُوهُ أَحَدَ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَئِذٍ خَطِيبًا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَاسْتَغْفَرَ لِلشُّهَدَاءِ الَّذِينَ قُتِلُوا يَوْمَ أُحُدٍ ثُمَّ قَالَ إِنَّكُمْ يَا مَعْشَرَ الْمُهَاجِرِينَ تَزِيدُونَ وَإِنَّ الْأَنْصَارَ لَا يَزِيدُونَ وَإِنَّ الْأَنْصَارَ عَيْبَتِي الَّتِي أَوَيْتُ إِلَيْهَا أَكْرِمُوا كَرِيمَهُمْ وَتَجَاوَزُوا عَنْ مُسِيئِهِمْ فَإِنَّهُمْ قَدْ قَضَوْا الَّذِي عَلَيْهِمْ وَبَقِيَ الَّذِي لَهُمْ","id":"Telah menceritakan kepada kami ['Abdur Rozzaq] dari [Ma'mar], ia berkata; berkata [Az Zuhri], telah memberitakan kepadaku ['Abdur Rohman bin Ka'ab bin Malik], ayahnya adalah salah satu dari tiga orang yang taubatnya diterima, dari [salah seorang sahabat Nabi Shallallahu'alaihi wasallam]; bahwa Nabi Shallallahu'alaihi wasallam saat itu berdiri berkhutbah, beliau memuja dan memuji Allah dan memintakan ampunan kepada para syuhada` yang terbunuh dalam perang Uhud, selanjutnya beliau bersabda; \"Wahai sekalian kaum Muhajirin, kalian akan bertambah sementara kaum Anshar tidak bertambah. Sesungguhnya Anshar adalah tempatku berlindung. Muliakanlah orang mulia mereka dan maafkanlah kesalahan-kesalahan mereka karena mereka telah menunaikan kewajiban mereka dan yang masih tersisa tinggal hak mereka."},"3144":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو يَعْنِي الرَّقِّيَّ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ عَنْ أَبِي الْمُثَنَّى الْعَبْدِيِّ قَالَ سَمِعْتُ السَّدُوسِيَّ يَعْنِي ابْنَ الْخَصَاصِيَّةِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَايِعَهُ قَالَ فَاشْتَرَطَ عَلَيَّ شَهَادَةَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنْ أُقِيمَ الصَّلَاةَ وَأَنْ أُؤَدِّيَ الزَّكَاةَ وَأَنْ أَحُجَّ حَجَّةَ الْإِسْلَامِ وَأَنْ أَصُومَ شَهْرَ رَمَضَانَ وَأَنْ أُجَاهِدَ فِي سَبِيلِ اللَّهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَمَّا اثْنَتَانِ فَوَاللَّهِ مَا أُطِيقُهُمَا الْجِهَادُ وَالصَّدَقَةُ فَإِنَّهُمْ زَعَمُوا أَنَّهُ مَنْ وَلَّى الدُّبُرَ فَقَدْ بَاءَ بِغَضَبٍ مِنْ اللَّهِ فَأَخَافُ إِنْ حَضَرْتُ تِلْكَ جَشِعَتْ نَفْسِي وَكَرِهَتْ الْمَوْتَ وَالصَّدَقَةُ فَوَاللَّهِ مَا لِي إِلَّا غُنَيْمَةٌ وَعَشْرُ ذَوْدٍ هُنَّ رَسَلُ أَهْلِي وَحَمُولَتُهُمْ قَالَ فَقَبَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ حَرَّكَ يَدَهُ ثُمَّ قَالَ فَلَا جِهَادَ وَلَا صَدَقَةَ فَلِمَ تَدْخُلُ الْجَنَّةَ إِذًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَنَا أُبَايِعُكَ قَالَ فَبَايَعْتُ عَلَيْهِنَّ كُلِّهِنَّ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami ['Ubaidillah bin Amr Ar Roqqi] dari [Zaid bin Abu Unaisah] telah menceritakan kepada kami [Jabalah bin Suhaim] dari [Abu Al Mutsanna Al 'Abdi], ia berkata; Saya mendengar [As Sadusi bin Al Khashashiyyah] berkata; Aku mendatangi Nabi Shallallahu'alaihi wasallam untuk berbaiat, kemudian beliau mensyaratkanku agar bersaksi bahwa tidak ada Ilah (yang haq) kecuali Allah dan bahwa Muhammad adalah hamba dan utusan-Nya, agar saya mendirikan shalat, menunaikan zakat, menunaikan haji Islam, puasa dibulan Ramadhan dan berjihad di jalan Allah. Kemudian aku berkata; Wahai Rasulullah! Demi Allah, dua diantaranya aku tidak mampu; jihad dan zakat, karena mereka menduga bahwa siapa pun yang lari meninggalkan peperangan maka ia kembali dengan kemurkaan Allah, karena itu aku khawatir bila berperang diriku akan serakah dan aku takut mati. Sementara zakat, demi Allah aku hanya sedikit harta rampasan perang dan sepuluh ekor unta, semuanya adalah penggembalaan dan bawaan keluargaku. Kemudian Rasulullah Shallallahu'alaihi wasallam menjabat tanganku, beliau menggerakkan tangan beliau lalu bersabda; \"Tidak ada jihad dan zakat, lalu kenapa kau masuk surga?\" aku berkata; Wahai Rasulullah! Aku berbaiat kepada tuan. Kemudian aku berbaiat atas semua itu."},"3145":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ عَنْ بَشِيرِ ��ْنِ نَهِيكٍ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَّةِ بَشِيرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَمْشِي فِي نَعْلَيْنِ بَيْنَ الْقُبُورِ فَقَالَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ أَلْقِهِمَا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepadaku [Al Aswad bin Syaiban] dari [Khalid bin Sumair] dari [Basyir bin Nahik] dari [Basyir bin Al Khoshoshiyyah, penyampai kabar gembira Rasulullah Shallallahu'alaihi wasallam], ia berkata; 'Nabi Shallallahu'alaihi wasallam melihat seseorang berjalan mengenakan sandal diantara pemakaman, kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Hai pemilik dua sandal bagus, lemparkan keduanya!\""},"3146":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ وَعَفَّانُ قَالَا ثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ سَمِعْتُ إِيَادَ بْنَ لَقِيطٍ يَقُولُ سَمِعْتُ لَيْلَى امْرَأَةَ بَشِيرٍ تَقُولُإِنَّ بَشِيرًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصُومُ يَوْمَ الْجُمُعَةِ وَلَا أُكَلِّمُ ذَلِكَ الْيَوْمَ أَحَدًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصُمْ يَوْمَ الْجُمُعَةِ إِلَّا فِي أَيَّامٍ هُوَ أَحَدُهَا أَوْ فِي شَهْرٍ وَأَمَّا أَنْ لَا تُكَلِّمَ أَحَدًا فَلَعَمْرِي لَأَنْ تَكَلَّمَ بِمَعْرُوفٍ وَتَنْهَى عَنْ مُنْكَرٍ خَيْرٌ مِنْ أَنْ تَسْكُتَ","id":"Telah menceritakan kepada kami [Abu Al Walid] dan ['Affan], keduanya berkata; telah menceritakan kepada kami ['Ubaidullah bin Iyad bin Laqith], ia berkata; Saya mendengar [Iyad bin Laqith] berkata; saya mendengar [Laila, istri Basyir] berkata; Basyir bertanya kepada Nabi Shallallahu'alaihi wasallam; 'Bolehkan saya puasa pada hari jum'at dan tidak berbicara pada hari itu pada siapa pun.' Nabi Shallallahu'alaihi wasallam bersabda; \"Jangan puasa khusus hari jum'at, kecuali puasa beberapa hari dan jumat menjadi salah satunya atau puasa sebulan. Adapun masalahmu engkau berniat tidak berbicara kepada siapa pun, sungguh bila kau berbicara kebaikan dan mencegah kemungkaran itu lebih baik dari pada diam.\""},"3147":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدُ وَعَفَّانُ قَالَا ثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ حَدَّثَنَا إِيَادٌ يَعْنِي ابْنَ لَقِيطٍ عَنْ لَيْلَى امْرَأَةِ بَشِيرٍ قَالَتْأَرَدْتُ أَنْ أَصُومَ يَوْمَيْنِ مُوَاصِلَةً فَمَنَعَنِي بَشِيرٌ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ وَقَالَ يَفْعَلُ ذَلِكَ النَّصَارَى وَقَالَ عَفَّانُ يَفْعَلُ ذَلِكَ النَّصَارَى وَلَكِنْ صُومُوا كَمَا أَمَرَكُمْ اللَّهُ عَزَّ وَجَلَّ وَأَتِمُّوا الصِّيَامَ إِلَى اللَّيْلِ فَإِذَا كَانَ اللَّيْلُ فَأَفْطِرُوا","id":"Telah menceritakan kepada kami [Abu Al Walid] dan ['Affan] keduanya berkata; telah menceritakan kepada kami ['Ubaidullah bin Iyad], telah menceritakan kepada kami [Iyad bin Laqith] dari [Laila, istri Basyir], ia berkata; Saya ingin puasa dua hari secara berturut-turut, kemudian [Basyir] melarangku dan berkata; Rasulullah Shallallahu'alaihi wasallam melarangnya. Perawi menuturkan; Orang-orang Anshar melakukannya. Berkata 'Affan; Orang-orang Anshar melakukannya, tapi berpuasalah seperti yang diperintahkan Allah kepada kalian dan sempurnakanlah puasa hingga malam, bila sudah malam berbukalah."},"3148":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ الشَّيْبَانِيُّ عَنْ أَبِيهِ عَنْ لَيْلَى امْرَأَةِ بَشِيرِ ابْنِ الْخَصَاصِيَّةِ عَنْ بَشِيرٍ قَالَوَكَانَ قَدْ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُهُ زَحْمٌ فَسَمَّاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِيرًا","id":"Telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami ['Ubaidullah bin Iyad bin Laqith Asy Syaibani] dari [ayahnya] dari [Laila, istri Basyir bin Al Khoshoshiyyah] dari [Basyir] ia berkata, bahwasanya ia pernah mendatangi Nabi Shallallahu'alaihi wasallam; (pada waktu itu) ia bernama Zahm. Kemudian Nabi Shallallahu'alaihi wasallam memberinya nama Basyir."},"3149":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ أَيُّوبَ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ حَنْظَلَةَ غَسِيلِ الْمَلَائِكَةِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْهَمٌ رِبًا يَأْكُلُهُ الرَّجُلُ وَهُوَ يَعْلَمُ أَشَدُّ مِنْ سِتَّةٍ وَثَلَاثِينَ زَنْيَةً","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Jarir bin Hazim] dari [Ayyub] dari [Ibnu Abi Mulaikah] dari ['Abdullah bin Hanzhalah, yang dimandikan oleh para malaikat], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Satu dirham hasil riba yang dimakan seseorang sementara ia mengetahuinya, itu lebih buruk dari tigapuluh kali berzina.\""},"3150":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنِ ابْنِ حَنْظَلَةَ بْنِ الرَّاهِبِ عَنْ كَعْبٍ قَالَلَأَنْ أَزْنِيَ ثَلَاثًا وَثَلَاثِينَ زَنْيَةً أَحَبُّ إِلَيَّ مِنْ أَنْ آكُلَ دِرْهَمَ رِبًا يَعْلَمُ اللَّهُ أَنِّي أَكَلْتُهُ حِينَ أَكَلْتُهُ رِبًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari ['Abdul 'Aziz bin Rofi'] dari [Ibnu Abi Mulaikah] dari [Ibnu Hanzhalah bin Ar Rohib] dari [Ka'ab], ia berkata; 'Sungguh bila saya berzina tigapuluh tiga kali itu lebih aku sukai dari pada memakan satu dirham hasil riba, dan Allah mengetahui saat aku memakannya itu hasil riba.'"},"3151":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَعِيدٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ رَجُلٍ عَنْ عَبْدِ اللَّهِ بْنِ حَنْظَلَةَ بْنِ الرَّاهِبِأَنَّ رَجُلًا سَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ بَالَ فَلَمْ يَرُدَّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى قَالَ بِيَدِهِ إِلَى الْحَائِطِ يَعْنِي أَنَّهُ تَيَمَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah], telah menceritakan kepada kami [Sa'id], dari [Muhammad bin Al Munkadir] dari [seseorang] dari ['Abdullah bin Hanzhalah bin Ar Rahib] bahwa seseorang mengucapkan salam pada Nabi Shallallahu'alaihi wasallam dan ia habis buang air kecil, Nabi Shallallahu'alaihi wasallam tidak menjawab salamnya hingga beliau mengisyaratkan tangannya ke sebuah dinding. Maksud beliau, 'agar bertayammum.'"},"3152":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ الْأَنْصَارِيُّ ثُمَّ الْمَازِنِيُّ مَازِنُ بَنِي النَّجَّارِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ قُلْتُ لَهُ أَرَأَيْتَ وُضُوءَ عَبْدِ اللَّهِ بْنِ عُمَرَ لِكُلِّ صَلَاةٍ طَاهِرًا كَانَ أَوْ غَيْرَ طَاهِرٍ عَمَّ هُوَ فَقَالَ حَدَّثَتْهُ أَسْمَاءُ بِنْتُ زَيْدِ بْنِ الْخَطَّابِ أَنَّ عَبْدَ اللَّهِ بْنَ حَنْظَلَةَ بْنِ أَبِي عَامِرِ ابْنَ الْغَّسِيلِ حَدَّثَهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أُمِرَ بِالْوُضُوءِ لِكُلِّ صَلَاةٍ طَاهِرًا كَانَ أَوْ غَيْرَ طَاهِرٍ فَلَمَّا شَقَّ ذَلِكَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرَ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ وَوُضِعَ عَنْهُ الْوُضُوءُ إِلَّا مِنْ حَدَثٍقَالَ فَكَانَ عَبْدُ اللَّهِ يَرَى أَنَّ بِهِ قُوَّةً عَلَى ذَلِكَ كَانَ يَفْعَلُهُ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishak] telah menceritakan kepadaku [Muhammad bin Yahya bin Habban Al Anshori Al Mazini Mazin Bani An Najar] dari ['Ubaidullah bin 'Abdullah bin 'Umar]; (Muhammad) Berkata: saya bertanya padanya; Apa kau pernah melihat wudhu 'Abdullah bin 'Umar, ia bersuci setiap shalat ataukah tidak?. Kemudian ia menjawab; [Asma` binti Zaid bin Al Khaththab] telah bercerita kepadanya bahwa ['Abdullah bin Hanzhalah bin Abu 'Amir bin Al Ghasil] bercerita kepadanya bahwa Rasulullah Shallallahu'alaihi wasallam diperintahkan untuk berwudhu setiap shalat ataukah tidak. Saat hal itu memberatkan Rasulullah Shallallahu'alaihi wasallam, Rasulullah Shallallahu'alaihi wasallam diperintahkan untuk bersiwak setiap kali shalat dan wudhu tidak diberlakukan pada beliau kecuali karena hadats. Kemudian 'Abdullah menaksir dirinya mampu melakukan yang demikian hingga ia meninggal dunia."},"3153":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ مُحَمَّدٍ وَهُوَ أَبُو إِبْرَاهِيمَ الْمُعَقِّبُ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ مُعَاوِيَةَ الْفَزَارِيَّ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ الْأَسَدِيُّ عَنْ سُلَيْمَانَ بْنِ بِشْرٍ الْخُزَاعِيِّ عَنْ خَالِهِ مَالِكِ بْنِ عَبْدِ اللَّهِ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أُصَلِّ خَلْفَ إِمَامٍ كَانَ أَوْجَزَ مِنْهُ صَلَاةً فِي تَمَامِ الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad Abu Ibrahim Al Mu'aqqab] telah menceritakan kepada kami [Marwan bin Mua'wiyah Al Fazari] telah menceritakan kepada kami [Manshur bin Hayyan Al Asadi] dari [Sulaiman bin Bisyr Al Khuza'i] dari pamannya - [Malik bin 'Abdullah] -, ia berkata; saya perang bersama Rasulullah Shallallahu'alaihi wasallam, saya tidak shalat dibelakang imam yang mempercepat shalatnya dalam ruku' dan sujud."},"3154":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ جَابِرٍ أَنَّ أَبَا الْمُصَبِّحِ الْأَوْزَاعِيَّ حَدَّثَهُمْ قَالَبَيْنَا نَسِيرُ فِي دَرْبِ قَلَمْيَةَ إِذْ نَادَى الْأَمِيرَ مَالِكَ بْنَ عَبْدِ اللَّهِ الْخَثْعَمِيَّ رَجُلٌ يَقُودُ فَرَسَهُ فِي عِرَاضِ الْجَبَلِ يَا أَبَا عَبْدِ اللَّهِ أَلَا تَرْكَبُ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ سَاعَةً مِنْ نَهَارٍ فَهُمَا حَرَامٌ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Jabir] bahwa [Abu Al Mushobbih Al Auza'i] bercerita kepada mereka, ia berkata; Saat kami berjalan digerbang Qolaimah, seseorang yang tengah menuntun kudanya dari arah gunung memanggil sang pemimpin [Malik bin 'Abdullah Al Khots'ami]; Hai Abu Abdullah, apa kau tidak naik. Ia berkata; 'Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa yang kedua kakinya berdebu dijalan Allah Azza wa jalla sesaat, keduanya haram bagi neraka.\""},"3155":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ عَنْ لَيْثِ بْنِ الْمُتَوَكِّلِ عَنْ مَالِكِ بْنِ عَبْدِ اللَّهِ الْخَثْعَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ حَرَّمَهُ اللَّهُ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Muhammad bin 'Abdullah Asy Syu'aitsi] dari [Laits bin Al Mutawakkil] dari [Malik bin 'Abdullah Al Khats'ami], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa yang keduanya kakinya berdebu dijalan Allah, Allah mengharamkannya dari neraka.\""},"3156":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ حَدَّثَنِي سُلَيْمَانُ الْخُزَاعِيُّ عَنْ خَالِهِ مَالِكِ بْنِ عَبْدِ اللَّهِ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا صَلَّيْتُ خَلْفَ إِمَامٍ يَؤُمُّ النَّاسَ أَخَفَّ صَلَاةً مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Manshur bin Hayyan] telah menceritakan kepadaku [Sulaiman Al Khuza'i] dari pamannya - [Malik bin 'Abdullah] -, ia berkata; Saya berperang bersama Rasulullah Shallallahu'alaihi wasallam, saya tidak shalat dibelakang imam yang mengimami orang yang paling cepat shalatnya melebihi Rasulullah Shallallahu'alaihi wasallam."},"3157":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ مُظَفَّرُ بْنُ مُدْرِكٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنِي سِمَاكُ بْنُ حَرْبٍ حَدَّثَنِي قَبِيصَةُ بْنُ هُلْبٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَسَأَلَهُ رَجُلٌ فَقَالَ إِنَّ مِنْ الطَّعَامِ طَعَامًا أَتَحَرَّجُ مِنْهُ فَقَالَ لَا يَخْتَلِجَنَّ فِي نَفْسِكَ شَيْءٌ ضَارَعْتَ فِيهِ النَّصْرَانِيَّةَ","id":"Telah menceritakan kepada kami [Abu Kamil Muzhaffar bin Mudrik] telah menceritakan kepada kami [Zuhair] telah menceritakan kepadaku [Simak bin Harb] telah menceritakan kepadaku [Qabishah bin Hulb] dari [ayahnya], ia berkata; Saya mendengar Rasulullah Shallallahu'alaihi wasallam bersabda saat seseorang berkata kepada beliau; Diantara berbagai makanan ada satu makanan yang tidak saya sukai. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jangan sampai ada sesuatu menggelisahkan dirimu, yang itu menyamai Nasrani.\""},"3158":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ طَعَامِ النَّصَارَى فَقَالَ لَا يَخْتَلِجَنَّ فِي صَدْرِكَ طَعَامٌ ضَارَعْتَ فِيهِ النَّصْرَانِيَّةَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb] dari [Qabishoh bin Hulb] dari [ayahnya], ia berkata; Saya bertanya kepada Rasulullah Shallallahu'alaihi wasallam tentang makanan kaum Nasrani, lalu beliau bersabda; \"Jangan sampai ada satu makanan pun yang menggelisahkan hatimu, yang itu menyamai Nasrani.\""},"3159":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ الْهُلْبِ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ وَرَأَيْتُهُ يَنْصَرِفُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak bin Harb] dari [Qabishah bin Al Hulb] dari [ayahnya], ia berkata; Saya melihat Nabi Shallallahu'alaihi wasallam meletakkan tangan kanan beliau diatas tangan kiri saat shalat dan saya melihat beliau menoleh ke kanan dan ke kiri."},"3160":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلْتُهُ عَنْ طَعَامِ النَّصَارَى فَقَالَ لَا يَخْتَلِجَنَّ أَوْ لَا يَحِيكَنَّ فِي صَدْرِكَ طَعَامٌ ضَارَعْتَ فِيهِ النَّصْرَانِيَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far Al Warakani] telah menceritakan kepada kami [Syarik] dari [Simak] dari [Qabishah bin Hulb] dari [ayahnya] dari Nabi Shallallahu'alaihi wasallam; Aku bertanya kepada beliau tentang makanan orang-orang Nasrani, beliau bersabda: \"Jangan ada makanan yang meresahkan di dadamu, yang menyamai Nasrani.\""},"3161":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ أَخْبَرَنِي سِمَاكُ بْنُ حَرْبٍ قَالَ سَمِعْتُ قَبِيصَةَ بْنَ هُلْبٍ يُحَدِّثُ عَنْ أَبِيهِسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَذَكَرَ الصَّدَقَةَ قَالَ لَا يَجِيئَنَّ أَحَدُكُمْ بِشَاةٍ لَهَا يُعَارٌ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] telah mengabarkan kepadaku [Simak bin Harb], ia berkata; Saya mendengar [Qobishoh bin Hulb] menceritakan dari [ayahnya], ia mendengar Nabi Shallallahu'alaihi wasallam menyebutkan sedekah, beliau bersabda; \"Janganlah salah satu dari kalian datang membawa seekor kambing yang ada cacatnya pada hari kiamat.\""},"3162":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى بْنِ صُبَيْحٍ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ الْهُلْبِ عَنْ أَبِيهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ طَعَامِ النَّصَارَى فَقَالَ لَا يَحِيكَنَّ فِي صَدْرِكَ طَعَامٌ ضَارَعْتَ فِيهِ النَّصْرَانِيَّةَ قَالَ وَرَأَيْتُهُ يَضَعُ إِحْدَى يَدَيْهِ عَلَى الْأُخْرَى","id":"Telah menceritakan kepada kami [Zakariya bin Yahya bin Shubaih] telah menceritakan kepada kami [Syarik] dari [Simak] dari [Qobishoh bin Al Hulb] dari [ayahnya], ia berkata; saya bertanya kepada Nabi Shallallahu'alaihi wasallam tentang makanan orang-orang Nasrani, beliau bersabda; \"Jangan sampai ada satu makanan pun yang meresahkan dadamu yang menyamai Nasrani.\" Ia berkata; dan saya melihat beliau meletakkan salah satu tangan beliau diatas tangan yang lain."},"3163":{"ar":"قَالَوَرَأَيْتُهُ يَنْصَرِفُ مَرَّةً عَنْ يَمِينِهِ وَمَرَّةً عَنْ شِمَالِهِ","id":"(Masih dari jalur yang sama dengan hadits sebelumnya, dari [Hulub]) Ia berkata; Dan saya melihat beliau menoleh ke kanan sekali dan menoleh ke kiri sekali."},"3164":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْصَرِفُ عَنْ شِقَّيْهِ","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Simak] dari [Qobishoh bin Hulb] dari [ayahnya], ia berkata; Saya melihat Rasulullah Shallallahu'alaihi wasallam menoleh ke kedua sisi beliau."},"3165":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ النَّرْسِيُّ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا ثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّنَا فَيَأْخُذُ شِمَالَهُ بِيَمِينِهِ وَكَانَ يَنْصَرِفُ عَنْ جَانِبَيْهِ جَمِيعًا عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Al 'Abbas bin Al Walid An Narsi] dan [Hannad bin Al Sari] keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Qobishoh bin Hulb] dari [ayahnya], ia berkata; Rasulullah Shallallahu'alaihi wasallam mengimami kami, beliau memegang tangan kiri dengan tangan kanan dan beliau menoleh ke kedua sisinya; kanan dan kiri."},"3166":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّنَا فَيَأْخُذُ شِمَالَهُ بِيَمِينِهِ وَكَانَ يَنْصَرِفُ عَلَى جَانِبَيْهِ جَمِيعًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Qobishoh bin Hulb] dari [ayahnya], ia berkata; Rasulullah Shallallahu'alaihi wasallam mengimami kami, beliau memegang tangan kiri dengan tangan kanan dan menoleh ke kedua sisi beliau."},"3167":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ مَطَرِ بْنِ عُكَامِسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى اللَّهُ مِيتَةَ عَبْدٍ بِأَرْضٍ جَعَلَ لَهُ إِلَيْهَا حَاجَةً","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Sufyan] dari [Abu Ishaq] dari [Mathor bin 'Ukamis], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila Allah menetapkan kematian seorang hamba disuatu bumi, Allah menjadikan ia memerlukan tempat itu.\""},"3168":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ حَدَّثَنَا حُدَيْجٌ أَبُو سُلَيْمَانَ عَنْ أَبِي إِسْحَاقَ عَنْ مَطَرِ بْنِ عُكَامِسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقَدَّرُ لِأَحَدٍ يَمُوتُ بِأَرْضٍ إِلَّا حُبِّبَتْ إِلَيْهِ وَجُعِلَ لَهُ إِلَيْهَا حَاجَةٌ","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Muhammad bin Ja'far Al Warokani] telah menceritakan kepada kami [Hudaij Abu Sulaiman] dari [Abu Ishak] dari [Mathor bin 'Ukamis], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tidak seorang pun meninggal disuatu tempat melainkan ia pasti dibuat senang pada tempat itu dan ia memerlukan tempat tersebut.\""},"3169":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو أَيُّوبَ صَاحِبُ الْبَصْرِيِّ سُلَيْمَانُ بْنُ أَيُّوبَ حَدَّثَنَا هَارُونُ بْنُ دِينَارٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ مَيْمُونُ بْنُ سُنْبَادَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِوَامُ أُمَّتِي بِشِرَارِهَا قَالَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Abu Ayyub, temannya Al Bashri -Sulaiman bin Ayyub-] telah menceritakan kepada kami [Harun bin Dinar] dari [ayahnya], ia berkata; Saya mendengar salah seorang sahabat Nabi Shallallahu'alaihi wasallam bernama [Maimun bin Sunbad] berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tegaknya ummatku karena orang-orang jeleknya.\" Rasulullah Shallallahu'alaihi wasallam mengucapkannya tiga kali."},"3170":{"ar":"فِي سَنَةِ ثَمَانٍ وَعِشْرِينَ وَمِائَتَيْنِ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي ظَبْيَانَ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّهُ لَمَّا رَجَعَ مِنْ الْيَمَنِ قَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ رِجَالًا بِالْيَمَنِ يَسْجُدُ بَعْضُهُمْ لِبَعْضِهِمْ أَفَلَا نَسْجُدُ لَكَ قَالَ لَوْ كُنْتُ آمِرًا بَشَرًا يَسْجُدُ لِبَشَرٍ لَأَمَرْتُ الْمَرْأَةَ أَنْ تَسْجُدَ لِزَوْجِهَاحَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا ظَبْيَانَ يُحَدِّثُ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ أَقْبَلَ مُعَاذٌ مِنْ الْيَمَنِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَأَيْتُ رِجَالًا فَذَكَرَ مَعْنَاهُ","id":"Pada tahun duaratus duapuluh delapan, telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Al A'masy] dari [Abu Zhabyan] dari [Mu'adz bin Jabal]; bahwasanya saat ia kembali dari Yaman, ia berkata; Wahai Rasulullah! Saya melihat orang-orang di Yaman saling sujud satu sama lain, bolehkan kami bersujud pada baginda. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Andaikan aku memerintahkan manusia sujud kepada sesama manusia, pastilah aku perintahkan wanita bersujud kepada suaminya.\" Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Al A'masy] dari [Abu Zhabyan] ia menceritakan dari [seorang Anshar] dari [Mu'adz bin Jabal], ia datang dari Yaman dan berkata; Wahai Rasulullah! Saya melihat orang-orang. Ia menyebutkan maknanya."},"3171":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ مُعَاذٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا مُعَاذُ أَتْبِعْ السَّيِّئَةَ بِالْحَسَنَةِ تَمْحُهَا وَخَالِقْ النَّاسَ بِخُلُقٍ حَسَنٍفَقَالَ وَقَالَ وَكِيعٌ وَجَدْتُهُ فِي كِتَابِي عَنْ أَبِي ذَرٍّ وَهُوَ السَّمَاعُ الْأَوَّلُ قَالَ أَبِي وَقَالَ وَكِيعٌ قَالَ سُفْيَانُ مَرَّةً عَنْ مُعَاذٍ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Mu'adz] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda padanya; \"Hai Mu'adz! Ikutilah keburukan dengan kebaikan niscaya akan menghapusnya dan perlakukan orang dengan akhlak yang baik.\" Berkata [Waki']; saya menemukannya dalam buku saya dari [Abu Dzarr], itu adalah pendengaran pertama, berkata ayah saya; berkata Waki'; berkata Sufyan dari Mu'adz sekali."},"3172":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ جَابِرٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ مُعَاذٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قُرًى عَرَبِيَّةٍ فَأَمَرَنِي أَنْ آخُذَ حَظَّ الْأَرْضِو قَالَ عَبْدُ الرَّزَّاقِ يَعْنِي عَنْ سُفْيَانَ عَنْ جَابِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ مُحَمَّدِ بْنِ زَيْدٍ يَعْنِي فِي حَدِيثِ مُعَاذٍ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Jabir] dari [Muhammad bin Zaid] dari [Mu'adz], ia berkata; Rasulullah Shallallahu'alaihi wasallam mengutusku ke suatu perkampungan arab, beliau memerintahkanku untuk memunggut bagian bumi. Berkata ['Abdur Razzaq] dari ['Sufyan] dari [Jabir] dari ['Abdur Rahman bin Al Aswad] dari [Muhammad bin Zaid], maksudnya dalam hadits [Mu'adz]."},"3173":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ مُعَاذٍ قَالَكُنْتُ رِدْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُعَاذُ أَتَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَنْ تَعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا قَالَ فَهَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا هُمْ فَعَلُوا ذَلِكَ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ لَا يُعَذِّبُهُمْ","id":"Telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari ['Amr bin Maimun] dari [Mu'adz], ia berkata; Saya pernah membonceng Rasulullah Shallallahu'alaihi wasallam, beliau bersabda; \"Hai Mu'adz! Apa hak Allah atas manusia?\" saya menjawab; Allah dan RasulNya yang lebih tahu. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bahwa kalian menyembahnya dan tidak menyekutukan-Nya dengan sesuatu pun.\" Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apa kau tahu hak manusia atas Allah bila mereka melakukan hal itu?\" saya menjawab; Allah dan RasulNya yang lebih tahu. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Allah tidak menyiksa mereka.\""},"3174":{"ar":"حَدَّثَنَا وَكِيعٌ عَنِ النَّهَّاسِ بْنِ قَهْمٍ حَدَّثَنِي شَدَّادٌ أَبُو عَمَّارٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتٌّ مِنْ أَشْرَاطِ السَّاعَةِ مَوْتِي وَفَتْحُ بَيْتِ الْمَقْدِسِ وَمَوْتٌ يَأْخُذُ فِي النَّاسِ كَقُعَاصِ الْغَنَمِ وَفِتْنَةٌ يَدْخُلُ حَرْبُهَا بَيْتَ كُلِّ مُسْلِمٍ وَأَنْ يُعْطَى الرَّجُلُ أَلْفَ دِينَارٍ فَيَتَسَخَّطَهَا وَأَنْ تَغْدِرَ الرُّومُ فَيَسِيرُونَ فِي ثَمَانِينَ بَنْدًا تَحْتَ كُلِّ بَنْدٍ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Waki'] dari [An Nahhas bin Qahm] telah menceritakan kepada kami [Syaddad Abu 'Ammar] dari [Mu'adz bin Jabal], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Enam tanda-tanda kiamat; kematianku, penaklukkan Baitul Maqdis, kematian yang menyerang manusia laksana kematian kambing yang cepat, muncul fitnah yang serangannya masuk ke rumah setiap orang muslim, orang diberi seribu dinar kemudian ia marah, Romawi berkhianat kemudian mereka pergi dalam delapan bendera, dibawa setiap bendera ada duabelas (pasukan).\""},"3175":{"ar":"حَدَّثَنَاه عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّزَّاقِ قَالَ ثَنَا مَعْمَرٌ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَكُنْتُ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَزَّ وَجَلَّ عَلَى عِبَادِهِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا قَالَ هَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوا ذَلِكَ أَنْ يَغْفِرَ لَهُمْ وَلَا يُعَذِّبَهُمْ قَالَ مَعْمَرٌ فِي حَدِيثِهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَلَا أُبَشِّرُ النَّاسَ قَالَ دَعْهُمْ يَعْمَلُواحَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَصِينٍ عَنِ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ مُعَاذٍ بِنَحْوِهِ","id":"Telah menceritakan kepada kami ['Abdur Rahman] telah menceritakan kepada kami [Sufyan] dan ['Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Abu Ishak] dari ['Amr bin Maimun] dari [Mu'adz bin Jabal], ia berkata; Saya pernah membonceng Rasulullah Shallallahu'alaihi wasallam diatas keledai, beliau bersabda; \" Apa hak Allah Azza wa Jalla atas manusia?\" saya menjawab; Allah dan RasulNya yang lebih tahu. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bahwa kalian menyembahnya dan tidak menyekutukannya dengan sesuatu pun.\" Rasulullah Shallallahu'alaihi wasallam bersabda: \" Apa kau tahu hak manusia atas Allah bila mereka melakukan hal itu?\" saya menjawab; Allah dan RasulNya yang lebih tahu. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Mengampuni mereka dan tidak menyiksa mereka.\" Berkata Ma'mar dalam haditsnya, Mu'adz berkata; Wahai Rasulullah! Bolehkah saya sampaikan khabar gembira ini kepada orang-orang. Rasulullah Shallallahu'alaihi wasallam bersabda: \"Biarlah mereka beramal.\" Telah menceritakan kepada kami ['Abdur Rahman] telah menceritakan kepada kami [Sufyan] dari [Abu Hushain] dari [Al Aswad bin Hilal] dari [Mua'dz] hadits serupa."},"3176":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي رَزِينٍ عَنْ مُعَاذٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكَ عَلَى بَابٍ مِنْ أَبْوَابِ الْجَنَّةِ قَالَ وَمَا هُوَ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami ['Abdur Rahman] telah menceritakan kepada kami [Hammad bin Salamah] dari [Atho` bin As Sa`ib] dari [Abu Rozin] dari [Mu'adz], bahwa Nabi Shallallahu'alaihi wasallam bersabda; \"Maukah kau aku tunjukkan salah satu pintu surga?\" ia bertanya; Apa itu? Rasulullah Shallallahu'alaihi wasallam bersabda: \"Laa haula wa laa quwwata illa billaah.\""},"3177":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ أَبِي الزُّبَيْرِ حَدَّثَنَا أَبُو الطُّفَيْلِ حَدَّثَنَا مُعَاذُ بْنُ جَبَلٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفْرَةٍ سَافَرَهَا وَذَلِكَ فِي غَزْوَةِ تَبُوكَ فَجَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ قُلْتُ مَا حَمَلَهُ عَلَى ذَلِكَ قَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ","id":"Telah menceritakan kepada kami ['Abdur Rahman] telah menceritakan kepada kami [Qurroh bin Kholid] dari [Abu Az Zubair] telah menceritakan kepada kami [Abu Ath Thufail] telah menceritakan kepada kami [Mu'adz bin Jabal], ia berkata; Rasulullah Shallallahu'alaihi wasallam pergi dalam salah satu perjalanan beliau saat perang Tabuk, beliau menjamak dhuhur dan ashar, maghrib dan isya'. Saya bertanya; Apa yang menyebabkan beliau melakukannya. Ia menjawab; Agar tidak memberatkan ummat beliau."},"3178":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ الْحَجَّاجِ يَعْنِي ابْنَ أَبِي عُثْمَانَ حَدَّثَنِي حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنَا هِصَّانُ بْنُ الْكَاهِنِ الْعَدَوِيُّ قَالَ جَلَسْتُ مَجْلِسًا فِيهِ عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ وَلَا أَعْرِفُهُ قَالَ ثَنَا مُعَاذُ بْنُ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَلَى الْأَرْضِ نَفْسٌ تَمُوتُ لَا تُشْرِكُ بِاللَّهِ شَيْئًا تَشْهَدُ أَنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْجِعُ ذَاكُمْ إِلَى قَلْبٍ مُوقِنٍ إِلَّا غُفِرَ لَهَا قَالَ قُلْتُ أَنْتَ سَمِعْتَ هَذَا مِنْ مُعَاذِ بْنِ جَبَلٍ قَالَ فَعَنَّفَنِي الْقَوْمُ فَقَالَ دَعُوهُ فَإِنَّهُ لَمْ يُسِئْ الْقَوْلَ نَعَمْ أَنَا سَمِعْتُهُ مِنْ مُعَاذٍ زَعَمَ أَنَّهُ سَمِعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِصَّانَ بْنِ الْكَاهِنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ عَنْ مُعَاذٍ مِثْلَهُ نَحْوَ قَوْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Al Hajjaj bin Abu 'Utsman] telah menceritakan kepadaku [Humaid bin Hilal] telah menceritakan kepada kami [Hishshan bin Al Kahin Al 'Adawi], ia berkata; Saya duduk disuatu majlis disana ada ['Abdur Rahman bin Samurah] dan saya tidak mengetahuinya, ia berkata; Telah menceritakan kepada kami [Mu'adz bin Jabal], ia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tidaklah ada suatu jiwa diatas muka bumi yang meninggal dunia dengan tidak menyekutukan Allah dengan sesuatu pun dan bersaksi bahwa sesungguhnya aku adalah utusan Allah, dan semua itu kembali ke hati yang meyakini, melainkan ia akan diampuni.\" Saya berkata; Engkau mendengar hadits itu dari Mu'adz bin Jabal? Kemudian orang-orang memperlakukanku dengan sikap kasar Orang tua itu berkata; 'Biarkan dia karena ia tidak berkata buruk. Ya, saya mendengarnya dari Mu'adz bin Jabal, ia mengira mendengarnya dari Rasulullah Shallallahu'alaihi wasallam. Telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Habib bin Asy-Syahid] dari [Humaid bin Hilal] dari [Hishshan bin Al Kahin] dari ['Abdur Rahman bin Samurah] dari [Mu'adz] perkataan serupa."},"3179":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءِ بْنِ الْوَلِيدِ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي إِدْرِيسَ الْعَبْدِيِّ أَوْ الْخَوْلَانِيِّ قَالَجَلَسْتُ مَجْلِسًا فِيهِ عِشْرُونَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا فِيهِمْ شَابٌّ حَدِيثُ السِّنِّ حَسَنُ الْوَجْهِ أَدْعَجُ الْعَيْنَيْنِ أَغَرُّ الثَّنَايَا فَإِذَا اخْتَلَفُوا فِي شَيْءٍ فَقَالَ قَوْلًا انْتَهَوْا إِلَى قَوْلِهِ فَإِذَا هُوَ مُعَاذُ بْنُ جَبَلٍ فَلَمَّا كَانَ مِنْ الْغَدِ جِئْتُ فَإِذَا هُوَ يُصَلِّي إِلَى سَارِيَةٍ قَالَ فَحَذَفَ مِنْ صَلَاتِهِ ثُمَّ احْتَبَى فَسَكَتَ قَالَ فَقُلْتُ وَاللَّهِ إِنِّي لَأُحِبُّكَ مِنْ جَلَالِ اللَّهِ قَالَ أَاللَّهِ قَالَ قُلْتُ أَاللَّهِ قَالَ فَإِنَّ مِنْ الْمُتَحَابِّينَ فِي اللَّهِ فِيمَا أَحْسَبُ أَنَّهُ قَالَ فِي ظِلِّ اللَّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ ثُمَّ لَيْسَ فِي بَقِيَّتِهِ شَكٌّ يَعْنِي فِي بَقِيَّةِ الْحَدِيثِ يُوضَعُ لَهُمْ كَرَاسٍ مِنْ نُورٍ يَغْبِطُهُمْ بِمَجْلِسِهِمْ مِنْ الرَّبِّ عَزَّ وَجَلَّ النَّبِيُّونَ وَالصِّدِّيقُونَ وَالشُّهَدَاءُ قَالَ فَحَدَّثْتُهُ عُبَادَةَ بْنَ الصَّامِتِ فَقَالَ لَا أُحَدِّثُكَ إِلَّا مَا سَمِعْتُ عَنْ لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقَّتْ مَحَبَّتِي لِلْمُتَحَابِّينَ فِيَّ وَحَقَّتْ لِلْمُتَبَاذِلِينَ فِيَّ وَحَقَّتْ مَحَبَّتِي لِلْمُتَصَادِقِينَ فِيَّ وَالْمُتَوَاصِلِينَ شَكَّ شُعْبَةُ فِي الْمُتَوَاصِلِينَ أَوْ الْمُتَزَاوِرِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atho` bin Al Walid bin Abu 'Abdur Rahman] dari [Abu Idris Al 'Abdi atau Al Khoulani], ia berkata; Saya duduk disuatu majlis, disana ada duapuluh sahabat Nabi Shallallahu'alaihi wasallam, ditengah-tengah mereka ada pemuda, berusia muda, elok rupanya, hitam matanya, putih giginya. Bila mereka berbeda pendapat tentang suatu hal, ia mengatakan kata-kata pamungkas. Ternyata ia adalah [Mu'adz bin Jabal]. Keesokan harinya saya datang dan ia tengah shalat menghadap seseorang yang berjalan. Mu'adz menghentikan shalat lalu duduk memeluk lutut kemudian diam. Kemudian saya berkata; 'Demi Allah, aku mencintaimu karena keagungan Allah. Ia berkata; Allah. Saya berkata; Engkau mengucapkan; Allah. Ia berkata; Karena orang-orang yang saling mencintai karena Allah -menurut saya ia berkata- maka ia berada didalam naungan Allah pada saat tidak ada naungan selain naungan-Nya. Selanjutnya tidak ada keraguan pada kelanjutannya -maksudnya kelanjutan hadits- Kursi-kursi dari cahaya diletakkan untuk mereka, pertemuan mereka dengan Allah membuat iri para nabi, orang-orang jujur dan para syuhada. Ia berkata; Kemudian saya menceritakannya kepada ['Ubadah bin Ash Shamit], ia berkata; Aku tidak menceritakan kepadamu selain yang telah aku dengar dari lisan Rasulullah Shallallahu'alaihi wasallam'; \"Wajiblah cintaKu untuk orang-orang yang saling mencintai karena Aku, bagi orang-orang yang berkorban karena Aku, bagi orang-orang yang saling berteman dan menyambung sillalurrahim -Syu'bah ragu tentang orang-orang yang menyambung sillaturrahim ataukah orang-orang yang saling mengunjungi.\""},"3180":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَيْمَنَ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طُوبَى لِمَنْ رَآنِي وَآمَنَ بِي وَطُوبَى لِمَنْ آمَنَ بِي وَلَمْ يَرَنِي سَبْعَ مِرَارٍحَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامُ بَنُ يَحْيَى وَحَمَّادُ بْنُ الْجَعْدِ عَنْ قَتَادَةَ عَنْ أَيْمَنَ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ أَوْ نَحْوَهُ","id":"Telah menceritakan kepada kami [Musa bin Dawud] telah menceritakan kepada kami [Hammam] dari [Qotadah] dari [Aiman] dari [Abu Umamah] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Beruntunglah orang yang melihatku dan beriman padaku, beruntunglah orang yang beriman padaku namun tidak melihatku.\" Beliau mengucapkannya tujuh kali. Telah menceritakan kepada kami [Hudbah bin Kholid] telah menceritakan kepada kami [Hammam bin Yahya] dan [Hammad bin Al Ja'ad] dari [Qotadah] dari [Aiman] dari [Abu Umamah] dari Nabi Shallallahu'alaihiWasallam sepertinya."},"3181":{"ar":"حَدَّثَنَا رَوْحٌ عَنْ هِشَامٍ عَنْ وَاصِلٍ مَوْلَى أَبِي عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ أَبِي يَعْقُوبَ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَ قَالَأَنْشَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةً فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ لِي بِالشَّهَادَةِ فَقَالَ اللَّهُمَّ سَلِّمْهُمْ وَغَنِّمْهُمْ قَالَ فَسَلِمْنَا وَغَنِمْنَا قَالَ ثُمَّ أَنْشَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوًا ثَانِيًا فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ لِي بِالشَّهَادَةِ فَقَالَ اللَّهُمَّ سَلِّمْهُمْ وَغَنِّمْهُمْ قَالَ ثُمَّ أَنْشَأَ غَزْوًا ثَالِثًا فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَتَيْتُكَ مَرَّتَيْنِ قَبْلَ مَرَّتِي هَذِهِ فَسَأَلْتُكَ أَنْ تَدْعُوَ اللَّهَ لِي بِالشَّهَادَةِ فَدَعَوْتَ اللَّهَ عَزَّ وَجَلَّ أَنْ يُسَلِّمَنَا وَيُغَنِّمَنَا فَسَلِمْنَا وَغَنِمْنَا يَا رَسُولَ اللَّهِ فَادْعُ اللَّهَ لِي بِالشَّهَادَةِ فَقَالَ اللَّهُمَّ سَلِّمْهُمْ وَغَنِّمْهُمْ قَالَ فَسَلِمْنَا وَغَنِمْنَا ثُمَّ أَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِعَمَلٍ قَالَ عَلَيْكَ بِالصَّوْمِ فَإِنَّهُ لَا مِثْلَ لَهُ قَالَ فَمَا رُئِيَ أَبُو أُمَامَةَ وَلَا امْرَأَتُهُ وَلَا خَادِمُهُ إِلَّا صُيَّامًا قَالَ فَكَانَ إِذَا رُئِيَ فِي دَارِهِمْ دُخَانٌ بِالنَّهَارِ قِيلَ اعْتَرَاهُمْ ضَيْفٌ نَزَلَ بِهِمْ نَازِلٌ قَالَ فَلَبِثَ بِذَلِكَ مَا شَاءَ اللَّهُ ثُمَّ أَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَمَرْتَنَا بِالصِّيَامِ فَأَرْجُو أَنْ يَكُونَ قَدْ بَارَكَ اللَّهُ لَنَا فِيهِ يَا رَسُولَ اللَّهِ فَمُرْنِي بِعَمَلٍ آخَرَ قَالَ اعْلَمْ أَنَّكَ لَنْ تَسْجُدَ لِلَّهِ سَجْدَةً إِلَّا رَفَعَ اللَّهُ لَكَ بِهَا دَرَجَةً وَحَطَّ عَنْكَ بِهَا خَطِيئَةًحَدَّثَنَا رَوْحٌ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَ قَالَ أَنْشَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوًا فَأَتَيْتُهُ فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ مُرْنِي بِعَمَلٍ آخُذُهُ عَنْكَ يَنْفَعُنِي اللَّهُ بِهِ قَالَ عَلَيْكَ بِالصَّوْمِ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا فِطْرُ بْنُ حَمَّادِ بْنِ وَاقِ��ٍ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ عَنِ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ أَوْ نَحْوَهُ","id":"Telah menceritakan kepada kami [Rouh] dari [Hisyam] dari [Washil, budak Abu 'Uyainah] dari [Muhammad bin Abu Ya'qub] dari [Raja` bin Haiwah] dari [Abu Umamah] berkata; 'Rasulullah Shallallahu'alaihiWasallam mengadakan peperangan, saya mendatangi beliau dan saya berkata; Wahai Rasulullah! Berdoalah kepada Allah untuk saya agar mati syahid. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ya Allah! Berilah mereka keselamatan dan harta rampasan perang.\" Berkata Abu Umamah; Kami menang dan mendapatkan harta rampasan perang. Kemudian Rasulullah Shallallahu'alaihiWasallam mengadakan perang selanjutnya, saya mendatangi beliau lalu berkata; Wahai Rasulullah! Berdoalah pada Allah untuk saya agar saya mati syahid. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ya Allah! Berilah mereka keselamatan dan harta rampasan perang.\" Berkata Abu Umamah; Kami menang dan mendapatkan harta rampasan perang. Kemudian Rasulullah Shallallahu'alaihiWasallam mengadakan perang selanjutnya, lalu saya berkata; wahai Rasulullah! aku mendatangi baginda dua kali sebelumnya, aku meminta baginda berdoa untuk saya agar saya mati syahid lalu baginda berdoa; \"Ya Allah! Berilah mereka keselamatan dan harta rampasan perang.\" Kami pun menang dan mendapatkan harta rampasan perang. Berkata Abu Umamah kemudian saya mendatangi beliau dan berkata; Wahai Rasulullah! Perintahkanlah aku untuk melakukan suatu amalan. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berpuasalah karena tidak ada amalan lain sepertinya.\" Semenjak itu Abu Umamah, istri dan pembantunya tidak pernah terlihat melainkan gemar puasa. Bila di siang hari ada asap dirumahnya, ada yang berkata; Ada tamu yang datang atau mereka ada keperluan. Hal itu terus berlangsung sampai waktu yang dikehendaki Allah subhanahu wata'ala kemudian aku (Abu Umamah) mendatangi Rasulullah Shallallahu'alaihiWasallam dan berkata; Wahai Rasulullah! baginda memerintahkanku untuk berpuasa, saya harap Allah memberkahi kami. Wahai Rasulullah! Perintahkanlah kami untuk melakukan amalan lain. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ketahuilah! Tidaklah engkau sujud karena Allah satu kali melainkan Allah akan mengangkat satu derajat karenanya dan menghapus satu kesalahan karenanya.\" Telah menceritakan kepada kami [Rouh] telah menceritakan kepada kami [Mahdi bin Maimun] telah menceritakan kepada kami [Muhammad bin Abu Ya'qub] dari [Roja` bin Haiwah] dari [Abu Umamah] berkata; Rasulullah Shallallahu'alaihiWasallam mengadakan peperangan kemudian saya mendatangi beliau. Ia menyebutkan makna hadits hanya saja ia berkata; Perintahkanlah aku untuk melakukan suatu amalan yang saya ambil darimu yang dengannya Allah memanfaatkanku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berpuasalah.\" Telah menceritakan kepada kami 'Abdullah, telah menceritakan kepada kami [Fithr bin Hammad bin Waqid] telah menceritakan kepada kami [Mahdi bin Maimun] dari [Muhammad bin 'Abdullah bin Abu Ya'qub] dari [Roja` bin Haiwah] dari [Abu Umamah] dari Nabi Shallallahu'alaihiWasallam sepertinya."},"3182":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا فِطْرُ بْنُ حَمَّادٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مَالِكَ بْنَ دِينَارٍ يَقُولُيَقُولُ النَّاسُ مَالِكُ بْنُ دِينَارٍ يَعْنِي مَالِكَ بْنَ دِينَارٍ زَاهِدٌ إِنَّمَا الزَّاهِدُ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ الَّذِي أَتَتْهُ الدُّنْيَا فَتَرَكَهَا","id":"Telah menceritakan kepada kami 'Abdullah telah menceritakan kepada kami [Fithr bin Hammad] telah menceritakan kepada kami [ayahku] berkata; Saya mendengar [Malik bin Dinar] berkata; Orang-orang berkata bahwa Malik bin Dinar orang zuhud, sesungguhnya orang yang zuhud hanyalah 'Umar bin 'Abdul 'Azzi, yang dunia datang kepadanya tapi justru ia meninggalkannya."},"3183":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادٌ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي الْمَشَّاءِ وَهُوَ لَقِيطُ بْنُ الْمَشَّاءِ عَنْ أَبِي أُمَامَةَ قَالَلَا تَقُومُ السَّاعَةُ حَتَّى يَتَحَوَّلَ خِيَارُ أَهْلِ الْعِرَاقِ إِلَى الشَّامِ وَيَتَحَوَّلَ شِرَارُ أَهْلِ الشَّامِ إِلَى الْعِرَاقِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالشَّامِقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو الْمُثَنَّى يُقَالُ لَهُ لَقِيطٌ وَيَقُولُونَ ابْنُ الْمُثَنَّى وَأَبُو الْمُثَنَّى","id":"Telah menceritakan kepada kami ['Abdush Shomad] telah menceritakan kepada kami [Hammad] dari [Al Jurairi] dari [Abu Al Masysya`, anak pungutan Ibnu Al Masysya`] dari [Abu Umamah] berkata; Kiamat tidaklah terjadi hingga penduduk Irak yang terbaik pindah ke Syam dan penduduk jahat Syam pindah ke Irak. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Hendaklah kalian ke Syam.\" Berkata Abu 'Abdur Rahman; Abu Al Mutsanna, disebut-sebut sebagai anak pungutan mereka berkata Ibnu Al Mutsanna dan Abu Al Mutsanna."},"3184":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ حَدَّثَهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْرَءُوا الْقُرْآنَ فَإِنَّهُ شَافِعٌ لِأَصْحَابِهِ يَوْمَ الْقِيَامَةِ اقْرَءُوا الزَّهْرَاوَيْنِ الْبَقَرَةَ وَآلَ عِمْرَانَ فَإِنَّهُمَا يَأْتِيَانِ يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ كَأَنَّهُمَا غَيَايَتَانِ أَوْ كَأَنَّهُمَا فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ يُحَاجَّانِ عَنْ أَهْلِهِمَا ثُمَّ قَالَ اقْرَءُوا الْبَقَرَةَ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُحَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ أَنَّ رَسُولَ اللَّهِ قَالَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami ['Abdul Malik bin 'Amr] telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Zaid] dari [Abu Sallam] dari [Abu Umamah] telah menceritakan padanya, ia berkata; Saya mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Bacalah Al Quran karena ia memberi syafaat pada para pembacanya pada hari kiamat, bacalah zahrawain; Albaqarah dan Ali 'Imran, karena keduanya datang pada hari kiamat seperti dua awan, naungan atau seperti dua kumpulan burung yang berjajar berhujjah untuk membela para pemiliknya.\" Selanjutnya Rasulullah Shallallahu'alaihiWasallam bersabda; \"Bacalah Albaqarah karena mengambilnya berkah dan meninggalkannya rugi dan tidak bisa dikalahkan oleh tukang-tukang sihir.\" Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid] dari [Abu Sallam] dari [Abu Umamah] bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; ia (Abu Umamah) menyebutkan hadits serupa."},"3185":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ الضَّبِّيُّ قَالَ سَمِعْتُ أَبَا نَصْرٍ يُحَدِّثُ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مُرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ قَالَ عَلَيْكَ بِالصَّوْمِ فَإِنَّهُ لَا عِدْلَ لَهُ ثُمَّ أَتَيْتُهُ الثَّانِيَةَ فَقَالَ عَلَيْكَ بِالصِّيَامِ","id":"Telah menceritakan kepada kami ['Abdush Shomad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Abu Ya'qub Adh Dhoby] berkata; Saya mendengar [Abu Nashr] menceritakan dari [Roja` bin Haiwah] dari [Abu Umamah] berkata; Saya mendatangi Rasulullah Shallallahu'alaihiWasallam, kemudian saya berkata; Perintahkanlah aku suatu amalan yang bisa memasukkanku ke surga. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berpuasalah karena ia tidak ada tandingannya.\" Kemudian saya mendatangi beliau lagi, beliau bersabda; \"Berpuasalah.\""},"3186":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَحِيرٍ حَدَّثَنَا سَيَّارٌ أَنَّ أَبَا أُمَامَةَ ذَكَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَكُونُ فِي هَذِهِ الْأُمَّةِ فِي آخِرِ الزَّمَانِ رِجَالٌ أَوْ قَالَ يَخْرُجُ رِجَالٌ مِنْ هَذِهِ الْأُمَّةِ فِي آخِرِ الزَّمَانِ مَعَهُمْ أَسْيَاطٌ كَأَنَّهَا أَذْنَابُ الْبَقَرِ يَغْدُونَ فِي سَخَطِ اللَّهِ وَيَرُوحُونَ فِي غَضَبِهِ","id":"Telah menceritakan kepada kami [Abu Sa'id] telah menceritakan kepada kami ['Abdullah bin Bahir] telah menceritakan kepada kami [Sayyar] bahwa [Abu Umamah] menyebutkan bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; \"Di akhir zaman di ummat ini ada beberapa orang -atau beliau bersabda; \"Akan muncul beberapa orang dari ummat ini diakhir zaman\"- membawa cambuk seperti ekor sapi, dipagi hari mereka berada didalam kemurkaan Allah dan disore hari mereka berada di dalam kemarahan Allah.\""},"3187":{"ar":"حَدَّثَنَا ��َبُو سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَحِيرٍ حَدَّثَنَا سَيَّارٌ قَالَجِيءَ بِرُءُوسٍ مِنْ قِبَلِ الْعِرَاقِ فَنُصِبَتْ عِنْدَ بَابِ الْمَسْجِدِ وَجَاءَ أَبُو أُمَامَةَ فَدَخَلَ الْمَسْجِدَ فَرَكَعَ رَكْعَتَيْنِ ثُمَّ خَرَجَ إِلَيْهِمْ فَنَظَرَ إِلَيْهِمْ فَرَفَعَ رَأْسَهُ فَقَالَ شَرُّ قَتْلَى تَحْتَ ظِلِّ السَّمَاءِ ثَلَاثًا وَخَيْرُ قَتْلَى تَحْتَ ظِلِّ السَّمَاءِ مَنْ قَتَلُوهُ وَقَالَ كِلَابُ النَّارِ ثَلَاثًا ثُمَّ إِنَّهُ بَكَى ثُمَّ انْصَرَفَ عَنْهُمْ فَقَالَ لَهُ قَائِلٌ يَا أَبَا أُمَامَةَ أَرَأَيْتَ هَذَا الْحَدِيثَ حَيْثُ قُلْتَ كِلَابُ النَّارِ شَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ شَيْءٌ تَقُولُهُ بِرَأْيِكَ قَالَ سُبْحَانَ اللَّهِ إِنِّي إِذًا لَجَرِيءٌ لَوْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً أَوْ مَرَّتَيْنِ حَتَّى ذَكَرَ سَبْعًا لَخِلْتُ أَنْ لَا أَذْكُرَهُ فَقَالَ الرَّجُلُ لِأَيِّ شَيْءٍ بَكَيْتَ قَالَ رَحْمَةً لَهُمْ أَوْ مِنْ رَحْمَتِهِمْ","id":"Telah menceritakan kepada kami [Abu Sa'id] telah menceritakan kepada kami ['Abdullah bin Bahir] telah menceritakan kepada kami [Sayyar] berkata; Beberapa kepala didatangkan dari Irak kemudian dipasang didekat pintu masjid. [Abu Umamah] datang lalu masuk masjid, ia shalat dua rakaat kemudian keluar dan melihat kepala-kepala itu, ia mengangkat kepala dan berkata; Korban-korban terburuk yang ada dibawah naungan langit. Ia mengucapkannya tiga kali. Kemudian ia berkata; Dan sebaik-baik korban yang ada dibawah naungan langit adalah orang-orang yang mereka bunuh. Ia berkata; Anjing-anjing neraka, sebanyak tiga kali. Ia menangis lalu pergi meninggalkan kepala-kepala itu. Ada yang berkata padanya; Hai Abu Umamah, apa kau mengetahui suatu hadits yang kau dengar dari Rasulullah Shallallahu'alaihiWasallam saat kau katakan; Anjing-anjing neraka, ataukah hanya kau katakan berdasarkan pendapatmu sendiri? Ia berkata; Subhanallah! Kalau begitu aku gegabah, andai aku mendengarnya dari Rasulullah Shallallahu'alaihiWasallam sekali, dua kali hingga tujuh kali kemudian tidak aku sebutkan dari Nabi. Seseorang berkata; Kenapa kau menangis? Ia berkata; Sebagai kasih sayang untuk mereka atau karena menyayangi mereka."},"3188":{"ar":"حَدَّثَنَا أَبُو إِسْحَاقَ الطَّالَقَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنِ الْقَاسِمِ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَحَ رَأْسَ يَتِيمٍ لَمْ يَمْسَحْهُ إِلَّا لِلَّهِ كَانَ لَهُ بِكُلِّ شَعْرَةٍ مَرَّتْ عَلَيْهَا يَدُهُ حَسَنَاتٌ وَمَنْ أَحْسَنَ إِلَى يَتِيمَةٍ أَوْ يَتِيمٍ عِنْدَهُ كُنْتُ أَنَا وَهُوَ فِي الْجَنَّةِ كَهَاتَيْنِ وَفَرَّقَ بَيْنَ أُصْبُعَيْهِ السَّبَّابَةِ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Abu Ishak Ath Tholaqoni] telah menceritakan kepada kami ['Abdullah bin Al Mubarok] dari [Yahya bin Ayyub] dari ['Ubaidillah bin Zahr] dari ['Ali bin Yazid] dari [Al Qosim] dari [Abu Umamah] bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; \"Barangsiapa mengusap kepala seorang anak yatim, dengan tidak ada dorongan mengusapnya kecuali karena Allah, ia mendapatkan beberapa kebaikan untuk setiap rambut yang dilalui tangannya. Barangsiapa berbuat baik kepada anak yatim perempuan atau yatim lelaki didekatnya, aku dan dia di surga seperti dua ini.\" Beliau memisahkan antara jari telunjuk dan jari tengah."},"3189":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ عَفَّانُ أَخْبَرَنَا أَبُو غَالِبٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ مِنْ خَيْبَرَ وَمَعَهُ غُلَامَانِ وَهَبَ أَحَدَهُمَا لِعَلِيِّ بْنِ أَبِي طَالِبٍ وَقَالَ لَا تَضْرِبْهُ فَإِنِّي قَدْ نَهَيْتُ عَنْ ضَرْبِ أَهْلِ الصَّلَاةِ وَقَدْ رَأَيْتُهُ يُصَلِّي قَالَ عَفَّانُ فِي حَدِيثِهِ أَخْبَرَنَا أَبُو طَالِبٍ عَنْ أَبِي أُمَامَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ مِنْ خَيْبَرَ وَمَعَهُ غُلَامَانِ فَقَالَ عَلِيٌّ يَا رَسُولَ اللَّهِ أَخْدِمْنَا قَالَ خُذْ أَيَّهُمَا شِئْتَ قَالَ خِرْ لِي قَالَ خُذْ هَذَا وَلَا تَضْرِبْهُ فَإِنِّي قَدْ رَأَيْتُهُ يُصَلِّي مَقْبَلَنَا مِنْ خَيْبَرَ وَإِنِّي قَدْ نَهَيْتُ وَأَعْطَى أَبَا ذَرٍّ غُلَامًا وَقَالَ اسْتَوْصِ بِهِ مَعْرُوفًا فَأَعْتَقَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فَعَلَ الْغُلَامُ قَالَ يَا رَسُولَ اللَّهِ أَمَرْتَنِي أَنْ أَسْتَوْصِيَ بِهِ مَعْرُوفًا فَأَعْتَقْتُهُ","id":"Telah menceritakan kepada kami [Hasan bin Musa] dan ['Affan] keduanya berkata; Telah menceritakan kepada kami [Hammad bin Salamah]. Berkata 'Affan; Telah mengabarkan kepada kami [Abu Ghalib] dari [Abu Umamah] bahwa Rasulullah Shallallahu'alaihiWasallam kembali dari Khaibar bersama dua budak, salah satunya milik 'Ali bin Abi Tholib, beliau bersabda; \"Jangan pukul dia karena aku melarang memukul orang yang mendirikan shalat dan aku pernah melihatnya shalat.\" Berkata 'Affan dalam haditsnya; Telah mengabarkan kepada kami Abu Tholib dari Abu Umamah bahwa Nabi Shallallahu'alaihiWasallam kembali dari Khaibar bersama dua budak lalu 'Ali berkata; Wahai Rasulullah! Layanilah kami. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ambillah salah satu dari keduanya yang kau mau. 'Ali berkata; Pilihkan untukku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ambillah ini dan jangan pukul dia karena aku pernah melihatnya shalat saat kami pulang dari Khaibar dan aku melarang.\" Beliau memberi Abu Dzarr seorang budak dan bersabda; \"Wasiatkan kebaikan padanya.\" Abu Dzarr memerdekakannya kemudian Nabi Shallallahu'alaihiWasallam bersabda padanya; \"Bagaimana khabar budak itu?\" ia berkata; Wahai Rasulullah! baginda memerintahkanku untuk mempergaulinya dengan baik, maka aku memerdekakannya."},"3190":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنِي مَالِكٌ عَنِ الْعَلَاءِ عَنْ مَعْبَدِ بْنِ كَعْبٍ السَّلَمِيِّ عَنْ أَخِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَطَعَ حَقَّ امْرِئٍ مُسْلِمٍ بِيَمِينِهِ فَقَدْ أَوْجَبَ اللَّهُ لَهُ النَّارَ وَحَرَّمَ عَلَيْهِ الْجَنَّةَ فَقَالَ لَهُ رَجُلٌ وَإِنْ كَانَ شَيْئًا يَسِيرًا يَا رَسُولَ اللَّهِ قَالَ وَإِنْ كَانَ قَضِيبًا مِنْ أَرَاكٍ","id":"Telah bercerita kepada kami [Ishaq bin 'Isa] berkata; Telah mengkhabarkan kepadaku [Malik] dari [Al 'Alaa] dari [Ma'bad bin Ka'ab As Salami] dari saudaranya ['Abdullah bin Ka'ab] dari [Abu Umamah] bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; \"Barangsiapa merampas hak seorang muslim dengan sumpahnya maka dengannya Allah mewajibkan neraka dan mengharamkan surga baginya. Seseorang berkata pada beliau; Meski hal sepele wahai Rasulullah! Rasulullah Shallallahu'alaihiWasallam bersabda; \"Meski sepotong dahan arok.\""},"3191":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ زُهَيْرٍ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ صَالِحٍ يَعْنِي ابْنَ كَيْسَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أُمَامَةَ الْحَارِثِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَذَاذَةُ مِنْ الْإِيمَانِ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Zuhair bin Muhammad] dari [Shalih bin Kaisan] dari ['Abdullah bin Abu Umamah Al Haritsi] dari [ayahnya] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kesederhanaan adalah bagian dari iman.\""},"3192":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِي عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ حَدَّثَنَا أَبُو صَخْرٍ أَنَّهُ سَمِعَ مَكْحُولًا يَقُولُ حَدَّثَنِي أَبُو هِنْدٍ الدَّارِيُّ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَامَ مَقَامَ رِيَاءٍ وَسُمْعَةٍ رَايَا اللَّهُ تَعَالَى بِهِ يَوْمَ الْقِيَامَةِ وَسَمَّعَ","id":"Telah bercerita kepada kami [Abu 'Abdur Rahman Al Muqri 'Abdullah bin Yazid] telah bercerita kepada kami [Haiwah] telah bercerita kepada kami [Abu Shakhr] bahwa ia mendengar [Makhul] berkata; Telah bercerita kepadaku [Abu Hind Ad Daari] bahwa ia mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Barangsiapa berdiri ditempat riya' dan sum'ah, Allah akan memperlihatkan dan menyiarkan aibnya pada hari kiamat.\""},"3193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا أَبُو بَكْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيُفْتَحُ عَلَيْكُمْ الشَّامُ وَإِنَّ بِهَا مَكَانًا يُقَالُ لَهُ الْغُوطَةُ يَعْنِي دِمَشْقَ مِنْ خَيْرِ مَنَازِلِ الْمُسْلِمِينَ يَعْنِي فِي الْمَلَاحِمِ","id":"Telah bercerita kepada kami [Muhammad bin Mush'ab] telah bercerita kepada kami [Abu Bakr] dari ['Abdur Rahman bin Jubair] dari [ayahnya] dari [seorang sahabat Nabi Shallallahu'alaihiWasallam] dari Nabi Shallallahu'alaihiWasallam bersabda; \"Syam akan ditaklukkan untuk kalian, disana ada sebuah tempat bernama Ghouthoh -yaitu Damaskus- salah satu tempat kaum muslimin terbaik.\" Yaitu dalam peperangan."},"3194":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عَطَاءٍ الْخُرَاسَانِيِّ حَدَّثَنِي ابْنُ مُحَيْرِيزٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّعْدِيِّ رَجُلٍ مِنْ بَنِي مَالِكِ بْنِ حَنْبَلٍأَنَّهُ قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاسٍ مِنْ أَصْحَابِهِ فَقَالُوا لَهُ احْفَظْ رِحَالَنَا ثُمَّ تَدْخُلُ وَكَانَ أَصْغَرَ الْقَوْمِ فَقَضَى لَهُمْ حَاجَتَهُمْ ثُمَّ قَالُوا لَهُ ادْخُلْ فَدَخَلَ فَقَالَ حَاجَتُكَ قَالَ حَاجَتِي تُحَدِّثُنِي أَنْقَضَتْ الْهِجْرَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجَتُكَ خَيْرٌ مِنْ حَوَائِجِهِمْ لَا تَنْقَطِعُ الْهِجْرَةُ مَا قُوتِلَ الْعَدُوُّ","id":"Telah bercerita kepada kami [Ishaq bin 'Isa] telah bercerita kepada kami [Yahya bin Hamzah] dari ['Atho` Al Khurasani] telah bercerita kepadaku [Ibnu Muhairiz] dari ['Abdullah bin As Sa'di] salah seorang Bani Malik bin Hambal, bahwa ia mendatangi Nabi Shallallahu'alaihiWasallam saat bersama beberapa sahabat, mereka berkata padanya; Jagalah perjalanan kita kemudian masuklah. Ia adalah yang paling muda lalu ia memebereskan keperluan mereka, lalu mereka berkata padanya; Masuklah. Ia pun masuk. Setelah masuk nabi Shallallahu 'alaihi wa Salam bertanya; Apa keperluanmu?. Abdullah menjawab; \"Keperluanku, tolong baginda berkomentar kepadaku, apakah hijrah telah berakhir?.' Lalu Rasulullah Shallallahu'alaihiWasallam bersabda; \"Keperluanmu lebih baik dari keperluan mereka, hijrah tidak berakhir selama musuh masih diperangi.\""},"3195":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مَسْعُودٍ عَنْ أَبِي السَّلِيلِ عَنْ عَجُوزٍ مِنْ بَنِي نُمَيْرٍ أَنَّهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي بِالنَّاسِ وَوَجْهُهُ إِلَى الْبَيْتِ قَالَ فَحَفِظَتْ مِنْهُ رَبِّ اغْفِرْ لِي خَطَايَايَ وَجَهْلِي","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Abu Mas'ud] dari [Abu As Salil] dari [seorang wanita tua dari Bani Numair] ia mendengar Nabi Shallallahu'alaihiWasallam saat beliau shalat bersama orang-orang dan wajah beliau menghadap ke baitullah, aku menghafal dari beliau; Ya Allah! Ampunilah kesalahan-kesalahan dan kejahilanku."},"3196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَاعِيلَ بْنِ أَبِي فُدَيْكٍ حَدَّثَنَا الضَّحَّاكُ بْنُ عَبْدِ اللَّهِ عَمَّنْ حَدَّثَهُ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنِ الْمَرْأَةِ مِنَ الْمُبَايِعَاتِ أَنَّهَا قَالَتْجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ أَصْحَابُهُ فِي بَنِي سَلِمَةَ فَقَرَّبْنَا إِلَيْهِ طَعَامًا فَأَكَلَ وَمَعَهُ أَصْحَابُهُ ثُمَّ قَرَّبْنَا إِلَيْهِ وَضُوءًا فَتَوَضَّأَ ثُمَّ أَقْبَلَ عَلَى أَصْحَابِهِ فَقَالَ أَلَا أُخْبِرُكُمْ بِمُكَفِّرَاتِ الْخَطَايَا قَالُوا بَلَى قَالَ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَى إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ","id":"Telah bercerita kepada kami [Muhammad bin Isma'il bin Abu Fudaik] telah bercerita kepada kami [Adh Dhahhak bin 'Abdullah] dari [orang yang bercerita padanya] dari ['Amr bin 'Abdullah bin Ka'ab] dari [seorang wanita] yang pernah berbaiat, ia berkata; Rasulullah Shallallahu'alaihiWasallam mendatangi kami bersama para sahabat beliau dari Bani Salamah, kami menyuguhkan makanan pada beliau, beliau makan bersama para sahabat beliau, kami menyuguhkan air wudhu, beliau berwudhu kemudian menghadap ke para sahabat lalu bersabda; \"Maukah kalian aku beritahu penghapus-penghapus kesalahan?\" mereka menjawab; Ya. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Menyempurnakan wudhu saat-saat tidak menyenangkan, memperbanyak langkah ke masjid dan menunggu shalat setelah shalat.\" "},"3197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِأَنَّهَا شَهِدَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ جَمْرَةِ الْعَقَبَةِ وَالنَّاسُ يَرْمُونَ فَقَالَ يَا أَيُّهَا النَّاسُ لَا تَقْتُلُوا أَوْ لَا تُهْلِكُوا أَنْفُسَكُمْ وَارْمُوا الْجَمْرَةَ أَوْ الْجَمَرَاتِ بِمِثْلِ حَصَى الْخَذْفِوَأَشَارَ شُعْبَةُ بِطَرَفِ إِصْبَعِهِ السَّبَّابَةِ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [ibunya] bahwa ia menyaksikan Nabi Shallallahu'alaihiWasallam saat melempar jumroh 'aqobah dan orang-orang juga tengah melempar, beliau bersabda; \"Wahai sekalian manusia! Janganlah kalian membunuh -atau membinasakan diri kalian- dan lemparlah jumrah -atau jamarat- seperti kerikil pelempar.\" Beliau berisyarat dengan ujung jari telunjuk."},"3198":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ يَعْنِي الْمُقْرِي حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ حَدَّثَنِي أَبُو عِيسَى الْخُرَاسَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ الْقَاسِمِ قَالَ حَدَّثَتْنِي جَارَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَاكَانَتْ تَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عِنْدَ طُلُوعِ الْفَجْرِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْقَبْرِقَالَ أَبُو عِيسَى فَقُلْتُ لِعَبْدِ اللَّهِ أَرَأَيْتَ إِنْ جَمَعَهُمَا إِنْسَانٌ قَالَ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ","id":"Telah bercerita kepada kami [Abu 'Abdur Rahman Al Muqri] telah bercerita kepada kami [Sa'id bin Abu Ayyub] telah bercerita kepadaku [Abu 'Isa Al Khurasani] dari ['Abdullah bin Al Qasim] berkata; Telah bercerita kepadaku [tetangga Nabi ShallallahuAlaihiWasallam], bahwa ia mendengar Rasulullah Shallallahu'alaihiWasallam bersabda saat fajar menyingsing; \"Ya Allah! Sesungguhnya aku berlindung kepadaMu dari adzab kubur dan fitnah kubur.\" Berkata Abu 'Isa; Aku berkata kepada 'Abdullah; Bagaimana menurutmu bila keduanya disatukan oleh seseorang? Ia berkata; Rasulullah Shallallahu'alaihiWasallam mengutarakan sabda yang beliau sampaikan."},"3199":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا خَالِدٌ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنِ السَّعْدِيِّ عَنْ أَبِيهِ أَوْ عَمِّهِ قَالَرَمَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاتِهِ فَكَانَ يَمْكُثُ فِي رُكُوعِهِ وَسُجُودِهِ قَدْرَ مَا يَقُولُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ ثَلَاثًا","id":"Telah bercerita kepada kami [Khalaf bin Al Walid] telah bercerita kepada kami [Khalid] dari [Sa'id Al Jurairi] dari [As Sa'di] dari [ayahnya] atau [pamannya], berkata; Saya melihat Rasulullah Shallallahu'alaihiWasallam saat shalat, beliau diam saat ruku' dan sujud seukuran membaca; Subnaanallaah wa bihamdihi, tiga kali."},"3200":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو جَعْفَرٍ عَنْ يَحْيَى الْبَكَّاءِ عَنْ أَبِي رَافِعٍ قَالَكُنْتُ أَصُوغُ لِأَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثْنَنِي أَنَّهُنَّ لَسَمِعْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الذَّهَبُ بِالذَّهَبِ وَالْفِضَّةُ بِالْفِضَّةِ وَزْنًا بِوَزْنٍ فَمَنْ زَادَ أَوْ اسْتَزَادَ فَقَدْ أَرْبَى","id":"Telah bercerita kepada kami [Abu An Nadhr] telah bercerita kepada kami [Abu Ja'far] dari [Yahya Al Bakka`] dari [Abu Rafi'] berkata; Aku pernah membuat (perhiasan) untuk istri-istri Nabi ShallallahuAalaihiWasallam, [mereka] bercerita kepadaku bahwa mereka mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Emas ditukar dengan emas, perak ditukar dengan perak, timbangan ditukar dengan timbangan, barangsiapa menambah atau meminta ditambah berarti telah melakukan riba.\""},"3201":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ عَمْرٍو حَدَّثَنَا خَالِدُ بْنُ عَمْرٍو عَنِ ابْنِ حَرْمَلَةَ عَنْ خَالَتِهِ قَالَتْخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَاصِبٌ إِصْبَعَهُ مِنْ لَدْغَةِ عَقْرَبٍ فَقَالَ إِنَّكُمْ تَقُولُونَ لَا عَدُوَّ وَإِنَّكُمْ لَا تَزَالُونَ تُقَاتِلُونَ عَدُوًّا حَتَّى يَأْتِيَ يَأْجُوجُ وَمَأْجُوجُ عِرَاضُ الْوُجُوهِ صِغَارُ الْعُيُونِ شُهْبُ الشِّعَافِ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah bercerita kepada kami [Muhammad bin Bisyr] telah bercerita kepada kami [Muhammad bin 'Amr] telah bercerita kepada kami Khalid bin 'Amr dari [Ibnu Harmalah] dari [bibinya] berkata; \"Rasulullah Shallallahu'alaihiWasallam berkhutbah seraya menegakkan jari beliau karena disengat kalajengking, beliau bersabda; \"Sesungguhnya kalian mengatakan tidak ada musuh dan sesungguhnya kalian akan senantiasa memerangi musuh hingga Ya`juj dan Ma`juj muncul, mukanya lebar, matanya sipit, jambul rambutnya berwarna putih, mereka turun dari tempat-tempat tinggi, wajah mereka seperti perisai yang ditempa (tebal dan keras)."},"3202":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا رَافِعُ بْنُ سَلَمَةَ الْأَشْجَعِيُّ حَدَّثَنِي حَشْرَجُ بْنُ زِيَادٍ الْأَشْجَعِيُّ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ أَنَّهَا قَالَتْخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةِ خَيْبَرَ وَأَنَا سَادِسُ سِتِّ نِسْوَةٍ فَبَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَعَهُ نِسَاءً فَأَرْسَلَ إِلَيْنَا فَقَالَ مَا أَخْرَجَكُنَّ وَبِأَمْرِ مَنْ خَرَجْتُنَّ فَقُلْنَا خَرَجْنَا نُنَاوِلُ السِّهَامَ وَنَسْقِي النَّاسَ السَّوِيقَ وَمَعَنَا مَا نُدَاوِي بِهِ الْجَرْحَى وَنَغْزِلُ الشَّعْرَ وَنُعِينُ بِهِ فِي سَبِيلِ اللَّهِ قَالَ قُمْنَ فَانْصَرِفْنَ فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِ خَيْبَرَ أَخْرَجَ لَنَا سِهَامًا كَسِهَامِ الرَّجُلِ قُلْتُ يَا جَدَّةُ مَا أَخْرَجَ لَكُنَّ قَالَتْ تَمْرًا","id":"Telah bercerita kepada kami ['Abdush Shamad bin 'Abdul Warits] telah bercerita kepada kami [Rafi' bin Salamah Al Asyja'i] telah bercerita kepadaku [Hasyraj bin Ziyad Al Asyja'i] dari [neneknya] (ibu ayahnya), bahwa ia berkata; Saya pergi bersama Rasulullah Shallallahu'alaihiWasallam dalam perang Khoibar dan aku adalah keenam dan enam wanita. Terdengarlah oleh Rasulullah Shallallahu'alaihiWasallam bahwa ada wanita-wanita yang turut serta bersama beliau, beliau mendatangi kami lalu bersabda; \"Kenapa kalian pergi dan dengan perintah siapa kalian pergi.\" Kami menjawab; Kami pergi untuk menyediakan anak panah, memberikan adonan tepung untuk para prajurit, kami membawa obat bagi yang luka-luka, kami memintal rambut dan dengan obat-obatan itu kami membantu dijalan Allah. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berdirilah kalian dan pulanglah.\" Saat Allah subhanahu wata'ala menaklukkan Khoibar, beliau memberi kami satu bagian seperti bagian seorang lelaki. Aku bertanya; Nenek! Apa yang diberikan untuk kalian? Ia menjawab; Kurma."},"3203":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبَانُ حَدَّثَنَا أَبُو عِمْرَانَ حَدَّثَنَا زُهَيْرُ بْنُ عَبْدِ اللَّهِ وَكَانَ عَامِلًا عَلَى تَوَّجَ وَأَثْنَى عَلَيْهِ خَيْرًا عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ نَامَ عَلَى إِجَّارٍ لَيْسَ عَلَيْهِ مَا يَدْفَعُ قَدَمَيْهِ فَخَرَّ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ وَمَنْ رَكِبَ الْبَحْرَ إِذَا ارْتَجَّ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ","id":"Telah menceritakan kepada kami ['Abdush Shamad] telah bercerita kepada kami [Aban] telah bercerita kepada kami [Abu 'Imran] telah bercerita kepada kami [Zuhair bin 'Abdullah] -seorang 'alim dan mendapat pujian baik- dari [sebagaian sahabat Nabi] Shallallahu'alaihiwasallam dari Nabi Shallallahu'alaihiwasallam bahwa beliau bersabda; \"Barangsiapa tidur mengenakan sarung tanpa mengenakan kain penutup kaki lalu sarungnya terlepas maka tanggungan telah terbebas darinya dan barangsiapa mengarungi laut saat bergelombang, maka tanggungan telah terbebas darinya.\""},"3204":{"ar":"حَدَّثَنَا سُرَيْجٌ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا الْحُرُّ بْنُ الصَّيَّاحِ قَالَ سُرَيْجٌ عَنِ الْحُرِّ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنِ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ تِسْعَ ذِي الْحِجَّةِ وَيَوْمَ عَاشُورَاءَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍقَالَ عَفَّانُ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ وَخَمِيسَيْنِ","id":"Telah menceritakan kepada kami [Suraij] dan ['Affan] keduanya berkata; Telah bercerita kepada kami [Abu 'Awanah] telah bercerita kepada kami [Al Hurr bin Ash Shoyyah]. berkata Suraij, dari [Al Hurr] dari [Hunaidah bin Khalid] dari [istrinya] dari [salah satu istri Nabi] Shallallahu'alaihiwasallam, berkata; Rasulullah Shallallahu'alaihiwasallam puasa pada tanggal sembilan Dzulhijah, hari 'Asyura` dan tiga hari setiap bulan. Berkata 'Affan; Senin pertama setiap bulan dan dua kamis."},"3205":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي هَمَّامٍ الشَّعْبَانِيِّ قَالَ حَدَّثَنِي رَجُلٌ مِنْ خَثْعَمَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَوَقَفَ ذَاتَ لَيْلَةٍ وَاجْتَمَعَ عَلَيْهِ أَصْحَابُهُ فَقَالَ إِنَّ اللَّهَ أَعْطَانِي اللَّيْلَةَ الْكَنْزَيْنِ كَنْزَ فَارِسَ وَالرُّومِ وَأَمَدَّنِي بِالْمُلُوكِ مُلُوكِ حِمْيَرَ إِلَّا الْأَحْمَرَيْنِ وَلَا مُلْكَ إِلَّا لِلَّهِ يَأْتُونَ يَأْخُذُونَ مِنْ مَالِ اللَّهِ وَيُقَاتِلُونَ فِي سَبِيلِ اللَّهِ قَالَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Hammam Asy Sya'bani] berkata; Telah bercerita kepadaku [seseorang dari Khots'am] berkata; Kami bersama Rasulullah Shallallahu'alaihiwasallam dalam perang Tabuk. Pada suatu malam beliau berdiri dan para sahabat mengerumuni beliau lalu bersabda; \"Pada malam ini Allah memberiku dua harta simpanan; Harta simpanan Persia dan Romawi dan memberiku pertolongan dengan kerajaan-kerajaan; kerajaan Himyar kecuali dua yang merah. Tidak ada kerajaan kecuali milik Allah, mereka datang mengambil harta Allah dan berperang dijalan Allah.\" Rasulullah Shallallahu'alaihiwasallam mengucapkannya sebanyak tiga kali."},"3206":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيَّ خَاتَمٌ مِنْ ذَهَبٍ فَأَخَذَ جَرِيدَةً فَضَرَبَ بِهَا كَفِّي وَقَالَ اطْرَحْهُ قَالَ فَخَرَجْتُ فَطَرَحْتُهُ ثُمَّ عُدْتُ إِلَيْهِ فَقَالَ مَا فَعَلَ الْخَاتَمُ قَالَ قُلْتُ طَرَحْتُهُ قَالَ إِنَّمَا أَمَرْتُكَ أَنْ تَسْتَمْتِعَ بِهِ وَلَا تَطْرَحَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Ashim] telah bercerita kepada kami [Hushain] dari [Salim bin Abu Al Ja'd] dari [seseorang dari kaumnya] berkata; Saya bertamu ke kediaman Nabi Shallallahu'alaihiwasallam dan saya mengenakan cincin emas. Beliau mengambil pelepah lalu dipukulkan ke telapak tanganku dan bersabda; \"Buanglah.\" Aku keluar dan membuangnya, lalu kembali menemui beliau, beliau bertanya; \"Bagaimana cincinnya?\" aku menjawab; Aku membuangnya. Rasulullah Shallallahu'alaihiwasallam bersabda; \"Aku hanya memerintahkanmu untuk menikmatinya, bukan membuangnya.\""},"3207":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ فَدَخَلَ شَابَّانِ مِنْ وَلَدِ عُمَرَ فَصَلَّيَا رَكْعَتَيْنِ بَعْدَ الْعَصْرِ فَأَرْسَلَ إِلَيْهِمَا فَدَعَاهُمَا فَقَالَ مَا هَذِهِ الصَّلَاةُ الَّتِي صَلَّيْتُمَاهَا وَقَدْ كَانَ أَبُوكُمَا يَنْهَى عَنْهَا قَالَا حَدَّثَتْنَا عَائِشَةُ رَضِيَ اللَّهُ تَعَالَى عَنْهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّاهُمَا عِنْدَهَا فَسَكَتَ وَلَمْ يَرُدَّ عَلَيْهِمَا شَيْئًا","id":"Telah menceritakan kepada kami ['Ali bin 'Ashim] dari ['Atho` bin As Sa`ib] berkata; Saya duduk bersama 'Abdullah bin Mughoffal kemudian dua pemuda putra 'Umar masuk kemudian shalat dua rakaat setelah ashar, 'Abdullah mengirim utusan untuk menemui keduanya lalu memanggil keduanya dan berkata; Shalat apa yang kalian lakukan, ayah kalian melarangnya. [Keduanya] berkata; Telah bercerita kepada kami ['Aisyah] bahwa Nabi Shallallahu'alaihiwasallam melakukannya saat berada didekat 'Aisyah lalu 'Abdullah diam dan tidak menanggapi apa pun."},"3208":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْمَلِيحِ عَنْ مُحَمَّدِ بْنِ خَالِدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ وَكَانَ لِجَدِّهِ صُحْبَةٌأَنَّهُ خَرَجَ زَائِرًا لِرَجُلٍ مِنْ إِخْوَانِهِ فَبَلَغَهُ شَكَاتُهُ قَالَ فَدَخَلَ عَلَيْهِ فَقَالَ أَتَيْتُكَ زَائِرًا عَائِدًا وَمُبَشِّرًا قَالَ كَيْفَ جَمَعْتَ هَذَا كُلَّهُ قَالَ خَرَجْتُ وَأَنَا أُرِيدُ زِيَارَتَكَ فَبَلَغَتْنِي شَكَاتُكَ فَكَانَتْ عِيَادَةً وَأُبَشِّرُكَ بِشَيْءٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَبَقَتْ لِلْعَبْدِ مِنْ اللَّهِ مَنْزِلَةٌ لَمْ يَبْلُغْهَا بِعَمَلِهِ ابْتَلَاهُ اللَّهُ فِي جَسَدِهِ أَوْ فِي مَالِهِ أَوْ فِي وَلَدِهِ ثُمَّ صَبَّرَهُ حَتَّى يُبْلِغَهُ الْمَنْزِلَةَ الَّتِي سَبَقَتْ لَهُ مِنْهُ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah bercerita kepada kami [Abu Al Malih] dari [Muhammad bin Khalid] dari [ayahnya] dari [kakeknya] dan ia adalah seorang sahabat, ia pergi mengunjungi salah seorang saudaranya, keluhannya terdengar olehnya. Berkata Muhammad bin Khalid; ia masuk lalu berkata; Aku mengunjungimu untuk menjengukmu dan memberi berita gembira. saudaranya bertanya; Bagaimana kau menyatukan semua itu? Ia menjawab; Aku pergi untuk mengunjungimu, aku mendengar keluhanmu, kunjunganku ini adalah untuk menjenguk dan menyampaikan khabar gembira tentang sesuatu yang pernah aku dengar dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda; \"Bila seorang hamba memperoleh kedudukan tinggi disisi Allah dan ia tidak bisa meraihnya dengan amalannya, Allah mengujinya pada diri, harta, atau anaknya kemudian ia bersabar hingga mengantarkannya kepada kedudukan yang diraihnya.\""},"3209":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُبْدِعَ بِي فَاحْمِلْنِي قَالَ فَقَالَ لَيْسَ عِنْدِي قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَفَلَا أَدُلُّهُ عَلَى مَنْ يَحْمِلُهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah bercerita kepada kami [Al A'masy] dari [Abu 'Amr Asy Syaibani] dari [Abu Mas'ud Al Anshari] berkata; Seseorang mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; Wahai Rasulullah! Aku letih, tolong boponglah aku. Rasulullah Shallallahu'alaihiwasallam bersabda; \"Aku tidak bisa.\" Kemudian seseorang berkata kepada beliau; Bolehkan aku menunjukkannya pada seseorang yang akan membopongnya? Rasulullah Shallallahu'alaihiwasallam bersabda; \"Barangsiapa yang menunjukkan kebaikan maka ia mendapatkan pahala seperti orang yang melakukannya.\""},"3210":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا الدَّسْتُوَائِيُّ وَيَزِيدُ أَخْبَرَنَا الدَّسْتُوَائِيُّ حَدَّثَنَا حَمَّادٌ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عَبْدِ اللَّهِ الْجَدَلِيِّ عَنْ عُقْبَةَ بْنِ عَمْرٍو أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُوتِرُ مِنْ أَوَّلِ اللَّيْلِ وَأَوْسَطِهِ وَآخِرِهِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] ia berkata, telah mengabarkan kepada kami [Ad Dastuwa`i]. Dan [Yazid] berkata, telah mengabarkan kepada kami [Ad Dastuwa`i] telah bercerita kepada kami [Hammad] dari [Ibrahim] dari [Abu 'Abdullah Al Jadali] dari ['Uqbah bin 'Amr Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam, bahwa beliau shalat witir di permulaan malam, pertengahan dan diakhir malam."},"3211":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ حَكِيمِ بْنِ أَفْلَحَ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْمُسْلِمِ عَلَى الْمُسْلِمِ أَرْبَعُ خِلَالٍ أَنْ يُجِيبَهُ إِذَا دَعَاهُ وَيُشَمِّتَهُ إِذَا عَطَسَ وَإِذَا مَرِضَ أَنْ يَعُودَهُ وَإِذَا مَاتَ أَنْ يَشْهَدَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Abdul Hamid bin Ja'far] telah bercerita kepadaku [ayahku] dari [Hakim bin Aflah] dari [Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda; \"Seorang muslim memilik empat hak atas muslim lain; hadir bila diundang, mendoakan bila bersin, menjenguk bila sakit dan mengantarkan jenazah bila meninggal.\""},"3212":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي قَيْسُ بْنُ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ عُقْبَةَ بْنِ عَمْرٍو قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَتَأَخَّرُ عَنْ صَلَاةِ الْغَدَاةِ مِنْ أَجْلِ فُلَانٍ مِمَّا يُطِيلُ بِنَا فَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ غَضَبًا فِي مَوْعِظَةٍ مِنْهُ يَوْمَئِذٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ لَمُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيَتَجَوَّزْ فَإِنَّ فِيهِمْ الضَّعِيفَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah bercerita kepada kami [Isma'il] telah bercerita kepadaku [Qais bin Abu Hazim] dari [Abu Mas'ud 'Uqbah bin 'Amr] berkata; Seseorang mendatangi Nabi Shallallahu'alaihiwasallam lalu berkata; Aku sengaja melambatkan diri pada shalat shubuh karena si fulan yang memperlama shalatnya bersama kami. Aku tidak pernah melihat Rasulullah Shallallahu'alaihiwasallam begitu marah seperti saat itu, beliau bersabda; \"Wahai sekalian manusia! Sesungguhnya diantara kalian ada yang menyusahkan. Siapa saja diantara kalian yang mengimami shalat hendaklah mempercepat karena diantara mereka ada yang lemah, tua dan punya keperluan.\""},"3213":{"ar":"حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا مَنْصُورٌ عَنْ رِبْعِيٍّ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى إِذَا لَمْ تَسْتَحِ فَاصْنَعْ مَا شِئْتَ","id":"Telah menceritakan kepada kami [Yahya] dari [Sufyan] telah bercerita kepada kami [Manshur] dari [Rib'iy] dari [Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam bersabda; \"Diantara kata-kata nubuwwah pertama yang ditemukan orang adalah bila kau tidak malu maka lakukan sesukamu.\""},"3214":{"ar":"زِيَادَات الْقُطَيْعِيِّ قَالَ ابْنُ مَالِكٍ حَدَّثَنَا الْفَضْلُ بْنُ الْحُبَابِ حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَنْصُورٌ عَنْ رِبْعِيٍّ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى إِذَا لَمْ تَسْتَحِ فَاصْنَعْ مَا شِئْتَ","id":"-Tambahan-tambahan dari Al Qutho'i- Ibnu Malik berkata; Telah bercerita kepada kami [Al Fadhl bin Al Hubab] telah bercerita kepada kami [Al Qo'nabi] telah bercerita kepada kami [Syu'bah] telah bercerita kepada kami [Manshur] dari [Rib'iy] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Diantara kata-kata nubuwah pertama yang ditemukan orang adalah; bila kau tidak malu maka lakukanlah sesukamu\"."},"3215":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَقَةُ الرَّجُلِ عَلَى أَهْلِهِ يَحْتَسِبُهَا صَدَقَةٌ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari ['Abdullah bin Yazid] dari [Abu Mas'ud Al Anshari] berkata; Nabi Shallallahu'alaihiwasallam bersabda; \"Nafkah seseorang untuk keluarganya jika disertai harapan memperoleh ganjaran, maka terhitung sebagai sedekah.\""},"3216":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ عِيَاضِ بْنِ عِيَاضٍ عَنْ أَبِيهِ عَنْ أَبِي مَسْعُودٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةً فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ فِيكُمْ مُنَافِقِينَ فَمَنْ سَمَّيْتُ فَلْيَقُمْ ثُمَّ قَالَ قُمْ يَا فُلَانُ قُمْ يَا فُلَانُ قُمْ يَا فُلَانُ حَتَّى سَمَّى سِتَّةً وَثَلَاثِينَ رَجُلًا ثُمَّ قَالَ إِنَّ فِيكُمْ أَوْ مِنْكُمْ فَاتَّقُوا اللَّهَ قَالَ فَمَرَّ عُمَرُ عَلَى رَجُلٍ مِمَّنْ سَمَّى مُقَنَّعٍ قَدْ كَانَ يَعْرِفُهُ قَالَ مَا لَكَ قَالَ فَحَدَّثَهُ بِمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بُعْدًا لَكَ سَائِرَ الْيَوْمِحَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ رَجُلٍ عَنْ أَبِيهِ قَالَ سُفْيَانُ أُرَاهُ عِيَاضَ بْنَ عِيَاضٍ عَنْ أَبِيهِ عَنْ أَبِي مَسْعُودٍ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Sufyan] dari [Salamah] dari ['Iyadh bin 'Iyadh] dari [ayahnya] dari [Abu Mas'ud] berkata; Rasulullah Shallallahu'alaihiwasallam berkhutbah pada kami, beliau memuja dan memuji Allah subhanahu wata'ala kemudian bersabda; \"Diantara kalian ada orang-orang munafik. Siapa pun yang namanya aku sebut hendaklah berdiri.\" Selanjutnya Rasulullah Shallallahu'alaihiwasallam bersabda; \"Berdirilah hai fulan, berdirilah hai fulan, berdirilah hai fulan, \" hingga beliau menyebut tigapuluh enam nama. Setelah itu beliau bersabda; \"Sesungguhnya diantara kalian -atau sebagaian dari kalian- bertakwalah kepada Allah.\" Lalu 'Umar melintasi seseorang yang namanya disebut Rasulullah Shallallahu'alaihiwasallam yang mengenakan penutup kepala yang ia kenal. Ia berkata; Ada apa denganmu? Ia mengatakan yang disampaikan Rasulullah Shallallahu'alaihiwasallam lalu 'Umar berkata; 'Celakalah kamu seharian ini.' Telah bercerita kepada kami [Abu Nu'aim] telah bercerita kepada kami [Sufyan] dari [Salamah] dari seseorang dari ayahnya. Sufyan berkata, ia memperlihatkannya pada ['Iyadh bin 'Iyadh] dari [ayahnya] dari [Abu Mas'ud] berkata; Rasulullah Shallallahu'alaihiwasallam berkhutbah. Lalu ia menyebutkan maknanya."},"3217":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ أَنَّهُ قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ مَا عِنْدِي مَا أُعْطِيكَ وَلَكِنْ ائْتِ فُلَانًا فَأَتَى الرَّجُلَ فَأَعْطَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ أَوْ عَامِلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Sulaiman] dari [Abu 'Amr Asy Syaibani] dari [Abu Mas'ud] bahwa ia berkata; Seseorang mendatangi Nabi Shallallahu'alaihiwasallam lalu meminta beliau, beliau bersabda; \"Aku tidak punya sesuatu yang bisa aku berikan padamu, tolong datangilah si fulan saja.\" Orang itu mendatangi si fulan lalu diberi, kemudian Rasulullah Shallallahu'alaihiwasallam bersabda; \"Barangsiapa menunjukkan pada kebaikan maka ia mendapatkan seperti pahala pelakunya atau orang yang mengerjakannya.\""},"3218":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ وَحَدَّثَنَا إِسْحَاقُ أَخْبَرَنِي مَالِكٌ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَنْصَارِيَّ فِي حَدِيثِ عَبْدِ الرَّحْمَنِ وَعَبْدُ اللَّهِ بْنُ زَيْدٍ هُوَ الَّذِي كَانَ أُرِيَ النِّدَاءَ بِالصَّلَاةِ أَخْبَرَهُ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ أَنَّهُ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسِ سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ بَشِيرُ بْنُ سَعْدٍ أَمَرَنَا اللَّهُ أَنْ نُصَلِّيَ عَلَيْكَ يَا رَسُولَ اللَّهِ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمَنَّيْنَا أَنَّهُ لَمْ يَسْأَلْهُ ثُمَّ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَالسَّلَامُ كَمَا قَدْ عَلِمْتُمْ","id":"Berkata (Muhammad bin Ja'far); Saya membaca dihadapan ['Abdur Rahman]; [Malik] dan telah bercerita kepada kami [Ishaq] telah bercerita kepadaku [Malik] dari [Nu'aim bin 'Abdullah Al Mujmir] bahwa [Muhammad bin 'Abdullah bin Zaid Al Anshari] dalam hadits 'Abdur Rahman dan 'Abdullah bin Zaid, yang pernah bermimpi diberitahu cara dan kalimat-kalimat adzan memberitahunya dari [Abu Mas'ud Al Anshari] bahwa ia berkata; Rasulullah Shallallahu'alaihiwasallam mendatangi kami di majlis Sa'ad bin 'Ubadah lalu Basyir bin Sa'ad berkata pada beliau; Allah memerintahkan kami untuk bershalawat untuk baginda wahai Rasulullah! Lalu bagaimana caranya kami bershalawat untuk baginda? Rasulullah Shallallahu'alaihiwasallam diam hingga kami berharap andai saja ia (Basyir) tidak bertanya. Setelah itu Rasulullah Shallallahu'alaihiwasallam bersabda; \"Ucapkan; Ya Allah! Limpahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad seperti Engkau melimpahkan kesejahteraan kepada Ibrahim, berkahilah Muhammad seperti Engkau memberkahi Ibrahim dan keluarga Ibrahim, diseluruh alam sesungguhnya Engkau Maha Terpuji dan Agung\" wassalam, seperti yang telah kalian ketahui.\""},"3219":{"ar":"حَدَّثَنَا حَسَنٌ وَحَجَّاجٌ قَالَا حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو قَبِيلٍ قَالَ سَمِعْتُ أَبَا عَبْدِ الرَّحْمَنِ الْمُقْرِئَ يَقُولُ قَالَ حَجَّاجٌ عَنْ أَبِي قَبِيلٍ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْجُبْلَانِيُّ أَنَّهُ سَمِعَ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أُحِبُّ أَنَّ لِي الدُّنْيَا وَمَا فِيهَا بِهَذِهِ الْآيَةِ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ إِنَّ اللَّهَ يَغْفِرُ الذُّنُوبَ جَمِيعًا إِنَّهُ هُوَ الْغَفُورُ الرَّحِيمُ }فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ فَمَنْ أَشْرَكَ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِلَّا مَنْ أَشْرَكَ ثَلَاثَ مَرَّاتِ","id":"Telah menceritakan kepada kami [Hasan] dan [Hajjaj] keduanya berkata; Telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepada kami [Abu Qobil], ia berkata; Saya mendengar [Abu 'Abdur Rahman Al Muqri`]. Berkata Hajjaj dari [Abu Qobil] telah bercerita kepadaku [Abu 'Abdur Rahman Al Jublani] bahwa ia mendengar [Tsauban], pelayan Rasulullah Shallallahu'alaihiwasallam berkata; Saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda; \"Ayat ini lebih aku sukai dari pada dunia seisinya; 'Hai hamba-hambaKu yang berlebih-lebihan atas dirinya, janganlah kamu berputus asa dari rahmat Allah, sesungguhnya Allah mengampuni seluruh dosa-dosa, sesungguhnya Ia Maha Pengampun lagi Penyayang'.\" Kemudian seseorang bertanya; Wahai Rasulullah! Lalu orang yang menyekutukan Allah? Nabi Shallallahu'alaihiwasallam diam lalu bersabda; \"Kecuali orang yang menyekutukan.\" Beliau mengucapkannya sebanyak tiga kali."},"3220":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى وَأَبُو الْيَمَانِ وَهَذَا حَدِيثُ إِسْحَاقَ قَالَا حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ رَاشِدِ بْنِ دَاوُدَ الْأُمْلُوكِيِّ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ إِنَّا مُدْلِجُونَ فَلَا يُدْلِجَنَّ مُصْعِبٌ وَلَا مُضْعِفٌ فَأَدْلَجَ رَجُلٌ عَلَى نَاقَةٍ لَهُ صَعْبَةٍ فَسَقَطَ فَانْدَقَّتْ فَخِذُهُ فَمَاتَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ عَلَيْهِ ثُمَّ أَمَرَ مُنَادِيًا يُنَادِي فِي النَّاسِ إِنَّ الْجَنَّةَ لَا تَحِلُّ لِعَاصٍ إِنَّ الْجَنَّةَ لَا تَحِلُّ لِعَاصٍ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] dan [Abu Al Yaman] dan ini adalah hadits Ishaq, keduanya berkata; Telah bercerita kepada kami [Isma'il bin 'Ayyasy] dari [Rasyid bin Dawud Al Amluki] dari [Abu Asma` Ar Rohabi] dari [Tsauban], pelayan Rasulullah Shallallahu'alaihiwasallam berkata; Rasulullah Shallallahu'alaihiwasallam bersabda dalam sebuah perjalanan beliau; \"Kami berjalan semalaman, maka janganlah tunggangan yang bermasalah dan lemah berjalan semalaman.\" Lalu seseorang berjalan semalaman dengan mengendarai unta yang bermasalah, ia terjatuh dan lututnya terbentur lalu mati. Kemudian Rasulullah Shallallahu'alaihiwasallam memerintahkan agar dishalati lalu memerintahkan seseorang menyerukan; Surga tidak halal bagi orang yang durhaka, surga tidak halal bagi orang yang durhaka. Sebanyak tiga kali."},"3221":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ أَبِي عَمَّارٍ شَدَّادٍ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنْصَرِفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah menceritakan kepada kami [Abu Al Mughiroh] telah bercerita kepada kami [Al Awza'i] dari [Abu 'Ammar Syaddad] dari [Abu Asma` Ar Rohabi] dari [Tsauban], pelayan Rasulullah Shallallahu'alaihiwasallam; Bila hendak beranjak dari shalat, Rasulullah Shallallahu'alaihiwasallam beristighfar tiga kali lalu bersabda; Ya Allah! Engkau Maha Selamat, dariMu-lah keselamatan, Maha Berbarokah Engkau wahai Pemilik Keagungan dan Kemuliaan.\""},"3222":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ المُهَاجِرِ عَنِ الْعَبَّاسِ بْنِ سَالِمٍ اللَّخْمِيِّ قَالَبَعَثَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِلَى أَبِي سَلَّامٍ الْحَبَشِيِّ فَحُمِلَ إِلَيْهِ عَلَى الْبَرِيدِ يَسْأَلُهُ عَنْ الْحَوْضِ فَقُدِمَ بِهِ عَلَيْهِ فَسَأَلَهُ فَقَالَ سَمِعْتُ ثَوْبَانَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ حَوْضِي مِنْ عَدَنَ إِلَى عَمَّانَ الْبَلْقَاءِ مَاؤُهُ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِ وَأَكَاوِيبُهُ عَدَدُ النُّجُومِ مَنْ شَرِبَ مِنْهُ شَرْبَةً لَمْ يَظْمَأْ بَعْدَهَا أَبَدًا أَوَّلُ النَّاسِ وُرُودًا عَلَيْهِ فُقَرَاءُ الْمُهَاجِرِينَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ مَنْ هُمْ يَا رَسُولَ اللَّهِ قَالَ هُمْ الشُّعْثُ رُءُوسًا الدُّنْسُ ثِيَابًا الَّذِينَ لَا يَنْكِحُونَ الْمُتَنَعِّمَاتِ وَلَا تُفْتَحُ لَهُمْ أَبْوَابُ السُّدَدِ فَقَالَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ لَقَدْ نَكَحْتُ الْمُتَنَعِّمَاتِ وَفُتِحَتْ لِي السُّدَدُ إِلَّا أَنْ يَرْحَمَنِي اللَّهُ وَاللَّهِ لَا جَرَمَ أَنْ لَا أَدْهُنَ رَأْسِي حَتَّى يَشْعَثَ وَلَا أَغْسِلَ ثَوْبِي الَّذِي يَلِي جَسَدِي حَتَّى يَتَّسِخَ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah bercerita kepada kami [Ibnu 'Ayyasy] dari [Muhammad bin Al Muhajir] dari [Al 'Abbas bin Salim Al Lakhmi] berkata; 'Umar bin 'Abdul 'Aziz mengirim utusan membawa surat ke Abu Sallam Al Habasy lalu dibawa petugas pos untuk menanyakan tentang telaga. Surat diberikan lalu ia menanyakannya. Berkata [Abu Sallam]; Aku mendengar [Tsauban] berkata; Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda; \"Sesungguhnya telagaku (seluas antara) Adn hingga Omman Al Baqla`, airnya lebih putih dari susu, lebih manis dari madu dan gelas-gelasnya sejumlah bintang, barangsiapa meminum satu tegukan tidak akan dahaga setelahnya selamanya. Orang-orang pertama yang mendatanginya adalah orang-orang fakir Muhajirin.\" Lalu 'Umar bin Al Khoththob Radliyallahu'anhu bertanya; Siapa mereka wahai Rasulullah Shallallahu'alaihiwasallam! Rasulullah Shallallahu'alaihiwasallam bersabda; \"Mereka adalah rakyat jelata yang berbaju lusuh yang tidak menikahi wanita-wanita berharta, dan pintu-pintu rumah tertutup untuk mereka, tidak dibukakan bagi mereka.\" Lalu 'Umar bin 'Abdul 'Aziz berkata; Aku menikahi wanita-wanita berharta dan pintu-pintu tertutup dibuka untukku, kecuali bila Allah merahmatiku. Demi Allah tidak masalah bila aku tidak meminyaki rambutku hingga acak-acakan dan aku tidak mencuci baju yang melilit tubuhku hingga lusuh. "},"3223":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ مِنْ كِتَابِهِ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا شَيْخٌ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَتَلَ صَغِيرًا أَوْ كَبِيرًا أَوْ أَحْرَقَ نَخْلًا أَوْ قَطَعَ شَجَرَةً مُثْمِرَةً أَوْ ذَبَحَ شَاةً لِإِهَابِهَا لَمْ يَرْجِعْ كَفَافًا","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dari bukunya; Telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepada kami [seorang guru] dari [Tsauban], pelayan Rasulullah Shallallahu'alaihiwasallam bahwa ia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda; \"Barangsiapa membunuh anak kecil, orang tua, membakar pohon kurma, menebang pohon berbuah atau menyembelih kambing untuk menakut-nakutinya maka ia tidak kembali dengan sekedarnya.\""},"3224":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ وَأَبَانُ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ سَالِمٍ عَنْ مَعْدَانَ عَنْ ثَوْبَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ فَارَقَ الرُّوحُ الْجَسَدَ وَهُوَ بَرِيءٌ مِنْ ثَلَاثٍ دَخَلَ الْجَنَّةَ الْكِبْرِ وَالدَّيْنِ وَالْغُلُولِ","id":"Telah menceritakan kepada kami ['Affan] telah bercerita kepada kami [Hammam] dan [Aban] keduanya berkata; Telah bercerita kepada kami [Qotadah] dari [Salim] dari [Ma'dan] dari [Tsauban] dari Nabi Shallallahu'alaihiwasallam bersabda; \"Barangsiapa yang nyawanya meninggalkan raganya dan ia terbebas dari tiga (hal) maka ia masuk surga; kesombongan, hutang dan pengkhianatan.\""},"3225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Qotadah] dari [Syahr bin Hausyab] dari ['Abdur Rahman bin Ghonm] dari [Tsauban], pelayan Rasulullah Shallallahu'alaihiwasallam bahwa Rasulullah Shallallahu'alaihiwasallam bersabda; \"Orang yang berbekam dan yang dibekam, berarti telah batal puasanya.\""},"3226":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَ��ِي الْجُودِيِّ عَنْ بَلْجٍ عَنْ أَبِي شَيْبَةَ الْمَهْرِيِّ قَالَ وَكَانَ قَاصَّ النَّاسِ بِقُسْطَنْطِينِيَّةَ قَالَقِيلَ لِثَوْبَانَ حَدِّثْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Abu Al Judi] dari [Balj] dari [Abu Syaibah Al Mahri] -ahli ceramah di Kostantinopel- berkata; Dikatakan kepada [Tsauban]; Ceritakan kepada kami dari Rasulullah Shallallahu'alaihiwasallam. Ia berkata; Aku melihat Rasulullah Shallallahu'alaihiwasallam muntah lalu beliau berbuka."},"3227":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ قَالَقُلْتُ لِأَبِي الْعَالِيَةِ مَا ثَوْبَانُ قَالَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَكَفَّلَ لِي أَنْ لَا يَسْأَلَ شَيْئًا وَأَتَكَفَّلُ لَهُ بِالْجَنَّةِ فَقَالَ ثَوْبَانُ أَنَافَكَانَ لَا يَسْأَلُ أَحَدًا شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari ['Ashim] ia berkata; Saya bertanya kepada [Abu Al 'Aliyah]; Tsauban siapa? Ia menjawab; Pelayan Rasulullah Shallallahu'alaihiwasallam. Berkata [Tsauban]; Rasulullah Shallallahu'alaihiwasallam bersabda; \"Barangsiapa menjamin untukku untuk tidak meminta-minta apa pun, aku akan menjaminnya surga.\" Tsauban berkata; Saya. Lalu ia tidak meminta-minta apa pun pada siapa pun."},"3228":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا عَادَ الرَّجُلُ أَخَاهُ فَإِنَّهُ فِي أَخْرَافِ الْجَنَّةِ حَتَّى يَرْجِعَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Abu Asma` Ar Rohabi] dari [Tsauban] dari Rasulullah Shallallahu'alaihiwasallam bahwa beliau bersabda; \"Bila seseorang menjenguk saudaranya, ia berada dalam dinding surga hingga ia kembali.\""},"3229":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عِيسَى بْنِ فَائِدٍ عَنْ رَجُلٍ عَنْ سَعْدِ بْنِ عُبَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا مِنْ أَمِيرِ عَشَرَةٍ إِلَّا أَتَى اللَّهَ عَزَّ وَجَلَّ مَغْلُولًا يَوْمَ الْقِيَامَةِ لَا يُطْلِقُهُ إِلَّا الْعَدْلُ وَمَا مِنْ أَحَدٍ يَتَعَلَّمُ الْقُرْآنَ ثُمَّ نَسِيَهُ إِلَّا لَقِيَ اللَّهَ عَزَّ وَجَلَّ أَجْذَمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Abu Ziyad] dari ['Isa bin Fa`id] dari [seseorang] dari [Sa'ad bin 'Ubadah] dari Nabi Shallallahu'alaihiWasallam bahwa beliau bersabda; \"Tidaklah seorang yang memimpin sepuluh orang melainkan akan mendatangi Allah Azzawajalla dalam keadaan terbelenggu pada hari kiamat, tidak ada yang melepaskannya kecuali keadilan dan tidaklah seseorang mempelajari Al Quran kemudian melupakannnya melainkan akan bertemu Allah dalam keadaan buntung tangannya.\""},"3230":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ بْنِ سَعِيدِ بْنِ سَعْدِ بْنِ عُبَادَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَخْبِرْنَا عَنْ يَوْمِ الْجُمُعَةِ مَاذَا فِيهِ مِنْ الْخَيْرِ قَالَ فِيهِ خَمْسُ خِلَالٍ فِيهِ خُلِقَ آدَمُ وَفِيهِ هَبَطَ آدَمُ وَفِيهِ تُوُفِّيَ آدَمُ وَفِيهِ سَاعَةٌ لَا يَسْأَلُ اللَّهَ عَبْدٌ فِيهَا شَيْئًا إِلَّا آتَاهُ اللَّهُ إِيَّاهُ مَا لَمْ يَسْأَلْ مَأْثَمًا أَوْ قَطِيعَةَ رَحِمٍ وَفِيهِ تَقُومُ السَّاعَةُ مَا مِنْ مَلَكٍ مُقَرَّبٍ وَلَا سَمَاءٍ وَلَا أَرْضٍ وَلَا جِبَالٍ وَلَا حَجَرٍ إِلَّا وَهُوَ يُشْفِقُ مِنْ يَوْمِ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Zuhair] dari ['Abdullah bin Muhammad] dari ['Amr bin Syurahbil bin Sa'id bin Sa'ad bin 'Ubadah] dari [ayahnya] dari [kakeknya] dari [Sa'id bin 'Ubadah] bahwa seseorang dari Anshor mendatangi Nabi Shallallahu'alaihiWasallam lalu berkata; Beritahukan kepada kami tentang hari jum'at, kebaikan apa yang ada padanya? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Didalamnya ada lima kejadian; di hari itu Adam diciptakan, Adam turun ke bumi, Adam wafat, dan di hari itu terjadi kiamat. Tidaklah seorang hamba meminta sesuatu kepada Allah pada hari itu melainkan pasti diberi, selama tidak meminta perbuatan dosa atau memutus silaturrahim dan dihari itu terjadi kiamat. Tidaklah malaikat yang dekat, tidaklah langit, bumi, gunung dan batu melainkan bersimpati kepada hari Jum'at.\""},"3231":{"ar":"حَدَّثَنَا هَاشِمٌ أَخْبَرَنَا الْمُبَارَكُ عَنِ الْحَسَنِ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى صَدَقَةٍ قَالَ اسْقِ الْمَاءَ","id":"Telah menceritakan kepada kami [Hasyim] telah mengkhabarkan kepada kami [Al Mubarak] dari [Al Hasan] dari [Sa'ad bin 'Ubadah] berkata; Rasulullah Shallallahu'alaihiWasallam melintasiku lalu aku berkata; Wahai Rasulullah! Tunjukkan aku pada suatu sedekah? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berilah air minum.\""},"3232":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ سَمِعْتُ شُعْبَةَ يُحَدِّثُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ الْحَسَنَ يُحَدِّثُ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّ أُمَّهُ مَاتَتْ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي مَاتَتْ فَأَتَصَدَّقُ عَنْهَا قَالَ نَعَمْ قَالَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِقَالَ فَتِلْكَ سِقَايَةُ آلِ سَعْدٍ بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Hajjaj], ia berkata; Saya mendengar [Syu'bah] menceritakan dari [Qatadah], ia berkata; Saya mendengar [Al Hasan] menceritakan dari [Sa'ad bin 'Ubadah]; bahwasanya ibunya meninggal dunia, ia berkata; Wahai Rasulullah! ibuku meninggal dunia, bolehkah aku bersedekah untuknya? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ya.\" Ia bertanya; Sedekah apa yang paling utama? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Memberi air minum.\" Berkata Al Hasan; Itulah air minum keluarga Sa'ad di Madinah."},"3233":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ إِسْمَاعِيلَ بْنِ عَمْرِو بْنِ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَ عَنْ أَبِيهِأَنَّهُمْ وَجَدُوا فِي كُتُبِ أَوْ فِي كِتَابِ سَعْدِ بْنِ عُبَادَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ مَعَ الشَّاهِدِ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abu 'Abdur Rahman] dari [Isma'il bin 'Amr bin Qais bin Sa'ad bin 'Ubadah] dari [ayahnya], bahwa mereka menemukan dibuku Sa'ad bin 'Ubadah bahwa Rasulullah Shallallahu'alaihiWasallam memutuskan berdasarkan sumpah dan seorang saksi."},"3234":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ عُبَادَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ قُمْ عَلَى صَدَقَةِ بَنِي فُلَانٍ وَانْظُرْ لَا تَأْتِي يَوْمَ الْقِيَامَةِ بِبَكْرٍ تَحْمِلُهُ عَلَى عَاتِقِكَ أَوْ عَلَى كَاهِلِكَ لَهُ رُغَاءٌ يَوْمَ الْقِيَامَةِ قَالَ يَا رَسُولَ اللَّهِ اصْرِفْهَا عَنِّي فَصَرَفَهَا عَنْهُ","id":"Telah menceritakan kepada kami [Abu Sa'id, budak Bani Hasyim], telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid bin Hilal] dari [Sa'id bin Al Musayyib] dari [Sa'ad bin 'Ubadah] dari Rasulullah Shallallahu'alaihiWasallam bersabda kepadanya; \"Pungutlah zakat dari Bani Fulan dan telitilah dengan benar, agar supaya pada hari Kiamat kelak, kamu tidak datang pada hari kiamat dengan memanggul anak unta yang mengeluh-eluh diatas pundakmu atau diatas punggungmu.\" Sa'ad berkata; Wahai Rasulullah! Palingkanlah hal itu dariku. Lalu Beliau memalingkan darinya.\""},"3235":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي شُمَيْلَةَ عَنْ رَجُلٍ رَدَّهُ إِلَى سَعِيدٍ الصَّرَّافِ عَنْ إِسْحَاقَ بْنِ سَعْدِ بْنِ عُبَادَةَ عَنْ أَبِيهِ سَعْدِ بْنِ عُبَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الْحَيَّ مِنْ الْأَنْصَارِ مِحْنَةٌ حُبُّهُمْ إِيمَانٌ وَبُغْضُهُمْ نِفَاقٌ","id":"Telah menceritakan kepada kami [Yunus], telah menceritakan kepada kami [Hammad bin Zaid], telah menceritakan kepada kami ['Abdur Rahman bin Abu Syumailah] dari [seseorang] yang menyandarkannya kepada [Sa'id Ash Shorrof] dari [Ishaq bin Sa'ad bin 'Ubadah] dari [ayahnya -Sa'ad bin 'Ubadah-], ia berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Perkampungan Anshar ini adalah ujian, mencintai mereka adalah keimanan dan membenci mereka adalah tanda kemunafikan.\""},"3236":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا خَالِدٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عِيسَى بْنِ فَائدٍ عَنْ رَجُلٍ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَ سَمِعْتُ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَمِيرِ عَشَرَةٍ إِلَّا يُؤْتَى بِهِ يَوْمَ الْقِيَامَةِ مَغْلُولٌ لَا يَفُكُّهُ مِنْ ذَلِكَ الْغُلِّ إِلَّا الْعَدْلُ وَمَا مِنْ رَجُلٍ قَرَأَ الْقُرْآنَ فَنَسِيَهُ إِلَّا لَقِيَ اللَّهَ يَوْمَ يَلْقَاهُ وَهُوَ أَجْذَمُ","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] telah menceritakan kepada kami [Khalid] dari [Yazid bin Abu Ziyad] dari ['Isa bin Fa`id] dari [seseorang] dari [Sa'ad bin 'Ubadah] berkata; Aku mendengar seseorang berkata bukan hanya sekali dua kali; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Tidaklah seorang yang memimpin sepuluh orang melainkan akan mendatangi Allah Azzawajalla dalam keadaan terbelenggu pada hari kiamat, tidak ada yang melepaskannya dari belenggu itu kecuali keadilan dan tidaklah seseorang mempelajari Al Quran kemudian melupakannnya melainkan bertemu Allah dalam keadaan putus tangannya.\""},"3237":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ سَلَمَةَ بْنِ نُعَيْمٍ وَكَانَ مِنْ أَصْحَابِ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَقِيَ اللَّهَ لَا يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ وَإِنْ زَنَى وَإِنْ سَرَقَ","id":"Telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Abu Mu'awiyah Sayiban] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Salamah bin Nu'aim] -salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam-, berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Barangsiapa bertemu Allah tanpa menyekutukanNya dengan sesuatu pun, ia masuk surga meski berzina dan meski mencuri.\""},"3238":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ قَالَجَاءَ رِعْيَةُ السُّحَيْمِيُّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُغِيرَ عَلَى وَلَدِي وَمَالِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا الْمَالُ فَقَدْ اقْتُسِمَ وَأَمَّا الْوَلَدُ فَاذْهَبْ مَعَهُ يَا بِلَالُ فَإِنْ عَرَفَ وَلَدَهُ فَادْفَعْهُ إِلَيْهِ قَالَ فَذَهَبَ مَعَهُ فَأَرَاهُ إِيَّاهُ فَقَالَ تَعْرِفُهُ قَالَ نَعَمْ فَدَفَعَهُ فَذَهَبَ إِلَيْهِقَالَ سُفْيَانُ يَرَوْنَ أَنَّهُ أَسْلَمَ قَبْلَ أَنْ يُغَارَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] telah menceritakan kepada kami [Abu Ishaq] dari [Sufyan] dari [Abu Ishaq] dari [Abu 'Amr Asy Syaibani] berkata; [Ri'yah As Suhaimi] mendatangi Nabi Shallallahu'alaihiWasallam lalu berkata; Anak dan hartaku diserang. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Harta telah dibagi, sedangkan anak, hai Bilal pergilah bersamanya. Bila ia mengenali anaknya, serahkan padanya.\" Bilal pergi bersama Ri'yah, Bilal memperlihatkan anak pada Ri'yah lalu bertanya; Kau mengenalinya. Ia menjawab; Ya. Lalu Bilal menyerahkan anak itu pada Ri'yah lalu pergi. Berkata Sufyan; Mereka meriwayatkan bahwa Ri'yah masuk Islam sebelum penyerangan."},"3239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنِ الشَّعْبِيِّ عَنْ رِعْيَةَ السُّحَيْمِيِّ قَالَكَتَبَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَدِيمٍ أَحْمَرَ فَأَخَذَ كِتَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَقَعَ بِهِ دَلْوَهُ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَلَمْ يَدَعُوا لَهُ رَائِحَةً وَلَا سَارِحَةً وَلَا أَهْلًا وَلَا مَالًا إِلَّا أَخَذُوهُ وَانْفَلَتَ عُرْيَانًا عَلَى فَرَسٍ لَهُ لَيْسَ عَلَيْهِ قِشْرَةٌ حَتَّى يَنْتَهِيَ إِلَى ابْنَتِهِ وَهِيَ مُتَزَوِّجَةٌ فِي بَنِي هِلَالٍ وَقَدْ أَسْلَمَتْ وَأَسْلَمَ أَهْلُهَا وَكَانَ مَجْلِسُ الْقَوْمِ بِفِنَاءِ بَيْتِهَا فَدَارَ حَتَّى دَخَلَ عَلَيْهَا مِنْ وَرَاءِ الْبَيْتِ قَالَ فَلَمَّا رَأَتْهُ أَلْقَتْ عَلَيْهِ ثَوْبًا قَالَتْ مَا لَكَ قَالَ كُلُّ الشَّرِّ نَزَلَ بِأَبِيكِ مَا تُرِكَ لَهُ رَائِحَةٌ وَلَا سَارِحَةٌ وَلَا أَهْلٌ وَلَا مَالٌ إِلَّا وَقَدْ أُخِذَ قَالَتْ دُعِيتَ إِلَى الْإِسْلَامِ قَالَ أَيْنَ بَعْلُكِ قَالَتْ فِي الْإِبِلِ قَالَ فَأَتَاهُ فَقَالَ مَا لَكَ قَالَ كُلُّ الشَّرِّ قَدْ نَزَلَ بِهِ مَا تُرِكَتْ لَهُ رَائِحَةٌ وَلَا سَارِحَةٌ وَلَا أَهْلٌ وَلَا مَالٌ إِلَّا وَقَدْ أُخِذَ وَأَنَا أُرِيدُ مُحَمَّدًا أُبَادِرُهُ قَبْلَ أَنْ يُقَسِّمَ أَهْلِي وَمَالِي قَالَ فَخُذْ رَاحِلَتِي بِرَحْلِهَا قَالَ لَا حَاجَةَ لِي فِيهَا قَالَ فَأَخَذَ قَعُودَ الرَّاعِي وَزَوَّدَهُ إِدَاوَةً مِنْ مَاءٍ قَالَ وَعَلَيْهِ ثَوْبٌ إِذَا غَطَّى بِهِ وَجْهَهُ خَرَجَتْ اسْتُهُ وَإِذَا غَطَّى اسْتَهُ خَرَجَ وَجْهُهُ وَهُوَ يَكْرَهُ أَنْ يُعْرَفَ حَتَّى انْتَهَى إِلَى الْمَدِينَةِ فَعَقَلَ رَاحِلَتَهُ ثُمَّ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ بِحِذَائِهِ حَيْثُ يُصَلِّي فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ قَالَ يَا رَسُولَ اللَّهِ ابْسُطْ يَدَيْكَ فَلْأُبَايِعْكَ فَبَسَطَهَا فَلَمَّا أَرَادَ أَنْ يَضْرِبَ عَلَيْهَا قَبَضَهَا إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَفَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ ثَلَاثًا قَبَضَهَا إِلَيْهِ وَيَفْعَلُهُ فَلَمَّا كَانَتْ الثَّالِثَةُ قَالَ مَنْ أَنْتَ قَالَ رِعْيَةُ السُّحَيْمِيُّ قَالَ فَتَنَاوَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَضُدَهُ ثُمَّ رَفَعَهُ ثُمَّ قَالَ يَا مَعْشَرَ الْمُسْلِمِينَ هَذَا رِعْيَةُ السُّحَيْمِيُّ الَّذِي كَتَبْتُ إِلَيْهِ فَأَخَذَ كِتَابِي فَرَقَعَ بِهِ دَلْوَهُ فَأَخَذَ يَتَضَرَّعُ إِلَيْهِ قُلْتُ يَا رَسُولَ اللَّهِ أَهْلِي وَمَالِي قَالَ أَمَّا مَالُكَ فَقَدْ قُسِّمَ وَأَمَّا أَهْلُكَ فَمَنْ قَدَرْتَ عَلَيْهِ مِنْهُمْ فَخَرَجَ فَإِذَا ابْنُهُ قَدْ عَرَفَ الرَّاحِلَةَ وَهُوَ قَائِمٌ عِنْدَهَا فَرَجَعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَذَا ابْنِي فَقَالَ يَا بِلَالُ اخْرُجْ مَعَهُ فَسَلْهُ أَبُوكَ هَذَا فَإِنْ قَالَ نَعَمْ فَادْفَعْهُ إِلَيْهِ فَخَرَجَ بِلَالٌ إِلَيْهِ فَقَالَ أَبُوكَ هَذَا قَالَ نَعَمْ فَرَجَعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا رَأَيْتُ أَحَدًا اسْتَعْبَرَ إِلَى صَاحِبِهِ فَقَالَ ذَاكَ جَفَاءُ الْأَعْرَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] telah menceritakan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari [Asy Sya'bi] dari [Ri'yah As Suhaimi] berkata; Rasulullah Shallallahu'alaihiWasallam mengirim surat padanya dalam kulit merah, ia mengambil surat Rasulullah Shallallahu'alaihiWasallam kemudian dipakai untuk menambal gayungnya. Kemudian Rasulullah Shallallahu'alaihiWasallam mengirim tentara sariyah (ekspedisi militer yang tanpa diikutsertai Rasulullah Shallallahu'alaihiwasallam), Tidaklah mereka meninggalkan angin, ternak, keluarga dan hartanya, melainkan mereka pasti mengambilnya. Ri'yah melarikan diri dengan telanjang mengendarai kuda miliknya yang tidak ada pelananya hingga tiba di hadapan putrinya yang sudah memiliki suami di Bani Hilal, putrinya sudah masuk Islam dan keluarganya juga. Majelis kaum diselenggarakan di halaman rumahnya. Ia berputar keliling hingga masuk ke rumah putrinya dari belakang. Saat purinya melihatnya, ia memberinya baju. Putrinya berkata; Ada apa denganmu? Ia menjawab; Semua keburukan menimpa ayahmu. Aku tidak ditinggali angin, binatang ternak, keluarga dan harta, semuanya diambil. Putrinya berkata; 'Kau diseru untuk masuk Islam? Ia balik bertanya; Mana suamimu? Putrinya menjawab; Sedang mengurus unta. Lalu Ri'yah mendatangi suami putrinya, suami putrinya bertanya; Ada apa denganmu? Ri'yah menjawab; Semua keburukan menimpaku. Aku tidak ditinggali angin, binatang ternak, keluarga dan harta, semuanya diambil dan aku menginginkan Muhammad, aku akan bergegas menemuinya sebelum membagi-bagikan keluarga dan hartaku. suami putrinya berkata; Ambillah kendaraanku sebagai gantinya. Ri'yah berkata; Aku tidak membutuhkannya. suami putrinya mengambil perbekalan dan membekalinya dengan sekantong air, ia mengenakan baju yang bila wajahnya ditutupi, pantatnya kelihatan dan bila pantatnya ditutupi, mukanya terlihat sementara ia tidak mau dikenali. Ia pergi hingga tiba di Madinah lalu mengikat tunggangannya kemudian mendatangi Rasulullah Shallallahu'alaihiwasallam, saat itu beliau tengah shalat. Seusai Rasulullah Shallallahu'alaihiWasallam shalat fajar, Ri'yah berkata; Wahai Rasulullah! Bentangkan tanganmu, aku akan berbaiat pada baginda. Rasulullah Shallallahu'alaihiWasallam membentangkan tangan beliau. Saat Ri'yah hendak memukul tangan Rasulullah Shallallahu'alaihiwasallam, Rasulullah Shallallahu'alaihiWasallam meraihnya, Rasulullah Shallallahu'alaihiWasallam melakukan hal itu sebanyak tiga kali. Pada kali ketiganya Rasulullah Shallallahu'alaihiWasallam bersabda; \"Siapa kamu?\" ia menjawab; Ri'yah As Suhaimi. Rasulullah Shallallahu'alaihiWasallam meraih lengan atasnya dan mengangkatnya lalu bersabda; \"Hai sekalian kaum muslimin! Ini Ri'yah As Suhaimi yang saya kirimi surat lalu suratku dipakai untuk menambal gayungnya.\" Ri'yah pun menunduk-nunduk pada beliau dan berkata; wahai Rasulullah! Keluarga dan hartaku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Harta sudah dibagi, sementara keluargamu, siapa yang bisa kau kenali dari mereka?\" ia keluar, ternyata putranya telah mengenali kendaraannya, ia tengah berdiri didekatnya ia lalu kembali menemui Rasulullah Shallallahu'alaihiwasallam, ia berkata; Ini putraku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Hai Bilal! Keluarlah bersamanya dan tanyakan siapa ayahnya, bila ia mengiyakan serahkan pada ayahnya.\" Bilal keluar menemuinya dan bertanya; Ini ayahmu? Ia menjawab; Ya. Kemudian Bilal kembali menemui Rasulullah Shallallahu'alaihiWasallam dan berkata; Wahai Rasulullah! Aku tidak melihat seorang pun yang bersedih hati pada temannya. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Itulah kasarnya tabiat orang badui.\""},"3240":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنِي يَعْلَى بْنُ عَطَاءٍ عَنْ أَبِي هَمَّامٍ قَالَ أَبُو الْأَسْوَدِ هُوَ عَبْدُ اللَّهِ بْنُ يَسَارٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْفِهْرِيِّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ حُنَيْنٍ فَسِرْنَا فِي يَوْمٍ قَائِظٍ شَدِيدِ الْحَرِّ فَنَزَلْنَا تَحْتَ ظِلَالِ الشَّجَرِ فَلَمَّا زَالَتْ الشَّمْسُ لَبِسْتُ لَأْمَتِي وَرَكِبْتُ فَرَسِي فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي فُسْطَاطِهِ فَقُلْتُ السَّلَامُ عَلَيْكَ يَا رَسُولَ اللَّهِ وَرَحْمَةُ اللَّهِ حَانَ الرَّوَاحُ فَقَالَ أَجَلْ فَقَالَ يَا بِلَالُ فَثَارَ مِنْ تَحْتِ سَمُرَةٍ كَأَنَّ ظِلَّهُ ظِلُّ طَائِرٍ فَقَالَ لَبَّيْكَ وَسَعْدَيْكَ وَأَنَا فِدَاؤُكَ فَقَالَ أَسْرِجْ لِي فَرَسِي فَأَخْرَجَ سَرْجًا دَفَّتَاهُ مِنْ لِيفٍ لَيْسَ فِيهِمَا أَشَرٌ وَلَا بَطَرٌ قَالَ فَأَسْرَجَ قَالَ فَرَكِبَ وَرَكِبْنَا فَصَافَفْنَاهُمْ عَشِيَّتَنَا وَلَيْلَتَنَا فَتَشَامَّتِ الْخَيْلَانِ فَوَلَّى الْمُسْلِمُونَ مُدْبِرِينَ كَمَا قَالَ اللَّهُ عَزَّ وَجَلَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عِبَادَ اللَّهِ أَنَا عَبْدُ اللَّهِ وَرَسُولُهُ ثُمَّ قَالَ يَا مَعْشَرَ الْمُهَاجِرِينَ أَنَا عَبْدُ اللَّهِ وَرَسُولُهُ قَالَ ثُمَّ اقْتَحَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَرَسِهِ فَأَخَذَ كَفًّا مِنْ تُرَابٍ فَأَخْبَرَنِي الَّذِي كَانَ أَدْنَى إِلَيْهِ مِنِّي ضَرَبَ بِهِ وُجُوهَهُمْ وَقَالَ شَاهَتْ الْوُجُوهُ فَهَزَمَهُمْ اللَّهُ عَزَّ وَجَلَّقَالَ يَعْلَى بْنُ عَطَاءٍ فَحَدَّثَنِي أَبْنَاؤُهُمْ عَنْ آبَائِهِمْ أَنَّهُمْ قَالُوا لَمْ يَبْقَ مِنَّا أَحَدٌ إِلَّا امْتَلَأَتْ عَيْنَاهُ وَفَمُهُ تُرَابًا وَسَمِعْنَا صَلْصَلَةً بَيْنَ السَّمَاءِ وَالْأَرْضِ كَإِمْرَارِ الْحَدِيدِ عَلَى الطَّسْتِ الْحَدِيدِ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ أَبِي هَمَّامٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْفِهْرِيِّ قَالَ كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ حُنَيْنٍ فَسِرْنَا فِي يَوْمٍ قَائِظٍ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah mengkhabarkan kepadaku [Ya'la bin 'Atho`] dari [Abu Hammam] -berkata Abu Al Aswad: Abu Hammam adalah 'Abdullah bin Yasar- dari [Abu 'Abdur Rahman Al Fihri] berkata; Aku bersama Rasulullah Shallallahu'alaihiWasallam dalam perang Hunain, kami berjalan di hari yang sangat panas, kami singgah dibawah naungan pohon. Saat matahari menghilang, aku mengenakan baju besiku lalu naik kuda. Aku pergi menghampiri Rasulullah Shallallahu'alaihiwasallam, beliau berada di tenda, aku mengucapkan salam; Assalamu'alaika wa rohmatullaah wahai Rasulullah, sudah saatnya jalan. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Baik.\" Lalu beliau bersabda; \"Hai Bilal, tolong pasang pelana kudaku.\" Bilal mengeluarkan pelana yang ditambali sabut, tidak ada kesombongan pada keduanya. Bilal pun memasangkan pelana. Beliau naik dan kami pun naik. Kami mengatur baris mereka di pagi dan malam hari. Ada dua kuda jatuh lalu kaum muslimin mundur seperti yang difirmankan Allah subhanahu wata'ala lalu Rasulullah Shallallahu'alaihiWasallam bersabda; \"Hai hamba-hamba Allah! Aku adalah hamba Allah dan rasulNya.\" Selanjutnya beliau bersabda; \"Hai sekalian kaum Muhajirin! Aku adalah hamba Allah dan rasulNya.\" Kemudian Rasulullah Shallallahu'alaihiWasallam masuk ke medan perang tanpa berkuda lalu mengambil segenggam pasir. Orang yang ada didekat beliau memberitahkan padaku; Rasulullah Shallallahu'alaihiWasallam melemparkannya ke muka orang-orang kafir dan bersabda; \"Buruklah wajah-wajah musuh.\" Allah Azzawajalla mengalahkan mereka. Berkata Ya'la bin 'Atho`; Anak-anak mereka bercerita kepadaku dari ayah-ayah mereka bahwa mereka berkata; Tidak seorang pun dari kami yang mata dan mulutnya tidak penuh dengan pasir. Kami mendengar suara berdering diantara langit dan bumi seperti hantaman besi mengenai baskom besi. Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengkhabarkan kepada kami [Ya'la bin 'Atho`] dari ['Abdullah bin Yasar Abu Hammam] dari [Abu 'Abdur Rahman Al Fihri] berkata; Aku bersama Rasulullah Shallallahu'alaihiWasallam saat perang Hunain, kami berjalan dihari yang sangat panas. Ia menyebutkan hadits serupa."},"3241":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ نُعَيْمِ بْنِ هَمَّارٍ الْغَطَفَانِيِّ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ يَا ابْنَ آدَمَ لَا تَعْجِزْ عَنْ أَرْبَعِ رَكَعَاتٍ مِنْ أَوَّلِ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyyah] dari [Katsir bin Murrah] dari [Nu'aim bin Hammar Al Ghothofani] bahwa ia mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Allah Azzawajalla berfirman; 'Hai anak cucu Adam! Jangan kau lemah untuk melaksanakan empat rakaat di permulaan siang, niscaya Aku mencukupimu pada sore harinya'.\""},"3242":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ عَبْدِ الْعَزِيزِ حَدَّثَنَا مَكْحُولٌ عَنْ نُعَيْمِ بْنِ هَمَّارٍ الْغَطَفَانِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ يَا ابْنَ آدَمَ لَا تَعْجِزْ عَنْ أَرْبَعِ رَكَعَاتٍ مِنْ أَوَّلِ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Sa'id bin 'Abdul 'Aziz] telah menceritakan kepada kami [Makhul] dari [Nu'aim bin Hammar Al Ghothofani] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Allah Azzawajalla berfirman; 'Hai anak cucu Adam! Janganlah kau malas melaksanakan empat rakaat di permulaan siang niscaya Aku mencukupimu pada sore harinya'.\""},"3243":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو زَيْدٍ يَعْنِي ثَابِتَ بْنَ يَزِيدَ عَنْ بَرْدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنِ ابْنِ مُرَّةَ عَنْ قَيْسٍ الْجُذَامِيِّ عَنْ نُعَيْمٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَا ابْنَ آدَمَ صَلِّ لِي أَرْبَعَ رَكَعَاتٍ أَوَّلَ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] telah menceritakan kepada kami [Abu Zaid Tsabit bin Yazid] dari [Bard] dari [Sulaiman bin Musa] dari [Makhul] dari [Ibnu Murrah] dari [Qais Al Judzami] dari [Nu'aim] dari Rasulullah Shallallahu'alaihiWasallam bahwa beliau bersabda; \"Hai anak cucu Adam! Shalatlah untukKu empat rakaat dipermulaan siang untukku, nicaya aku menukupimu pada sore harinya.\""},"3244":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ وَعَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ مَكْحُولٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ نُعَيْمِ بْنِ هَمَّارٍ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ رَبُّكُمْ عَزَّ وَجَلَّ صَلِّ لِي يَا ابْنَ آدَمَ أَرْبَعًا فِي أَوَّلِ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Abu An Nadhr] dan ['Abdush Shamad] berkata; Telah menceritakan kepada kami [Muhammad bin Rosyid] dari [Makhul] dari [Katsir bin Murrah Al Hadhromi] dari [Nua'im bin Hammar] bahwa ia mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Rabb kalian Azzawajalla berfirman; 'Hai anak cucu Adam! Shalatlah untukKu empat rakaat dipermulaan siang niscaya Aku mencukupimu pada sore harinya'.\""},"3245":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنِي سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ مَكْحُولٍ عَنِ ابْنِ مُرَّةَ عَنْ نُعَيمِ بْنِ هَمِّارٍ الْغَطَفَانِيِّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ يَا ابْنَ آدَمَ صَلِّ لِي أَرْبَعَ رَكَعَاتٍ مِنْ أَوَّلِ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] Telah mengkhabarkan kepadaku [Sa'id bin 'Abdul 'Aziz] dari [Makhul] dari [Ibnu Murrah] dari [Nua'im bin Hammar Al Ghothofani] berkata; Aku mendengar Nabi Shallallahu'alaihiWasallam bersabda; \"Hai anak cucu Adam! Shalatlah untukKu empat rakaat di permulaan siang niscaya Aku mencukupimu pada sore harinya'.\""},"3246":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ حَدَّثَنَا مُعَاوِيَةُ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ نُعَيْمِ بْنِ هَمَّارٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ابْنَ آدَمَ لَا تَعْجِزْ عَنْ أَرْبَعِ رَكَعَاتٍ أَوَّلَ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah menceritakan kepada kami [Hammad bin Khalid] telah menceritakan kepada kami [Mu'awiyah] dari [Abu Az Zahiriyyah] dari [Katsir bin Murrah] dari [Nu'aim bin Hammar] berkata; Aku mendengar Nabi Shallallahu'alaihiWasallam bersabda; \"Hai anak cucu Adam! Janganlah kau malas untuk melaksanakan empat rakaat di permulaan siang niscaya Aku mencukupimu di akhir siang'.\""},"3247":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ الدِّمَشْقِيُّ حَدَّثَنَا مَكْحُولٌ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ نُعَيْمِ بْنِ هَمَّارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَبُّكُمْ تَبَارَكَ وَتَعَالَى ابْنَ آدَمَ صَلِّ لِي أَرْبَعَ رَكَعَاتٍ أَوَّلَ النَّهَارِ أَكْفِكَ آخِرَهُلَيْسَ بِالشَّامِ رَجُلٌ أَصَحُّ حَدِيثًا مِنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ","id":"Telah menceritakan kepada kami [Abu Sa'id, budak Bani Hasyim] telah menceritakan kepada kami [Muhammad bin Rasyid Ad Dimasyqi] telah menceritakan kepada kami [Makhul] dari [Katsir bin Murrah Al Hadhromi] dari [Nu'aim bin Hammar] bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; \"Rabb kalian berfirman, 'Hai anak cucu Adam! Shalatlah untukKu empat rakaat di permulaan siang niscaya Aku mencukupimu di akhir siang'.\" Di Syam tidak ada seorang pun yang haditsnya lebih shahih melebihi Sa'id bin 'Abdul 'Aziz."},"3248":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ نُعَيْمِ بْنِ هَمَّارٍأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الشُّهَدَاءِ أَفْضَلُ قَالَ الَّذِينَ إِنْ يُلْقَوْا فِي الصَّفِّ يَلْفِتُونَ وُجُوهَهُمْ حَتَّى يُقْتَلُوا أُولَئِكَ يَنْطَلِقُونَ فِي الْغُرَفِ الْعُلَى مِنْ الْجَنَّةِ وَيَضْحَكُ إِلَيْهِمْ رَبُّهُمْ وَإِذَا ضَحِكَ رَبُّكَ إِلَى عَبْدٍ فِي الدُّنْيَا فَلَا حِسَابَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari [Nu'aim bin Hammar] bahwa seseorang bertanya kepada Nabi Shallallahu'alaihiwasallam; 'Siapa syuhada yang paling utama? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Orang-orang yang bila masuk ke barisan perang mereka memfokuskan pandangan mereka hingga terbunuh, mereka itulah orang-orang yang pergi menuju kamar-kamar disurga yang tinggi, Rabb mereka tertawa kepada mereka. Dan bila Rabbmu tertawa kepada seorang hamba didunia, maka ia tidak dihisab.\""},"3249":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ وَسَمِعْتُهُ أَنَا مِنْ ابْنِ أَبِي شَيْبَةَ بِالْكُوفَةِ وَقَالَ لَنَا فِيهِ ابْنُ أَبِي شَيْبَةَ عَنِ الزُّهْرِيِّ وَأَمَّا أَبِي فَحَدَّثَنَاهُ عَنْهُ وَلَمْ يَذْكُرْ الزُّهْرِيَّ وَحَدَّثَنَاهُ بِالْكُوفَةِ جَعَلَهُ لَنَا عَنْ الزُّهْرِيِّ ثُمَّ رَجَعَ إِلَى حَدِيثِ أَبِي حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَاعِيلَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَحْدَهُ عَيْنًا إِلَى قُرَيْشٍ قَالَ فَجِئْتُ إِلَى خَشَبَةِ خُبَيْبٍ وَأَنَا أَتَخَوَّفُ الْعُيُونَ فَرَقَيْتُ فِيهَا فَحَلَلْتُ خُبَيْبًا فَوَقَعَ إِلَى الْأَرْضِ فَانْتَبَذْتُ غَيْرَ بَعِيدٍ ثُمَّ الْتَفَتُّ فَلَمْ أَرَ خُبَيْبًا وَلَا كَأَنَّمَا ابْتَلَعَتْهُ الْأَرْضُ فَلَمْ يُرَ لِخُبَيْبٍ أَثَرٌ حَتَّى السَّاعَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad bin Abu Syaibah] dan saya mendengar dari Ibnu Abu Syaibah di Kufah. Ibnu Abu Syaibah berkata kepada kami dari [Az Zuhri] sementara ayahku, aku (Ibnu Abi Syaibah) menceritakan kepadanya dari 'Abdullah tapi Az Zuhri tidak menyebutkan dan kami menceritakan kepadanya (Abu Syaibah) di Kufah, ia menceritakan kepada kami dari Az Zuhri kemudian kembali ke hadits ayahku; Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Ibrahim bin Isma'il] telah mengkhabarkan kepadaku [Ja'far bin 'Amr bin Umaiyah] dari [ayahnya] bahwa Nabi Shallallahu'alaihi Wasallam mengutusnya (Ja'far) seorang diri sebagai mata-mata ke Quraisy. Ja'far berkata; Saya mendatangi rumah kayu milik Khubaib dan saya mengkhawatirkan adanya mata-mata, saya naik dan tinggal dikediaman Khubaib. Ia jatuh ke bawah lalu aku (Ja'far) meloncat tidak jauh lalu aku menoleh, saya tidak melihat Khubaib atau sepertinya sudah ditelan bumi. Tidak diketahui jejak Khubaib hingga saat ini."},"3250":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami ['Ali] dari Yahya dari [Abu Salamah] telah mengabarkan kepadaku [Ja'far bin 'Amr bin Umaiyah] dari [ayahnya] bahwa ia melihat Nabi Shallallahu'alaihiWasallam membasuh diatas dua sepatu."},"3251":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحٌ عَنِ الزُّهْرِيِّ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ عُضْوًا فِي الْمُصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih] dari [Az Zuhri] telah menceritakan kepadaku [Ja'far bin 'Amr bin Umaiyah] dari [ayahnya] bahwa ia melihat Nabi Shallallahu'alaihiWasallam memakan daging di musholla dan tidak berwudhu."},"3252":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ أَخْبَرَنَا عَيَّاشُ بْنُ عَبَّاسٍ أَنَّ كُلَيْبَ بْنَ صُبْحٍ حَدَّثَهُ أَنَّ الزِّبْرِقَانَ حَدَّثَهُ عَنْ عَمِّهِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَنَامَ عَنْ صَلَاةِ الصُّبْحِ حَتَّى طَلَعَتْ الشَّمْسُ لَمْ يَسْتَيْقِظُوا وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِالرَّكْعَتَيْنِ فَرَكَعَهُمَا ثُمَّ أَقَامَ الصَّلَاةَ فَصَلَّى","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman] telah menceritakan kepada kami [Haiwah] telah mengkhabarkan kepada kami ['Ayyasy bin 'Abbas] bahwa [Kulaib bin Shubh] menceritakan padanya bahwa [Az Zibriqon] menceritakan padanya dari [pamannya -'Amr bin Umaiyah Adh Dhamiri-] berkata; Kami bersama Rasulullah Shallallahu'alaihiWasallam dalam salah satu perjalanan beliau. Beliau tertidur dan tidak shalat shubuh hingga matahari terbit, mereka tidak bangun. Rasulullah Shallallahu'alaihiWasallam memulai shalat sunnah dua rakaat, lalu shalat diiqamati kemudian beliau shalat."},"3253":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ الْيَمَانِيُّ عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ وَالْعِمَامَةِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami ['Abdur Rahman bin 'Amr Al Auza'i] telah menceritakan kepadaku [Yahya bin Abu Katsir Al Yamani] dari [Abu Salamah] dari [Ja'far bin 'Amr bin Umaiyah Adh Dhamri] dari [ayahnya], bahwa ia melihat Rasulullah Shallallahu'alaihiWasallam mengusap bagian atas dua sepatu dan selendang."},"3254":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah menceritakan kepada kami [Muhammad bin Mush'ab] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ja'far bin 'Amr bin Umaiyah Adh Dhamri] dari [ayahnya] berkata; Aku melihat Rasulullah Shallallahu'alaihiWasallam mengusap bagian atas dua sepatunya dan tudung kepalanya."},"3255":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Ja'far bin 'Amr bin Umaiyah] dari [ayahnya] berkata; Aku melihat Rasulullah Shallallahu'alaihiWasallam mengusap bagian atas dua sepatunya."},"3256":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فَدُعِيَ إِلَى الصَّلَاةِ فَطَرَحَ السِّكِّينَ وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Shalih] berkata [Ibnu Syihab] telah menceritakan kepadaku [Ja'far bin 'Amr bin Umaiyah] bahwa [ayahnya] berkata; Aku melihat Rasulullah Shallallahu'alaihiWasallam memotong ketiak kambing kemudian shalat diserukan, beliau melempar pisau dan tidak berwudhu."},"3257":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ شِهَابٍ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ يَحْتَزُّ مِنْ كَتِفٍ ثُمَّ دُعِيَ إِلَى الصَّلَاةِ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Syihab] dari [Ja'far bin 'Amr bin Umaiyah] dari [ayahnya] bahwa ia berkata; Aku melihat Rasulullah Shallallahu'alaihiWasallam memotong ketiak kambing kemudian shalat diserukan, beliau melempar pisau dan tidak berwudhu."},"3258":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى وَحُسَيْنُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ جَعْفَرَ بْنَ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيَّ أَخْبَرَهُ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] dan [Husain bin Muhammad] keduanya berkata; Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] bahwa [Ja'far bin 'Amr bin Umaiyah Adh Dhomri] telah mengabarkan padanya bahwa [ayahnya] telah mengabarkan padanya, bahwa ia melihat Nabi Shallallahu'alaihiWasallam membasuh bagian atas dua sepatunya."},"3259":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ أَنَّ ابْنَ زُغْبٍ الْإِيَادِيَّ حَدَّثَهُ قَالَنَزَلَ عَلَيَّ عَبْدُ اللَّهِ بْنُ حَوَالَةَ الْأَزْدِيُّ فَقَالَ لِي وَإِنَّهُ لَنَازِلٌ عَلَيَّ فِي بَيْتِي بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَوْلَ الْمَدِينَةِ عَلَى أَقْدَامِنَا لِنَغْنَمَ فَرَجَعْنَا وَلَمْ نَغْنَمْ شَيْئًا وَعَرَفَ الْجَهْدَ فِي وُجُوهِنَا فَقَامَ فِينَا فَقَالَ اللَّهُمَّ لَا تَكِلْهُمْ إِلَيَّ فَأَضْعُفَ وَلَا تَكِلْهُمْ إِلَى أَنْفُسِهِمْ فَيَعْجِزُوا عَنْهَا وَلَا تَكِلْهُمْ إِلَى النَّاسِ فَيَسْتَأْثِرُوا عَلَيْهِمْ ثُمَّ قَالَ لَيُفْتَحَنَّ لَكُمْ الشَّامُ وَالرُّومُ وَفَارِسُ أَوْ الرُّومُ وَفَارِسُ حَتَّى يَكُونَ لِأَحَدِكُمْ مِنْ الْإِبِلِ كَذَا وَكَذَا وَمِنْ الْبَقَرِ كَذَا وَكَذَا وَمِنْ الْغَنَمِ حَتَّى يُعْطَى أَحَدُهُمْ مِائَةَ دِينَارٍ فَيَسْخَطَهَا ثُمَّ وَضَعَ يَدَهُ عَلَى رَأْسِي أَوْ هَامَتِي فَقَالَ يَا ابْنَ حَوَالَةَ إِذَا رَأَيْتَ الْخِلَافَةَ قَدْ نَزَلَتْ الْأَرْضَ الْمُقَدَّسَةَ فَقَدْ دَنَتْ الزَّلَازِلُ وَالْبَلَايَا وَالْأُمُورُ الْعِظَامُ وَالسَّاعَةُ يَوْمَئِذٍ أَقْرَبُ إِلَى النَّاسِ مِنْ يَدَيَّ هَذِهِ مِنْ رَأْسِكَ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah] dari [Dhomroh bin Habib] bahwa [Ibnu Zughbi Al Iyadi] menceritakan kepadanya, ia berkata; ['Abdullah bin Hawalah Al Azdi] singgah ditempatku, ia berkata padaku; Rasulullah Shallallahu'alaihiWasallam mengutus kami ke seputar Madinah berjalan kaki untuk mencari harta rampasan perang. Kami kembali tanpa mendapatkan apa pun. Beliau melihat keletihan di wajah-wajah kami. Beliau berdiri menghampiri kami lalu bersabda; \"Ya Allah! Janganlah Kau serahkan mereka padaku hingga aku lemah, janganlah mereka Engkau telantarkan hingga mereka lemah, jangan serahkan mereka pada orang-orang hingga mereka lebih mementingkan diri mereka sendiri.\" Selanjutnya Rasulullah Shallallahu'alaihiWasallam bersabda; \"Sesungguhnya Syam, Romawi dan Persia -atau Romawi dan Persia- akan ditaklukkan untuk kalian hingga salah seorang dari kalian memiliki unta sekian dan sekian, sapi sekian dan sekian dan kambing sekian dan sekian hingga salah satu diantara mereka diberi seratus dinar lalu ia memarahinya.\" Beliau meletakkan tangan beliau diatas kepalaku lalu bersabda; \"Hai Ibnu Hawalah! Bila kau melihat khilafah turun ditanah suci maka telah dekatlah gempa bumi-gempa bumi, bencana, dan hal-hal besar, dan kiamat saat itu lebih dekat pada manusia melebihi tanganku ini dari kepalamu.\""},"3260":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ رَبِيعَةَ بْنِ لَقِيطٍ التُّجِيبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَ الْأَزْدِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ نَجَا مِنْ ثَلَاثٍ فَقَدْ نَجَا قَالَهُ ثَلَاثَ مَرَّاتٍ قَالُوا مَاذَا يَا رَسُولَ اللَّهِ قَالَ مَوْتِي وَمِنْ قَتْلِ خَلِيفَةٍ مُصْطَبِرٍ بِالْحَقِّ يُعْطِيهِ وَالدَّجَّالِ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Laits] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Robi'ah bin Laqith At Tujini] dari ['Abdullah bin Hawalah Al Azdi Al Azdi] dari Rasulullah Shallallahu'alaihiWasallam bahwa beliau bersabda; \"Barangsiapa yang selamat dari tiga hal berarti ia selamat.\" Beliau mengucapkannya tiga kali. Mereka bertanya; Apa itu wahai Rasulullah Shallallahu'alaihiwasallam.! Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kematianku, terbunuhnya seorang khalifah yang sabar memegang teguh kebenaran yang diberikannya dan Dajjal.\""},"3261":{"ar":"حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ وَعَلِيُّ بْنُ عَيَّاشٍ قَالَا حَدَّثَنَا حَرِيزٌ عَنْ سُلَيْمَانَ بْنِ سُمَيْرٍ عَنِ ابْنِ حَوَالَةَ الْأَزْدِيِّ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ سَيَكُونُ أَجْنَادٌ مُجَنَّدَةٌ شَامٌ وَيَمَنٌ وَعِرَاقٌ وَاللَّهُ أَعْلَمُ بِأَيِّهَا بَدَأَ وَعَلَيْكُمْ بِالشَّامِ أَلَا وَعَلَيْكُمْ بِالشَّامِ أَلَا وَعَلَيْكُمْ بِالشَّامِ فَمَنْ كَرِهَ فَعَلَيْهِ بِيَمَنِهِ وَلْيَسْقِ فِي غُدُرِهِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ تَوَكَّلَ لِي بِالشَّامِ وَأَهْلِهِ","id":"Telah menceritakan kepada kami ['Ishom bin Khalid] dan ['Ali bin 'Ayyasy] berkata; Telah menceritakan kepada kami [Hariz] dari [Sulaiman bin Sumair] dari [Ibnu Hawalah Al Azdi] salah satu sahabat Rasulullah Shallallahu'alaihiwasallam, dari Nabi Shallallahu'alaihiWasallam bahwa beliau bersabda; \"Syam, Yaman dan 'Irak akan menjadi bala tentara kuat, wallahu a'lam, mana yang bermula terlebih dahulu. Hendaklah kalian ke Syam, ingat! hendaklah kalian ke Syam, ingat! hendaklah kalian ke Syam. Bagi yang tidak suka hendaklah ke Yaman dan hendaklah minum di kolamnya karena Allah Azzawajalla menyerahkan Syam dan penduduknya kepadaku.\""},"3262":{"ar":"حَدَّثَنَا بَهْزٌ وَأَبُو النَّضْرِ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدٌ قَالَ أَتَانِي الْوَلِيدُ أَنَا وَصَاحِبٌ لِي قَالَ فَقَالَ لَنَا هَلُمَّا فَأَنْتُمَا أَشَبُّ مِنِّي سِنًّا وَأَوْعَى لِلْحَدِيثِ مِنِّي قَالَ فَانْطَلَقَ بِنَا إِلَى بِشْرِ بْنِ عَاصِمٍ قَالَ فَقَالَ لَهُ أَبُو الْعَالِيَةِ تُحَدِّثُ هَذَيْنِ حَدِيثَكَ قَالَ حَدَّثَنَا عُقْبَةُ بْنُ مَالِكٍ قَالَ أَبُو النَّضْرِ اللَّيْثِيُّ قَالَ بَهْزٌ وَكَانَ مِنْ رَهْطِهِ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً قَالَ فَأَغَارَتْ عَلَى قَوْمٍ قَالَ فَشَذَّ مِنْ الْقَوْمِ رَجُلٌ قَالَ فَاتَّبَعَهُ رَجُلٌ مِنْ السَّرِيَّةِ شَاهِرًا سَيْفَهُ قَالَ فَقَالَ الشَّاذُّ مِنْ الْقَوْمِ إِنِّي مُسْلِمٌ قَالَ فَلَمْ يَنْظُرْ فِيمَا قَالَ فَضَرَبَهُ فَقَتَلَهُ قَالَ فَنَمَى الْحَدِيثُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ فِيهِ قَوْلًا شَدِيدًا فَبَلَغَ الْقَاتِلَ قَالَ فَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَالَ الْقَاتِلُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا قَالَ الَّذِي قَالَ إِلَّا تَعَوُّذًا مِنْ الْقَتْلِ قَالَ فَأَعْرَضَ عَنْهُ وَعَمَّنْ قِبَلَهُ مِنْ النَّاسِ وَأَخَذَ فِي خُطْبَتِهِ ثُمَّ قَالَ أَيْضًا يَا رَسُولَ اللَّهِ مَا قَالَ الَّذِي قَالَ إِلَّا تَعَوُّذًا مِنْ الْقَتْلِ فَأَعْرَضَ عَنْهُ وَعَمَّنْ قِبَلَهُ مِنْ النَّاسِ وَأَخَذَ فِي خُطْبَتِهِ ثُمَّ لَمْ يَصْبِرْ فَقَالَ الثَّالِثَةَ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا قَالَ إِلَّا تَعَوُّذًا مِنْ الْقَتْلِ فَأَقْبَلَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُعْرَفُ الْمَسَاءَةُ فِي وَجْهِهِ قَالَ لَهُ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَبَى عَلَى مَنْ قَتَلَ مُؤْمِنًا ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Bahz] dan [Abu An Nadhr] keduanya berkata; Telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid] berkata; Al Walid mendatangiku dan seorang temanku, ia berkata kepada kami; Kemarilah, kalian lebih muda dariku dan lebih mengerti hadits dari pada aku. Ia pergi bersama kami menuju Bisyr bin 'Ashim kemudian Abu Al 'Aliyah berkata padanya; Engkau menceritakan dua haditsmu. [Bisyr] berkata; Telah menceritakan kepada kami ['Uqbah bin Malik]. -berkata Abu An Nadhr Al Laitsi: Bahz berkata, salah satu kelompoknya berkata-; Rasulullah Shallallahu'alaihiWasallam mengirim tentara sariyah lalu menyerang suatu kaum. Ada seseorang melarikan diri kemudian diikuti salah seorang tentara sariyah seraya mengacungkan pedang. Orang yang melarikan diri itu berkata; Aku muslim. Tentara itu tidak memperhatikan ucapannya lalu menebas lehernya hingga mati. Kejadian itu terdengar oleh Rasulullah Shallallahu'alaihiWasallam kemudian beliau menyampaikan kata-kata keras. Hal itu terdengar oleh si pembunuh. Saat Rasulullah Shallallahu'alaihiWasallam berkhutbah, si pembunuh berkata; Wahai Rasulullah! Demi Allah ia hanya mengucapkannya untuk melindungi diri agar tidak terbunuh. Rasulullah Shallallahu'alaihiWasallam berpaling darinya dan dari orang-orang yang ada dihadapan beliau, beliau berkhutbah lalu si pembunuh tidak sabar hingga mengucapkan untuk kali ketiga; Wahai Rasulullah! Demi Allah ia hanya mengucapkannya untuk melindungi diri agar tidak terbunuh. Lalu Rasulullah Shallallahu'alaihiWasallam menghampirinya, kebencian terlihat diwajah beliau, beliau berkata padanya; \"Allah Azzawajalla enggan pada orang yang membunuh seorang muslim.\" Rasulullah Shallallahu'alaihiWasallam mengucapkannya sebanyak tiga kali. "},"3263":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ سُلَيْمَانَ أَبِي الرَّبِيعِ عَنِ الْقَاسِمِ مَوْلَى مُعَاوِيَةَ قَالَدَخَلْتُ مَسْجِدَ دِمَشْقَ فَرَأَيْتُ نَاسًا مُجْتَمِعِينَ وَشَيْخٌ يُحَدِّثُهُمْ قُلْتُ مَنْ هَذَا قَالُوا هَذَا سَهْلُ ابْنُ الْحَنْظَلِيَّةِ فَسَمِعْتُهُ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَكَلَ لَحْمًا فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Sulaiman Abu Ar Robi'] dari [Al Qosim, budak Mu'awiyah] berkata; Saya memasuki masjid Damaskus, aku melihat orang-orang tengah berkumpul sementara seorang guru menceritakan pada mereka. Aku bertanya; Siapa dia? Mereka menjawab; Dia [Sahl bin Al Handholah], aku mendengarnya berkata; Aku mendengar Rasulullah Shallallahu'alaihiWasallam bersabda; \"Barangsiapa makan daging hendaklah berwudhu.\""},"3264":{"ar":"حَدَّثَنَا نُوحُ بْنُ يَزِيدَ أَبُو مُحَمَّدٍ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنِيهِ ابْنُ إِسْحَاقَ عَنْ عِيسَى بْنِ مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْفَغْوَاءِ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَدَعَا��ِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَرَادَ أَنْ يَبْعَثَنِي بِمَالٍ إِلَى أَبِي سُفْيَانَ يَقْسِمُهُ فِي قُرَيْشٍ بِمَكَّةَ بَعْدَ الْفَتْحِ قَالَ فَقَالَ الْتَمِسْ صَاحِبًا قَالَ فَجَاءَنِي عَمْرُو بْنُ أُمَيَّةَ الضَّمْرِيُّ قَالَ بَلَغَنِي أَنَّكَ تُرِيدُ الْخُرُوجَ وَتَلْتَمِسُ صَاحِبًا قَالَ قُلْتُ أَجَلْ قَالَ فَأَنَا لَكَ صَاحِبٌ قَالَ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ وَجَدْتُ صَاحِبًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَجَدْتَ صَاحِبًا فَآذِنِّي قَالَ فَقَالَ مَنْ قُلْتُ عَمْرُو بْنُ أُمَيَّةَ الضَّمْرِيُّ قَالَ فَقَالَ إِذَا هَبَطْتَ بِلَادَ قَوْمِهِ فَاحْذَرْهُ فَإِنَّهُ قَدْ قَالَ الْقَائِلُ أَخُوكَ الْبَكْرِيُّ وَلَا تَأْمَنْهُ قَالَ فَخَرَجْنَا حَتَّى إِذَا جِئْتُ الْأَبْوَاءَ فَقَالَ لِي إِنِّي أُرِيدُ حَاجَةً إِلَى قَوْمِي بِوَدَّانَ فَتَلَبَّثْ لِي قَالَ قُلْتُ رَاشِدًا فَلَمَّا وَلَّى ذَكَرْتُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَدَدْتُ عَلَى بَعِيرِي ثُمَّ خَرَجْتُ أُوضِعُهُ حَتَّى إِذَا كُنْتُ بَالْأَصَافِرِ إِذَا هُوَ يُعَارِضُنِي فِي رَهْطِهِ قَالَ وَأَوْضَعْتُ فَسَبَقْتُهُ فَلَمَّا رَآنِي قَدْ فُتُّهُ انْصَرَفُوا وَجَاءَنِي قَالَ كَانَتْ لِي إِلَى قَوْمِي حَاجَةٌ قَالَ قُلْتُ أَجَلْ فَمَضَيْنَا حَتَّى قَدِمْنَا مَكَّةَ فَدَفَعْتُ الْمَالَ إِلَى أَبِي سُفْيَانَ","id":"Telah menceritakan kepada kami [Nuh bin Yazid Abu Muhammad] telah mengkhabarkan kepada kami [Ibrahim bin Sa'ad] telah menceritakannya kepadaku [Ibnu Ishaq] dari ['Isa bin Ma'mar] dari ['Abdullah bin 'Amr bin Al Faghwa` Al Khuza'i] dari [ayahnya] berkata; Rasulullah Shallallahu'alaihiWasallam memanggilku, beliau ingin mengutusku untuk memberi sejumah uang pada Sufyan agar dibagi-bagikan kepada orang-orang Quraisy di Mekkah setelah penaklukkan Mekkah. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Carilah seorang teman.\" Lalu datanglah 'Amr bin Umaiyah Adh Dhomri berkata; Saya dengar kau hendak pergi dan mencari seorang teman. Aku menjawab; Benar. Ia berkata; Aku akan menemanimu. Lalu aku mendatangi Rasulullah Shallallahu'alaihiWasallam dan aku berkata; Aku sudah mendapatkan seorang teman. Sebelumnya Rasulullah Shallallahu'alaihiWasallam bersabda padaku; \"Bila kau sudah menemukan seorang teman beritahukan padaku. Rasulullah Shallallahu'alaihiWasallam bertanya; \"Siapa?\" aku menjawab; 'Amr bin Umaiyah Adh Dhomri. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Bila kau singgah di kawasan kaumnya, waspadailah dia karena seseorang telah berkata, saudaramu Al Bakri, dan kau tidak mempercayainya.\" Kami pun pergi hingga tiga di Abwa, ia berkata kepadaku; Saya ada perlu dengan kaumku diWaddan. Ia pun meninggalkanku. Saat ia pergi, aku teringat sabda Rasulullah Shallallahu'alaihiWasallam kemudian aku naik unta dan pergi hingga tiba diAshofir, ternyata ia bersama kaumnya menjauhiku. Aku berjalan cepat dan mendahuluinya, Saat ia melihatku sudah jauh, mereka pergi lalu ia mendatangiku. Ia berkata; Aku tadi ada perlu dengan kaumku. Saya menjawab; Ya. Kami pun pergi hingga tiba di Mekkah lalu aku menyerahkan uang kepada Abu Sufyan."},"3265":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ زُهَيْرٍ عَنِ الْعَلَاءِ عَنْ أَبِي كَثِيرٍ مَوْلَى مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ جَحْشٍ قَالَكُنَّا جُلُوسًا بِفِنَاءِ الْمَسْجِدِ حَيْثُ تُوضَعُ الْجَنَائِزُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ بَيْنَ ظَهْرَيْنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَصَرَهُ قِبَلَ السَّمَاءِ فَنَظَرَ ثُمَّ طَأْطَأَ بَصَرَهُ وَوَضَعَ يَدَهُ عَلَى جَبْهَتِهِ ثُمَّ قَالَ سُبْحَانَ اللَّهِ سُبْحَانَ اللَّهِ مَاذَا نَزَلَ مِنْ التَّشْدِيدِ قَالَ فَسَكَتْنَا يَوْمَنَا وَلَيْلَتَنَا فَلَمْ نَرَهَا خَيْرًا حَتَّى أَصْبَحْنَا قَالَ مُحَمَّدٌ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا التَّشْدِيدُ الَّذِي نَزَلَ قَالَ فِي الدَّيْنِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ أَنَّ رَجُلًا قُتِلَ فِي سَبِيلِ اللَّهِ ثُمَّ عَاشَ ثُمَّ قُتِلَ فِي سَبِيلِ اللَّهِ ثُمَّ عَاشَ وَعَلَيْهِ دَيْنٌ مَا دَخَلَ الْجَنَّةَ حَتَّى يَقْضِيَ دَيْنَهُ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dari [Zuhri] dari [Al 'Alaa`] dari [Abu Katsir, budak Muhammad bin 'Abdullah bin Jahsy] berkata; Telah mengkhabarkan kepadaku [Muhammad bin 'Abdullah bin Jahsy] berkata; Kami duduk di halaman masjid tempat diletakkannya jenazah sementara Rasulullah Shallallahu'alaihiWasallam duduk dihadapan kami, Rasulullah Shallallahu'alaihiWasallam menengadahkan pandangan beliau ke arah langit, beliau melihat kemudian mengangguk-anggukkan pandangan dan meletakkan tangan diatas dahi lalu bersabda; \"Subhaanallaah, subhaanallaah, kesulitan apa yang turun.\" Berkata Muhammad bin 'Abdullah; Kami diam sehari semalam dan kami tidak menilainya baik hingga pagi hari. Berkata Muhammad; Aku bertanya kepada Rasulullah Shallallahu'alaihiWasallam kesulitan apakah yang turun. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Dalam agama, demi Dzat yang jiwa Muhammad berada ditangannya, andai seseorang terbunuh dijalan Allah kemudian hidup lagi kemudian terbunuh dijalan Allah kemudian hidup lagi dan ia memiliki hutang niscaya tidak masuk surga hingga ia melunasi hutangnya.\""},"3266":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ عَنِ الْعَلَاءِ عَنْ أَبِي كَثِيرٍ مَوْلَى مُحَمَّدِ بْنِ جَحْشٍ عَنْ مُحَمَّدِ بْنِ جَحْشٍ خَتَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى مَعْمَرٍ بِفِنَاءِ الْمَسْجِدِ مُحْتَبِيًا كَاشِفًا عَنْ طَرَفِ فَخِذِهِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمِّرْ فَخِذَكَ يَا مَعْمَرُ فَإِنَّ الْفَخِذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Hafsh bin Masiroh] dari [Al 'Alaa`] dari [Abu Katsir, budak Muhammad bin Jahsy] dari [Muhammad bin Jahsy] ipar Nabi Shallallahu'alaihiwasallam bahwa Nabi Shallallahu'alaihiWasallam melintasi Ma'mar di halaman masjid seraya duduk memeluk lutut dan membuka ujung lutut, lalu Nabi Shallallahu'alaihiWasallam bersabda kepadanya; \"Tutupilah lututmu hai Ma'mar karena lutut itu aurat.\""},"3267":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنِي الْعَلَاءُ عَنْ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ جَحْشٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ عَلَى مَعْمَرٍ وَفَخِذَاهُ مَكْشُوفَتَانِ فَقَالَ يَا مَعْمَرُ غَطِّ فَخِذَيْكَ فَإِنَّ الْفَخِذَيْنِ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud] telah menceritakan kepada kami [Isma'il] telah mengkhabarkan kepadaku [Al 'Aala`] dari [Abu Katsir] dari [Muhammad bin Jahsy] berkata; Nabi Shallallahu'alaihiWasallam melewati Ma'mar dan saya bersama beliau, dua lutut Ma'mar terbuka lalu beliau bersabda; \"Hai Ma'mar tutupilah lututmu karena lutut itu aurat.\""},"3268":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ حَدَّثَنَا سَمُرَةُ بْنُ سَهْمٍ قَالَنَزَلْتُ عَلَى أَبِي هَاشِمِ بْنِ عُتْبَةَ وَهُوَ طَعِينٌ فَدَخَلَ عَلَيْهِ مُعَاوِيَةُ يَعُودُهُ فَبَكَى فَقَالَ لَهُ مُعَاوِيَةُ مَا يُبْكِيكَ أَوَجَعٌ يَشْتَزُّكَ أَمْ عَلَى الدُّنْيَا فَقَدْ ذَهَبَ صَفْوُهَا فَقَالَ عَلَى كُلٍّ لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا فَوَدِدْتُ أَنِّي اتَّبَعْتُهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَلَّكَ أَنْ تُدْرِكَ أَمْوَالًا تُقْسَمُ بَيْنَ أَقْوَامٍ وَإِنَّمَا يَكْفِيكَ مِنْ جَمْعِ الْمَالِ خَادِمٌ وَمَرْكَبٌ فِي سَبِيلِ اللَّهِ تَعَالَى فَوَجَدْتُ فَجَمَعْتُ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] telah menceritakan kepada kami [Za`idah] dari [Manshur] dari [Syaqiq] telah menceritakan kepada kami [Samuroh bin Sahm] berkata; Aku bertamu ke kediaman [Abu Hasyim bin 'Utbah], ia tertikam lalu Mu'awiyah bertandang menjenguknya, ia menangis lalu Mu'awiyah bertanya; Apa yang membuatmu menangis, apakah rasa sakit yang menimpamu ataukah dunia yang telah hilang kesuciannya? Ia menjawab; Bukan itu semua tapi Rasulullah Shallallahu'alaihiWasallam mewasiatkanku suatu hal dan aku ingin mengikutinya, bahwa Rasulullah Shallallahu'alaihiWasallam bersabda; \"Mungkin kau menemui harta yang kau bagi diantara kaum-kaum, dalam hal mengumpulkan harta, cukuplah bagimu sebagai pelayan dan penumpang di jalan Allah.\" Aku pun menemukan lalu mengumpulkan."},"3269":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ عَنْ يُونُسَ بْنِ سَيْفٍ عَنِ الْحَارِثِ بْنِ غُطَيْفٍ أَوْ غُطَيْفِ بْنِ الْحَارِثِ قَالَمَا نَسِيتُ مِنْ الْأَشْيَاءِ لَمْ أَنْسَ أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah] dari [Yunus bin Saif] dari [Al Harits bin Ghuthoif atau Ghuthoif bin Al Harits] berkata; Aku tidak melupakan hal-hal yang tidak aku lupakan, aku melihat Rasulullah Shallallahu'alaihiWasallam meletakkan tangan kanan diatas tangan kiri beliau saat shalat."},"3270":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمِ بْنِ عَبْدِ اللَّهِ بْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ الْمَخْزُومِيِّ عَنْ أُمِّ سَلَمَةَ ابْنَةِ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمَّا نَزَلْنَا أَرْضَ الْحَبَشَةِ جَاوَرْنَا بِهَا خَيْرَ جَارٍ النَّجَاشِيَّ أَمَّنَّا عَلَى دِينِنَا وَعَبَدْنَا اللَّهَ تَعَالَى لَا نُؤْذَى وَلَا نَسْمَعُ شَيْئًا نَكْرَهُهُ فَلَمَّا بَلَغَ ذَلِكَ قُرَيْشًا ائْتَمَرُوا أَنْ يَبْعَثُوا إِلَى النَّجَاشِيِّ فِينَا رَجُلَيْنِ جَلْدَيْنِ وَأَنْ يُهْدُوا لِلنَّجَاشِيِّ هَدَايَا مِمَّا يُسْتَطْرَفُ مِنْ مَتَاعِ مَكَّةَ وَكَانَ مِنْ أَعْجَبِ مَا يَأْتِيهِ مِنْهَا إِلَيْهِ الْأَدَمُ فَجَمَعُوا لَهُ أَدَمًا كَثِيرًا وَلَمْ يَتْرُكُوا مِنْ بَطَارِقَتِهِ بِطْرِيقًا إِلَّا أَهْدَوْا لَهُ هَدِيَّةً ثُمَّ بَعَثُوا بِذَلِكَ عَبْدَ اللَّهِ بْنَ أَبِي رَبِيعَةَ بْنِ الْمُغِيرَةِ الْمَخْزُومِيَّ وَعَمْرَو بْنَ الْعَاصِ بْنِ وَائِلٍ السَّهْمِيَّ وَأَمَرُوهُمَا أَمْرَهُمْ وَقَالُوا لَهُمَا ادْفَعَا إِلَى كُلِّ بِطْرِيقٍ هَدِيَّتَهُ قَبْلَ أَنْ تُكَلِّمُوا النَّجَاشِيَّ فِيهِمْ ثُمَّ قَدِّمُوا لِلنَّجَاشِيِّ هَدَايَاهُ ثُمَّ سَلُوهُ أَنْ يُسَلِّمَهُمْ إِلَيْكُمْ قَبْلَ أَنْ يُكَلِّمَهُمْ قَالَتْ فَخَرَجَا فَقَدِمَا عَلَى النَّجَاشِيِّ وَنَحْنُ عِنْدَهُ بِخَيْرِ دَارٍ وَخَيْرِ جَارٍ فَلَمْ يَبْقَ مِنْ بَطَارِقَتِهِ بِطْرِيقٌ إِلَّا دَفَعَا إِلَيْهِ هَدِيَّتَهُ قَبْلَ أَنْ يُكَلِّمَا النَّجَاشِيَّ ثُمَّ قَالَ لِكُلِّ بِطْرِيقٍ مِنْهُمْ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِ الْمَلِكِ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكُمْ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتُمْ وَقَدْ بَعَثَنَا إِلَى الْمَلِكِ فِيهِمْ أَشْرَافُ قَوْمِهِمْ لِنَرُدَّهُمْ إِلَيْهِمْ فَإِذَا كَلَّمْنَا الْمَلِكَ فِيهِمْ فَأَشِيرُوا عَلَيْهِ بِأَنْ يُسَلِّمَهُمْ إِلَيْنَا وَلَا يُكَلِّمَهُمْ ف��إِنَّ قَوْمَهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَقَالُوا لَهُمَا نَعَمْ ثُمَّ إِنَّهُمَا قَرَّبَا هَدَايَاهُمْ إِلَى النَّجَاشِيِّ فَقَبِلَهَا مِنْهُمَا ثُمَّ كَلَّمَاهُ فَقَالَا لَهُ أَيُّهَا الْمَلِكُ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِكَ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكَ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتَ وَقَدْ بَعَثَنَا إِلَيْكَ فِيهِمْ أَشْرَافُ قَوْمِهِمْ مِنْ آبَائِهِمْ وَأَعْمَامِهِمْ وَعَشَائِرِهِمْ لِتَرُدَّهُمْ إِلَيْهِمْ فَهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ وَعَاتَبُوهُمْ فِيهِ قَالَتْ وَلَمْ يَكُنْ شَيْءٌ أَبْغَضُ إِلَى عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ وَعَمْرِو بْنِ الْعَاصِ مِنْ أَنْ يَسْمَعَ النَّجَاشِيُّ كَلَامَهُمْ فَقَالَتْ بَطَارِقَتُهُ حَوْلَهُ صَدَقُوا أَيُّهَا الْمَلِكُ قَوْمُهُمْ أَعْلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَأَسْلِمْهُمْ إِلَيْهِمَا فَلْيَرُدَّانِهِمْ إِلَى بِلَادِهِمْ وَقَوْمِهِمْ قَالَ فَغَضِبَ النَّجَاشِيُّ ثُمَّ قَالَ لَا هَايْمُ اللَّهِ إِذًا لَا أُسْلِمَهُمْ إِلَيْهِمَا وَلَا أَكَادُ قَوْمًا جَاوَرُونِي وَنَزَلُوا بِلَادِي وَاخْتَارُونِي عَلَى مَنْ سِوَايَ حَتَّى أَدْعُوَهُمْ فَأَسْأَلَهُمْ مَا يَقُولُ هَذَانِ فِي أَمْرِهِمْ فَإِنْ كَانُوا كَمَا يَقُولَانِ أَسْلَمْتُهُمْ إِلَيْهِمَا وَرَدَدْتُهُمْ إِلَى قَوْمِهِمْ وَإِنْ كَانُوا عَلَى غَيْرِ ذَلِكَ مَنَعْتُهُمْ مِنْهُمَا وَأَحْسَنْتُ جِوَارَهُمْ مَا جَاوَرُونِي قَالَتْ ثُمَّ أَرْسَلَ إِلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَاهُمْ فَلَمَّا جَاءَهُمْ رَسُولُهُ اجْتَمَعُوا ثُمَّ قَالَ بَعْضُهُمْ لِبَعْضٍ مَا تَقُولُونَ لِلرَّجُلِ إِذَا جِئْتُمُوهُ قَالُوا نَقُولُ وَاللَّهِ مَا عَلِمْنَا وَمَا أَمَرَنَا بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنٌ فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا جَاءُوهُ وَقَدْ دَعَا النَّجَاشِيُّ أَسَاقِفَتَهُ فَنَشَرُوا مَصَاحِفَهُمْ حَوْلَهُ لِيَسْأَلَهُمْ فَقَالَ مَا هَذَا الدِّينُ الَّذِي فَارَقْتُمْ فِيهِ قَوْمَكُمْ وَلَمْ تَدْخُلُوا فِي دِينِي وَلَا فِي دِينِ أَحَدٍ مِنْ هَذِهِ الْأُمَمِ قَالَتْ فَكَانَ الَّذِي كَلَّمَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ كُنَّا قَوْمًا أَهْلَ جَاهِلِيَّةٍ نَعْبُدُ الْأَصْنَامَ وَنَأْكُلُ الْمَيْتَةَ وَنَأْتِي الْفَوَاحِشَ وَنَقْطَعُ الْأَرْحَامَ وَنُسِيئُ الْجِوَارَ يَأْكُلُ الْقَوِيُّ مِنَّا الضَّعِيفَ فَكُنَّا عَلَى ذَلِكَ حَتَّى بَعَثَ اللَّهُ إِلَيْنَا رَسُولًا مِنَّا نَعْرِفُ نَسَبَهُ وَصِدْقَهُ وَأَمَانَتَهُ وَعَفَافَهُ فَدَعَانَا إِلَى اللَّهِ تَعَالَى لِنُوَحِّدَهُ وَنَعْبُدَهُ وَنَخْلَعَ مَا كُنَّا نَعْبُدُ نَحْنُ وَآبَاؤُنَا مِنْ دُونِهِ مِنْ الْحِجَارَةِ وَالْأَوْثَانِ وَأَمَرَ بِصِدْقِ الْحَدِيثِ وَأَدَاءِ الْأَمَانَةِ وَصِلَةِ الرَّحِمِ وَحُسْنِ الْجِوَارِ وَالْكَفِّ عَنْ الْمَحَارِمِ وَالدِّمَاءِ وَنَهَانَا عَنْ الْفَوَاحِشِ وَقَوْلِ الزُّورِ وَأَكْلِ مَالِ الْيَتِيمِ وَقَذْفِ الْمُحْصَنَةِ وَأَمَرَنَا أَنْ نَعْبُدَ اللَّهَ وَحْدَهُ لَا نُشْرِكُ بِهِ شَيْئًا وَأَمَرَنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّيَامِ قَالَ فَعَدَّدَ عَلَيْهِ أُمُورَ الْإِسْلَامِ فَصَدَّقْنَاهُ وَآمَنَّا بِهِ وَاتَّبَعْنَاهُ عَلَى مَا جَاءَ بِهِ فَعَبَدْنَا اللَّهَ وَحْدَهُ فَلَمْ نُشْرِكْ بِهِ شَيْئًا وَحَرَّمْنَا مَا حَرَّمَ عَلَيْنَا وَأَحْلَلْنَا مَا أَحَلَّ لَنَا فَعَدَا عَلَيْنَا قَوْمُنَا فَعَذَّبُونَا فَفَتَنُونَا عَنْ دِينِنَا لِيَرُدُّونَا إِلَى عِبَادَةِ الْأَوْثَانِ مِنْ عِبَادَةِ اللَّهِ وَأَنْ نَسْتَحِلَّ مَا كُنَّا نَسْتَحِلُّ مِنْ الْخَبَائِثِ وَلَمَّا قَهَرُونَا وَظَلَمُونَا وَشَقُّوا عَلَيْنَا وَحَالُوا بَيْنَنَا وَبَيْنَ دِينِنَا خَرَجْنَا إِلَى بَلَدِكَ وَاخْتَرْنَاكَ عَلَى مَنْ سِوَاكَ وَرَغِبْنَا فِي جِوَارِكَ وَرَجَوْنَا أَنْ لَا نُظْلَمَ عِنْدَكَ أَيُّهَا الْمَلِكُ قَالَتْ فَقَالَ لَهُ النَّجَاشِيُّ هَلْ مَعَكَ مِمَّا جَاءَ بِهِ عَنْ اللَّهِ مِنْ شَيْءٍ قَالَتْ فَقَالَ لَهُ جَعْفَرٌ نَعَمْ فَقَالَ لَهُ النَّجَاشِيُّ فَاقْرَأْهُ عَلَيَّ فَقَرَأَ عَلَيْهِ صَدْرًا مِنْ كهيعص قَالَتْ فَبَكَى وَاللَّهِ النَّجَاشِيُّ حَتَّى أَخْضَلَ لِحْيَتَهُ وَبَكَتْ أَسَاقِفَتُهُ حَتَّى أَخْضَلُوا مَصَاحِفَهُمْ حِينَ سَمِعُوا مَا تَلَا عَلَيْهِمْ ثُمَّ قَالَ النَّجَاشِيُّ إِنَّ هَذَا وَالَّذِي جَاءَ بِهِ مُوسَى لَيَخْرُجُ مِنْ مِشْكَاةٍ وَاحِدَةٍ انْطَلِقَا فَوَاللَّهِ لَا أُسْلِمُهُمْ إِلَيْكُمْ أَبَدًا وَلَا أَكَادُ قَالَتْ أُمُّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا فَلَمَّا خَرَجَا مِنْ عِنْدِهِ قَالَ عَمْرُو بْنُ الْعَاصِ وَاللَّهِ لَآتِيَنَّهُ غَدًا أَعِيبُهُمْ عِنْدَهُ ثُمَّ أَسْتَأْصِلُ بِهِ خَضْرَاءَهُمْ قَالَتْ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أَبِي رَبِيعَةَ وَكَانَ أَتْقَى الرَّجُلَيْنِ فِينَا لَا تَفْعَلْ فَإِنَّ لَهُمْ أَرْحَامًا وَإِنْ كَانُوا قَدْ خَالَفُونَا قَالَ وَاللَّهِ لَأُخْبِرَنَّهُ أَنَّهُمْ يَزْعُمُونَ أَنَّ عِيسَى ابْنَ مَرْيَمَ عَلَيْهِمَا السَّلَام عَبْدٌ قَالَتْ ثُمَّ غَدَا عَلَيْهِ الْغَدَ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ إِنَّهُمْ يَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ قَوْلًا عَظِيمًا فَأَرْسِلْ إِلَيْهِمْ فَسَلْهُمْ عَمَّا يَقُولُونَ فِيهِ قَالَتْ أُمُّ سَلَمَةَ فَأَرْسَلَ إِلَيْهِمْ يَسْأَلُهُمْ عَنْهُ قَالَتْ وَلَمْ يَنْزِلْ بِنَا مِثْلُهَا فَاجْتَمَعَ الْقَوْمُ فَقَالَ بَعْضُهُمْ لِبَعْضٍ مَاذَا تَقُولُونَ فِي عِيسَى إِذَا سَأَلَكُمْ عَنْهُ قَالُوا نَقُولُ وَاللَّهِ فِيهِ مَا قَالَ اللَّهُ سُبْحَانَهُ وَتَعَالَى وَمَا جَاءَ بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنًا فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا دَخَلُوا عَلَيْهِ قَالَ لَهُمْ مَا تَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ فَقَالَ لَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ نَقُولُ فِيهِ الَّذِي جَاءَ بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ عَبْدُ اللَّهِ وَرَسُولُهُ وَرُوحُهُ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ الْعَذْرَاءِ الْبَتُولِ قَالَتْ فَضَرَبَ النَّجَاشِيُّ يَدَهُ عَلَى الْأَرْضِ فَأَخَذَ مِنْهَا عُودًا ثُمَّ قَالَ مَا عَدَا عِيسَى ابْنُ مَرْيَمَ مَا قُلْتَ هَذَا الْعُودَ فَنَاخَرَتْ بَطَارِقَتُهُ حَوْلَهُ حِينَ قَالَ مَا قَالَ فَقَالَ وَإِنْ نَخَرْتُمْ وَاللَّهِ اذْهَبُوا فَأَنْتُمْ سُيُومٌ بِأَرْضِي وَالسُّيُومُ الْآمِنُونَ مَنْ سَبَّكُمْ غَرِمَ ثُمَّ مَنْ سَبَّكُمْ غَرِمَ ثُمَّ مَنْ سَبَّكُمْ غَرِمَ فَمَا أُحِبُّ أَنَّ لِي دَبْرَ ذَهَبٍ وَأَنِّي آذَيْتُ رَجُلًا مِنْكُمْ وَالدَّبْرُ بِلِسَانِ الْحَبَشَةِ الْجَبَلُ رُدُّوا عَلَيْهِمَا هَدَايَاهُمَا فَلَا حَاجَةَ لَنَا بِهَا فَوَاللَّهِ مَا أَخَذَ اللَّهُ مِنِّي الرِّشْوَةَ حِينَ رَدَّ عَلَيَّ مُلْكِي فَآخُذَ الرِّشْوَةَ فِيهِ وَمَا أَطَاعَ فِيَّ النَّاسَ فَأُطِيعَهُمْ فِيهِ قَالَتْ فَخَرَجَا مِنْ عِنْدِهِ مَقْبُوحَيْنِ مَرْدُودًا عَلَيْهِمَا مَا جَاءَا بِهِ وَأَقَمْنَا عِنْدَهُ بِخَيْرِ دَارٍ مَعَ خَيْرِ جَارٍ قَالَتْ فَوَاللَّهِ إِنَّا عَلَى ذَلِكَ إِذْ نَزَلَ بِهِ يَعْنِي مَنْ يُنَازِعُهُ فِي مُلْكِهِ قَالَتْ فَوَاللَّهِ مَا عَلِمْنَا حُزْنًا قَطُّ كَانَ أَشَدَّ مِنْ حُزْنٍ حَزِنَّاهُ عِنْدَ ذَلِكَ تَخَوُّفًا أَنْ يَظْهَرَ ذَلِكَ عَلَى النَّجَاشِيِّ فَيَأْتِيَ رَجُلٌ لَا يَعْرِفُ مِنْ حَقِّنَا مَا كَانَ النَّجَاشِيُّ يَعْرِفُ مِنْهُ قَالَتْ وَسَارَ النَّجَاشِيُّ وَبَيْنَهُمَا عُرْضُ النِّيلِ قَالَ فَق","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Muhammad bin Muslim bin 'Abdullah bin Syihab] dari [Abu Bakr bin 'Abdur Rahman bin Al Harits bin Hisyam Al Makhzumi] dari [Ummu Salamah binti Abu Umaiyah bin Al Mughirah istri Nabi Shallallahu'alaihiwasallam] berkata; Saat kami tinggal ditanah Habasyah dan kami tinggal bersama tetangga yang baik An Najasy, ia memberi jaminan keamanan atas agama kami, kami menyembah Allah subhanahu wata'ala, kami tidak diganggu dan kami tidak mendengar sesuatu pun yang tidak kami sukai. Saat hal itu terdengar oleh kaum Quraisy, mereka bersekongkol untuk mengutus dua orang kuat untuk menemui An Najasy tentang kami dan memberi hadiah barang Mekkah yang paling menakjubkan. Ketika itu, barang yang paling menakjubkan baginya adalah kulit yang disamak buatan Makkah. Maka mereka kumpulkan sebanyak-banyaknya. Tidaklah mereka tinggalkan satu pun panglima pasukan Najasyi melainkan pasti diberinya hadiah. Orang yang ditugasi Quraisy untuk mengirim hadiah-hadiah ini adalah 'Abdullah bin Rabi'ah bin Al Mughirah Al Makhzumi dan 'Amr bin Al 'Ash bin Wa`il As Sahmi. Mereka limpahkan kepentingan mereka kepada dua orang ini, seraya mereka katakan kepada keduanya; 'Tolong, serahkan hadiah kepada setiap komandan pasukan sebelum kalian berbicara dengan An Najasy ditengah-tengah mereka, setelah itu serahkan hadiah untuk An Najasy. Dan mintalah dia agar menyerahkankan orang-orang muslim itu kepada kalian berdua sebelum dia mengajak bicara mereka. (Ummu Salamah) mengatakan; Kami tinggal dan bertetangga baik dengannya. Tidak ada satu pun komandan Najasyi melainkan pasti diberi hadiah oleh keduanya sebelum keduanya berbicara dengan An Najasy, kemudian berkata kepada semua petinggi-petinggi Negara saat itu; Sesungguhnya orang-orang tolol kami telah datang ke negeri sang raja, mereka meninggalkan agama mereka dan mereka tidak masuk ke dalam agama kalian, mereka membawa agama baru yang sama-sama tidak kami dan kalian kenal. Para pembesar mereka mengutus kami kepada sang raja agar mengembalikan mereka. Bila kami berbicara dengan sang raja tentang mereka, berisyaratlah kalian kepadanya agar menyerahkan mereka kepada kami dan jangan sampai sang raja mengajak berbicara dengan mereka karena mereka lebih tahu terhadap satu persatu diantara mereka dan kekurangan-kekurangan mereka. Para petinggi Najasyi berkata kepada keduanya; Baik. Selanjutnya keduanya menyerahkan hadiah-hadiah kepada An Najasy lalu diterima dari keduanya. Selanjutnya mereka berdua berbicara pada An Najasy; Wahai raja! Sesungguhnya orang-orang tolol kami kami telah mendatangi negeri raja, mereka meninggalkan agama kaum mereka dan tidak mau masuk ke dalam agamamu, mereka membawa agama baru yang tidak kami kenal dan tidak juga engkau. Para pembesar kaum mereka, ayah-ayah mereka, paman-paman mereka, dan kelompok-kelompok mereka mengutus kami dengan tujuan agar baginda raja mau mengembalikan mereka. Yang demikian karena mereka lebih tahu terhadap satu persatu diantara mereka dan tahu borok-borok kekurangan dan aib mereka. Berkata Ummu Salamah; Dan sebenarnya tidak ada sesuatu hal yang lebih dibenci oleh 'Abdullah bin Abu Robi'ah dan 'Amr bin Al 'Ash daripada jika An Najasy mau mendengar keluh kesah mereka. Para petinggi negara di sekitar raja lantas berkata; Utusan ini benar, wahai raja. Kaum mereka lebih tahu perihal kejelekan-kejelekan mereka, maka serahkan saja mereka kepada keduanya untuk dikembalikan ke negeri dan kaum mereka. Ternyata raja An Najasy justeru marah atas celaan yang mereka lancarkan lalu berkata; 'Tidak demi Allah, sekali-kali aku tidak akan menyerahkan mereka kepada keduanya. Tidak bakalan aku melakukan tindak kejahatan kepada suatu kaum yang bertetangga denganku, tinggal dinegeriku dan memilihku dari selainku, hingga aku memanggil mereka dan menanyakan mereka tentang perkataan kedua utusan ini mengenai mereka. Bila mereka seperti yang dikatakan oleh kedua utusan ini, akan kuserahkan mereka kepada keduanya dan akan kukembalikan kepada kaum mereka. Sebaliknya bila tidak, maka aku melindungi mereka dari kedua orang ini dan aku akan bertetangga baik dengan mereka selama mereka bertetangga baik denganku. Berkata Ummu Salamah; Kemudian An Najasy mengirim utusan untuk menemui sahabat-sahabat Rasulullah Shallallahu'alaihiWasallam dan memanggil mereka. Saat utusan An Najasy datang, para sahabat muslimin berkumpul dan saling berkata satu sama lain; Bagaimana pendapat kalian tentang orang itu bila kalian menemuinya?. Mereka menjawab; Demi Allah, Kita mengatakan terus terang apa yang kita ketahui, dan yang Nabi Shallallahu'alaihiWasallam perintahkan kepada kita dan terjadilah segala yang terjadi. Saat utusan itu kembali menemui An Najasy, An Najasy telah memanggil uskup-uskupnya, dan menyebarkan kitab suci mereka disekitar An Najasy untuk menanyai para sahabat muslimin. Raja Najasy bertanya; 'Tolong jelaskan agama yang kalian anut, yang karenanya kalian kalian berpisah dengan kaum kalian dan kalian tidak mau masuk ke dalam agamaku, tidak juga kepada satu pun agama yang dianut manusia? Berkata Ummu Salamah; Yang tampil menjawab pertanyaan raja adalah [Ja'far bin bu Thalib]. Ia berkata kepada An Najasy; 'Wahai raja! Dulunya kami kaum jahiliyah, kami dulu menyembah berhala, gemar makan bangkai, melakukan tindakan-tindakan keji, memutuskan tali sillaturrahim, bersikap buruk terhadap tetangga, yang kuat mencaplok yang lemah dan kami berada dalam kondisi seperti itu hingga Allah mengutus seorang rasul dari kalangan kami, kami mengenal nasab, kejujuran dan keamanahannya. Ia menyerukan kami kepada Allah Subhanahu wa ta'ala untuk kami esakan, kami sembah dan kami lepaskan apa pun yang kami dan nenek moyang kami sembah selain Allah seperti batu dan berhala, ia memerintahkan kami agar berbicara dengan jujur, menunaikan amanah, menyambung tali sillaturrahim, bersikap baik terhadap tetangga, menjaga diri dari keharaman, memerintahkan kami agar berdoa dan melarang kami dari perbuatan-perbuatan keji, berkata dusta, memakan harta anak yatim, menuduh wanita bersuami berzina, memerintahkan kami untuk menyembah Allah semata, tidak menyekutukannya dengan apa pun, memerintahkan kami agar menunaikan shalat, zakat dan berpuasa. Ia menyebarkan ajaran-ajaran Islam, kami mempercayai dan mengimaninya, kami mengikuti ajaran yang ia bawa, kami menyembah Allah semata dan tidak menyekutukanNya dengan apa pun, kami mengharamkan yang diharamkan pada kami dan menghalalkan yang dihalalkan bagi kami lalu kaum kami memusuhi kami, mereka menyiksa dan menimpakan ujian pada kami karena masalah agama kami agar mereka mengembalikan kami menyembah berhala lagi selain Allah, menghalalkan kekejian-kekejian yang dulu pernah kami lakukan. Saat mereka memaksa kami, menzhalimi kami dan memecah kami, mereka menghalangi kami untuk menjalankan agama kami akhirnya kami pergi ke negerimu, kami lebih memilihmu atas selainmu, kami ingin bertetangga denganmu dan kami harap engkau tidak mendzalimi kami wahai raja. Berkata Ummu Salamah; An Najasy berkata padanya; Mungkin kalian bisa membacakan yang Rasulullah terima dari Allah? Ja'far menjawab; Ya. An Najasy berkata; Bacalah. Kemudian Ja'far membaca permulaan surat Maryam lalu An Najasy menangis, demi Allah, sampai membasahi jenggotnya, dan uskup-uskupnya pun menangis hingga membasahi kitab suci-kitab suci mereka saat mendengar yang dibacakan Ja'far kepada mereka. Kemudian An Najasy berkomentar; Sesungguhnya ini demi yang dibawa Musa, berasal dari lentera yang sama. Demi Allah, aku tidak bakalan menyerahkan mereka kepada kalian dan tidak akan berbuat yang tidak-tidak untuk mereka. Berkata Ummu Salamah; Saat keduanya keluar meninggalkan An Najasy, berkata 'Amr bin Al 'Ash; 'Demi Allah, aku akan mendatanginya lagi besok, dan akan kucela mereka didekatnya, kemudian mereka akan aku habisi hingga ke akar-akarnya. Berkata Ummu Salamah; 'Abdullah bin Abu Robi'ah, orang yang paling menahan diri diantara dua orang itu bagi kami berkata padanya; 'Jangan kau lakukan karena mereka memiliki kerabat meski mereka berselisih dengan kami.' 'Amru bin 'Ash mengatakan; 'Demi Allah, akan kuberitahu mereka bahwa mereka menilai 'Isa putra Maryam adalah seorang hamba.' Berkata Ummu Salamah; Kemudian 'Amr pergi di keesokan harinya lalu berkata kepada An Najasy; Wahai raja! Sesungguhnya mereka mengemukakan komentar yang lancang tentang 'Isa putra Maryam. Utuslah seseorang untuk menemui mereka dan tanyakan kepada mereka bagaimana pendapat mereka tentang 'Isa. Berkata Ummu Salamah; An Najasy mengirim utusan untuk menanyakan pandangan mereka tentang 'Isa. Kaum muslimin berkumpul lalu sebagaian dari mereka berkata kepada yang lain; Apa yang akan kalian katakan tentang 'Isa bila raja bertanya pada kalian. Mereka berkata; Demi Allah, akan kami katakan seperti yang difirmankan Allah subhanahu wata'ala tentangnya dan yang dibawa oleh Nabi Shallallahu'alaihiWasallam tentang hal itu bagaimana pun juga. Saat kaum muslimin mendatangi An Najasy, ia bertanya pada mereka; Bagaimana pandangan kalian tentang 'Isa putra Maryam? Ja'far bin Abu Thalib Radliyallahu'anhu menjawab; Pendapat kami seperti yang disampaikan Nabi kami, dia adalah hamba dan rasul Allah, ruh dan kalimatNya yang disematkan kepada Maryam, perawan suci. Berkata Ummu Salamah; An Najasy memukulkan tangannya ke tanah lalu mengambil sebilah kayu dan berkata; Selain 'Isa putra Maryam, bagaimana pendapatmu tentang kayu ini?. Para petinggi kerajaan lantas berbincang-bincang tentang suatu hal yang tak bisa dimengerti. Lantas raja berkata; Kendatipun kalian wahai petinggi kerajaanku masih berbincang-bincang, pergilah kalian dengan aman wahai muslimin di tanahku, siapa pun yang menawan kalian dia harus mengganti jaminan, siapa pun yang menawan kalian harus mengganti jaminan, siapa pun yang menawan kalian harus mengganti jaminan. Aku tidak mau memiliki segunung emas sementara aku menyakiti salah seorang dari kalian. Kembalikan hadiah mereka berdua, kami tidak memerlukannya. Demi Allah, Allah tidak mengambil suap dariku saat mengembalikan kerajaanku kepadaku lalu bagaimana mungkin aku mengambilnya? Dan tidaklah mungkin manusia yang Allah jadikan taat kepadaku, lalu aku langsung taat begitu saja kepada mereka. Berkata Ummu Salamah; Keduanya pergi meninggalkannya dengan menanggung malu dan tertolak tujuannya. Kami tinggal dinegerinya dengan baik dan bersama tetangga yang baik. Demi Allah, kami terus seperti itu hingga ada yang menentangnya dalam kekuasaannya. Demi Allah, kami tidak mengetahui kesedihan yang lebih besar dari kesedihan yang menimpa kami saat itu karena kami khawatir muncul raja baru yang tidak mengenal hak kami seperti yang dikenali oleh An Najasy. Berkata Ummu Salamah; An Najasy berjalan dan diantara keduanya ada lembah sungai Nil. Kemudian para sahabat Rasulullah Shallallahu'alaihiWasallam berkata; Siapa yang mau pergi untuk menghadiri peristiwa yang terjadi lalu datang membawa khabar untuk kami. Berkata Ummu Salamah; Berkata Az Zubair bin Al 'Awwam Radliyallahu'anhu; Aku. Dan ia yang paling muda diantara kami. Mereka meniup geriba untuknya lalu diletakkan didada lalu berenang hingga ke tepi sungai Nil tempat bertemunya kaum. Ia pergi hingga mendatangi mereka dan kami berdoa kepada Allah subhanahu wata'ala untuk An Najasy agar mengalahkan musuhnya, kembali berkuasa diatas negerinya dan urusan rakyat Habasyah menguat. Kami tinggal ditempat terbaik disisinya hingga kami mendatangi Rasulullah Shallallahu'alaihiWasallam saat beliau di Mekah."},"3271":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي عُثْمَانَ عَنْ خَالِدِ بْنِ عُرْفُطَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا خَالِدُ إِنَّهَا سَتَكُونُ بَعْدِي أَحْدَاثٌ وَفِتَنٌ وَاخْتِلَافٌ فَإِنْ اسْتَطَعْتَ أَنْ تَكُونَ عَبْدَ اللَّهِ الْمَقْتُولَ لَا الْقَاتِلَ فَافْعَلْ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] telah menceritakan kepada kami [Hammd bin Salamah] dari ['Ali bin Zaid] dari [Abu 'Utsman] dari [Khalid bin 'Urfuthoh] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda kepadaku; \"Hai Khalid! Akan ada beberapa perisitiwa, fitnah dan perselisihan sepeninggalku, bila kau bisa menjadi hamba Allah yang terbunuh, bukan pembunuh, lakukan.\""},"3272":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَسَارٍ قَالَكُنْتُ جَالِسًا مَعَ سُلَيْمَانَ بْنِ صُرَدٍ وَخَالِدِ بْنِ عُرْفُطَةَ قَالَ فَذَكَرُوا رَجُلًا مَاتَ مِنْ بَطْنِهِ قَالَ فَكَأَنَّمَا اشْتَهَيَا أَنْ يُصَلِّيَا عَلَيْهِ قَالَ فَقَالَ أَحَدُهُمَا لِلْآخَرِ أَلَمْ يَقُلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَهُ بَطْنُهُ فَإِنَّهُ لَنْ يُعَذَّبَ فِي قَبْرِهِ قَالَ الْآخَرُ بَلَى","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad] berkata; Aku mendengar ['Abdullah bin Yasar] berkata; Aku duduk bersama [Sulaiman bin Shurod] dan [Khalid bin Ghurfuthah], mereka menyebutkan seseorang yang meninggal dunia karena sakit perut. Sepertinya kami hendak menshalatinya kemudian salah satu dari keduanya berkata kepada yang lain; Bukankah Nabi Shallallahu'alaihiWasallam bersabda; \"Barangsiapa yang mati karena sakit perut maka ia tidak akan disiksa didalam kuburnya?.\" Yang lain menjawab; Benar."},"3273":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ حَدَّثَنَا خَالِدُ بْنُ سَلَمَةَ حَدَّثَنَا مُسْلِمٌ مَوْلَى خَالِدِ بْنِ عُرْفُطَةَ أَنَّ خَالِدَ بْنَ عُرْفُطَةَ قَالَ وَسَمِعْتُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ يَعْنِي حَدَّثَنَا مُسْلِمٌ مَوْلَى خَالِدِ بْنِ عُرْفُطَةَ أَنَّ خَالِدَ بْنَ عُرْفُطَةَ قَالَ لِلْمُخْتَارِ هَذَا رَجُلٌ كَذَّابٌ وَلَقَدْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ جَهَنَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Zakariya bin Abu Za`idah] telah menceritakan kepada kami [Khalid bin Salamah] telah menceritakan kepada kami [Muslim, budak Khalid bin 'Urfuthah] bahwa [Khalid bin 'Urfuthah] berkata -dan saya menengar dari 'Adullah bin Muhammad bin Abu Syaibah; Telah menceritakan kepada kami Muslim, budak Khalid bin Ghurfuthah bahwa Khalid bin Ghurfuthah berkata kepada Al Mukhtar; Dia pendusta- saya mendengar Nabi Shallallahu'alaihiWasallam bersabda; \"Barangsiapa berdusta atas namaku maka hendaknya mempersiapkan tempatnya di neraka jahannam.\""},"3274":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ طَارِقِ بْنِ سُوَيْدٍ الْحَضْرَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بِأَرْضِنَا أَعْنَابًا نَعْصِرُهَا أَفَنَشْرَبُ مِنْهَا قَالَ لَا فَرَاجَعْتُهُ فَقَالَ لَا ثُمَّ رَاجَعْتُهُ فَقَالَ لَا فَقُلْتُ إِنَّا نَسْتَشْفِي بِهَا لِلْمَرِيضِ قَالَ إِنَّهُ لَيْسَ بِشِفَاءٍ وَلَكِنَّهُ دَاءٌ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad] dari [Simak bin Harb] dari ['Alqamah bin Wa`il] dari [Thariq bin Suwaid Al Hadhromi] berkata; Aku berkata; Wahai Rasulullah! Di tanah kami ada anggur yang kami peras, bolehkan kami meminumnya?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Tidak.\" Kemudian aku merujuk beliau lagi, beliau bersabda; \"Tidak.\" Kemudian aku merujuk beliau lagi, beliau bersabda; \"Tidak.\" Lalu aku berkata; \"Kami memakainya untuk menyembuhkan orang sakit.\" Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ia bukan obat tapi penyakit.\""},"3275":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زُهْرَةُ يَعْنِي ابْنَ مَعْبَدِ بْنِ عَبْدِ اللَّهِ بْنِ هِشَامٍ أَبُو عَقِيلٍ عَنْ جَدِّهِ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ آخِذٌ بِيَدِ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَقَالَ عُمَرُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَأَنْتَ أَحَبُّ إِلَيَّ مِنْ كُلِّ شَيْءٍ إِلَّا نَفْسِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَالَّذِي نَفْسِي بِيَدِهِ حَتَّى أَكُونَ أَحَبَّ إِلَيْكَ مِنْ نَفْسِكَ قَالَ عُمَرُ فَأَنْتَ الْآنَ وَاللَّهِ أَحَبُّ إِلَيَّ مِنْ نَفْسِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآنَ يَا عُمَرُ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Zuhroh bin Ma'bad bin 'Abdullah bin Hisyam Abu 'Aqil] dari [kakeknya] berkata; Aku bersama Rasulullah Shallallahu'alaihiwasallam, beliau menggandeng tangan Umar bin Al Khaththab Radliyallahu'anhu, 'Umar berkata; Demi Allah wahai Rasulullah! Engkau lebih aku cintai dari apa pun kecuali diriku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Tidak, demi Dzat yang jiwaku berada ditanganNya, hingga aku lebih kau cintai dari dirimu sendiri.\" Berkata 'Umar; Engkau sekarang, demi Allah, lebih aku cintai melebihi diriku sendiri. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Sekarang baru benar, wahai 'Umar.\""},"3276":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا زُهْرَةُ أَبُو عَقِيلٍ الْقُرَشِيُّأَنَّ جَدَّهُ عَبْدَ اللَّهِ بْنَ هِشَامٍ احْتَلَمَ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَكَحَ النِّسَاءَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Zuhroh Abu 'Aqil Al Qurosy] bahwa kakeknya ['Abdullah bin Hisyam] bermimpi basah dimasa Rasulullah Shallallahu'alaihiWasallam dan menikahi wanita-wanita."},"3277":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنِ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ حَرَامِ بْنِ مُعَاوِيَةَ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُؤَاكَلَةِ الْحَائِضِ فَقَالَ وَاكِلْهَا","id":"Telah menceritakan kepada kami ['Abdur Rahman] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Al 'Alaa` bin Al Harits] dari [Harom bin Mu'awiyah] dari pamannya ['Abdullah bin Sa'ad] berkata; Aku bertanya kepada Nabi Shallallahu'alaihiWasallam tentang menemani makan wanita yang sedang haidh, beliau bersabda; (Boleh) juga menyuapinya."},"3278":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا الْبَخْتَرِيِّ الطَّائِيَّ قَالَ أَخْبَرَنِي مَنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يَهْلِكَ النَّاسُ حَتَّى يُعْذِرُوا مِنْ أَنْفُسِهِمْ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] berkata; Saya mendengar [Abu Al Bahkhturi Ath Tho`i] berkata; Telah mengkhabarkan kepadaku [orang yang telah mendengar] Nabi Shallallahu'alaihiWasallam bersabda; \"Manusia tidak akan binasa hingga mereka mengemukakan alasan dari diri mereka.\""},"3279":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَمَّنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّ الْعَارِيَةَ مُؤَدَّاةٌ وَالْمِنْحَةَ مَرْدُودَةٌ وَالدَّيْنَ مَقْضِيٌّ وَالزَّعِيمَ غَارِمٌ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] telah mengkhabarkan kepada kami [Ibnu Mubarok] telah menceritakan kepada kami ['Abdur Rahman bin Yazid bin Jabir] berkata; Telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [seseorang] yang telah mendengar Nabi Shallallahu'alaihiWasallam bersabda; \"Ingatlah sesungguhnya barang pinjaman harus dikembalikan, pemberian sebaiknya dibalas, hutang harus dilunasi dan pemimpin itu menjamin tanggung jawab.\""},"3280":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا إِسْحَاقُ يَعْنِي ابْنَ أَبِي طَلْحَةَ عَنْ أَبِي الْمُنْذِرِ مَوْلَى أَبِي ذَرٍّ عَنْ أَبِي أُمَيَّةَ الْمَخْزُومِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلِصٍّ فَاعْتَرَفَ وَلَمْ يُوجَدْ مَعَهُ مَتَاعٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَخَالُكَ سَرَقْتَ قَالَ بَلَى مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْطَعُوهُ ثُمَّ جِيئُوا بِهِ قَالَ فَقَطَعُوهُ ثُمَّ جَاءُوا بِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ قَالَ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ تُبْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad] telah mengkhabarkan kepada kami [Ishaq bin Abu Thalhah] dari [Abu Al Mundzir, budak Abu Dzarr] dari [Abu Umaiyah Al Makhzumi] bahwa seorang pencuri dihadapkan ke Rasulullah Shallallahu'alaihiWasallam kemudian ia mengakui tapi barangnya tidak bersamanya, Rasulullah Shallallahu'alaihiWasallam bersabda kepadanya; \"Menurutku kau tidak mencuri.\" Orang itu menjawab; Betul, aku telah mencuri. Orang itu mengulangi ucapannya sebanyak dua atau tiga kali, kemudian Rasulullah Shallallahu'alaihiWasallam bersabda; \"Potonglah tangannya.\" Mereka membawanya lalu memotong tangannya. Setelah itu mereka membawanya kemudian Rasulullah Shallallahu'alaihiWasallam bersabda padanya; \"Ucapkan; Aku meminta ampun pada Allah dan bertaubat padaNya.\" Ia berkata; Aku meminta ampun pada Allah dan bertaubat padaNya. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ya Allah! terimalah taubatnya.\""},"3281":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ زَائِدَةَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَخْبَرَهُ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَلَمَّا رَجَعْنَا لَقِيَنَا دَاعِي امْرَأَةٍ مِنْ قُرَيْشٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانَةَ تَدْعُوكَ وَمَنْ مَعَكَ إِلَى طَعَامٍ فَانْصَرَفَ فَانْصَرَفْنَا مَعَهُ فَجَلَسْنَا مَجَالِسَ الْغِلْمَانِ مِنْ آبَائِهِمْ بَيْنَ أَيْدِيهِمْ ثُمَّ جِيءَ بِالطَّعَامِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ وَوَضَعَ الْقَوْمُ أَيْدِيَهُمْ فَفَطِنَ لَهُ الْقَوْمُ وَهُوَ يَلُوكُ لُقْمَتَهُ لَا يُجِيزُهَا فَرَفَعُوا أَيْدِيَهُمْ وَغَفَلُوا عَنَّا ثُمَّ ذَكَرُوا فَأَخَذُوا بِأَيْدِينَا فَجَعَلَ الرَّجُلُ يَضْرِبُ اللُّقْمَةَ بِيَدِهِ حَتَّى تَسْقُطَ ثُمَّ أَمْسَكُوا بِأَيْدِينَا يَنْظُرُونَ مَا يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَفَظَهَا فَأَلْقَاهَا فَقَالَ أَجِدُ لَحْمَ شَاةٍ أُخِذَتْ بِغَيْرِ إِذْنِ أَهْلِهَا فَقَامَتْ الْمَرْأَةُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهُ كَانَ فِي نَفْسِي أَنْ أَجْمَعَكَ وَمَنْ مَعَكَ عَلَى طَعَامٍ فَأَرْسَلْتُ إِلَى الْبَقِيعِ فَلَمْ أَجِدْ شَاةً تُبَاعُ وَكَانَ عَامِرُ بْنُ أَبِي وَقَّاصٍ ابْتَاعَ شَاةً أَمْسِ مِنْ الْبَقِيعِ فَأَرْسَلْتُ إِلَيْهِ أَنْ ابْتُغِيَ لِي شَاةٌ فِي الْبَقِيعِ فَلَمْ تُوجَدْ فَذُكِرَ لِي أَنَّكَ اشْتَرَيْتَ شَاةً فَأَرْسِلْ بِهَا إِلَيَّ فَلَمْ يَجِدْهُ الرَّسُولُ وَوَجَدَ أَهْلَهُ فَدَفَعُوهَا إِلَى رَسُولِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْعِمُوهَا الْأُسَارَى","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amr] telah menceritakan kepada kami [Abu Ishaq] dari [Za`idah] dari ['Ashim bin Kulaib] dari [ayahnya] bahwa [seseorang dari Anshor] memberi khabar padanya, ia berkata; Kami pergi bersama Rasulullah Shallallahu'alaihiWasallam mengikuti jenazah. Saat kembali, kami bertemu seorang utusan wanita Quraisy. Utusan itu mengatakan; 'Hai Rasulullah Shallallahu'alaihiWasallam, si Fulanah mengundangmu dan orang-orang yang bersamamu untuk makan.\" Nabi shallallahu 'alaihi wasallam pun berangkat dan kami berangkat bersamanya. Lalu kami duduk seperti duduknya anak-anak di depan ayah-ayah mereka. Kemudian makanan dihidangkan, Rasulullah Shallallahu'alaihiWasallam meletakkan tangan kemudian orang-orang meletakkan tangan. Orang-orang memahami saat beliau mengunyah makanan, itu pertanda beliau tidak membolehkannya. Lalu orang-orang mengangkat tangan dan melalaikan kami. Lalu mereka ingat, dan meraih tangan kami. Kemudian seseorang memukul makanan yang ada ditangannya hingga jatuh, lalu mereka menahan tangan kami, mereka melihat apa yang dilakukan Rasulullah Shallallahu'alaihiwasallam. Beliau membuang dan melemparnya, beliau bersabda; \"Aku menemukan daging kambing yang diambil tanpa izin dari pemiliknya.\" Wanita itu berdiri lalu berkata; 'Wahai Rasulullah! Niatku semula, aku ingin mengumpulkan baginda dan orang-orang yang bersama baginda untuk hidangan makanan, kemudian aku pergi ke Baqi' tapi aku tidak menemukan adanya kambing yang dijual, sedang 'Amir bin Abu Waqqash membeli kambing dari Baqi' kemarin, aku mengutus seorang utusan kepadanya agar ia mencarikanku seekor kambing di Baqi' tapi tidak ada, kemudian ada yang bercerita kepadaku bahwa engkau telah membeli seekor kambing, maka kirimkanlah kepadaku, tapi utusanku tidak menemukannya. Keuarganya lantas menemukannya lalu mereka serahkan kepada Rasulullah Shallallahu'alaihiWasallam bersabda dan beliau bersabda; \"Berikan kepada para tawanan.\""},"3282":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ حَدَّثَنَا السُّمَيْطُ عَنْ أَبِي السَّوَّارِ حَدَّثَهُ أَبُو السَّوَّارِ عَنْ خَالِهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُنَاسٌ يَتْبَعُونَهُ فَأَتْبَعْتُهُ مَعَهُمْ قَالَ فَفَجِئَنِي الْقَوْمُ يَسْعَوْنَ قَالَ وَأَبْقَى الْقَوْمُ قَالَ فَأَتَى عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبَنِي ضَرْبَةً إِمَّا بِعَسِيبٍ أَوْ قَضِيبٍ أَوْ سِوَاكٍ وَشَيْءٍ كَانَ مَعَهُ قَالَ فَوَاللَّهِ مَا أَوْجَعَنِي قَالَ فَبِتُّ بِلَيْلَةٍ قَالَ أَوْ قُلْتُ مَا ضَرَبَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا لِشَيْءٍ عَلِمَهُ اللَّهُ فِيَّ قَالَ وَحَدَّثَتْنِي نَفْسِي أَنْ آتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصْبَحْتُ قَالَ فَنَزَلَ جِبْرِيلُ عَلَيْهِ السَّلَام عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّكَ رَاعٍ لَا تَكْسِرَنَّ قُرُونَ رَعِيَّتِكَ قَالَ فَلَمَّا صَلَّيْنَا الْغَدَاةَ أَوْ قَالَ صَبَّحْنَا قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنَّ أُنَاسًا يَتْبَعُونِي وَإِنِّي لَا يُعْجِبُنِي أَنْ يَتْبَعُونِي اللَّهُمَّ فَمَنْ ضَرَبْتُ أَوْ سَبَبْتُ فَاجْعَلْهَا لَهُ كَفَّارَةً وَأَجْرًا أَوْ قَالَ مَغْفِرَةً وَرَحْمَةً أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami ['Arim] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] telah menceritakan kepada kami [As Sumaith] dari [Abu As Sawwar] telah menceritakan kepadanya dari [pamannya], berkata; Saya melihat Rasulullah Shallallahu'alaihiWasallam diikuti oleh orang-orang lalu saya turut mengikuti mereka. Sekelompok kaum tiba-tiba datang, mereka berlari-lari kecil kemudian Rasulullah Shallallahu'alaihiWasallam mendatangiku kemudian memukulku dengan tulang ekor, dahan, siwak atau suatu benda yang beliau bawa. Demi Allah pukulan itu tidak menyakitiku lalu aku bermalam atau berkata; Tidaklah Rasulullah Shallallahu'alaihiWasallam memukulku kecuali karena suatu hal yang diketahui Allah subhanahu wata'ala berkenaan denganku. Hatiku berkata aku harus mendatangi Rasulullah Shallallahu'alaihiWasallam pagi nanti. Kemudian Jibril 'alaihissalam turun mendatangi Nabi Shallallahu'alaihiWasallam dan berkata; 'Engkau adalah penggembala, janganlah kau mematahkan tanduk gembalaanmu.' Berkata Abu As Sawwar; Saat kami shalat shubuh -atau berkata; Dipagi harinya- Rasulullah Shallallahu'alaihiWasallam bersabda; \"Orang-orang mengikutiku dan aku tidak suka diikuti. Ya Allah! Orang yang aku pukul atau cela, jadikanlah itu sebagai penghapus dosanya dan sebagai pahala\" -atau bersabda; Ampunan, rahmat, atau seperti yang beliau sabdakan."},"3283":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا هُرَيْمُ بْنُ سُفْيَانَ عَنْ بَيَانٍ عَنْ قَيْسٍ عَنْ أَبِي شَهْمٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَرَّتْ بِي جَارِيَةٌ بِالْمَدِينَةِ فَأَخَذْتُ بِكَشْحِهَا قَالَ وَأَصْبَحَ الرَّسُولُ يُبَايِعُ النَّاسَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَيْتُهُ فَلَمْ يُبَايِعْنِي فَقَالَ صَاحِبُ الْجُبَيْذَةِ الْآنَ قَالَ قُلْتُ وَاللَّهِ لَا أَعُودُ قَالَ فَبَايَعَنِي","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Huroim bin Sufyan] dari [Bayan] dari [Qais] dari [Abu Syahm Radliyallahu'anhu] berkata; Seorang budak wanita melewatiku di Madinah lalu aku menarik pinggulnya. Dipagi harinya Rasulullah Shallallahu'alaihiWasallam membaiat semua orang kemudian aku mendatangi beliau tapi beliau tidak membaiatku, beliau bersabda; \"Sekarang gilirannya orang yang menarik pinggul.\" Aku berkata; Demi Allah aku tidak akan mengulanginya. Kemudian beliau membaiatku."},"3284":{"ar":"حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا يَزِيدُ بْنُ عَطَاءٍ عَنْ بَيَانِ بْنِ بِشْرٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي شَهْمٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ رَجُلًا بَطَّالًا قَالَ فَمَرَّتْ بِي جَارِيَةٌ فِي بَعْضِ طُرُقِ الْمَدِينَةِ إِذْ هَوَيْتُ إِلَى كَشْحِهَا فَلَمَّا كَانَ الْغَدُ قَالَ فَأَتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَايِعُونَهُ فَأَتَيْتُهُ فَبَسَطْتُ يَدِي لِأُبَايِعَهُ فَقَبَضَ يَدَهُ وَقَالَ أَحْسِبُكَ صَاحِبُ الْجُبَيْذَةِ يَعْنِي أَمَا إِنَّكَ صَاحِبُ الْجُبَيْذَةِ أَمْسِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ بَايِعْنِي فَوَاللَّهِ لَا أَعُودُ أَبَدًا قَالَ فَنَعَمْ إِذًا","id":"Telah menceritakan kepada kami [Suraij] telah menceritakan kepada kami [Yazid bin 'Atho`] dari [Bayan bin Bisyr] dari [Qais bin Abu Hazim] dari [Abu Syahm Radliyallahu'Anhu] berkata; Aku seorang pemberani, kemudian seorang budak wanita melewatiku di sebagaian jalan Madinah lalu aku ingin menarik pinggulnya. Di keesokan harinya, orang-orang mendatangi Rasulullah Shallallahu'alaihiWasallam untuk berbaiat kepada beliau. Aku mendatangi beliau, aku membentangkan tangan untuk berbaiat kepada beliau tapi beliau menggenggam tangan, beliau bersabda; \"Menurutku, kau adalah laki-laki yang menarik pinggul itu?.\" Maksud beliau; Yang menarik pinggul perempuan di hari kemaren. Aku berkata; Wahai Rasulullah! Baiatah aku, demi Allah aku tidak akan mengulangi selamanya. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Ya kalau begitu.\""},"3285":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ قَابُوسَ بْنِ مُخَارِقٍ عَنْ أَبِيهِ أَنَّرَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَرَأَيْتَ إِنْ جَاءَ رَجُلٌ يُرِيدُ أَنْ يَسْرِقَنِي أَوْ يَأْخُذَ مِنِّي مَا تَأْمُرُنِي بِهِ قَالَ تُعْظِمُ عَلَيْهِ بِاللَّهِ قَالَ فَإِنْ فَعَلْتُ فَلَمْ يَنْتَهِ قَالَ تَسْتَعْدِي السُّلْطَانَ قَالَ فَإِنْ لَمْ يَكُنْ بِقُرْبِي مِنْهُمْ أَحَدٌ قَالَ تُجَاهِدُهُ أَوْ تُقَاتِلُهُ حَتَّى تُكْتَبَ فِي شُهَدَاءِ الْآخِرَةِ أَوْ تَمْنَعَ مَالَكَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Simak bin Harb] dari [Qobus bin Mukhoriq] dari [ayahnya] bahwa seseorang mendatangi Rasulullah Shallallahu'alaihiWasallam lalu berkata; Bagaimana pendapat Baginda bila seseorang datang ingin mencuri atau mengambil dariku, apa yang kau perintahkan? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau agung-agungkan nama Allah di hadapannya.\" Ia berkata; Bila aku melakukannya namun ia tidak berhenti? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau meminta tolong penguasa.\" Ia berkata; Bila aku tidak dekat dengan seorang pun dari mereka? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau perangi dia hingga kau ditulis sebagai syuhada` akhirat atau kau menahan hartamu.\""},"3286":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ قَرْمٍ عَنْ سِمَاكٍ عَنْ قَابُوسَ بْنِ مُخَارِقٍ عَنْ أَبِيهِ قَالَأَتَى رَجُلٌ النَّبِيَّ فَقَالَ أَرَأَيْتَ إِنْ أَتَانِي رَجُلٌ يَأْخُذُ مَالِي قَالَ تُذَكِّرُهُ بِاللَّهِ تَعَالَى قَالَ أَرَأَيْتَ إِنْ ذَكَّرْتُهُ بِاللَّهِ قَالَ فَإِنْ فَعَلْتُ فَلَمْ يَنْتَهِ قَالَ تَسْتَعِينُ عَلَيْهِ بِالسُّلْطَانِ قَالَ أَرَأَيْتَ إِنْ كَانَ السُّلْطَانُ مِنِّي نَائِيًا قَالَ تَسْتَعِينُ بِالْمُسْلِمِينَ قَالَ أَرَأَيْتَ إِنْ لَمْ يَحْضُرْنِي أَحَدٌ مِنْ الْمُسْلِمِينَ وَعَجِلَ عَلَيَّ قَالَ فَقَاتِلْ حَتَّى تَحْرُزَ مَالَكَ أَوْ تُقْتَلَ فَتَكُونَ فِي شُهَدَاءِ الْآخِرَةِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Qorm] dari [Simak] dari [Qobus bin Mukhoriq] dari [ayahnya] berkata; Seseorang mendatangi Nabi Shallallahu'alaihiWasallam lalu bertanya; Bagaimana bila seseorang mendatangiku, ia mengambil hartaku? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau mengingatkan Allah subhanahu wata'ala. Ia bertanya; Bagaimana menurut Baginda bila aku sudah mengingatkannya kepada Allah subhanahu wata'ala namun ia tidak berhenti? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau meminta tolong kepada penguasa.\" Ia bertanya; Bagaimana menurut Baginda bila penguasanya jauh dariku? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Kau meminta tolong kaum muslimin. Ia bertanya; Bagaimana menurut Baginda bila tidak ada seorang pun dari kaum muslimin yang mendatangiku dan segera mendatangiku. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Perangilah hingga kau menjaga hartamu, atau perangilah sehingga kau termasuk syuhada` akhirat.\""},"3287":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عُقْبَةَ عَنْ أَبِي عُقْبَةَ وَكَانَ مَوْلًى مِنْ أَهْلِ فَارِسَ قَالَشَهِدْتُ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَضَرَبْتُ رَجُلًا مِنْ الْمُشْرِكِينَ فَقُلْتُ خُذْهَا مِنِّي وَأَنَا الْغُلَامُ الْفَارِسِيُّ فَبَلَغَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَّا قُلْتَ خُذْهَا مِنِّي وَأَنَا الْغُلَامُ الْأَنْصَارِيُّ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Jarir bin Hazim] dari [Muhammad bin Ishaq] dari [Dawud bin Hushain] dari ['Abdur Rahman bin Abu 'Uqbah] dari [Abu 'Uqbah] -dia adalah bekas budak dari Persia- ia berkata; Aku turut perang Uhud bersama Rasulullah Shallallahu'alaihiwasallam, aku memukul seorang musyrik. Aku berkata; Ambillah dariku, aku adalah budak Persia. Hal itu terdengar oleh Nabi Shallallahu'alaihiWasallam lalu beliau bersabda; \"Kenapa tidak kau katakan; Ambillah dariku, aku adalah budak Anshor.\""},"3288":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ يُونُسَ عَنِ الزُّهْرِيِّ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ فِي الصَّلَاةِ فَلَا يَرْفَعْ بَصَرَهُ إِلَى السَّمَاءِ أَنْ يُلْتَمَعَ بَصَرُهُ","id":"Telah menceritakan kepada kami [Ibrahim] telah menceritakan kepada kami [Ibnu Mubarok] dari [Yunus] dari [Az Zuhri] telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] bahwa [salah seorang sahabat Nabi] Shallallahu'alaihiWasallam menceritakan padanya bahwa ia mendengar Nabi Shallallahu'alaihiWasallam bersabda; \"Bila salah seorang dari kalian shalat, janganlah mengangkat pandangannya ke langit, siapa tahu pandangannya disambar.\""},"3289":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ قَالَكُنْتُ أَرَى الرُّؤْيَا أُعْرَى مِنْهَا غَيْرَ أَنِّي لَا أُزَمَّلُ حَتَّى لَقِيتُ أَبَا قَتَادَةَ فَذَكَرْتُ ذَلِكَ لَهُ فَحَدَّثَنِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَمَنْ رَأَى رُؤْيَا يَكْرَهُهَا فَلَا يُخْبِرْ بِهَا وَلْيَتْفُلْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَسْتَعِذْ بِاللَّهِ مِنْ شَرِّهَا فَإِنَّهَا لَا تَضُرُّهُ قَالَ سُفْيَانُ مَرَّةً أُخْرَى فَإِنَّهُ لَنْ يَرَى شَيْئًا يَكْرَهُهُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Abu Salamah] berkata; Aku bermimpi, seolah-olah aku terkena demam karena ketakutan, karena tak kuat kupendam sendirian, maka aku temui [Abu Qatadah] dan kuberitahukan hal itu, ia menceritakan kepadaku dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda; \"Mimpi itu dari Allah sedangkan mimpi buruk itu dari setan. Barangsiapa yang bermimpi melihat sesuatu yang tidak disukai maka jangan memberitahukannya dan hendaklah meludah tiga kali ke arah kirinya lalu hendaklah berlindung kepada Allah dari keburukannya karena (mimpinya) tidaklah membahayakannya.\" Di lain kesempatan Sufyan mengatakan; Niscaya ia tidak bermimpi sesuatu yang dibencinya."},"3290":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ جَلِيسُ أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ قَالَبَارَزْتُ رَجُلًا يَوْمَ حُنَيْنٍ فَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ","id":"Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Umar bin Katsir bin Aflah] dari [Abu Muhammad -teman Abu Qatadah-] dari [Abu Qatadah] berkata; Aku bisa mengalahkan seseorang saat perang Hunain kemudian Rasulullah Shallallahu'alaihiWasallam memberiku barang bawaan orang itu."},"3291":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنِي إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَتْنِي امْرَأَةُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ أَبَا قَتَادَةَ كَانَ يُصْغِي الْإِنَاءَ لِلْهِرِّ فَيَشْرَبُوَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَنَّهَا لَيْسَتْ بِنَجَسٍ إِنَّهَا مِنْ الطَّوَّافِينَ وَالطَّوَّافَاتِ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Ishaq bin 'Abdullah bin Abu Thalhah] telah menceritakan kepadaku [istri 'Abdullah bin Abu Thalhah] bahwa [Abu Qatadah] memiringkan bejana air untuk seekor kucing lalu kucing itu minum. Ia berkata; Rasulullah Shallallahu'alaihiWasallam telah menceritakan kepada kami bahwa kucing tidak najis, ia adalah hewan yang suka berkeliaran diantara kalian.\""},"3292":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ وَابْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُصَلِّ رَكْعَتَيْنِ مِنْ قَبْلِ أَنْ يَجْلِسَ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Utsman bin Abu Sulaiman] dan [Ibnu 'Ajlan] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amr bin Sulaim] dari [Abu Qatadah] dari Nabi Shallallahu'alaihiWasallam bersabda; \"Bila salah seorang dari kalian masuk masjid hendaklah shalat dua rakaat sebelum duduk.\""},"3293":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ وَابْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ النَّاسَ وَأُمَامَةُ بِنْتُ أَبِي الْعَاصِ يَعْنِي حَامِلُهَا فَإِذَا رَكَعَ وَضَعَهَا وَإِذَا فَرَغَ مِنْ السُّجُودِ رَفَعَهَا","id":"Telah menceritakan kepada kami [Sufyan] dari ['Utsman bin Abu Sulaiman] dan [Ibnu 'Ajlan] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amr bin Sulaim] dari [Abu Qatadah] berkata; Aku melihat Rasulullah Shallallahu'alaihiWasallam mengimami orang dan beliau menggendong Umamah binti Abu Al 'Ash, bila ruku' beliau meletakkannya dan bila usia sujud beliau mengangkatnya."},"3294":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نُودِيَ لِلصَّلَاةِ فَلَا تَقُومُوا حَتَّى تَرَوْنِي","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Al Hajjaj bin Abu 'Utsman] telah menceritakan kepadaku [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [ayahnya] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Bila telah dipanggil untuk shalat, janganlah kalian berdiri hingga kalian melihatku.\""},"3295":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ حَرْمَلَةَ بْنِ إِيَاسٍ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْمُ يَوْمِ عَرَفَةَ يُكَفِّرُ سَنَتَيْنِ مَاضِيَةً وَمُسْتَقْبَلَةً وَصَوْمُ عَاشُورَاءَ يُكَفِّرُ سَنَةً مَاضِيَةً","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari [Harmalah bin Iyas] dari [Abu Qatadah] berkata; Rasulullah Shallallahu'alaihiWasallam bersabda; \"Puasa hari 'arafah menghapus (kesalahan) dua tahun; yang telah lalu dan yang akan datang dan puasa 'asyura` menghapus (kesalahan) tahun lalu.\""},"3296":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ يَعْنِي ابْنَ أَبِي هِنْدٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ حَلْحَلَةَ عَنِ ابْنٍ لِكَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ بْنِ رِبْعِيٍّ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجِنَازَةٍ قَالَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ قَالُوا يَا رَسُولَ اللَّهِ مَا الْمُسْتَرِيحُ وَالْمُسْتَرَاحُ مِنْهُ قَالَ الْمُؤْمِنُ اسْتَرَاحَ مِنْ نَصَبِ الدُّنْيَا وَأَذَاهَا إِلَى رَحْمَةِ اللَّهِ تَعَالَى وَالْفَاجِرُ اسْتَرَاحَ مِنْهُ الْعِبَادُ وَالْبِلَادُ وَالشَّجَرُ وَالدَّوَابُّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami ['Abdullah bin Sa'id bin Abu Hind] telah menceritakan kepadaku [Muhammad bin 'Amr bin Halhalah] dari [seorang putra Ka'ab bin Malik] dari [Abu Qatadah bin Rib'i] berkata; Sesosok jenazah melintas dihadapan Nabi Shallallahu'alaihiwasallam, beliau bersabda; \"Ia istirahat dan yang lain istirahat karenanya.\" Mereka bertanya; Apa maksud ia istirahat dan yang lain istirahat karenanya? Rasulullah Shallallahu'alaihiWasallam bersabda; \"Orang mu`min istrirahat dari kelelahan dunia dan segala kesusahannya menuju rahmat Allah subhanahu wata'ala sedangkan orang keji, semua manusia, negeri, pohon dan hewan bisa istirahat dari (keburukannya).\""},"3297":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ قَالَ شُعْبَةُ قُلْتُ لِغَيْلَانَ الْأَنْصَارِيِّ فَقَالَ بِرَأْسِهِ أَيْ نَعَمْأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِهِ فَغَضِبَ فَقَالَ عُمَرُ رَضِيتُ أَوْ قَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا قَالَ وَلَا أَعْلَمُهُ إِلَّا قَدْ قَالَ وَبِمُحَمَّدٍ رَسُولًا وَبِبَيْعَتِنَا بَيْعَةً قَالَ فَقَامَ عُمَرُ أَوْ رَجُلٌ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ رَجُلٌ صَامَ الْأَبَدَ قَالَ لَا صَامَ وَلَا أَفْطَرَ أَوْ مَا صَامَ وَمَا أَفْطَرَ قَالَ صَوْمُ يَوْمَيْنِ وَإِفْطَارُ يَوْمٍ قَالَ وَمَنْ يُطِيقُ ذَلِكَ قَالَ إِفْطَارُ يَوْمَيْنِ وَصَوْمُ يَوْمٍ قَالَ لَيْتَ اللَّهَ عَزَّ وَجَلَّ قَوَّانَا لِذَلِكَ قَالَ صَوْمُ يَوْمٍ وَإِفْطَارُ يَوْمٍ قَالَ ذَاكَ صَوْمُ أَخِي دَاوُدَ قَالَ صَوْمُ الِاثْنَيْنِ وَالْخَمِيسِ قَالَ ذَاكَ يَوْمٌ وُلِدْتُ فِيهِ وَأُنْزِلَ عَلَيَّ فِيهِ قَالَ صَوْمُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَرَمَضَانَ إِلَى رَمَضَانَ صَوْمُ الدَّهْرِ وَإِفْطَارُهُ قَالَ صَوْمُ يَوْمِ عَرَفَةَ قَالَ يُكَفِّرُ السَّنَةَ الْمَاضِيَةَ وَالْبَاقِيَةَ قَالَ صَوْمُ يَوْمِ عَاشُورَاءَ قَالَ يُكَفِّرُ السَّنَةَ الْمَاضِيَةَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] telah menceritakan kepada kami [Ghailan bin Jarir] dari ['Abdullah bin Ma'bad Az Zammanni] dari [Abu Qatadah]. Syu'bah berkata; Aku pernah berkata kepada Ghailan Al Anshari, dan ia menjawab 'Iya' dengan isyarat kepalanya, bahwa seseorang bertanya Nabi Shallallahu'alaihiWasallam tentang puasanya, ternyata beliau marah kemudian 'Umar berkata; Aku rela -atau berkata; Kami rela, Allah sebagai Rabb dan Islam sebagai agama.\" Aku mengetahuinya berkata; Muhammad sebagai rasul dan baiat kami sebagai baiat. Lalu 'Umar atau seseorang lainnya berdiri dan berkata; Wahai Rasulullah! Bagaimana tanggapan anda mengenai orang yang puasa terus menerus?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Berarti orang itu tidak puasa dan tidak pula berbuka\" atau bersabda; \"Ia dianggap tidak puasa dan tidak berbuka.\" Ia berkata; \"Bagaimana kalau puasa dua hari dan berbuka sehari?.\" Rasulullah Shallallahu'alaihiWasallam bersabda; \"Siapa yang kuat melakukannya?\" ia berkata; \"Berbuka dua hari dan puasa sehari. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Andai saja Allah memberi kita kekuatan untuk melakukannya.\" Ia berkata; Bagaimana kalau puasa sehari dan berbuka sehari?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Itu puasanya saudaraku, Dawud.\" Ia berkata; Bagaimana kalau puasa senin dan kamis?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Itulah hari kelahiranku dan hari turunnya wahyu padaku.\" Rasulullah Shallallahu'alaihiWasallam bersabda; \" Puasa tiga hari setiap bulan, Ramadhan hingga Ramadhan adalah puasa sepanjang masa dan berbuka sepanjang masa.\" Ia berkata; Bagaimana kalau puasa hari 'arafah?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Menghapus (kesalahan) tahun yang lalu dan tahun yang tersisa. Ia berkata; Bagaimana kalau puasa hari 'asyura`?. Rasulullah Shallallahu'alaihiWasallam bersabda; \"Menghapus (kesalahan) tahun lalu."},"3298":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْمِعُنَا الْآيَةَ فِي الظُّهْرِ وَالْعَصْرِ أَحْيَانًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami ['Ali bin Al Mubarok] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [ayahnya] berkata; Rasulullah Shallallahu'alaihiWasallam terkadang memperdengarkan ayat kepada kami saat shalat zhuhur dan 'ashar."},"3299":{"ar":"حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ عَطِيَّةَ الْقُرَظِيِّ قَالَعُرِضْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَشَكُّوا فِيَّ فَأَمَرَ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْظُرُوا إِلَيَّ هَلْ أَنْبَتُّ بَعْدُ فَنَظَرُوا فَلَمْ يَجِدُونِي أَنْبَتُّ فَخَلَّى عَنِّي وَأَلْحَقَنِي بِالسَّبْيِ","id":"Telah menceritakan kepada kami [Husyaim bin basyir] telah mengabarkan kepada kami ['Abdul Malik bin 'Umair] dari ['Athiyah Al Qurozhi] berkata; Saya dibawa kehadapan Nabi Shallallahu'alaihiwasallamsaat perang Quraizhah, mereka melaporkanku kepada beliau kemudian beliau memerintahkan mereka agar melihatku apakah rambut kemaluanku sudah tumbuh, mereka tidak melihat rambut kemaluanku kemudian beliau melepaskanku dan menggabungkanku bersama para tawanan."},"3300":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ سَمِعَ عَطِيَّةَ يَقُولُكُنْتُ يَوْمَ حَكَمَ سَعْدٌ فِيهَا غُلَامًا فَلَمْ يَجِدُونِي أَنْبَتُّ فِيهَا فَهَا أَنَا ذَا بَيْنَ أَظْهُرِكُمْ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Abdul Malik], ia mendengar ['Athiyyah] berkata; Sa'ad berkuasa ketika aku masih kecil, mereka tidak menemukanku sudah tumbuh rambut kemaluanku saat itu. Dan sekarang ini aku ada di hadapan kalian."},"3301":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ عَنِ الْمَقْبُرِيِّ عَنْ صَفْوَانَ بْنِ الْمُعَطَّلِ السُّلَمِيِّ أَنَّهُسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ إِنِّي أَسْأَلُكَ عَمَّا أَنْتَ بِهِ عَالِمٌ وَأَنَا بِهِ جَاهِلٌ مِنْ اللَّيْلِ وَالنَّهَارِ سَاعَةٌ تُكْرَهُ فِيهَا الصَّلَاةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتَ الصُّبْحَ فَأَمْسِكْ عَنْ الصَّلَاةِ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ فَصَلِّ فَإِنَّ الصَّلَاةَ مَحْضُورَةٌ مُتَقَبَّلَةٌ حَتَّى تَعْتَدِلَ عَلَى رَأْسِكَ مِثْلَ الرُّمْحِ فَإِذَا اعْتَدَلَتْ عَلَى رَأْسِكَ فَإِنَّ تِلْكَ السَّاعَةَ تُسْجَرُ فِيهَا جَهَنَّمُ وَتُفْتَحُ فِيهَا أَبْوَابُهَا حَتَّى تَزُولَ عَنْ حَاجِبِكَ الْأَيْمَنِ فَإِذَا زَالَتْ عَنْ حَاجِبِكَ الْأَيْمَنِ فَصَلِّ فَإِنَّ الصَّلَاةَ مَحْضُورَةٌ مُتَقَبَّلَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ","id":"Telah menceritakan kepada kami 'Abdullah, telah bercerita kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah bercerita kepada kami [Humaid bin Al Aswad] telah bercerita kepada kami [Adh Dhahhak bin 'Utsman] dari [Al Maqburi] dari [Shofwan bin Al Mu'aththol As Sulami] bahwa ia bertanya kepada Nabi Shallallahu'alaihiwasallam, ia berkata: 'Wahai Nabi Allah, saya bertanya kepadamu tentang perkara yang baginda ketahui namun tidak saya ketahui, yaitu masalah waktu malam dan siang yang dimakruhkan untuk mendirikan shalat, maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika kamu telah mengerjakan shalat subuh maka tahanlah dirimu dari shalat sehingga terbit matahari, dan jika matahari telah terbit maka shalatlah karena shalat (di waktu itu) dihadiri oleh malaikat dan diterima di sisi Allah sehingga matahari tegak lurus di atas kepalamu seperti tombak, dan jika matahari telah tegak lurus di atas kepalamu maka itu adalah saat neraka jahannam dididihkan dan dibuka pintu-pintunya sehingga sirna dari kelopak mata kananmu, dan jika matahahari telah condong dari kelopak mata kananmu maka shalatlah, karena shalat (di waktu itu) dihadiri dan diterima hingga kamu shalat ashar.\""},"3302":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيِّ بْنِ بَحْرِ بْنِ كَثِيرٍ السَّقَّاءُ حَدَّثَنَا أَبُو قُتَيْبَةَ حَدَّثَنَا عُمَرُ بْنُ نَبْهَانَ حَدَّثَنَا سَلَّامٌ أَبُو عِيسَى حَدَّثَنَا صَفْوَانُ بْنُ الْمُعَطَّلِ قَالَخَرَجْنَا حُجَّاجًا فَلَمَّا كُنَّا بِالْعَرْجِ إِذَا نَحْنُ بِحَيَّةٍ تَضْطَرِبُ فَلَمْ تَلْبَثْ أَنْ مَاتَتْ فَأَخْرَجَ لَهَا رَجُلٌ خِرْقَةً مِنْ عَيْبَتِهِ فَلَفَّهَا فِيهَا وَدَفَنَهَا وَخَذَّ لَهَا فِي الْأَرْضِ فَلَمَّا أَتَيْنَا مَكَّةَ فَإِنَّا لَبِالْمَسْجِدِ الْحَرَامِ إِذْ وَقَفَ عَلَيْنَا شَخْصٌ فَقَالَ أَيُّكُمْ صَاحِبُ عَمْرِو بْنِ جَابِرٍ قُلْنَا مَا نَعْرِفُهُ قَالَ أَيُّكُمْ صَاحِبُ الْجَانِّ قَالُوا هَذَا قَالَ أَمَا إِنَّهُ جَزَاكَ اللَّهُ خَيْرًا أَمَا إِنَّهُ قَدْ كَانَ مِنْ آخِرِ التِّسْعَةِ مَوْتًا الَّذِينَ أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَمِعُونَ الْقُرْآنَ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Abu Hafsh 'Amru bin 'Ali bin Bahr bin Katsir As Saqqa`] telah bercerita kepada kami [Abu Qutaibah] telah bercerita kepada kami ['Umar bin Nabhan] telah bercerita kepada kami [Sallam Abu 'Isa] telah bercerita kepada kami [Shafwan bin Al Mu'aththal], ia berkata; Kami pergi berhaji, saat kami di 'Araj, ada seekor ular tergelepar-gelepar, tidak lama berselang ular itu mati kemudian seseorang mengeluarkan sobekan kain dari tasnya, lalu ia menggulung ular itu dengan kain dan menguburnya ditanah. Saat kami datang di Makkah dan kami berada di masjidil haram, tiba-tiba ada seseorang bertanya; Siapa diantara kalian temannya 'Amru bin Jabir? Kami menjawab; Kami tidak mengenalnya. Ia bertanya; siapa diantara kalian temannya jin? Kami menjawab; dia. Orang itu berkata; Ingatlah sesunggunya Allah memberimu balasan baik, ia adalah orang terakhir yang meninggal dunia dari sembilan orang yang mendatangi Rasulullah Shallallahu'alaihiwasallam seraya mendengarkan Al Quran."},"3303":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدُ بْنُ يُوسُفَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ صَفْوَانَ بْنِ الْمُعَطَّلِ السُّلَمِيِّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَرَمَقْتُ صَلَاتَهُ لَيْلَةً فَصَلَّى الْعِشَاءَ الْآخِرَةَ ثُمَّ نَامَ فَلَمَّا كَانَ نِصْفُ اللَّيْلِ اسْتَيْقَظَ فَتَلَا الْآيَاتِ الْعَشْرَ آخِرَ سُورَةِ آلِ عِمْرَانَ ثُمَّ تَسَوَّكَ ثُمَّ تَوَضَّأَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ فَلَا أَدْرِي أَقِيَامُهُ أَمْ رُكُوعُهُ أَمْ سُجُودُهُ أَطْوَلُ ثُمَّ انْصَرَفَ فَنَامَ ثُمَّ اسْتَيْقَظَ فَتَلَا الْآيَاتِ ثُمَّ تَسَوَّكَ ثُمَّ تَوَضَّأَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ لَا أَدْرِي أَقِيَامُهُ أَمْ رُكُوعُهُ أَمْ سُجُودُهُ أَطْوَلُ ثُمَّ انْصَرَفَ فَنَامَ ثُمَّ اسْتَيْقَظَ فَفَعَلَ ذَلِكَ ثُمَّ لَمْ يَزَلْ يَفْعَلُ كَمَا فَعَلَ أَوَّلَ مَرَّةٍ حَتَّى صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepadaku ['Ubaidullah bin 'Umar Al Qawariri] telah bercerita kepada kami ['Abdullah bin Ja'far] telah mengabarkan kepadaku [Muhammad bin Yusuf] dari ['Abdullah bin Al Fadhl] dari [Abu Bakar bin 'Abdur Rahman bin Al Harits] dari [Shafwan bin Al Muaththal As Sulami] berkata: Saya bersama Rasulullah Shallallahu'alaihiwasallam dalam sebuah perjalanan, maka pada suatu malam saya menyelidiki shalat beliau Shallallahu'alaihiwasallam, beliau Shallallahu'alaihiwasallam shalat isya' yang diakhirkan kemudian kemudian tidur, dan ketika tiba paruh malam beliau Shallallahu'alaihiwasallam bangun dan membaca sepuluh ayat terakhir dari surat Ali-Imran kemudian bersiwak, berwudhu lalu shalat dua rakaat, saya tidak tahu apakah berdirinya yang lebih lama atau ruku'nya atau sujudnya, kemudian beliau Shallallahu'alaihiwasallam selesai lalu tidur kemudian bangun dan membaca sepuluh ayat terakhir dari surat Aali-Imraan kemudian beliau Shallallahu'alaihiwasallam bersiwak kemudian berwudlu lalu shalat dua rakaat, saya tidak tahu apakah berdirinya yang lebih lama, ruku'nya atau sujudnya, kemudian beliau Shallallahu'alaihiwasallam selesai kemudian tidur lalu melakukan hal demikian, beliau Shallallahu'alaihiwasallam masih selalu melakukan hal itu sebagaimana yang beliau lakukan pertama kali hingga beliau Shallallahu'alaihiwasallam shalat sebelas rakaat."},"3304":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ أَسِيدِ بْنِ أَبِي أَسِيدٍ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ قَالَأَصَابَنَا طَشٌّ وَظُلْمَةٌ فَانْتَظَرْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ لَنَا فَخَرَجَ فَأَخَذَ بِيَدِي فَقَالَ قُلْ فَسَكَتُّ قَالَ قُلْ قُلْتُ مَا أَقُولُ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ حِينَ تُمْسِي وَحِينَ تُصْبِحُ ثَلَاثًا يَكْفِيكَ كُلَّ يَوْمٍ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah bercerita kepada kami [Adh Dhahhak bin Makhlad] telah bercerita kepada kami [Ibnu Abi Dzi'b] dari [Asid bin Abu Asid] dari [Mu'adz bin 'Abdullah bin Khubaib] dari [ayahnya] berkata; Kami tertimpa hujan gerimis dan suasana gelap, lalu kami menunggu Rasulullah Shallallahu'alaihiwasallam untuk shalat bersama kami. Beliau keluar lalu meraih tanganku lalu beliau bersabda: \"Katakan.\" Aku hanya diam. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Katakan.\" Aku berkata; Apa yang harus aku katakan. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Katakan bahwa Dia adalah Allah Yang esa (maksudnya membaca surat al-Ikhlash) dan mu'awwidzatain saat kau berada diwaktu sore dan pagi hari sebanyak tiga kali niscaya Ia akan mencukupimu setiap hari dua kali.\""},"3305":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنِ الْحَارِثِ بْنِ أُقَيْشٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمَيْنِ يَمُوتُ لَهُمَا أَرْبَعَةُ أَوْلَادٍ إِلَّا أَدْخَلَهُمَا اللَّهُ الْجَنَّةَ قَالُوا يَا رَسُولَ اللَّهِ وَثَلَاثَةٌ قَالَ وَثَلَاثَةٌ قَالُوا يَا رَسُولَ اللَّهِ وَاثْنَانِ قَالَ وَاثْنَانِ وَإِنَّ مِنْ أُمَّتِي لَمَنْ يَعْظُمُ لِلنَّارِ حَتَّى يَكُونَ أَحَدَ زَوَايَاهَا وَإِنَّ مِنْ أُمَّتِي لَمَنْ يَدْخُلُ بِشَفَاعَتِهِ الْجَنَّةَ أَكْثَرُ مِنْ مُضَرَ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepadaku [Muhammad bin Abu Bakar Al Muqaddami] telah bercerita kepada kami [Bisyr bin Al Mufadhdhal] dari [Dawud bin Abu Hind] dari ['Abdullah bin Qais] dari [Al Harits bin Uqais] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah dua orang muslim yang empat anaknya meninggal dunia melainkan Allah akan memasukkan keduanya ke surga.\" Mereka bertanya; Wahai Rasulullah! Bagaimana kalau tiga anak? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dan tiga anak.\" Mereka bertanya; Wahai Rasulullah! Bagaimana kalau dua anak? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Dan dua anak, sesungguhnya diantara ummatku ada orang yang terlalu besar bagi neraka hingga mencapai tepi-tepinya, dan diantara ummatku ada yang karena syafaat-Nya bisa masuk surga, dan jumlahnya lebih banyak dari kabilah Mudhar.\""},"3306":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ عَنِ الْحَسَنِ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا عَنِّي خُذُوا عَنِّي قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الْبِكْرُ بِالْبِكْرِ جَلْدُ مِائَةٍ وَنَفْيُ سَنَةٍ وَالثَّيِّبُ بِالثَّيِّبِ جَلْدُ مِائَةٍ وَالرَّجْمُ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur] dari [Al Hasan] dari [Hiththan bin 'Abdullah Ar Roqasi] dari ['Ubadah bin Ash Shamit] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tegakkan hukuman dariku, tegakkan hukuman dariku, sungguh Allah telah memberi ketetapan hukuman bagi mereka, zinanya seorang gadis dengan jejaka hukumannya adalah seratus kali cambuk dan diasingkan selama satu tahun, dan zinanya seorang janda dengan seorang duda hukumannya adalah seratus kali cambuk dan rajam.\""},"3307":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ قَالَ خَالِدٌ أَحْسِبُهُ ذَكَرَهُ عَنْ أَبِي أَسْمَاءَ قَالَ عُبَادَةُ بْنُ الصَّامِتِأَخَذَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَخَذَ عَلَى النِّسَاءِ سِتًّا أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا يَعْضِدْ بَعْضُكُمْ بَعْضًا وَلَا تَعْصُونِي فِي مَعْرُوفٍ فَمَنْ أَصَابَ مِنْكُمْ مِنْهُنَّ حَدًّا فَعُجِّلَ لَهُ عُقُوبَتُهُ فَهُوَ كَفَّارَتُهُ وَإِنْ أُخِّرَ عَنْهُ فَأَمْرُهُ إِلَى اللَّهِ تَعَالَى إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ رَحِمَهُحَدَّثَنَا هُشَيْمٌ عَنْ خَالِدٍ قَالَ سَمِعْتُ أَبَا قِلَابَةَ يُحَدِّثُ عَنْ أَبِي الْأَشْعَثِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ قَالَ سَمِعْتُ أَبَا قِلَابَةَ يُحَدِّثُ عَنْ أَبِي الْأَشْعَثِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا كَمَا أَخَذَ عَلَى النِّسَاءِ أَوْ عَلَى النَّاسِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Khalid Al Hadzdza`] dari [Abu Qilabah] berkata Khalid; aku mengiranya disebutkan dari [Abu Asma`] berkata [Ubadah bin Ash Shamit]; Rasulullah Shallallahu'alaihiwasallam membaiat kami sebagaimana beliau Shallallahu'alaihiwasallam membaiat para wanita dengan tujuh hal, (yaitu): 1) janganlah berbuat syirik kepada Allah sedikit pun, 2) janganlah mencuri, 3) janganlah berzina, 4) janganlah membunuh anak-anak kalian, 5) dan janganlah sebagian dari kalian memutus hubungan dengan sebagian yang lain, 6) janganlah bermaksiat (membangkang) kepadaku dalam kebaikan, dan barang siapa diantara kalian yang melanggar had (hukuman) lalu disegerakan hukuman tersebut kepadanya maka yang demikian itu sebagai kafarat (penghapus dosa) baginya, dan jika hukuman tersebut ditangguhkan darinya maka urusannya kembali kepada Allah, jika Allah berkehendak maka akan mengadzabnya dan jika berkehendak maka akan merahmatinya\". Telah bercerita kepadaku [Husyaim] dari [Khalid], ia berkata: saya mendengar [Abu Qilabah] bercerita dari [Abu Al Asy'ats] dari ['Ubadah bin Ash Shamit] dari Nabi Shallallahu'alaihiwasallam hadits serupa. Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khalid], ia berkata, aku mendengar [Abu Qilabah] bercerita dari [Abu Al Asy'ats] dari [Ubadah bin Ash Shamit], ia berkata; Nabi Shallallahu'alaihiwasallam membaiat kepada kami sebagaimana beliau Shallallahu'alaihiwasallam membaiat para wanita atau membaiat orang-orang. Ia menyebutkan makna hadits."},"3308":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنِ ابْنِ إِسْحَاقَ عَنْ مَكْحُولٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ فَثَقُلَتْ عَلَيْهِ الْقِرَاءَةُ فَلَمَّا فَرَغَ قَالَ تَقْرَءُونَ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا إِلَّا بِفَاتِحَةِ الْكِتَابِ فَإِنَّهُ لَا صَلَاةَ إِلَّا بِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Mak-hul] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam shalat bersama kami, beliau membaca namun beliau Shallallahu'alaihiwasallam merasa berat dengan bacaannya, ketika selesai beliau Shallallahu'alaihiwasallam bersabda: \"Apakah kalian membaca?\" kami berkata: Iya wahai Rasulullah Shallallahu'alaihiwasallam. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah wajib atas kalian untuk melakukan itu kecuali membaca Al Faatihah karena shalat tidak dianggap sah kecuali dengan membaca Al Fatihah.\""},"3309":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُرِيدُ أَنْ يُخْبِرَنَا بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجْتُ وَأَنَا أُرِيدُ أَنْ أُخْبِرَكُمْ بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ فَرُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا لَكُمْ فَالْتَمِسُوهَا فِي التَّاسِعَةِ أَوْ السَّابِعَةِ أَوْ الْخَامِسَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Humaid] dari [Anas] dari ['Ubadah bin Ash Shamit] berkata; Rasulullah Shallallahu'alaihiwasallam keluar menghampiri kami, beliau ingin memberitahukan lailatul qadar kepada kami lalu ada dua orang yang saling mencaci maki, beliau bersabda: \"Sebenarnya aku keluar ingin memberitahukan lailatul qadar kepada kalian, hanya tadi ada dua orang yang saling mencaci maki kemudian pemberitaan itu pun diangkat, semoga itu lebih baik bagi kalian. Maka carilah dia di malam kesembilan, ketujuh atau kelima.\""},"3310":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عُمَيْرُ بْنُ هَانِئٍ أَنَّ جُنَادَةَ بْنَ أَبِي أُمَيَّةَ حَدَّثَهُ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنَّ عِيسَى عَبْدُ اللَّهِ وَرَسُولُهُ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ وَرُوحٌ مِنْهُ وَأَنَّ الْجَنَّةَ حَقٌّ وَالنَّارَ حَقٌّ أَدْخَلَهُ اللَّهُ تَبَارَكَ وَتَعَالَى الْجَنَّةَ عَلَى مَا كَانَ مِنْ عَمَلٍحَدَّثَنَا الْوَلِيدُ حَدَّثَنِي ابْنُ جَابِرٍ أَنَّهُ سَمِعَ عُمَيْرَ بْنَ هَانِئٍ يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ جُنَادَةَ عَنْ عُبَادَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ إِلَّا أَنَّهُ قَالَ أَدْخَلَهُ اللَّهُ تَبَارَكَ وَتَعَالَى الْجَنَّةَ مِنْ أَبْوَابِهَا الثَّمَانِيَةِ مِنْ أَيِّهَا شَاءَ دَخَلَ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] telah bercerita kepada kami [Al Auza'i] telah bercerita kepadaku ['Umair bin Hani`] bahwa [Junadah bin Abu Umaiyah] bercerita padanya dari ['Ubadah bin Ash Shamit] dari Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barang siapa bersaksi bahwa tidak ada Ilah kecuali Allah dan Muhammad adalah hamba Allah dan utusan-Nya, Isa bin Maryam adalah hamba Allah dan utusan-Nya dan kalimat-Nya yang diucapkan ke dalam perut maryam dan ruh (yang tercipta dari-Nya), dan surga adalah benar, dan bersaksi bahwa neraka juga benar, maka Allah Tabaaroka wa ta'ala akan memasukkannya ke surga atas amalan yang ia kerjakan\". Telah bercerita kepadaku [Al Walid] telah bercerita kepadaku [Ibnu Jabir] bahwasanya ia mendengar ['Umair bin Hani`] bercerita hadits ini dari [Junadah] dari ['Ubadah] dari Rasulullah Shallallahu'alaihiwasallam sepertinya, hanyasaja ia berkata dalam riwayatnya: \"Maka Allah Tabaaroka wa Ta'ala akan memasukkannya ke surga dari delapan pintunya, ia masuk dari pintu mana saja yang ia kehendaki.\""},"3311":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ رِوَايَةًيَبْلُغُ بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit] secara riwayat yang sampai pada Nabi Shallallahu'alaihiwasallam; Tidak dianggap shalat bagi orang yang tidak membaca alfatihah."},"3312":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ سَمِعَهُ مِنْ جَدِّهِ وَقَالَ سُفْيَانُ مَرَّةً عَنْ جَدِّهِ عُبَادَةَ قَالَ سُفْيَانُ وَعُبَادَةُ نَقِيبٌ وَهُوَ مِنْ السَّبْعَةِبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ وَلَا نُنَازِعُ الْأَمْرَ أَهْلَهُ نَقُولُ بِالْحَقِّ حَيْثُمَا كُنَّا لَا نَخَافُ فِي اللَّهِ لَوْمَةَ لَائِمٍ قَالَ سُفْيَانُ زَادَ بَعْضُ النَّاسِ مَا لَمْ تَرَوْا كُفْرًا بَوَاحًا","id":"Telah menceritakan kepada kami [Sufyan] dari [Yahya] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] ia mendengarnya dari [kakeknya], -Sufyan berkata; Sesekali dari kakeknya -'Ubadah-, 'Ubadah dan Naqib, satu dari tujuh orang-; Kami berbaiat kepada Rasulullah Shallallahu'alaihiwasallam untuk mendengar dan taat saat susah, senang, giat dan malas, tidak membantah sesuatu pada ahlinya, berkata benar dimana saja kami berada, tidak takut celaan siapa pun karena Allah subhanahu wata'ala. Berkata Sufyan; Sebagian orang menambahi; Selama kalian tidak melihat kekufuran yang jelas."},"3313":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي سَلَّامٍ الْأَعْرَجِ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاهِدُوا فِي سَبِيلِ اللَّهِ فَإِنَّ الْجِهَادَ فِي سَبِيلِ اللَّهِ تَبَارَكَ وَتَعَالَى بَابٌ مِنْ أَبْوَابِ الْجَنَّةِ يُنَجِّي اللَّهُ تَبَارَكَ وَتَعَالَى بِهِ مِنْ الْهَمِّ وَالْغَمِّ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] telah bercerita kepada kami [Isma'il bin 'Ayyasy] dari [Abu Bakr bin 'Abdullah bin Abu Maryam] dari [Abu Sallam Al A'raj] dari [Al Miqdam bin Ma'di] dari ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berjihadlah dijalan Allah karena jihad di jalan Allah Tabaaroka wa Ta'ala termasuk salah satu pintu surga, dengan jihad tersebut Allah mengobati kesusahan dan kesedihan.\""},"3314":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ أَبِي الْمُثَنَّى عَنِ ابْنِ امْرَأَةِ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ أُمَرَاءُ تَشْغَلُهُمْ أَشْيَاءُ يُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا فَصَلُّوا الصَّلَاةَ لِوَقْتِهَا وَاجْعَلُوا صَلَاتَكُمْ مَعَهُمْ تَطَوُّعًاحَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي الْمُثَنَّى عَنِ ابْنِ امْرَأَةِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yisaf] dari [Abu Al Mutsanna] dari [seorang putra dari istri 'Ubadah bin Ash Shamit] dari Nabi Shallallahu'alaihiwasallam, akan ada para pemimpin sesudahku yang disibukkan oleh perkara-perkara sehingga mereka mengakhirkan shalat dari waktunya, maka shalatlah kalian tepat pada waktunya, dan jadikan shalat kalian bersama mereka sebagai amalan sunnah.\" Telah menceritakan kepada kami [Hajjaj], telah menceritakan kepada kami [Syu'bah], dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Al Mutsanna] dari [seorang putra dari istri 'Ubadah bin Ash Shamit] dari Nabi Shallallahu'alaihiwasallam, ia menyebutkan hadits serupa."},"3315":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ حَفْصٍ عَنِ ابْنِ الْمُصَبِّحِ أَوْ أَبِي الْمُصَبِّحِ عَنِ ابْنِ السِّمْطِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَعَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ فَمَا تَحَوَّزَ لَهُ عَنْ فِرَاشِهِ فَقَالَ مَنْ شُهَدَاءُ أُمَّتِي قَالُوا قَتْلُ الْمُسْلِمِ شَهَادَةٌ قَالَ إِنَّ شُهَدَاءَ أُمَّتِي إِذًا لَقَلِيلٌ قَتْلُ الْمُسْلِمِ شَهَادَةٌ وَالطَّاعُونُ شَهَادَةٌ وَالْبَطْنُ وَالْغَرَقُ وَالْمَرْأَةُ يَقْتُلُهَا وَلَدُهَا جَمْعَاءَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata; Telah bercerita kepadaku [Abu Bakar bin Hafsh] dari [Ibnu Al Mushabbih atau Abu Al Mushabbih] dari [Ibnu As Simth] dari ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam menjenguk 'Abdullah bin Rowahah, ketika beliau Shallallahu'alaihiwasallam duduk di ranjangnya, beliau Shallallahu'alaihiwasallam bersabda: \"Siapakah orang yang syahid dari umatku?\" mereka berkata: orang muslim yang terbunuhlah yang terhitung syahid. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kalau begitu orang yang syahid dari umatku sangat sedikit, padahal terbunuhnya seorang muslim terhitung syahid, kematian karena wabah thaun terhitung syahid, kematian karena sakit perut terhitung syahid, kematian karena tenggelam terhitung syahid dan seorang wanita yang mati karena melahirkan anaknya terhitung syahid.\""},"3316":{"ar":"قَالَ سَمِعْت سُفْيَانَ بْنَ عُيَيْنَةَيُسَمِّي النُّقَبَاءَ فَسَمَّى عُبَادَةَ بْنَ الصَّامِتِ مِنْهُمْ قَالَ سُفْيَانُ عُبَادَةُ عَقَبِيٌّ أُحُدِيٌّ بَدْرِيٌّ شَجَرِيٌّ وَهُوَ نَقِيبٌ","id":"Ahmad berkata: Saya mendengar Sufyan bin 'Uyainah menyebut para cendekia, ia menyebutkan bahwa 'Ubadah bin Ash Shamit termasuk di dalamnya, [Sufyan] berkata: 'Ubadah seorang sahabat yang ikut dalam bai'ah Aqobah, yang mengikuti perang Uhud, Badar, yang berbaiah ridlwan dan dia seorang cendekia.\""},"3317":{"ar":"قَالَ قَرَأْتُ عَلَى يَعْقُوبَ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنِ ابْنِ إِسْحَاقَ قَالَعُبَادَةُ بْنُ الصَّامِتِ بْنِ قَيْسِ بْنِ أَصْرَمَ بْنِ فِهْرِ بْنِ ثَعْلَبَةَ فِي الِاثْنَيْ عَشَرَ الَّذِينَ بَايَعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعَقَبَةِ الْأُولَى","id":"Ahmad berkata: Aku membacakan riwayat [Ya'qub bin Ibrahim] dari [ayahnya] dari [Ibnu Ishaq] berkata: 'Ubadah bin Ash Shamit bin Qois bin Ashram bin Fihir bin Tsa'labah termasuk satu dari dua belas orang yang berbaiat kepada Rasulullah Shallallahu'alaihiwasallam saat baiat Aqobah pertama."},"3318":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ أَبُو زَكَرِيَّا الْنَّصْرِيُّ الْحَرْبِيُّ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَلَّامٍ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ الْكِنْدِيِّ أَنَّهُجَلَسَ مَعَ عُبَادَةَ بْنِ الصَّامِتِ وَأَبِي الدَّرْدَاءِ وَالْحَارِثِ بْنِ مُعَاوِيَةَ الْكِنْدِيِّ فَتَذَاكَرُوا حَدِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو الدَّرْدَاءِ لِعُبَادَةَ يَا عُبَادَةُ كَلِمَاتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ كَذَا فِي شَأْنِ الْأَخْمَاسِ فَقَالَ عُبَادَةُ قَالَ إِسْحَاقُ يَعْنِي ابْنَ عِيسَى فِي حَدِيثِهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فِي غَزْوَتِهِمْ إِلَى بَعِيرٍ مِنْ الْمُقَسَّمِ فَلَمَّا سَلَّمَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَنَاوَلَ وَبَرَةً بَيْنَ أُنْمُلَتَيْهِ فَقَالَ إِنَّ هَذِهِ مِنْ غَنَائِمِكُمْ وَإِنَّهُ لَيْسَ لِي فِيهَا إِلَّا نَصِيبِي مَعَكُمْ إِلَّا الْخُمُسُ وَالْخُمُسُ مَرْدُودٌ عَلَيْكُمْ فَأَدُّوا الْخَيْطَ وَالْمَخِيطَ وَأَكْبَرَ مِنْ ذَلِكَ وَأَصْغَرَ لَا تَغُلُّوا فَإِنَّ الْغُلُولَ نَارٌ وَعَارٌ عَلَى أَصْحَابِهِ فِي الدُّنْيَا وَالْآخِرَةِ وَجَاهِدُوا النَّاسَ فِي اللَّهِ تَبَارَكَ وَتَعَالَى الْقَرِيبَ وَالْبَعِيدَ وَلَا تُبَالُوا فِي اللَّهِ لَوْمَةَ لَائِمٍ وَأَقِيمُوا حُدُودَ اللَّهِ فِي الْحَضَرِ وَالسَّفَرِ وَجَاهِدُوا فِي سَبِيلِ اللَّهِ فَإِنَّ الْجِهَادَ بَابٌ مِنْ أَبْوَابِ الْجَنَّةِ عَظِيمٌ يُنَجِّي اللَّهُ تَبَارَكَ وَتَعَالَى بِهِ مِنْ الْهَمِّ وَالْغَمِّحَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ سَعِيدِ بْنِ يُوسُفَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَّامٍ نَحْوَ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin 'Utsman Abu Zakariya An Nashri Al Harbi] telah bercerita kepada kami [Isma'il bin 'Ayyasy] dari [Abu Bakar bin 'Abdullah] dari [Abu Sallam] dari [Al Miqdam bin Ma'di Karib Al Kindi] bahwa ia duduk bersama 'Ubadah bin Ash Shamit, Abu Ad Darda` dan Al Harits bin Mu'awiyah Al Kindi mereka menyebut hadits Rasulullah Shallallahu'alaihiwasallam lalu berkata Abu Ad-Darda` kepada 'Ubadah; 'Hai Ubadah, tolong dong sampaikan kata-kata Rasulullah Shallallahu'alaihiwasallam saat perang ini dan itu tentang rampasan perang. Berkata ['Ubadah] - [Ishaq] menyebutkan dalam haditsnya- bahwa Rasulullah Shallallahu'alaihiwasallam shalat mengimami mereka dalam peperangan, mereka menghadap unta rampasan perang, setelah salam beliau berdiri kemudian beliau mengambil bulu kapas diantara ujung-ujung jari beliau dan bersabda: \"Ini termasuk harta rampasan perang kalian dan aku hanya mendapatkan seperlima bagianku darinya dan seperlimanya lagi dikembalikan kepada kalian, karena itu tolong kumpulkan sekalipun benang atau kain yang dijahit, atau barang yang lebih besar dan lebih kecil darinya, jangan sesekali kalian berkhianat karena pengkhinatan adalah neraka dan aib bagi pelakunya di dunia dan akhirat, perangilah orang dengan niat karena Allah Tabaaroka wa Ta'aala, baik yang dekat atau pun yang jauh, jangan hiraukan cercaan orang karena melaksanakan aturan Allah, tegakkanlah hukum-hukum Allah saat bermukim dan bepergian, berjihadlah dijalan Allah karena jihad adalah salah satu pintu surga yang besar, dengan jihad Allah Tabaaroka wa Ta'aala mengobati duka dan kesedihan.\" Telah bercerita kepada kami [Yahya bin 'Utsman] telah bercerita kepada kami [Isma'il bin 'Ayyasy] dari [Sa'id bin Yusuf] dari [Yahya bin Abu Katsir] dari [Abu Sallam] seperti hadits di atas."},"3319":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا شَيْبَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ قَالَ قَالَ عُبَادَةُ بْنُ الصَّامِتِنَزَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَاللَّاتِي يَأْتِينَ الْفَاحِشَةَ }إِلَى آخِرِ الْآيَةِ قَالَ فَفَعَلَ ذَلِكَ بِهِنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ وَنَحْنُ حَوْلَهُ وَكَانَ إِذَا نَزَلَ عَلَيْهِ الْوَحْيُ أَعْرَضَ عَنَّا وَأَعْرَضْنَا عَنْهُ وَتَرَبَّدَ وَجْهُهُ وَكَرَبَ لِذَلِكَ فَلَمَّا رُفِعَ عَنْهُ الْوَحْيُ قَالَ خُذُوا عَنِّي قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الْبِكْرُ بِالْبِكْرِ جَلْدُ مِائَةٍ وَنَفْيُ سَنَةٍ وَالثَّيِّبُ بِالثَّيِّبِ جَلْدُ مِائَةٍ ثُمَّ الرَّجْمُ قَالَ الْحَسَنُ فَلَا أَدْرِي أَمِنَ الْحَدِيثِ هُوَ أَمْ لَا قَالَ فَإِنْ شَهِدُوا أَنَّهُمَا وُجِدَا فِي لِحَافٍ لَا يَشْهَدُونَ عَلَى جِمَاعٍ خَالَطَهَا بِهِ جَلْدُ مِائَةٍ وَجُزَّتْ رُءُوسُهُمَا","id":"Telah menceritakan kepada kami 'Abdullah, telah bercerita kepada kami [Syaiban bin Abu Syaibah] telah bercerita kepada kami [Jarir bin Hazim] telah bercerita kepada kami [Al Hasan] berkata: ['Ubadah bin Ash Shamit] berkata: Wahyu turun kepada Rasulullah Shallallahu'alaihiwasallam, yaitu ayat: \"Dan (terhadap) para wanita yang mengerjakan perbuatan keji, hendaklah ada empat orang saksi diantara kamu (yang menyaksikannya). Kemudian apabila mereka telah memberi persaksian, Maka kurunglah mereka (wanita-wanita itu) dalam rumah sampai mereka menemui ajalnya, atau sampai Allah memberi jalan lain kepadanya.\" (An-Nisaa`: 15), Rasulullah Shallallahu'alaihiwasallam pun memberlakukan (ayat ini) terhadap mereka. Pernah ketika Rasulullah sedang duduk dan kami berada di sekitar beliau, wahyu turun kepada beliau Shallallahu'alaihiwasallam. Adalah kebiasaan beliau jika mendapat wahyu, beliau berpaling dari kami dan kami berpaling dari beliau Shallallahu'alaihiwasallam, wajah beliau Shallallahu'alaihiwasallam berubah menjadi padam dan terasa berat dengan turunnya wahyu tersebut, tatkala wahyu telah diangkat darinya beliau Shallallahu'alaihiwasallam bersabda: \"Ambillah ketetapan hukumku!.\" Kami berkata: Baik wahai Rasulullah, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah memberi ketetapan hukum kepada kalian, hukuman bagi seorang perawan yang berzina dengan jejaka adalah dicambuk seratus kali dan diasingkan selama satu tahun, dan hukuman bagi seorang wanita berzina sedang ia telah menikah dengan seorang pria yang telah menikah, ia dicambuk seratus kali kemudian dirajam.\" Al Hasan berkata: Saya tidak tahu apa yang saya sebut ini termasuk hadits atau tidak: \"Jika mereka bersaksi bahwa kedua laki-laki dan wanita berada dalam satu selimut dan mereka tidak melihat persetubuhannya maka hukumannya adalah seratus kali cambuk dan rambut mereka dicukur.\""},"3320":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عَلِيُّ بْنُ شُعَيْبٍ الْبَزَّارُ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَاقَ الْحَضْرَمِيُّ أَخْبَرَنِي أَبُو عَوَانَةَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عِيسَى قَالَ وَكَانَ أَمِيرًا عَلَى الرَّقَّةِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَمِيرِ عَشَرَةٍ إِلَّا جِيءَ بِهِ يَوْمَ الْقِيَامَةِ مَغْلُولَةٌ يَدُهُ إِلَى عُنُقِهِ حَتَّى يُطْلِقَهُ الْحَقُّ أَوْ يُوبِقَهُ وَمَنْ تَعَلَّمَ الْقُرْآنَ ثُمَّ نَسِيَهُ لَقِيَ اللَّهَ وَهُوَ أَجْذَمُ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami ['Ali bin Syu'aib Al Bazzar] telah bercerita kepada kami [Ya'qub bin Ishaq Al Hadhrami] telah mengabarkan kepadaku [Abu 'Awanah] dari [Yazid bin Abu Ziyad] dari ['Isa], saat menjabat gubernur Raqqah berkata: Dari ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seseorang yang memimpin sepuluh orang melainkan kelak pada hari kiamat akan didatangkan dalam keadaan terbelenggu, kebenaran akan melepaskannya atau membinasakannya dan tidaklah seseorang belajar al Qur`an kemudian ia melupakannya melainkan ia akan bertemu kepada Allah pada hari kiamat dalam keadaan terputus tangannya.\" "},"3321":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو أَحْمَدَ مَخْلَدُ بْنُ الْحَسَنِ بْنِ أَبِي زُمَيْلٍ إِمْلَاءً مِنْ كِتَابِهِ حَدَّثَنَا الْحَسَنُ بْنُ عَمْرِو بْنِ يَحْيَى الْفَزَارِيُّ وَيُكْنَى أَبَا عَبْدِ اللَّهِ وَلَقَبُهُ أَبُو الْمَلِيحِ يَعْنِي الرَّقِّيَّ عَنْ حَبِيبِ بْنِ أَبِي مَرْزُوقٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِي مُسْلِمٍ قَالَدَخَلْتُ مَسْجِدَ حِمْصَ فَإِذَا فِيهِ حَلْقَةٌ فِيهَا اثْنَانِ وَثَلَاثُونَ رَجُلًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَفِيهِمْ شَابٌّ أَكْحَلُ بَرَّاقُ الثَّنَايَا مُحْتَبٍ فَإِذَا اخْتَلَفُوا فِي شَيْءٍ سَأَلُوهُ فَأَخْبَرَهُمْ فَانْتَهَوْا إِلَى خَبَرِهِ قَالَ قُلْتُ مَنْ هَذَا قَالُوا هَذَا مُعَاذُ بْنُ جَبَلٍ قَالَ فَقُمْتُ إِلَى الصَّلَاةِ قَالَ فَأَرَدْتُ أَنْ أَلْقَى بَعْضَهُمْ فَلَمْ أَقْدِرْ عَلَى أَحَدٍ مِنْهُمْ انْصَرَفُوا فَلَمَّا كَانَ الْغَدُ دَخَلْتُ فَإِذَا مُعَاذٌ يُصَلِّي إِلَى سَارِيَةٍ قَالَ فَصَلَّيْتُ عِنْدَهُ فَلَمَّا انْصَرَفَ جَلَسْتُ بَيْنِي وَبَيْنَهُ السَّارِيَةُ ثُمَّ احْتَبَيْتُ فَلَبِثْتُ سَاعَةً لَا أُكَلِّمُهُ وَلَا يُكَلِّمُنِي قَالَ ثُمَّ قُلْتُ وَاللَّهِ إِنِّي لَأُحِبُّكَ لِغَيْرِ دُنْيَا أَرْجُوهَا أُصِيبُهَا مِنْكَ وَلَا قَرَابَةَ بَيْنِي وَبَيْنَكَ قَالَ فَلِأَيِّ شَيْءٍ قَالَ قُلْتُ لِلَّهِ تَبَارَكَ وَتَعَالَى قَالَ فَنَثَرَ حِبْوَتِي ثُمَّ قَالَ فَأَبْشِرْ إِنْ كُنْتَ صَادِقًا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُتَحَابُّونَ فِي اللَّهِ تَبَارَكَ وَتَعَالَى فِي ظِلِّ الْعَرْشِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ يَغْبِطُهُمْ بِمَكَانِهِمْ النَّبِيُّونَ وَالشُّهَدَاءُ قَالَ ثُمَّ خَرَجْتُ فَأَلْقَى عُبَادَةَ بْنَ الصَّامِتِ قَالَ فَحَدَّثْتُهُ بِالَّذِي حَدَّثَنِي مُعَاذٌ فَقَالَ عُبَادَةُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْوِي عَنْ رَبِّهِ تَبَارَكَ وَتَعَالَى أَنَّهُ قَالَ حَقَّتْ مَحَبَّتِي عَلَى الْمُتَزَاوِرِينَ فِيَّ وَحَقَّتْ مَحَبَّتِي عَلَى الْمُتَبَاذِلِينَ فِيَّ عَلَى مَنَابِرَ مِنْ نُورٍ يَغْبِطُهُمْ بِمَكَانِهِمْ النَّبِيُّونَ وَالصِّدِّيقُونَ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Abu Ahmad Makhlad bin Al Hasan bin Abu Zumail] dengan mengimlakkan dari bukunya: telah bercerita kepada kami [Al Hasan bin 'Amru bin Yahya Al Fazari] kuniahnya Abu 'Abdullah dan julukannya Abu Al Malih Ar Raqqi dari [Habib bin Abu Marzuq] dari ['Atho` bin Abu Rabah] dari [Abu Muslim] berkata: Saya memasuki masjid Himsh, disana ada tigapuluh dua sahabat Rasulullah Shallallahu'alaihiwasallam, diantara mereka ada seorang pemuda yang sangat putih giginya, ia duduk memeluk lutut. Bila mereka berbeda pendapat tentang sesuatu, mereka bertanya kepada pemuda itu dan mereka berhenti berdebat dengan memperhatikan jawabannya. Saya bertanya siapa pemuda itu, lalu ada yang menjawab; Dia Mu'adz bin Jabal. Aku lalu shalat dan ingin menemui sebagian mereka, tapi aku tidak bisa menemui seorang pun dari mereka, mereka pergi. Keesokan harinya saya pergi ke masjid ternyata disana ada [Mu'adz bin Jabal] yang tengah shalat menghadap tiang masjid. Aku pun shalat di dekatnya, saat ia hendak pergi, aku duduk dihadapannya, aku diam sesaat, tidak berbicara apa pun dengannya, lalu aku berkata: Demi Allah, aku mencintaimu bukan karena dunia yang aku harapkan darimu atau pun kedekatan denganmu. Ia bertanya; Karena apa? Saya berkata; karena Allah Tabaaroka wa Ta'aalaa. Kemudian ia melebarkan serbanku lalu berkata; Bergembiralah bila kau memang benar karena aku pernah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda; \"Orang-orang yang saling menyintai karena keagungan-Ku akan mendapatkan mimbar-mimbar dari cahaya yang membuat iri para nabi dan syuhada`.\" Kemudian saya keluar dan menemui 'Ubadah bin Ash-Shomit lalu saya berkata; Hai Abu Al Walid! Aku tidak akan menceritakan hadits yang disampaikan Mu'adz bin Jabal kepadaku tentang orang-orang yang saling mencintai. ['Ubadah] berkata; Aku akan bercerita kepadamu dari Nabi Shallallahu'alaihiwasallam dari Rabb Tabaaroka wa Ta'aalaa, Ia berfirman; 'Wajiblah cintaKu untuk orang-orang yang saling mencintai karena Aku, wajiblah cintaKu untuk orang-orang yang saling berkunjung karena Aku, wajiblah cintaKu untuk orang-orang yang saling berkorban karena Aku, wajiblah cintaKu untuk orang-orang yang saling bersillaturrahim karena Aku, wajiblah cintaKu untuk orang-orang yang saling berkorban karena Aku, (mereka) diatas mimbar-mimbar dari cahaya, para nabi dan orang-orang jujur iri atas tempat yang mereka dapatkan itu.\""},"3322":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَحْرٍ عَبْدُ الْوَاحِدِ بْنُ غِيَاثٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي سِنَانٍ عَنْ يَعْلَى بْنِ شَدَّادٍ قَالَ سَمِعْتُ عُبَادَةَ بْنَ الصَّامِتِ يَقُولُعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ أَصْحَابِهِ فَقَالَ هَلْ تَدْرُونَ مَنْ الشُّهَدَاءُ مِنْ أُمَّتِي مَرَّتَيْنِ أَوْ ثَلَاثًا فَسَكَتُوا فَقَالَ عُبَادَةُ أَخْبِرْنَا يَا رَسُولَ اللَّهِ فَقَالَ الْقَتِيلُ فِي سَبِيلِ اللَّهِ شَهِيدٌ وَالْمَبْطُونُ شَهِيدٌ وَالْمَطْعُونُ شَهِيدٌ وَالنُّفَسَاءُ شَهِيدٌ يَجُرُّهَا وَلَدُهَا بِسُرَرِهِ إِلَى الْجَنَّةِ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Abu Bahr 'Abdul Wahid bin Ghiyats] telah bercerita kepada kami [Hammad bin Salamah] dari [Abu Sinan] dari [Ya'la bin Syaddad] berkata: Aku mendengar ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam mendatangiku saat aku sakit, beliau bersabda: \"Apakah kalian tahu siapa syuhada` ummatku?\" beliau menanyakannya dua atau tiga kali, para sahabat hanya diam kemudian 'Ubadah bin Ash Shamit berkata: \"Beritahukanlah kepada kami wahai Rasulullah! Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang terbunuh dijalan Allah itu syahid, orang mati karena sakit perut itu syahid, orang yang mati karena penyakit tha'un itu syahid, wanita-wanita nifas yang mati itu syahid, anaknya menyeretnya ke surga dengan ari-arinya.\""},"3323":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ الْكَوْسَجُ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ أَنَّ عُبَادَةَ بْنَ الصَّامِتِ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَلَى ظَهْرِ الْأَرْضِ مِنْ رَجُلٍ مُسْلِمٍ يَدْعُو اللَّهَ عَزَّ وَجَلَّ بِدَعْوَةٍ إِلَّا آتَاهُ اللَّهُ إِيَّاهَا أَوْ كَفَّ عَنْهُ مِنْ السُّوءِ مِثْلَهَا مَا لَمْ يَدْعُ بِإِثْمٍ أَوْ قَطِيعَةِ رَحِمٍ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Ishaq bin Manshur Al Kausaj] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah bercerita kepada kami [Ibnu Tsauban] dari [ayahnya] dari [Makhul] dari [Jubair bin Nufair] bahwa ['Ubadah bin Ash Shamit] bercerita kepada mereka; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang muslim pun dimuka bumi yang berdoa kepada Allah AzzaWaJalla dengan sebuah doa melainkan Allah akan memberikan hal itu kepadanya atau atau menjaganya dari kejelekan semisalnya selama ia tidak meminta dengan kejelekan atau memutus hubungan rahim.\""},"3324":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي الْمُثَنَّى عَنِ ابْنِ أُخْتِ عُبَادَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ عَلَيْكُمْ أُمَرَاءُ تَشْغَلُهُمْ أَشْيَاءُ عَنْ الصَّلَاةِ حَتَّى يُؤَخِّرُوهَا عَنْ وَقْتِهَا فَصَلُّوهَا لِوَقْتِهَا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ فَإِنْ أَدْرَكْتُ مَعَهُمْ أُصَلِّي قَالَ إِنْ شِئْتَ","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami [Abu Khaitsamah Zuhair bin Harb] telah bercerita kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Al Mutsanna] dari [keponakan 'Ubadah] dari ['Ubadah bin Ash Shamit] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Akan ada para pemimpin sesudahku yang disibukkan oleh banyak urusan sehingga mereka mengakhirkan shalat dari waktunya, maka shalatlah kalian tepat pada waktunya.\" Seseorang berkata; Wahai Rasulullah! Bila aku berjumpa dengan mereka, apakah aku shalat (bersama mereka)? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Silahkan, bila kau mau.\""},"3325":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ غِيَاثٍ وَإِبْرَاهِيمُ بْنُ الْحَجَّاجِ النَّاجِيُّ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ جَبَلَةَ بْنِ عَطِيَّةَ عَنْ يَحْيَى بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَزَا قَالَ إِبْرَاهِيمُ فِي حَدِيثِهِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ وَلَا يَنْوِي فِي غَزَاتِهِ إِلَّا عِقَالًا فَلَهُ مَا نَوَى","id":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepada kami ['Abdul Wahid bin Ghiyats] dan [Ibrahim bin Al Hajjaj An Naji] keduanya berkata: telah bercerita kepada kami [Hammad bin Salamah] dari [Jabalah bin 'Athiyyah] dari [Yahya bin Al Walid bin 'Ubadah bin Ash Shamit] dari ['Ubadah bin Ash Shamit] Bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berperang di jalan Allah -dalam redaksi Ibrahim: dijalan Allah AzzaWaJalla- dan dia tidak berniat di dalam perangnya kecuali untuk mendapatkan harta rampasan, maka hanya mendapatkan yang diniatinya.\""},"3326":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَذِهِ مِنْ هَذِهِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahal] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jarak antara aku diutus dan hari kiamat seperti halnya perbedaan panjang jari ini dan jari ini \"."},"3327":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ يَقُولُأَنَا فِي الْقَوْمِ إِذْ دَخَلَتْ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَ فِيهَا رَأْيَكَ فَقَالَ رَجُلٌ زَوِّجْنِيهَا فَلَمْ يُجِبْهُ حَتَّى قَامَتْ الثَّالِثَةَ فَقَالَ لَهُ عِنْدَكَ شَيْءٌ قَالَ لَا قَالَ اذْهَبْ فَاطْلُبْ قَالَ لَمْ أَجِدْ قَالَ فَاذْهَبْ فَاطْلُبْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ قَالَ مَا وَجَدْتُ خَاتَمًا مِنْ حَدِيدٍ قَالَ هَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا قَالَ قَدْ أَنْكَحْتُكَهَا عَلَى مَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Sufyan] telah bercerita kepada kami [Abu Hazim] berkata: Aku mendengar [Sahal bin Sa'ad] berkata: \"Saya bersama orang-orang ketika ada seorang wanita yang datang menemui Nabi Shallallahu'alaihiwasallam dan berkata: wahai Rasulullah, saya menghibahkan diriku kepadamu, bagaimana menurut baginda? lalu ada seseorang menyela: Nikahkan saya dengannya, namun beliau Shallallahu'alaihiwasallam tidak menjawabnya sehingga wanita itu berdiri untuk yang ketiga kalinya, dan beliau Shallallahu'alaihiwasallam bersabda kepada laki-laki itu: \"Apakah kamu memiliki sesuatu?\" orang itu menjawab: Tidak. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pergi sana dan carilah sesuatu.\" Orang itu berkata: Saya tidak menemukan apa pun, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pergi dan carilah meski hanya cincin besi.\" Orang itu berkata: Saya tidak menemukan apa pun, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah kamu memiliki hafalan Al Qur'an?\" orang itu berkata: Iya, surat ini dan surat ini, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya menikahkanmu dengan hafalan Al Qur'anmu.\""},"3328":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلٍبِأَيِّ شَيْءٍ دُووِيَ جُرْحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ عَلِيٌّ يَجِيءُ بِالْمَاءِ فِي تُرْسِهِ وَفَاطِمَةُ تَغْسِلُ الدَّمَ عَنْ وَجْهِهِ وَأَخَذَ حَصِيرًا فَأَحْرَقَهُ فَحَشَا بِهِ جُرْحَهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahal bin Sa'ad] (ia ditanya), dengan apa luka Rasulullah Shallallahu'alaihiwasallam diobati? ia berkata: Ali datang dengan membawa air di tamengnya dan Fathimah membersihkan darah dari wajah beliau Shallallahu'alaihiwasallam, lalu Ali mengambil tikar dan membakarnya lalu menambalkannya pada luka beliau Shallallahu'alaihiwasallam."},"3329":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ سَمِعَ سَهْلَ بْنَ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ إِنَّمَا التَّصْفِيحُ لِلنِّسَاءِ وَالتَّسْبِيحُ لِلرِّجَالِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] bahwasanya ia mendengar [Sahal bin Sa'ad] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barang siapa yang teringat sesuatu yang terlupakan saat shalat maka hendaklah ia berkata: Subhaanallah, karena tepuk tangan hanya bagi wanita sedangkan tasbih untuk kaum lelaki.\""},"3330":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍاطَّلَعَ رَجُلٌ مِنْ جُحْرٍ فِي حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ مِدْرًى يَحُكُّ بِهِ رَأْسَهُ فَقَالَ لَوْ أَعْلَمُكَ تَنْتَظِرُ لَطَعَنْتُ بِهِ عَيْنَكَ إِنَّمَا جُعِلَ الِاسْتِئْذَانُ مِنْ أَجْلِ الْبَصَرِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sahal bin Sa'ad] berkata: Ada seseorang yang mengintip pada sebuah lubang di kamar Nabi Shallallahu'alaihiwasallam, sedang nabi shallallahu 'alaihi wasallam sedang membawa sisir yang ia sisirkan pada kepalanya (rambutnya), maka Nabi Shallallahu'alaihiwasallam bersabda: \"Jikalau saya mengetahuimu mengintip maka saya akan mencolok matamu, diberlakukannya meminta ijin (untuk masuk rumah) itu demi pandangan.\""},"3331":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ سَمِعَ سَهْلَ بْنَ سَعْدٍشَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُتَلَاعِنَيْنِ فَتَلَاعَنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ قَالَ يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَقَدْ كَذَبْتُ عَلَيْهَا قَالَ فَجَاءَتْ بِهِ لِلَّذِي كَانَ يَكْرَهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] ia mendengar [Sahal bin Sa'ad]; Aku menyaksikan Nabi Shallallahu'alaihiwasallam tentang dua orang yang saling bersumpah li'an, keduanya bersumpah li'an dimasa Rasulullah Shallallahu'alaihiwasallam, saat itu aku berusia limabelas tahun. Salah satunya berkata: \"Wahai Rasulullah! Bila aku mempertahankannya berarti aku mendustakannya\". Sahal menambahkan: Kemudian wanita itu melahirkan bayi yang ciri-cirinya memuakkan suaminya."},"3332":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا رَبِيعَةُ بْنُ عُثْمَانَ التَّيْمِيُّ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَاخْتَلَفَ رَجُلَانِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ الَّذِي أُسِّسَ عَلَى التَّقْوَى فَقَالَ أَحَدُهُمَا هُوَ مَسْجِدُ الرَّسُولِ وَقَالَ الْآخَرُ هُوَ مَسْجِدُ قُبَاءٍ فَأَتَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَاهُ فَقَالَ هُوَ مَسْجِدِي هَذَاحَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي أَبُو حَازِمٍ الْأَفْزَرُ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ الْمَخْزُومِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ مِنْ بَنِي عَمْرٍو فِي مُنَازَعَةٍ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Rabi'ah bin 'Utsman At Taimi] dari ['Imran bin Abu Anas] dari [Sahal bin Sa'ad] berkata: Dua orang berbeda pendapat dimasa Rasulullah Shallallahu'alaihiwasallam tentang masjid yang didirikan diatas ketakwaan, salah satu diantara keduanya berkata: Itu adalah masjidnya Rasul. Yang lain berkata: Itu adalah masjid Quba. Kemudian keduanya mendatangi Nabi Shallallahu'alaihiwasallam dan bertanya kepada beliau, beliau bersabda: Itu adalah masjidku ini. Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [ayahku] dari [Ibnu Ishaq] telah bercerita kepadaku [Abu Hazim Al Afzar], budak Al Aswad bin Sufyan Al Makhzumi dari [Sahal bin Sa'ad As Sa'idi dari Bani 'Amru] tentang perbedaan pendapat, lalu ia menyebutkan hadits."},"3333":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا الْمَسْعُودِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ بَيْنَ نَاسٍ مِنْ الْأَنْصَارِ شَيْءٌ فَانْطَلَقَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصْلِحَ بَيْنَهُمْ فَحَضَرَتْ الصَّلَاةُ فَجَاءَ بِلَالٌ إِلَى أَبِي بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ قَدْ حَضَرَتْ الصَّلَاةُ وَلَيْسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاهُنَا فَأُؤَذِّنُ وَأُقِيمُ فَتَتَقَدَّمَ وَتُصَلِّيَ قَالَ مَا شِئْتَ فَافْعَلْ فَتَقَدَّمَ أَبُو بَكْرٍ فَاسْتَفْتَحَ الصَّلَاةَ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَفَّحَ النَّاسُ بِأَبِي بَكْرٍ فَذَهَبَ أَبُو بَكْرٍ يَتَنَحَّى فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ مَكَانَكَ فَتَأَخَّرَ أَبُو بَكْرٍ وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمَّا قَضَى الصَّلَاةَ قَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تَثْبُتَ قَالَ مَا كَانَ لِابْنِ أَبِي قُحَافَةَ أَنْ يَتَقَدَّمَ أَمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَنْتُمْ لِمَ صَفَّحْتُمْ قَالُوا لِنُعْلِمَ أَبَا بَكْرٍ قَالَ إِنَّ التَّصْفِيحَ لِلنِّسَاءِ وَالتَّسْبِيحَ لِلرِّجَالِ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Al Mas'udi] dari [Abu Hazim] dari [Sahal bin Sa'ad] berkata: Ada perbedaan pendapat diantara orang-orang Anshar. Rasulullah Shallallahu'alaihiwasallam kemudian mendatangi mereka untuk mendamaikan mereka, waktu shalat pun tiba lalu Bilal mendatangi Abu Bakar dan berkata: Hai Abu Bakar sudah waktunya shalat tapi Rasulullah Shallallahu'alaihiwasallam tidak ada disini, aku akan mengumandangkan adzan lalu kau maju dan mengimami. Ia berkata: Terserah, silahkan kau lakukan. Abu Bakar maju dan memulai shalat kemudian Rasulullah Shallallahu'alaihiwasallam datang, orang-orang menepuk tangan (memberi sinyal) untuk Abu Bakar lalu Abu Bakar menyingkir, Rasulullah Shallallahu'alaihiwasallam berisyarat padanya agar tetap berada ditempatnya, Abu Bakar mundur sementara Rasulullah Shallallahu'alaihiwasallam maju kemudian shalat. Seusai shalat Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hai Abu Bakar! Apa yang menghalangimu untuk tetap berada ditempatmu?\" Abu Bakar menjawab: Ibnu Abi Quhafah tidak layak maju di depan Rasulullah Shallallahu'alaihiwasallam. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Lalu kalian, mengapa menepuk tangan?\" mereka menjawab: Untuk memberitahu Abu Bakar. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tepuk tangan hanya diperuntukkan bagi kaum wanita, sedang tasbih untuk kaum lelaki.\""},"3334":{"ar":"و قَالَ أَبُو حَازِمٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو ضَمْرَةَ لَا أَعْلَمُهُ إِلَّا عَنْ سَهْلِ بْنِ سَعْدٍ قَالَمَثَلِي وَمَثَلُ السَّاعَةِ كَهَاتَيْنِ وَفَرَّقَ بَيْنَ أُصْبُعَيْهِ الْوُسْطَى وَالَّتِي تَلِي الْإِبْهَامَ ثُمَّ قَالَ مَثَلِي وَمَثَلُ السَّاعَةِ كَمَثَلِ فَرَسَيْ رِهَانٍ ثُمَّ قَالَ مَثَلِي وَمَثَلُ السَّاعَةِ كَمَثَلِ رَجُلٍ بَعَثَهُ قَوْمُهُ طَلِيعَةً فَلَمَّا خَشِيَ أَنْ يُسْبَقَ أَلَاحَ بِثَوْبِهِ أُتِيتُمْ أُتِيتُمْ ثُمَّ يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا ذَلِكَ","id":"Dan [Abu Hazim] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda - [Abu Dhamrah] menjelaskan: Aku hanya mengetahuinya dari [Sahal bin Sa'ad] - \"Perumpamaanku dengan waktu kiamat seperti dua ini.\" Beliau merenggangkan jari tengah dan jari telunjuk. Selanjutnya beliau bersabda: \"Perumpamaanku dengan hari kiamat seperti dua kuda yang diperlombakan (diadu kecepatannya).\" Selanjutnya beliau bersabda: \"Perumpamaanku dengan hari kiamat seperti seseorang yang diutus kaumnya sebagai pasukan pengintai, saat merasa khawatir didahului, ia melambai-lambaikan bajunya: kalian telah didatangi, kalian telah didatangi.\" Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Akulah orang itu.\""},"3335":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ يَقُولُكَانَ رِجَالٌ يُصَلُّونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَاقِدِي أُزُرِهِمْ عَلَى رِقَابِهِمْ كَهَيْئَةِ الصِّبْيَانِ فَيُقَالُ لِلنِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَسْتَوِيَ الرِّجَالُ جُلُوسًا","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] telah bercerita kepada kami [Sufyan] dari [Abu Hazim] berkata: Aku mendengar [Sahal bin Sa'ad] berkata: Ada beberapa orang shalat bersama Rasulullah Shallallahu'alaihiwasallam seraya mengikatkan kain sarung diatas leher seperti anak kecil, kaum wanita diseru: Janganlah kalian mengangkat kepala hingga kaum lelaki duduk."},"3336":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا حُسَيْنٌ حَدَّثَنِي أَبُو نَهِيكٍ حَدَّثَنِي أَبُو زَيْدٍ عَمْرُو بْنُ أَخْطَبَ الْأَنْصَارِيُّ قَالَاسْتَسْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءً فَأَتَيْتُهُ بِقَدَحٍ فِيهِ مَاءٌ فَكَانَتْ فِيهِ شَعَرَةٌ فَأَخَذْتُهَا فَقَالَ اللَّهُمَّ جَمِّلْهُ قَالَ فَرَأَيْتُهُ وَهُوَ ابْنُ أَرْبَعٍ وَتِسْعِينَ لَيْسَ فِي لِحْيَتِهِ شَعَرَةٌ بَيْضَاءُ","id":"Telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepada kami [Husain] telah menceritakan kepadaku [Abu Nahik] telah menceritakan kepadaku [Abu Zaid 'Amru bin Akhthab Al Anshari] berkata: Rasulullah Shallallahu'alaihiwasallam meminta air minum lalu aku membawakan gelas berisi air, didalamnya ada rambut lalu aku mengambilnya kemudian beliau bersabda: \"Ya Allah perindahlah dia.\" Berkata Abu Nahik: Aku melihat Abu Zaid saat ia berusia sembilanpuluh empat namun di jenggotnya tidak ada satu helai pun yang beruban."},"3337":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي حُسَيْنُ بْنُ وَاقِدٍ قَالَ سَمِعْتُ أَبَا نَهِيكٍ يَقُولُ سَمِعْتُ أَبَا زَيْدٍ عَمْرَو بْنَ أَخْطَبَ قَالَرَأَيْتُ الْخَاتَمَ الَّذِي بَيْنَ كَتِفَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرَجُلٍ قَالَ بِإِصْبَعِهِ الثَّلَاثَةِ هَكَذَا فَمَسَحْتُهُ بِيَدِي","id":"Telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepadaku [Husain bin Waqid] berkata: Aku mendengar [Abu Nuhaik] berkata: Aku mendengar [Abu Zaid 'Amru bin Akhthab] berkata: Aku melihat tanda di dua pundak Rasulullah Shallallahu'alaihiwasallam seperti bentuk orang. Berkata Abu Nuhaik dengan tiga jarinya seperti ini kemudian aku mengusapnya dengan tanganku."},"3338":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ يَعْنِي ابْنَ شَقِيقٍ حَدَّثَنِي الْحُسَيْنُ بْنُ وَاقِدٍ حَدَّثَنَا أَبُو نَهِيكٍ الْأَزْدِيُّ عَنْ عَمْرِو بْنِ أَخْطَبَ قَالَاسْتَسْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ بِإِنَاءٍ فِيهِ مَاءٌ وَفِيهِ شَعْرَةٌ فَرَفَعْتُهَا ثُمَّ نَاوَلْتُهُ فَقَالَ اللَّهُمَّ جَمِّلْهُقَالَ فَرَأَيْتُهُ بَعْدَ ثَلَاثٍ وَتِسْعِينَ سَنَةً وَمَا فِي رَأْسِهِ وَلِحْيَتِهِ شَعَرَةٌ بَيْضَاءُ","id":"Telah menceritakan kepada kami ['Ali bin Al Hasan bin Syaqiq] telah menceritakan kepadaku [Al Husain bin Waqid] telah menceritakan kepada kami [Abu Nahik Al Azdi] dari ['Amru bin Akhthab] berkata: Rasulullah Shallallahu'alaihiwasallam meminta air minum lalu aku membawakan gelas berisi air, didalamnya ada rambut lalu aku mengambilnya kemudian memberikannya pada beliau, lalu beliau bersabda: \"Ya Allah perindahlah dia.\" Berkata Abu Nahik: Aku melihat Abu Zaid saat berusia sembilanpuluh tiga namun di jenggotnya tidak ada satu helai pun yang beruban."},"3339":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا تَمِيمُ بْنُ حُوَيَصٍ قَالَ سَمِعْتُ أَبَا زَيْدٍ يَقُولُقَاتَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ عَشْرَةَ مَرَّةًقَالَ شُعْبَةُ وَهُوَ جَدُّ عَزْرَةَ هَذَا","id":"Telah menceritakan kepada kami ['Abdush Shamad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Tamim bin Huwayash] berkata: Aku mendengar [Abu Zaid] berkata: Aku berperang bersama Rasulullah Shallallahu'alaihiwasallam sebanyak tigabelas kali. Syu'bah menjelaskan, ia adalah kakek 'Azrah."},"3340":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ نُصَيْرٍ الْفَسَاطِيطِيُّ قَالَ وَلَمْ أَسْمَعْ مِنْهُ غَيْرَهُ قَالَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ أَنَسِ بْنِ سِيرِينَ حَدَّثَنِي أَبُو زَيْدِ بْنُ أَخْطَبَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَّلَكَ اللَّهُقَالَ أَنَسٌ وَكَانَ رَجُلًا جَمِيلًا حَسَنَ السَّمْتِ","id":"Telah menceritakan kepada kami [Hajjaj bin Nushair Al Fasathithi] berkata: Aku tidak mendengar hadits lain darinya selain hadits ini, ia berkata: telah menceritakan kepada kami [Qurrah bin Khalid] dari [Anas bin Sirin] telah menceritakan kepadaku [Abu Zaid bin Akhthab] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku: \"Semoga Allah memperindahmu.\" Berkata Anas: Abu Zaid adalah orang yang rupawan, berkepribadian baik."},"3341":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَ خَالِدٌ أَحْسِبُهُ عَمْرَو بْنَ بُجْدَانَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ دُورِ الْأَنْصَارِ فَوَجَدَ قُتَارًا فَقَالَ مَنْ صَنَعَ هَذَا أَوْ كَمَا قَالَ شَكَّ إِسْمَاعِيلُ فَخَرَجَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا يَوْمٌ اللَّحْمُ فِيهِ كَرِيهٌ وَإِنِّي عَجَّلْتُ نَسِيكَتِي قَالَ فَأَعِدْ قَالَ وَاللَّهِ مَا عِنْدِي إِلَّا جَذَعٌ أَوْ حَمَلٌ مِنْ الضَّأْنِ قَالَ فَاذْبَحْهُ وَلَا يُجْزِئُ جَذَعٌ عَنْ أَحَدٍ بَعْدَكَحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبِي حَدَّثَنَا خَالِدٌ الْحَذَّاءُ حَدَّثَنَا أَبُو قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّ قَالَ مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِ دِيَارِنَا فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Khalid] dari [Abu Qilabah] dari seseorang dari kaumnya -Khalid berkata, saya rasa orang itu adalah ['Amru bin Bujdan] - dari [Abu Zaid Al Anshari] berkata: Rasulullah Shallallahu'alaihiwasallam melintasi rumah-rumah kaum Anshar kemudian ia melihat sebuah pos, beliau bertanya: \"Siapa yang membuat ini?\" atau seperti yang beliau sabdakan -Isma'il ragu kepastian redaksinya- seseorang keluar kemudian bersabda: Wahai Rasulullah! Ini adalah hari menyembelih daging, didalamnya ada sesuatu yang tidak aku suka, aku menyegerakan kurbanku.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ulangilah.\" Orang itu berkata: demi Allah aku hanya memiliki anak kambing atau kambing gibas yang bunting. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sembelihlah dan seekor anak kambing tidak mencukupi untuk seorang pun setelahmu.\" telah menceritakan kepada kami ['Abdush Shamad] telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Khalid Al Hadzdza`] telah menceritakan kepada kami [Abu Qilbah] dari ['Amru bin Bujdan] dari [Abu Zaid Al Anshari] berkata: Rasulullah Shallallahu'alaihiwasallam melintasi depan rumah-rumah kami lalu ia menyebutkan maknanya."},"3342":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ حَدَّثَنَا عِلْبَاءُ بْنُ أَحْمَرَ الْيَشْكُرِيُّ حَدَّثَنَا أَبُو زَيْدٍ الْأَنْصَارِيُّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ ثُمَّ صَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى حَضَرَتْ الظُّهْرُ ثُمَّ نَزَلَ فَصَلَّى الظُّهْرَ ثُمَّ صَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى حَضَرَتْ الْعَصْرُ ثُمَّ نَزَلَ فَصَلَّى الْعَصْرَ فَصَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى غَابَتْ الشَّمْسُ فَحَدَّثَنَا بِمَا كَانَ وَمَا هُوَ كَائِنٌ فَأَعْلَمُنَا أَحْفَظُنَا","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami ['Azrah bin Tsabit] telah menceritakan kepada kami ['Ilba` bin Ahmar Al Yasykuri] telah menceritakan kepada kami [Abu Zaid Al Anshari] berkata: Rasulullah Shallallahu'alaihiwasallam shalat shubuh bersama kami, kemudian beliau naik mimbar, beliau berkhutbah hingga tiba waktu zhuhur, beliau turun kemudian shalat zhuhur, lalu naik mimbar berkhutbah hingga tiba waktu ashar, beliau turun lalu shalat ashar, kemudian naik mimbar berkhutbah hingga matahari terbenam. Beliau menceritakan yang telah terjadi dan yang tengah terjadi. Yang paling tahu diantara kami adalah yang paling hafal."},"3343":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَزْرَةُ حَدَّثَنَا عِلْبَاءُ بْنُ أَحْمَرَ حَدَّثَنَا أَبُو زَيْدٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا زَيْدٍ ادْنُ مِنِّي وَامْسَحْ ظَهْرِي وَكَشَفَ ظَهْرَهُ فَمَسَحْتُ ظَهْرَهُ وَجَعَلْتُ الْخَاتَمَ بَيْنَ أَصَابِعِي قَالَ فَغَمَزْتُهَا قَالَ فَقِيلَ وَمَا الْخَاتَمُ قَالَ شَعَرٌ مُجْتَمِعٌ عَلَى كَتِفِهِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami ['Azrah] telah menceritakan kepada kami ['Ilba` bin Ahmar] telah menceritakan kepada kami [Abu Zaid] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku: \"Hai Abu Zaid! Mendekatlah kearahku dan usaplah punggungku.\" Beliau membuka punggung beliau kemudian aku mengusap punggung beliau, aku tempatkan tanda di antara jari-jariku, aku merabanya. Ia ditanya: Tanda apa? Abu Zaid berkata: rambut yang mengumpul di pundak beliau."},"3344":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ حَدَّثَنَا عِلْبَاءُ بْنُ أَحْمَرَ حَدَّثَنَا أَبُو زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ وَجْهَهُ وَدَعَا لَهُ بِالْجَمَالِقَالَ و أَخْبَرَنِي غَيْرُ وَاحِدٍ أَنَّهُ بَلَغَ بِضْعًا وَمِائَةَ سَنَةٍ أَسْوَدَ الرَّأْسِ وَاللِّحْيَةِ إِلَّا نُبَذُ شَعَرٍ بِيضٌ فِي رَأْسِهِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami ['Azrah bin Tsabit] telah menceritakan kepada kami ['Ilba` bin Ahmar] telah menceritakan kepada kami [Abu Zaid] bahwa Rasulullah Shallallahu'alaihiwasallam mengusap wajahnya dan mendoakan keindahan untuknya. Berkata 'Ilba`: Telah mengabarkan kepadaku lebih dari seorang bahwa Abu Zaid telah mencapai usia seratus sekian tahun, rambut dan jenggotnya masih hitam kecuali rambut bagian depannya yang beruban."},"3345":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّأَنَّ رَجُلًا أَعْتَقَ سِتَّةَ أَعْبُدٍ عِنْدَ مَوْتِهِ لَيْسَ لَهُ مَالٌ غَيْرَهُمْ فَأَقْرَعَ بَيْنَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْتَقَ اثْنَيْنِ وَأَرَقَّ أَرْبَعَةًحَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ حَدَّثَنَا أَبُو قِلَابَةَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ يَعْنِي مِثْلَ حَدِيثِ مَنْصُورٍ عَنْ الْحَسَنِ أَنَّ رَجُلًا أَعْتَقَ سِتَّةَ مَمْلُوكِينَ لَهُ وَقَالَ فِيهِ فَأَقْرَعَ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] telah menceritakan kepada kami [Husyaim] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Zaid Al Anshari] bahwa seseorang memerdekakan enam budak saat sekarat, ia tidak punya harta lain selain budak-budak itu kemudian Rasulullah Shallallahu'alaihiwasallam mengundi mereka, beliau memerdekakan dua budak dan tetap mempertahankan empat lainnya sebagai budak. Telah menceritakan kepada kami [Suraij bin An Nu'man] telah menceritakan kepada kami [Husayim] telah mengabarkan kepada kami [Khalid] telah menceritakan kepada kami [Abu Qilabah] dari [Abu Zaid Al Anshari] dari Nabi Shallallahu'alaihiwasallam seperti itu, yaitu seperti hadits Manshur dari Al Hasan bahwa seseorang memerdekakan enam budak miliknya. Ia berkata dalam riwayatnya: Kemudian Rasulullah Shallallahu'alaihiwasallam mengundi mereka."},"3346":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ الْعَطَّارُ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّأَنَّهُ جَمَعَ أَصْحَابَهُ فَقَالَ هَلُمَّ أُصَلِّي صَلَاةَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَانَ رَجُلًا مِنْ الْأَشْعَرِيِّينَ قَالَ فَدَعَا بِجَفْنَةٍ مِنْ مَاءٍ فَغَسَلَ يَدَيْهِ ثَلَاثًا وَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا وَمَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ وَغَسَلَ قَدَمَيْهِ قَالَ فَصَلَّى الظُّهْرَ فَقَرَأَ فِيهَا بِفَاتِحَةِ الْكِتَابِ وَكَبَّرَ ثِنْتَيْنِ وَعِشْرِينَ تَكْبِيرَةًحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ ابْنِ أَبِي حُسَيْنٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَ كُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ عَلَيْهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }قَالَ فَنَحْنُ نَسْأَلُهُ أَوْ قَالَ لِلَّهِ عَزَّ وَجَلَّ عِبَادٌ لَيْسُوا بِأَنْبِيَاءَ وَلَا شُهَدَاءَ يَغْبِطُهُمْ النَّبِيُّونَ وَالشُّهَدَاءُ لِمَقْعَدِهِمْ وَقُرْبِهِمْ مِنْ اللَّهِ يَوْمَ الْقِيَامَةِ فَذَكَرَ الْحَدِيثَ بِطُولِهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban Al Aththar] telah menceritakan kepada kami [Qotadah] dari [Syahr bin Hausyab] dari ['Abdur Rahman bin Ghanm] dari [Abu Malik Al Asy'ari] bahwa ia mengumpulkan sahabat-sahabatnya lalu berkata kepada mereka: Mari bersamaku, aku akan shalat seperti shalatnya Nabi Allah Shallallahu'alaihiwasallam. Berkata Ibnu Ghanm: Abu Malik adalah orang dari Asy'ar. Ia meminta seember air lalu membasuh kedua tangan tiga kali, berkumur dan menghirup air, membasuh wajah tiga kali, kedua tangan hingga lengan tiga kali, mengusap rambut dan kedua telinga, membasuh kedua kaki lalu shalat zhuhur. Ia membaca faatihatul kitaab, bertakbir sebanyak duapuluh dua kali. Telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Abu Husain] dari [Syahr bin Hausyab] dari ['Abdur Rahman bin Ghanm] dari [Abu Malik Al Anshari] berkata: Aku berada didekat Nabi Shallallahu'alaihiwasallam kemudian turun wahyu kepada beliau \"Hai orang-orang yang beriman! Jangan bertanya tentang segala sesuatu bila diperlihatkan kepadamu niscaya akan menyusahkanmu.\" (Al Maa`idah (5): 101). Abu Malik berkata: Kami bertanya pada beliau, beliau bersabda: \" Allah AzzaWaJalla memiliki hamba-hamba, mereka bukan nabi atau pun syuhada` tapi para nabi dan syuhada` iri pada mereka, karena tempat dan kedekatan mereka dengan Allah pada hari kiamat.\" Abu Malik menyebutkan hadits secara panjang lebar."},"3347":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْظَمُ الْغُلُولِ عِنْدَ اللَّهِ عَزَّ وَجَلَّ ذِرَاعٌ مِنْ الْأَرْضِ تَجِدُونَ الرَّجُلَيْنِ جَارَيْنِ فِي الْأَرْضِ أَوْ فِي الدَّارِ فَيَقْتَطِعُ أَحَدُهُمَا مِنْ حَظِّ صَاحِبِهِ ذِرَاعًا إِذَا اقْتَطَعَهُ طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Abdul Malik bin 'Amru] telah menceritakan kepada kami [Zuhair bin Muhammad] dari ['Abdullah bin Muhammad bin 'Aqil] dari ['Atho` bin Yasar] dari [Abu Malik Al Asy'ari] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Pengkhianatan terbesar disisi Allah AzzaWaJalla adalah satu dzira' (hasta) tanah, kalian lihat dua orang bertetangga disuatu tempat atau di suatu rumah lalu salah satunya meyerobot bagian temannya, padahal bila ia menyerobotnya maka ia akan dikalungi tujuh bumi hingga hari kiamat.\""},"3348":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ قَالَقَالَ أَبُو مَالِكٍ الْأَشْعَرِيُّ لِقَوْمِهِ أَلَا أُصَلِّي لَكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَفَّ الرِّجَالُ ثُمَّ صَفَّ الْوِلْدَانُ خَلْفَ الرِّجَالِ ثُمَّ صَفَّ النِّسَاءُ خَلْفَ الْوِلْدَانِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepadaku ['Abdul Hamid bin Bahram] dari [Syahr bin Hausyab] dari ['Abdur Rahman bin Ghanm] berkata: Berkata [Abu Malik Al Asya'ari] kepada kaumnya: Bolehkan aku shalat untuk kalian seperti shalatnya Rasulullah Shallallahu'alaihiwasallam? Kemudian orang-orang berbaris, anak-anak berbaris dibelakang orang-orang dewasa kemudian kaum wanita berbaris dibelakang anak-anak."},"3349":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ أَنَّهُقَالَ لِقَوْمِهِ اجْتَمِعُوا أُصَلِّي بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا اجْتَمَعُوا قَالَ هَلْ فِيكُمْ أَحَدٌ مِنْ غَيْرِكُمْ قَالُوا لَا إِلَّا ابْنُ أُخْتٍ لَنَا قَالَ ابْنُ أُخْتِ الْقَوْمِ مِنْهُمْ فَدَعَا بِجَفْنَةٍ فِيهَا مَاءٌ فَتَوَضَّأَ وَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا ثَلَاثًا وَمَسَحَ بِرَأْسِهِ وَظَهْرَ قَدَمَيْهِ ثُمَّ صَلَّى بِهِمْ فَكَبَّرَ بِهِمْ ثِنْتَيْنِ وَعِشْرِينَ تَكْبِيرَةً يُكَبِّرُ إِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَقَرَأَ فِي الرَّكْعَتَيْنِ بِفَاتِحَةِ الْكِتَابِ وَأَسْمَعَ مَنْ يَلِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id] dari [Qotadah] dari [Syahr bin Hausyab] dari ['Abdur Rahman bin Ghanm] dari [Abu Malik Al Asy'ari] bahwa ia berkata kepada kaumnya: Berkumpullah kalian, aku akan shalat mengimami kalian seperti shalatnya Rasulullah Shallallahu'alaihiwasallam. Saat mereka berkumpul, Abu Malik bertanya: Apa masih ada orang lain? Mereka menjawab: Tidak ada selain keponakan kami. Abu Malik berkata: Keponakan suatu kaum termasuk bagian dari mereka. Lalu Abu Malik meminta seember air, ia pun berwudhu, berkumur, menghirup air, membasuh wajah dan tangan hingga siku sebanyak tiga kali, membasuh rambut dan bagian atas kaki kemudian shalat mengimami mereka, ia takbir sebanyak duapuluh dua kali, ia bertakbir saat hendak sujud dan mengangkat kepala setelah sujud, pada dua rakaat pertama ia membaca faatihatul kitaab dan memperdengarkannya kepada orang dibelakangnya."},"3350":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ الْحَضْرَمِيِّأَنَّ أَبَا مَالِكٍ الْأَشْعَرِيَّ لَمَّا حَضَرَتْهُ الْوَفَاةُ قَالَ يَا سَامِعَ الْأَشْعَرِيِّينَ لِيُبَلِّغْ الشَّاهِدُ مِنْكُمْ الْغَائِبَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حُلْوَةُ الدُّنْيَا مُرَّةُ الْآخِرَةِ وَمُرَّةُ الدُّنْيَا حُلْوَةُ الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] dari [Syuraih bin 'Ubaid Al Hadhrami] bahwa [Abu Malik Al Asy'ari] saat sekarat berkata: Wahai kaum Asy'ari yang mendengar, hendaklah yang hadir diantara kalian menyampaikan pada yang tidak hadir, aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Manisnya dunia adalah getirnya akhirat dan getirnya dunia adalah manisnya akhirat.\""},"3351":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنِي أَبَانُ بْنُ يَزِيدَ وَحَدَّثَنَا عَفَّانُ قَالَ أَخْبَرَنَا أَبَانُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطُّهُورُ شَطْرُ الْإِيمَانِ وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ قَالَ عَفَّانُ وَسُبْحَانَ اللَّهِ وَاللَّهُ أَكْبَرُ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ تَمْلَأُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ قَالَ عَفَّانُ وَسُبْحَانَ اللَّهِ وَاللَّهُ أَكْبَرُ وَلَا إِلَهَ إِلَّا اللَّهُ وَقَالَ عَفَّانُ مَا بَيْنَ السَّمَوَاتِ وَالْأَرْضِ وَالصَّلَاةُ نُورٌ وَالصَّدَقَةُ بُرْهَانٌ وَالصَّبْرُ ضِيَاءٌ وَالْقُرْآنُ حُجَّةٌ عَلَيْكَ أَوْ لَكَ كُلُّ النَّاسِ يَغْدُو فَبَائِعٌ نَفْسَهُ فَمُوبِقُهَا أَوْ مُعْتِقُهَا","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepadaku [Aban bin Yazid]. Dan telah menceritakan kepada kami ['Affan] berkata: telah mengabarkan kepada kami ['Aban bin Yazid] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari Abu Sallam dari [Abu Malik Al Asy'ari] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bersuci adalah setengah iman dan Al Hamdulillah memenuhi timbangan -Affan berkata dalam riwayatnya- dan subhaanallaah dan Allaahu akbar dan laa ilaaha illallaah wallaahu akbar memenuhi seisi langit dan bumi -Affan berkata dalam riwayatnya- Al hamdulillaah dan Allaahu akbar dan laa ilaaha illallaah seisi langit dan bumi- shalat adalah cahaya, sedekah adalah bukti, sabar adalah cahaya, Al Qur`an adalah hujjah yang menentangmu atau membelamu dan semua orang pergi dipagi hari kemudian menjual dirinya, ia membinasakannya atau membebaskannya."},"3352":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ حَدَّثَنَا مُوسَى أَخْبَرَنِي أَبَانُ بْنُ يَزِيدَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ أَبِي سَلَّامٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعٌ مِنْ الْجَاهِلِيَّةِ لَا يُتْرَكُنَّ الْفَخْرُ فِي الْأَحْسَابِ وَالطَّعْنُ فِي الْأَنْسَابِ وَالِاسْتِسْقَاءُ بِالنُّجُومِ وَالنِّيَاحَةُ وَالنَّائِحَةُ إِذَا لَمْ تَتُبْ قَبْلَ مَوْتِهَا تُقَامُ يَوْمَ الْقِيَامَةِ وَعَلَيْهَا سِرْبَالٌ مِنْ قَطِرَانٍ أَوْ دِرْعٌ مِنْ جَرَبٍ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah menceritakan kepada kami [Musa] telah mengabarkan kepadaku [Aban bin Yazid] dari [Yahya bin Abu Katisr] dari [Zaid bin Abu Sallam] dari [Abu Malik Al Asy'ari] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ada empat perkara termasuk jahiliyyah yang belum ditinggalkan; berbangga-bangga dengan keturunan, mencela nasab, meminta hujan dengan bintang-bintang dan meratapi mayit, jika seorang yang meratapi mayit tidak bertaubat sebelum meninggalnya maka pada hari kiamat akan dibangkitkan dengan memakai baju dari ter atau baju dari kudis.\" kemudian bagian atasnya dikenakan kobaran api neraka.\""},"3353":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ زَيْدِ بْنِ سَلَّامٍ عَنْ أَبِي سَلَّامٍ قَالَ قَالَ أَبُو مَالِكٍإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي أُمَّتِي أَرْبَعًا مِنْ الْجَاهِلِيَّةِ لَيْسُوا بِتَارِكِيهِنَّ الْفَخْرُ بِالْأَحْسَابِ وَالِاسْتِسْقَاءُ بِالنُّجُومِ وَالنِّيَاحَةُ عَلَى الْمَيِّتِ فَإِنَّ النَّائِحَةَ إِنْ لَمْ تَتُبْ قَبْلَ أَنْ تَمُوتَ فَإِنَّهَا تَقُومُ يَوْمَ الْقِيَامَةِ عَلَيْهَا سَرَابِيلُ مِنْ قَطِرَانٍ ثُمَّ يُعْلَى عَلَيْهَا دِرْعٌ مِنْ لَهَبِ النَّارِ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami ['Ali bin Al Mubarok] dari [Yahya bin Abu Katsir] dari [Zaid bin Sallam] dari [Abu Sallam], ia berkata: [Abu Malik] berkata, bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \" Ada empat perkara pada ummatku yang termasuk jahiliyyah yang belum ditinggalkan; berbangga dengan keturunan, mencela nasab, meminta hujan dengan bintang-bintang dan meratapi mayit, jika seorang yang meratapi mayit tidak bertaubat sebelum meninggalnya maka pada hari kiamat akan dibangkitkan dengan memakai baju dari ter kemudian bagian atasnya dikenakan kobaran api neraka.\""},"3354":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ الْفَزَارِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ غَنْمٍأَنَّ أَبَا مَالِكٍ الْأَشْعَرِيَّ جَمَعَ قَوْمَهُ فَقَالَ يَا مَعْشَرَ الْأَشْعَرِيِّينَ اجْتَمِعُوا وَاجْمَعُوا نِسَاءَكُمْ وَأَبْنَاءَكُمْ أُعَلِّمْكُمْ صَلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى لَنَا بِالْمَدِينَةِ فَاجْتَمَعُوا وَجَمَعُوا نِسَاءَهُمْ وَأَبْنَاءَهُمْ فَتَوَضَّأَ وَأَرَاهُمْ كَيْفَ يَتَوَضَّأُ فَأَحْصَى الْوُضُوءَ إِلَى أَمَاكِنِهِ حَتَّى لَمَّا أَنْ فَاءَ الْفَيْءُ وَانْكَسَرَ الظِّلُّ قَامَ فَأَذَّنَ فَصَفَّ الرِّجَالَ فِي أَدْنَى الصَّفِّ وَصَفَّ الْوِلْدَانَ خَلْفَهُمْ وَصَفَّ النِّسَاءَ خَلْفَ الْوِلْدَانِ ثُمَّ أَقَامَ الصَّلَاةَ فَتَقَدَّمَ فَرَفَعَ يَدَيْهِ فَكَبَّرَ فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ يُسِرُّهُمَا ثُمَّ كَبَّرَ فَرَكَعَ فَقَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ ثَلَاثَ مِرَارٍ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَاسْتَوَى قَائِمًا ثُمَّ كَبَّرَ وَخَرَّ سَاجِدًا ثُمَّ كَبَّرَ فَرَفَعَ رَأْسَهُ ثُمَّ كَبَّرَ فَسَجَدَ ثُمَّ كَبَّرَ فَانْتَهَضَ قَائِمًا فَكَانَ تَكْبِيرُهُ فِي أَوَّلِ رَكْعَةٍ سِتَّ تَكْبِيرَاتٍ وَكَبَّرَ حِينَ قَامَ إِلَى الرَّكْعَةِ الثَّانِيَةِ فَلَمَّا قَضَى صَلَاتَهُ أَقْبَلَ إِلَى قَوْمِهِ بِوَجْهِهِ فَقَالَ احْفَظُوا تَكْبِيرِي وَتَعَلَّمُوا رُكُوعِي وَسُجُودِي فَإِنَّهَا صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي كَانَ يُصَلِّي لَنَا كَذَا السَّاعَةِ مِنْ النَّهَارِ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَضَى صَلَاتَهُ أَقْبَلَ إِلَى النَّاسِ بِوَجْهِهِ فَقَالَ يَا أَيُّهَا النَّاسُ اسْمَعُوا وَاعْقِلُوا وَاعْلَمُوا أَنَّ لِلَّهِ عَزَّ وَجَلَّ عِبَادًا لَيْسُوا بِأَنْبِيَاءَ وَلَا شُهَدَاءَ يَغْبِطُهُمْ الْأَنْبِيَاءُ وَالشُّهَدَاءُ عَلَى مَجَالِسِهِمْ وَقُرْبِهِمْ مِنْ اللَّهِ فَجَاءَ رَجُلٌ مِنْ الْأَعْرَابِ مِنْ قَاصِيَةِ النَّاسِ وَأَلْوَى بِيَدِهِ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ نَاسٌ مِنْ النَّاسِ لَيْسُوا بِأَنْبِيَاءَ وَلَا شُهَدَاءَ يَغْبِطُهُمْ الْأَنْبِيَاءُ وَالشُّهَدَاءُ عَلَى مَجَالِسِهِمْ وَقُرْبِهِمْ مِنْ اللَّهِ انْعَتْهُمْ لَنَا يَعْنِي صِفْهُمْ لَنَا فَسُرَّ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِسُؤَالِ الْأَعْرَابِيِّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ نَاسٌ مِنْ أَفْنَاءِ النَّاسِ وَنَوَازِعِ الْقَبَائِلِ لَمْ تَصِلْ بَيْنَهُمْ أَرْحَامٌ مُتَقَارِبَةٌ تَحَابُّوا فِي اللَّهِ وَتَصَافَوْا يَضَعُ اللَّهُ لَهُمْ يَوْمَ الْقِيَامَةِ مَنَابِرَ مِنْ نُورٍ فَيُجْلِسُهُمْ عَلَيْهَا فَيَجْعَلُ وُجُوهَهُمْ نُورًا وَثِيَابَهُمْ نُورًا يَفْزَعُ النَّاسُ يَوْمَ الْقِيَامَةِ وَلَا يَفْزَعُونَ وَهُمْ أَوْلِيَاءُ اللَّهِ الَّذِينَ لَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","id":"Telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami ['Abdul Hamid bin Bahram Al Fazari] dari [Syahr bin Hausyab] telah menceritakan kepada kami ['Abdur Rahman bin Ghanm] bahwa [Abu Malik Al Asy'ari] mengumpulkan kaumnya lalu berkata: Hai sekalian kaum Asy'ari! Berkumpullah, kumpulkan istri-istri dan anak-anak kalian, aku akan mengajarkan kepada kalian shalatnya Nabi Shallallahu'alaihiwasallam yang beliau lakukan di Madinah. Mereka pun berkumpul, mengumpulkan istri-istri dan anak-anak mereka, Abu Malik Al Asy'ari berwudhu dan memperlihatkan kepada mereka bagaimana caranya berwudhu, ia menyempurnakan wudhu hingga ke tempat-tempatnya hingga usai, ia pun berdiri lalu mengumandangkan adzan, kaum lelaki pun berbaris dalam shaf yang dekat, anak-anak berbaris dibelakang mereka dan kaum wanita berbaris dibelakang anak-anak. Shalat pun diiqamati. Ia maju kemudian mengangkat kedua tangan seraya bertakbir, ia membaca faatihatul kitaab dan surat yang dibaca pelan, selanjutnya ia bertakbir ruku' dan membaca: Subhaanallaah wa bihamdihi sebanyak tiga kali, setelah itu mengucapkan: Sami'allaahu liman hamidah dan berdiri lurus, setelah itu ia bertakbir dan turun sujud, selanjutnya bertakbir dan mengangkat kepala, setelah itu bertakbir lalu sujud, lalu bertakbir dan berdiri, ia bertakbir sebanyak enam kali dalam rakaat pertama, ia bertakbir saat berdiri untuk rakaat kedua. Seusai shalat ia menghadap ke kaumnya lalu berkata: Hafalkan takbirku, pelajarilah ruku'ku dan sujudku karena itulah shalat Rasulullah Shallallahu'alaihiwasallam yang beliau kerjakan untuk kami seperti itu saat di siang hari. Selanjutnya saat Rasulullah Shallallahu'alaihiwasallam usai shalat, beliau menghadap ke arah jamaah dengan wajah beliau lalu bersabda: \"Wahai sekalian manusia! Dengar, fahami dan ketahuilah bahwa Allah AzzaWaJalla memiliki hamba-hamba, mereka bukan nabi atau pun syuhada` tapi para nabi dan syuhada` iri pada mereka karena tempat dan kedekatan mereka dengan Allah pada hari kiamat.\" Kemudian salah seorang badui datang, ia berasal dari pedalaman jauh dan menyendiri, ia menunjuk tangannya ke arah Nabi Shallallahu'alaihiwasallam lalu berkata: Hai Nabi Allah! Sekelompok orang yang bukan Nabi ataupun syuhada` tapi para nabi dan syuhada` iri kepada mereka karena kedudukan dan kedekatan mereka dengan Allah, sebutkan ciri-ciri mereka untuk kami. Wajah Rasulullah Shallallahu'alaihiwasallam bergembira karena pertanyaan orang badui itu lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mereka adalah orang-orang yang berasal dari berbagai penjuru dan orang-orang asing, diantara meraka tidak dihubungkan oleh kekerabatan yang dekat, mereka saling mencintai karena Allah dan saling tulus ikhlas, Allah menempatkan untuk mereka mimbar-mimbar dari cahaya pada hari kiamat, Allah mendudukan mereka diatasnya, Allah menjadikan wajah-wajah mereka cahaya, pakaian-pakaian mereka cahaya, orang-orang ketakutan pada hari kiamat sementara mereka tidak ketakuan, mereka adalah para wali-wali Allah yang tidak takut dan tidak bersedih hati.\""},"3355":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا حَرِيزٌ عَنْ حَبِيبِ بْنِ عُبَيْدٍ عَنْ أَبِي مَالِكٍ عُبَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا بَلَغَهُ دَعَا لَهُ اللَّهُمَّ صَلِّ عَلَى عُبَيْدٍ أَبِي مَالِكٍ وَاجْعَلْهُ فَوْقَ كَثِيرٍ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Hariz] dari [Habib bin 'Ubaid] dari [Abu Malik 'Ubaid] bahwa Rasulullah Shallallahu'alaihiwasallam (sebagaimana yang telah sampai kepadanya) berdoa untuknya: \"Ya Allah berilah kesejahteraan kepada 'Ubaid Abu Malik dan tempatkan dia diatas kebanyakan manusia.\""},"3356":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنِ الْأَعْرَجِ عَنِ ابْنِ بُحَيْنَةَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً نَظُنُّ أَنَّهَا الْعَصْرُ فَقَامَ فِي الثَّانِيَةِ لَمْ يَجْلِسْ فَلَمَّا كَانَ قَبْلَ أَنْ يُسَلِّمَ سَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Al A'raj] dari [Ibnu Buhainah] Rasulullah Shallallahu'alaihiwasallam shalat mengimami kami, menurutku shalat ashar, beliau berdiri pada rakaat kedua dan tidak duduk. Sebelum salam, beliau sujud dua kali."},"3357":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ وَحَدَّثَنَا شُعْبَةُ حَدَّثَنِي سَعْدُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي حَفْصُ بْنُ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكِ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُصَلِّي رَكْعَتَيْ الْفَجْرِ وَقَدْ أُقِيمَتْ الصَّلَاةُ فَلَمَّا قَضَى الصَّلَاةَ لَاثَ النَّاسُ بِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحُ أَرْبَعًا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata: telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Sa'ad bin Ibrahim] telah menceritakan kepadaku [Hafsh bin 'Ashim] dari ['Abdullah bin Malik bin Buhainah] bahwa Nabi Shallallahu'alaihiwasallam melihat seseorang mengerjakan dua rakaat fajar sunnah sementara shalat telah ditegakkan, maka tatkala shalat telah selesai orang-orang mengelilingi Nabi Shallallahu'alaihiwasallam dan Nabi Shallallahu'alaihiwasallam bersabda: \"Apakah shubuh empat rekaat?\""},"3358":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ قَرَأَ أَحَدٌ مِنْكُمْ مَعِي آنِفًا قَالُوا نَعَمْ قَالَ إِنِّي أَقُولُ مَا لِي أُنَازَعُ الْقُرْآنَ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ مَعَهُ حِينَ قَالَ ذَلِكَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Keponakan Ibnu Syihab] dari [pamannya] berkata: Telah mengabarkan kepadaku ['Abdur Rahman bin Hurmuz] dari ['Abdullah Ibnu Buhainah], salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam, bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apakah tadi diantara kalian ada yang membaca bersamaku?\" mereka berkata: Ya. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tadi aku berhati dalam hati mengapa bacaanku kacau?.\" Akhirnya orang-orang tidak lagi membaca bersama beliau Shallallahhu'alaihiwasallam setelah beliau Shallallahhu'alaihiwasallam bersabda seperti itu."},"3359":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَلْقَمَةَ بْنِ أَبِي عَلْقَمَةَ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ الْأَعْرَجَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ بُحَيْنَةَ يَقُولُاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْيِ جَمَلٍ مِنْ طَرِيقِ مَكَّةَ عَلَى وَسَطِ رَأْسِهِ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah menceritakan kepada kami [Sulaiman bin Bilal] dari ['Alqamah bin Abu 'Alqamah] bahwa ia mendengar ['Abdur Rahman Al A'raj] bahwa ia mendengar ['Abdullah Ibnu Buhainah] berkata: Rasulullah Shallallahu'alaihiwasallam membekam tengah kepala beliau di Lahyu Jamal dari jalan Makkah ketika beliauShallallahhu'alaihiwasallam dalam keadaan berihram."},"3360":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكِ ابْنِ بُحَيْنَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَرَّجَ بَيْنَ يَدَيْهِ حَتَّى يَبْدُوَ بَيَاضُ إِبْطَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakr bin Mudhar] dari [Ja'far bin Rabi'ah] dari [Al A'raj] dari ['Abdulklah bin Malik bin Buhainah] bahwa Rasulullah Shallallahu'alaihiwasallam bila shalat merenggangkan kedua tangan beliau hingga terlihat warna putih ketiak beliau."},"3361":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكِ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يُصَلِّي يُطَوِّلُ صَلَاتَهُ أَوْ نَحْوَ هَذَا بَيْنَ يَدَيْ صَلَاةِ الْفَجْرِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْعَلُوا هَذِهِ مِثْلَ صَلَاةِ الظُّهْرِ قَبْلَهَا وَبَعْدَهَا اجْعَلُوا بَيْنَهُمَا فَصْلًا","id":"Telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Muhammad bin 'Abdur Rahman bin Tsauban] dari ['Abdullah bin Malik bin Buhainah] bahwasanya Nabi Shallallahu'alaihiwasallam melewatinya ketika ia sedang shalat dengan lamanya, atau seperti ini sebelum shalat fajar, Nabi Shallallahu'alaihiwasallam bersabda kepadanya: \"Jangan jadikan shalat ini seperti shalat dhuhur, berilah selang (rentang waktu) antara shalat sunnah dengan shalat fardhu, baik shalat sunnah itu sebelum atau sesudahnya.\""},"3362":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ أَخْبَرَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حَفْصِ بْنِ عَاصِمٍ وَغَيْرِهِ قَالَ حَجَّاجٌ فِي حَدِيثِهِ قَالَ سَمِعْتُ حَفْصَ بْنَ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ مَالِكِ ابْنِ بُحَيْنَةَأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ وَقَدْ أُقِيمَتْ الصَّلَاةُ فَصَلَّى رَكْعَتَيْ الْفَجْرِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَاثَ بِهِ النَّاسُ فَقَالَ الصُّبْحُ أَرْبَعًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah]. Dan [Hajjaj] telah mengabarkan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Hafsh bin 'Ashim] dan lainnya. -Hajjaj menjelaskan- Aku mendengar Hafsh bin 'Ashim bin 'Umar bin Al Khaththab dari [Malik bin Buhainah] bahwa seseorang masuk masjid sementara shalat telah ditegakkan, ia shalat sunnah dua rakaat fajar. Setelah Rasulullah Shallallahu'alaihiwasallam menyelesaikan shalat, para jamaah mengerumuni orang itu lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Shubuh empat rakaat?\""},"3363":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ عَنْ مَالِكٍ عَنِ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ قَامَ فَلَمْ يَجْلِسْ فَقَامَ النَّاسُ مَعَهُ فَلَمَّا قَضَى صَلَاتَهُ وَنَظَرْنَا تَسْلِيمَهُ كَبَّرَ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ ثُمَّ سَلَّمَ","id":"Berkata Ahmad: Aku meriwayatkan dengan membaca dari ['Abdur Rahman] dari [Malik] dari [Ibnu Syihab] dari ['Abdur Rahman Al A'raj] dari ['Abdullah bin Buhainah] bahwa ia berkata: Rasulullah Shallallahu'alaihiwasallam shalat dua rakaat mengimami kami, beliau berdiri dan tidak duduk, orang-orang juga berdiri bersama beliau. Seusai beliau shalat dan kami melihat salam beliau, beliau bertakbir lalu sujud dua kali saat beliau duduk sebelum salam, setelah itu beliau salam."},"3364":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ أَيْضًا عَنِ ابْنِ بُحَيْنَةَ الْأَسَدِيِّ وَقَالَ ابْنُ بَكْرٍ الْأَزْدِيِّ حَلِيفِ بَنِي عَبْدِ الْمُطَّلِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي الظُّهْرِ وَعَلَيْهِ جُلُوسٌ فَلَمَّا أَتَمَّ صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ يُكَبِّرُ فِي كُلِّ سَجْدَةٍ وَسَجَدَهُمَا النَّاسُ مَعَهُ مَكَانَ مَا نَسِيَ مِنْ الْجُلُوسِ","id":"Telah menceritakan kepada kami ['Abdur Razzaq] dan [Ibnu Bakr] keduanya berkata: telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] dari ['Abdullah bin Buhainah Al Asadi]. Dan berkata Ibnu Bakr Al Azdi, teman Bani 'Abdul Muththallib, bahwa Rasulullah Shallallahu'alaihiwasallam berdiri saat shalat zhuhur padahal seharusnya beliau duduk, setelah beliau menyelesaikan shalat, beliau sujud dua kali, tepatnya saat beliau duduk sebelum salam, beliau takbir setiap kali sujud, orang-orang turut bersujud dua kali bersama beliau sebagai pengganti duduk diantara dua sujud yang beliau lupakan."},"3365":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا أَبُو أُوَيْسٍ عَنِ الزُّهْرِيِّ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ الْأَعْرَجَ مَوْلَى رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ ابْنَ بُحَيْنَةَ الْأَزْدِيَّ أَزْدَ شَنُوءَةَ وَهُوَ حَلِيفُ بَنِي عَبْدِ الْمُطَّلِبِ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ قَامَ وَلَمْ يَجْلِسْ بَعْدَ الرَّكْعَتَيْنِ فَقَامَ النَّاسُ مَعَهُ فَلَمَّا قَضَى صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] telah menceritakan kepada kami [Abu Uwais] dari [Az Zuhri] bahwa ['Abdur Rahman bin Hurmuz Al A'raj], budak Rabi'ah bin Al Harits bin 'Abdul Muththallib telah memberitahunya bahwa ia mendengar ['Abdullah bin Buhainah Al Azdi Azda Syanu`ah], teman Bani 'Abdul Muththallib berkata: Rasulullah Shallallahu'alaihiwasallam shalat dua rakaat untuk kami, beliau berdiri dan tidak duduk setelah dua rakaat, orang-orang turut berdiri bersama beliau, setelah beliau menyelesaikan shalat, beliau sujud dua kali tepatnya saat beliau duduk sebelum salam, setelah itu beliau salam."},"3366":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَلِيُّ بْنُ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَاجْتَمَعَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُيَيْنَةُ بْنُ بَدْرٍ وَالْأَقْرَعُ بْنُ حَابِسٍ وَعَلْقَمَةُ بْنُ عُلَاثَةَ فَذَكَرُوا الْجُدُودَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمْ أَخْبَرْتُكُمْ جَدُّ بَنِي عَامِرٍ جَمَلٌ أَحْمَرُ أَوْ آدَمُ يَأْكُلُ مِنْ أَطْرَافِ الشَّجَرِ قَالَ وَأَحْسِبُهُ قَالَ فِي رَوْضَةٍ وَغَطَفَانُ أَكَمَةٌ خَشَّاءُ تَنْفِي النَّاسَ عَنْهَا قَالَ فَقَالَ الْأَقْرَعُ بْنُ حَابِسٍ فَأَيْنَ جَدُّ بَنِي تَمِيمٍ قَالَ لَوْ سَكَتَ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami ['Ali bin Suwaid] dari ['Abdullah bin Buraidah] dari [ayahnya] berkata: 'Uyainah bin Badr, Al Aqra bin Habis, dan 'Alqamah bin 'Ulatsah berkumpul di dekat Nabi Shallallahhu'alaihiwasallam, mereka menyebut-nyebut kebanggaan, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Bila kalian mau, aku akan memberitahukan kalian kebanggaan Bani 'Amir; unta merah atau kelabu, memakan ujung-ujung pohon -perawi berkata: Aku kira beliau bersabda- Dalam sebuah taman sementara Ghathafan, Akmah dan Khassya` mengusir orang-orang dari taman itu.\" Al Aqra' bin Habis berkata: Lalu mana kebanggaan Bani Tamim? Buraidah berkata: Ohh… Andaikan ia diam."},"3367":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ أَخْبَرَنَا الْحُسَيْنُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ جَالِسًا عَلَى حِرَاءٍ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ رَضِيَ اللَّهُ عَنْهُمْ فَتَحَرَّكَ الْجَبَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْبُتْ حِرَاءُ فَإِنَّهُ لَيْسَ عَلَيْكَ إِلَّا نَبِيٌّ أَوْ صِدِّيقٌ أَوْ شَهِيدٌ","id":"Telah menceritakan kepada kami ['Ali bin Al Hasan] telah mengabarkan kepada kami [Al Husain] telah menceritakan kepada kami ['Abdullah bin Buraidah] dari [ayahnya] bahwa Rasulullah Shallallahu'alaihiwasallam duduk diatas gua Hira, beliau bersama Abu Bakar, 'Umar dan 'Utsman. Gunung bergetar kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tenanglah Hira, yang ada diatasmu hanya seorang nabi atau orang jujur atau orang syahid.\""},"3368":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ وَاصِلِ بْنِ حِبَّانَ الْبَجَلِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ الْكَمْأَةُ دَوَاءُ الْعَيْنِ وَإِنَّ الْعَجْوَةَ مِنْ فَاكِهَةِ الْجَنَّةِ وَإِنَّ هَذِهِ الْحَبَّةَ السَّوْدَاءَ قَالَ ابْنُ بُرَيْدَةَ يَعْنِي الشُّونِيزَ الَّذِي يَكُونُ فِي الْمِلْحِ دَوَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا الْمَوْتَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Zuhair] dari [Washil bin Hibban Al Bajali] telah menceritakan kepadaku ['Abdullah bin Buraidah] dari [ayahnya] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Kam`ah adalah obat mata, (kurma) 'ajwah termasuk buah surga dan biji hitam ini -berkata Ibnu Buraidah: yaitu Syunaiz (jintan hitam/Nigella Sativa) - yang diberi garam adalah obat segala penyakit kecuali kematian.\""},"3369":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنِي مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُولُوا لِلْمُنَافِقِ سَيِّدَنَا فَإِنَّهُ إِنْ يَكُ سَيِّدَكُمْ فَقَدْ أَسْخَطْتُمْ رَبَّكُمْ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepadaku [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari ['Abdullah bin Buraidah] dari [ayahnya] bahwa Nabi Shallallahu'alaihiwasallam bersabda: \"Jangan katakan untuk orang munafik 'Tuan kami' karena bila ia menjadi tuan kalian maka Rabb kalian AzzaWaJalla murka pada kalian.\""},"3370":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي حُسَيْنٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَدَخَلْتُ أَنَا وَأَبِي عَلَى مُعَاوِيَةَ فَأَجْلَسَنَا عَلَى الْفُرُشِ ثُمَّ أُتِينَا بِالطَّعَامِ فَأَكَلْنَا ثُمَّ أُتِينَا بِالشَّرَابِ فَشَرِبَ مُعَاوِيَةُ ثُمَّ نَاوَلَ أَبِي ثُمَّ قَالَ مَا شَرِبْتُهُ مُنْذُ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُعَاوِيَةُ كُنْتُ أَجْ��َلَ شَبَابِ قُرَيْشٍ وَأَجْوَدَهُ ثَغْرًا وَمَا شَيْءٌ كُنْتُ أَجِدُ لَهُ لَذَّةً كَمَا كُنْتُ أَجِدُهُ وَأَنَا شَابٌّ غَيْرُ اللَّبَنِ أَوْ إِنْسَانٍ حَسَنِ الْحَدِيثِ يُحَدِّثُنِي","id":"Telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepadaku [Husain] telah menceritakan kepada kami ['Abdullah bin Buraidah] berkata: Aku bersama ayahku bertamu ke Mu'awiyah, ia mempersilahkan kami duduk diatas hamparan, kami pun disuguhi makanan dan minuman, Mu'awiyah minum lalu menawarkan pada ayahku, kemudian [ayahku] berkata: Aku tidak meminumnya sejak diharamkan Rasulullah Shallallahu'alaihiwasallam. Mu'awiyah berkata: Aku dulu adalah pemuda Quraisy yang paling rupawan dan paling bagus gigi depannya, aku dulu menemukan kenikmatan seperti yang dulu aku temukan saat aku muda selain susu atau orang yang ucapannya baik yang bercerita padaku."},"3371":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرُ بْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ يُقَالُ لَهُ مَاعِزُ بْنُ مَالِكٍ فَقَالَ يَا نَبِيَّ اللَّهِ إِنِّي قَدْ زَنَيْتُ وَأَنَا أُرِيدُ أَنْ تُطَهِّرَنِي فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَلَمَّا كَانَ مِنْ الْغَدِ أَتَاهُ أَيْضًا فَاعْتَرَفَ عِنْدَهُ بِالزِّنَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ ثُمَّ أَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمِهِ فَسَأَلَهُمْ عَنْهُ فَقَالَ لَهُمْ مَا تَعْلَمُونَ مِنْ مَاعِزِ بْنِ مَالِكٍ الْأَسْلَمِيِّ هَلْ تَرَوْنَ بِهِ بَأْسًا أَوْ تُنْكِرُونَ مِنْ عَقْلِهِ شَيْئَا قَالُوا يَا نَبِيَّ اللَّهِ مَا نَرَى بِهِ بَأْسًا وَمَا نُنْكِرُ مِنْ عَقْلِهِ شَيْئًا ثُمَّ عَادَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثَّالِثَةَ فَاعْتَرَفَ عِنْدَهُ بِالزِّنَا أَيْضًا فَقَالَ يَا نَبِيَّ اللَّهِ طَهِّرْنِي فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمِهِ أَيْضًا فَسَأَلَهُمْ عَنْهُ فَقَالُوا لَهُ كَمَا قَالُوا لَهُ الْمَرَّةَ الْأُولَى مَا نَرَى بِهِ بَأْسًا وَمَا نُنْكِرُ مِنْ عَقْلِهِ شَيْئًا ثُمَّ رَجَعَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّابِعَةَ أَيْضًا فَاعْتَرَفَ عِنْدَهُ بِالزِّنَا فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَفَرْنَا لَهُ حُفْرَةً فَجُعِلَ فِيهَا إِلَى صَدْرِهِ ثُمَّ أَمَرَ النَّاسَ أَنْ يَرْجُمُوهُ وَقَالَ بُرَيْدَةُ كُنَّا نَتَحَدَّثُ أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَنَا أَنَّ مَاعِزَ بْنَ مَالِكٍ لَوْ جَلَسَ فِي رَحْلِهِ بَعْدَ اعْتِرَافِهِ ثَلَاثَ مِرَارٍ لَمْ يَطْلُبْهُ وَإِنَّمَا رَجَمَهُ عِنْدَ الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir bin Al Muhajir] telah menceritakan kepadaku ['Abdullah bin Buraidah] dari [ayahnya] berkata: Aku duduk didekat Nabi Shallallahhu'alaihiwasallam, tiba-tiba seseorang bernama Ma'iz bin Malik mendatangi beliau lalu berkata: Wahai nabi Allah! aku telah berzina dan aku ingin sekali baginda mensucikanku. Nabi Shallallahu'alaihiwasallam bersabda padanya: \"Kembalilah.\" Di keesokan harinya, ia mendatangi Nabi Shallallahu'alaihiwasallam lagi, lalu mengakui di hadapan Nabi Shallallahu'alaihiwasallam bahwa dirinya berzina, Nabi Shallallahu'alaihiwasallam bersabda kepadanya: \"Kembalilah.\" Kemudian Nabi Shallallahu'alaihiwasallam mengirim utusan ke kaumnya dan menanyakan tentangnya pada mereka. Nabi Shallallahu'alaihiwasallam bertanya: \"Apa yang kalian ketahui dari Ma'iz bin Malik Al Aslami, apakah kalian melihat ketidakberesan padanya atau kalian mengingkari akalnya?\" mereka berkata: Kami tidak melihat ketidakberesan padanya dan kami tidak memungkiri akalnya. Ma'iz kembali menemui Nabi Shallallahu'alaihiwasallam untuk ketigakalinya, ia mengakui di hadapan beliau telah berzina, ia berkata: Wahai Nabi Allah! Sucikanlah aku. Nabi Shallallahu'alaihiwasallam mengirim utusan lagi ke kaumnya dan menanyakan pada mereka, mereka menjawab seperti yang pernah mereka katakan pertama kali. Ia kembali mendatangi Nabi Shallallahu'alaihiwasallam untuk keempat kalinya dan mengaku telah berzina di hadapan beliau kemudian beliau memerintahkan untuk dirajam, kami pun membuat galian untuknya sebatas dada, setelah itu beliau memerintahkan orang-orang untuk merajamnya. Berkata Buraidah: Kami membicarakan sahabat-sahabat Nabi Shallallahu'alaihiwasallam di antara kami mengatakan, bahwa andai Ma'iz bin Malik duduk di kendaraannya setelah ia mengaku tiga kali niscaya Nabi Shallallahu'alaihiwasallam tidak menghukumnya, beliau merajamnya pada pengakuan keempat."},"3372":{"ar":"حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ أَخْبَرَنَا أَبُو إِسْرَائِيلَ عَنْ حَارِثِ بْنِ حَصِيرَةَ عَنِ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَدَخَلَ عَلَى مُعَاوِيَةَ فَإِذَا رَجُلٌ يَتَكَلَّمُ فَقَالَ بُرَيْدَةُ يَا مُعَاوِيَةُ فَائْذَنْ لِي فِي الْكَلَامِ فَقَالَ نَعَمْ وَهُوَ يَرَى أَنَّهُ سَيَتَكَلَّمُ بِمِثْلِ مَا قَالَ الْآخَرُ فَقَالَ بُرَيْدَةُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي لَأَرْجُو أَنْ أَشْفَعَ يَوْمَ الْقِيَامَةِ عَدَدَ مَا عَلَى الْأَرْضِ مِنْ شَجَرَةٍ وَمَدَرَةٍ قَالَ أَفَتَرْجُوهَا أَنْتَ يَا مُعَاوِيَةُ وَلَا يَرْجُوهَا عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Al Aswad bin 'Amir] telah mengabarkan kepada kami [Abu Isra`il] dari [Harits bin Hashirah] dari [Ibnu Buraidah] dari [ayahnya] berkata: Ia bertamu ke kediaman Mu'awiyah tiba-tiba ada seseorang berbicara kemudian Buraidah berkata: Hai Mu'awiyah, izinkan aku berbicara. Mu'awiyah berkata: Silahkan. Ia menilai akan menyampaikan pembicaraan seperti yang telah disampaikan yang lainnya, kemudian Buraidah berkata: Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Aku berharap memberi syafaat pada hari kiamat sejumlah pohon dan potongan tanah liat di atas bumi.\" Buraidah berkata: Apa kau mengharapkannya wahai Mu'awiyah sementara 'Ali bin Abi Thalib Radliyallahu'anhu tidak mengharapnya? "},"3373":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ عَنِ الْحَكَمِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنِ ابْنِ عَبَّاسٍ عَنْ بُرَيْدَةَ قَالَغَزَوْتُ مَعَ عَلِيٍّ الْيَمَنَ فَرَأَيْتُ مِنْهُ جَفْوَةً فَلَمَّا قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْتُ عَلِيًّا فَتَنَقَّصْتُهُ فَرَأَيْتُ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَغَيَّرُ فَقَالَ يَا بُرَيْدَةُ أَلَسْتُ أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ مَنْ كُنْتُ مَوْلَاهُ فَعَلِيٌّ مَوْلَاهُ","id":"Telah menceritakan kepada kami [Al Fadhl bin Dukain] telah menceritakan kepada kami [Ibnu Abi Ghaniyyah] dari [Al Hakam] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari [Buraidah] berkata: Aku perang bersama 'Ali di Yaman, aku melihat sikap dingin darinya, saat aku tiba dihadapan Rasulullah Shallallahu'alaihiwasallam, aku menyebut-nyebut Ali, aku mencelanya lalu aku melihat rona muka Rasulullah Shallallahu'alaihiwasallam berubah kemudian bersabda: Hai Buraidah! Bukankah aku lebih utama bagi orang-orang mu`min melebihi diri mereka. Aku menjawab: Benar wahai Rasulullah! Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapa pun yang walinya adalah aku maka 'Ali adalah walinya.\""},"3374":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَطَيَّرُ مِنْ شَيْءٍ وَلَكِنَّهُ كَانَ إِذَا أَرَادَ أَنْ يَأْتِيَ امْرَأَةً سَأَلَ عَنْ اسْمِهَا فَإِنْ كَانَ حَسَنًا رُئِيَ الْبِشْرُ فِي وَجْهِهِ وَإِنْ كَانَ قَبِيحًا رُئِيَ ذَلِكَ فِي وَجْهِهِ وَكَانَ إِذَا بَعَثَ رَجُلًا سَأَلَ عَنْ اسْمِهِ فَإِنْ كَانَ حَسَنَ الِاسْمِ رُئِيَ الْبِشْرُ فِي وَجْهِهِ وَإِنْ كَانَ قَبِيحًا رُئِيَ ذَلِكَ فِي وَجْهِهِ","id":"Telah menceritakan kepada kami ['Abdush Shamad] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari ['Abdullah bin Buraidah] dari [ayahnya]: Rasulullah Shallallahu'alaihiwasallam tidak bersuci dari apa pun namun bila beliau hendak mendatangi seorang wanita, beliau menanyakan namanya, bila namanya baik rona muka beliau terlihat gembira dan bila namanya jelek hal itu terlihat di rona muka beliau, bila beliau hendak mengutus seseorang, beliau menanyakan namanya, bila bila namanya baik rona muka beliau terlihat gembira dan bila namanya jelek hal itu terlihat di rona muka beliau."},"3375":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرٌ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَخَرَجَ إِلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَنَادَى ثَلَاثَ مِرَارٍ فَقَالَ يَا أَيُّهَا النَّاسُ تَدْرُونَ مَا مَثَلِي وَمَثَلُكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ إِنَّمَا مَثَلِي وَمَثَلُكُمْ مَثَلُ قَوْمٍ خَافُوا عَدُوًّا يَأْتِيهِمْ فَبَعَثُوا رَجُلًا يَتَرَايَا لَهُمْ فَبَيْنَمَا هُمْ كَذَلِكَ أَبْصَرَ الْعَدُوَّ فَأَقْبَلَ لِيُنْذِرَهُمْ وَخَشِيَ أَنْ يُدْرِكَهُ الْعَدُوُّ قَبْلَ أَنْ يُنْذِرَ قَوْمَهُ فَأَهْوَى بِثَوْبِهِ أَيُّهَا النَّاسُ أُتِيتُمْ أَيُّهَا النَّاسُ أُتِيتُمْ ثَلَاثَ مِرَارٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir] telah menceritakan kepadaku ['Abdullah bin Buraidah] dari [ayahnya] berkata: Pada suatu hari Nabi Shallallahu'alaihiwasallam keluar menghampiri kami, beliau memanggil tiga kali, beliau bersabda: \"Wahai sekalian manusia! Tahukah kalian perumpaanku dengan kalian?\" mereka menjawab: Allah dan rasulNya lebih tahu. Rasulullah Shallallahu'alaihiwasallam bersabda: \" Perumpamaanku dengan kalian adalah seperti suatu kaum yang takut kepada musuh yang akan mendatangi mereka, mereka mengirim seseorang untuk mengintai mereka, saat seperti itu, ia melihat musuh lalu ia menghadap untuk mengingatkan mereka sementara ia khawatir disusul musuh sebelum mengingatkan kaumnya, lalu ia melambai-lambaikan bajunya: Wahai sekalian manusia kalian telah didatangi, Wahai sekalian manusia kalian telah didatangi.\" Beliau mengucapkannya sebanyak tiga kali."},"3376":{"ar":"حَدَّثَنَا يَحْيَى عَنِ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ بَعْضِ أَصْحَابِهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَرَّ عَلَى مُوسَى لَيْلَةَ أُسْرِيَ بِهِ قَائِمًا يُصَلِّي فِي قَبْرِهِ قَالَ يَحْيَى قَائِمٌ إِنْ شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Yahya] dari [At Taimi] dari [Anas bin Malik] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melewati Musa saat isra`, ia berdiri shalat di makamnya. Berkata Yahya: Berdiri, insya Allah."},"3377":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيٍّ قَالَأَخْبَرَنِي رَجُلَانِ أَنَّهُمَا أَتَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ يَسْأَلَانِهِ الصَّدَقَةَ قَالَ فَرَفَعَ فِيهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَصَرَ وَخَفَضَهُ فَرَآهُمَا رَجُلَيْنِ جَلْدَيْنِ فَقَالَ إِنْ شِئْتُمَا أَعْطَيْتُكُمَا مِنْهَا وَلَا حَظَّ فِيهَا لِغَنِيٍّ وَلَا لِقَوِيٍّ مُكْتَسِبٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Numair] dari [Hisyam] dari [ayahnya] dari ['Ubaidullah bin 'Adi] berkata: telah mengabarkan kepadaku [dua orang] bahwa keduanya mendatangi Nabi shallallahu 'alaihi wasallam saat haji wada', keduanya meminta sedekah kepada beliau. Berkata 'Ubaidullah: Lalu Rasulullah shallallahu 'alaihi wasallam mengangkat pandangan beliau ke arah kedua orang itu kemudian beliau menundukkannya, beliau melihat kedua orang itu masih kuat lalu beliau bersabda: \"Bila kalian berdua mau, aku akan memberimu sedekah namun orang kaya dan orang kuat yang bisa bekerja tidak punya bagian darinya.\""},"3378":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ الْجُهَنِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ حَدَّثَنَا أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْكَانُوا يَسِيرُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ فَنَامَ رَجُلٌ مِنْهُمْ فَانْطَلَقَ بَعْضُهُمْ إِلَى نَبْلٍ مَعَهُ فَأَخَذَهَا فَلَمَّا اسْتَيْقَظَ الرَّجُلُ فَزِعَ فَضَحِكَ الْقَوْمُ فَقَالَ مَا يُضْحِكُكُمْ فَقَالُوا لَا إِلَّا أَنَّا أَخَذْنَا نَبْلَ هَذَا فَفَزِعَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يُرَوِّعَ مُسْلِمًا","id":"Telah menceritakan kepada kami ['Abdullah bin Numair] telah menceritakan kepada kami [Al A'masy] dari ['Abdullah bin Yasar Al Juhani] dari ['Abdur Rahman bin Abu Laila] berkata: telah menceritakan kepada kami [sahabat-sahabat Nabi shallallahu 'alaihi wasallam] bahwa mereka berjalan bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan lalu seseorang diantara mereka tidur, sebagaian dari mereka mendekati anak panahnya lalu mengambilnya kemudian orang itu terbangun dan kaget, orang-orang tertawa kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang membuat kalian tertawa?\" mereka berkata: Tidak, kami hanya mengambil anak panah orang ini lalu ia kaget. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang muslim menakut-nakuti muslim lain.\""},"3379":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدٌ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَاتِلِ وَالْآمِرِ قَالَ قُسِّمَتْ النَّارُ سَبْعِينَ جُزْءًا فَلِلْآمِرِ تِسْعٌ وَسِتُّونَ وَلِلْقَاتِلِ جُزْءٌ وَحَسْبُهُ","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Muhammad] dari [Yazid bin Abu Habib] dari [Murtsid bin 'Abdullah] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam] berkata: Rasulullah shallallahu 'alaihi wasallam ditanya tentang orang yang berperang dan pemimpin, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Neraka dibagi tujuhpuluh bagian, enampuluh sembilannya untuk pemimpin dan satunya untuk orang yang berperang.\""},"3380":{"ar":"حَدَّثَنَا أَبُو أُسَامَةَ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ حَدَّثَنِي جَارٌ لِخَدِيجَةَ بِنْتِ خُوَيْلِدٍ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ لِخَدِيجَةَ أَيْ خَدِيجَةُ وَاللَّهِ لَا أَعْبُدُ اللَّاتَ أَبَدًا وَاللَّهِ لَا أَعْبُدُ الْعُزَّى أَبَدًا قَالَ فَتَقُولُ خَدِيجَةُ حِلَّ الْعُزَّى قَالَ كَانَتْ صَنَمَهُمْ الَّتِي يَعْبُدُونَ ثُمَّ يَضْطَجِعُونَ","id":"Telah menceritakan kepada kami [Abu Usamah] telah mengabarkan kepada kami [Hisyam] dari [ayahnya] telah menceritakan kepadaku [seorang tetangga Khadijah binti Khuwailid] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda kepada Khadijah: \"Demi Allah aku tidak akan menyembah Lata selamanya, demi Allah aku tidak akan menyembah 'Uzza selamanya.\" Khadijah bertanya: Apa itu 'Uzza? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia adalah berhala mereka yang mereka sembah kemudian mereka tidur.\""},"3381":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ بَعْضِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَصْبَحَ النَّاسُ صِيَامًا لِتَمَامِ ثَلَاثِينَ قَالَ فَجَاءَ أَعْرَابِيَّانِ فَشَهِدَا أَنَّهُمَا أَهَلَّا الْهِلَالَ بِالْأَمْسِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ فَأَفْطَرُوا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i bin Hirasy] dari [seorang sahabat Rasulullah shallallahu 'alaihi wasallam] berkata: Dipagi hari orang-orang puasa untuk menggenapkan tiga puluh hari kemudian dua orang badui datang, keduanya bersaksi bahwa hilal sudah muncul kemarin kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan orang-orang berbuka, mereka pun berbuka."},"3382":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي قُرَّةُ بْنُ خَالِدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنِ الْأَعْرَابِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صَوْمُ شَهْرِ الصَّبْرِ وَثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ يُذْهِبْنَ وَحَرَ الصَّدْرِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepadaku [Qurrah bin Khalid] dari [Yazid bin 'Abdullah bin Asy Syakhir] dari [seorang badui] berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa sebulan adalah kesabaran dan (puasa) tiga hari setiap bulan menghilangkan kedengkian hati.\""},"3383":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ بَعْضِ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنَّمَا نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ فِي الصِّيَامِ وَالْحِجَامَةِ لِلصَّائِمِ إِبْقَاءً عَلَى أَصْحَابِهِ وَلَمْ يُحَرِّمْهَا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari ['Abdur Rahman bin 'Abis] dari ['Abdur Rahman bin Abu Laila] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam] berkata: Hanyasanya yang Nabi shallallahu 'alaihi wasallam larang adalah puasa terus menerus (wisal), sedang beliau larang berbekam bagi orang puasa adalah agar para sahabat bisa bertahan meneruskan puasanya, dan beliau tidak mengharamkannya."},"3384":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ بْنِ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ جُرَيَّ بْنَ كُلَيْبٍ النَّهْدِيَّ عَنْ رَجُلٍ مِنْ بَنِي سُلَيْمٍ قَالَعَدَّهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِي أَوْ فِي يَدِهِ التَّسْبِيحُ نِصْفُ الْمِيزَانِ وَالْحَمْدُ لِلَّهِ تَمْلَؤُهُ وَالتَّكْبِيرُ يَمْلَأُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَالصَّوْمُ نِصْفُ الصَّبْرِ وَالطُّهُورُ نِصْفُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Waki'] dari [Yunus bin Abu Ishaq] berkata: Aku mendengar [Jurai bin Kulaib An Nahdi] dari [seseorang dari Bani Sulaim] berkata: Rasulullah shallallahu 'alaihi wasallam -seraya bertasbih dengan tangan- bersabda; Bacaan tasbih adalah separuh timbangan, alhamdulillah memenuhinya, takbir memenuhi antara langit dan bumi, puasa adalah separuh kesabaran dan bersuci adalah separuh keimanan.\""},"3385":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي قَتَادَةَ وَأَبِي الدَّهْمَاءِ قَالَاأَتَيْنَا عَلَى رَجُلٍ مِنْ أَهْلِ الْبَادِيَةِ فَقُلْنَا هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا قَالَ نَعَمْ سَمِعْتُهُ يَقُولُ إِنَّكَ لَنْ تَدَعَ شَيْئًا لِلَّهِ عَزَّ وَجَلَّ إِلَّا بَدَّلَكَ اللَّهُ بِهِ مَا هُوَ خَيْرٌ لَكَ مِنْهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal] dari [Abu Qatadah] dan [Abu Ad Dahma`] keduanya berkata: Kami mendatangi [salah seorang pedalaman], kami bertanya: Apa kau pernah mendengar sesuatu dari Rasulullah shallallahu 'alaihi wasallam? Ia menjawaba: Ya, aku mendengar beliau bersabda: \"Tidaklah engkau meninggalkan sesuatu karena Allah AzzaWaJalla melainkan Allah akan mengganti dengan sesuatu yang lebih baik darinya untukmu.\""},"3386":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ أُمِّهِ ابْنَةِ أَبِي الْحَكَمِ الْغِفَارِيِّ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرَّجُلَ لَيَدْنُو مِنْ الْجَنَّةِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إِلَّا قِيدُ ذِرَاعٍ فَيَتَكَلَّمُ بِالْكَلِمَةِ فَيَتَبَاعَدُ مِنْهَا أَبْعَدَ مِنْ صَنْعَاءَ","id":"Telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Muhammad bin Ishaq] dari [Sulaiman bin Suhaim] dari [ibunya, putri Abu Al Halam Al Ghifari] berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Ada seseorang yang mendekati surga hingga tidak ada (jarak) antaranya dengan surga kecuali seukuran satu dzira', kemudian ia mengucapkan kata-kata hingga menjauhinya lebih jauh dari Shan'a`.\""},"3387":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَشْهَلِيِّ عَنْ جَدَّتِهِ أَنَّها قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا نِسَاءَ الْمُؤْمِنَاتِ لَا تَحْقِرَنَّ إِحْدَاكُنَّ لِجَارَتِهَا وَلَوْ كُرَاعُ شَاةٍ مُحْرَقٌ","id":"Telah menceritakan kepada kami [Rauh] telah bercerita kepada kami [Malik] dari [Zaid bin Aslam] dari ['Amru bin Mu'adz Al Asyhali] dari [neneknya] bahwa ia berkata; Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Wahai wanita-wanita yang beriman! Janganlah salah seorang dari kalian meremehkan (pemberian) tetangganya meski hanya kaki kambing yang dibakar.\""},"3388":{"ar":"حَدَّثَنَا رَوْحٌ وَعَبْدُ الرَّزَّاقِ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي حَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍعَنْ رَجُلٍ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الطَّوَافُ صَلَاةٌ فَإِذَا طُفْتُمْ فَأَقِلُّوا الْكَلَامَوَلَمْ يَرْفَعْهُ ابْنُ بَكْرٍ","id":"Telah menceritakan kepada kami [Rauh] dan ['Abdur Razzaq] keduanya berkata; telah bercerita kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Hasan bin Muslim] dari [Thawus] dari [seseorang] yang bertemu Nabi Shallallahu 'alaihi wa salam, ia berkata; Nabi Shallallahu 'alaihi wa salam bersabda: \" Thawaf adalah shalat, bila kalian berthawaf jangan banyak berbicara.\" Ibnu Bakr tidak memarfu'kannya."},"3389":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبُو عَوَانَةَ عَنِ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ بَنِي يَرْبُوعَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ وَهُوَ يُكَلِّمُ النَّاسَ يَقُولُ يَدُ الْمُعْطِي الْعُلْيَا أُمَّكَ وَأَبَاكَ وَأُخْتَكَ وَأَخَاكَ ثُمَّ أَدْنَاكَ أَدْنَاكَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ بْنِ يَرْبُوعَ الَّذِينَ أَصَابُوا فُلَانًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah menceritakan kepada kami [Yunus] telah bercerita kepada kami [Abu 'Awanah] dari [Al Asy'ats bin Sulaim] dari [ayahnya] dari [seseorang dari Bani Yarbu'] berkata; Aku mendatangi Nabi Shallallahu 'alaihi wa salam lalu aku mendengar beliau tengah menceramahi orang-orang, beliau bersabda: \"Tangan diatas (pemberi) awalmulakanlah untuk ibumu, ayahmu, saudara perempuanmu, saudara lelakimu kemudian yang sebawahnya kemudian yang sebawahnya.\" Seseorang berkata; Wahai Rasulullah! Bani Tsa'labah bin Yarbu' adalah orang-orang yang membunuh Fulan. Lalu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ingat, janganlah jiwa melakukan tindakan pidana pada yang lain.\""},"3390":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْأَزْرَقِ بْنِ قَيْسٍ عَنْ يَحْيَى بْنِ يَعْمُرَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ صَلَاتُهُ فَإِنْ كَانَ أَتَمَّهَا كُتِبَتْ لَهُ تَامَّةً وَإِنْ لَمْ يَكُنْ أَتَمَّهَا قَالَ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا هَلْ تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَتُكَمِّلُوا بِهَا فَرِيضَتَهُ ثُمَّ الزَّكَاةُ كَذَلِكَ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah bercerita kepada kami [Hammad bin Salamah] dari [Al Arzuq bin Qais] dari [Yahya bin Ya'mur] dari [seorang] sahabat Nabi Shallallahu 'alaihi wa salam berkata; Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Yang pertama dihisab dari seorang hamba adalah shalatnya, bila ia menyempurnakannya, maka ditulis sempurna untuknya, bila ia tidak menyempurnakannya maka Allah 'azza wajalla berfirman: Lihatlah, apakah kalian melihat shalat sunnah hambaKu lalu kalian menyempurnakan shalat wajibnya dengan shalat sunnah itu? zakat seperti itu juga kemudian semua amal juga dihukumi seperti itu.\""},"3391":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَاقَ عَنِ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أُرَاهُمْ اللَّيْلَةَ إِلَّا سَيُبَيِّتُونَكُمْ فَإِنْ فَعَلُوا فَشِعَارُكُمْ حم لَا يُنْصَرُونَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah bercerita kepada kami [Syuraik] dari [Abu Ishaq] dari [Al Muhallab bin Abu Shufrah] dari [seorang] sahabat Nabi Shallallahu 'alaihi wa salam dari Nabi Shallallahu 'alaihi wa salam bersada : \"Sepertinya malam ini mereka akan menyerang kalian, bila mereka melakukannya maka sandi kalian adalah: Jagalah, mereka tidak akan menang.\""},"3392":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْحَكَمُ بْنُ فُضَيْلٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي تَمِيمَةَ عَنْ رَجُلٍ مِنْ قَوْمِهِ أَنَّهُأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَتَاهُ رَجُلٌ فَقَالَ أَنْتَ رَسُولُ اللَّهِ أَوْ قَالَ أَنْتَ مُحَمَّدٌ فَقَالَ نَعَمْ قَالَ فَإِلَامَ تَدْعُو قَالَ أَدْعُو إِلَى اللَّهِ وَحْدَهُ مَنْ إِذَا كَانَ بِكَ ضُرٌّ فَدَعَوْتَهُ كَشَفَهُ عَنْكَ وَمَنْ إِذَا أَصَابَكَ عَامُ سَنَةٍ فَدَعَوْتَهُ أَنْبَتَ لَكَ وَمَنْ إِذَا كُنْتَ فِي أَرْضٍ قَفْرٍ فَأَضْلَلْتَ فَدَعَوْتَهُ رَدَّ عَلَيْكَ قَالَ فَأَسْلَمَ الرَّجُلُ ثُمَّ قَالَ أَوْصِنِي يَا رَسُولَ اللَّهِ فَقَالَ لَهُ لَا تَسُبَّنَّ شَيْئًا أَوْ قَالَ أَحَدًا شَكَّ الْحَكَمُ قَالَ فَمَا سَبَبْتُ شَيْئًا بَعِيرًا وَلَا شَاةً مُنْذُ أَوْصَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَزْهَدْ فِي الْمَعْرُوفِ وَلَوْ بِبَسْطِ وَجْهِكَ إِلَى أَخِيكَ وَأَنْتَ تُكَلِّمُهُ وَأَفْرِغْ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَاتَّزِرْ إِلَى نِصْفِ السَّاقِ فَإِنْ أَبَيْتَ فَإِلَى الْكَعْبَيْنِ وَإِيَّاكَ وَإِسْبَالَ الْإِزَارِ قَالَ فَإِنَّهَا مِنْ الْمَخِيلَةِ وَاللَّهُ لَا يُحِبُّ الْمَخِيلَةَ","id":"Telah menceritakan kepada kami [Abu An Nadhr] telah bercerita kepada kami [Al Hakam bin Fudhail] dari [Khalid Al Hadzdza`] dari [Abu Tamimah] dari [salah seorang kaumnya] bahwa ia mendatangi Nabi Shallallahu 'alaihi wa salam -atau ia berkata; Aku menyaksikan Rasulullah Shallallahu 'alaihi wa salam- kemudian seseorang mendatangi beliau, ia berkata; baginda utusan Allah? -atau berkata; baginda adalah Muhammad? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ya.\" Orang itu bertanya: Kemanakah tujuan da'wah baginda? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Menuju Allah semata, Yang kalian seru bila petaka menimpamu agar Ia melenyapkannya darimu, Yang kalian seru bila kau tertimpa kemarau panjang agar Ia menumbuhkan tanaman untukmu, Yang kau seru bila kau tersesat ditanah sepi agar Ia mengembalikanmu.\" Orang itu pun masuk Islam kemudian berkata; Wahai Rasulullah! Berilah aku wasiat. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Jangan mencela apa pun -atau bersabda: siapa pun, Al Hakam ragu kepastian redaksinya, ia berkata; Setelah Rasulullah Shallallahu 'alaihi wa salam berwasiat padaku, aku tidak pernah mencela apa pun, baik unta atau pun kambing- jangan pelit dalam kebaikan meski hanya menghadapkan wajahmu ke wajah saudaramu saat kau berbicara dengannya, tuangkan gayungmu di bejana orang yang meminta air, kenakan sarung hingga setengah betis, bila kau enggan maka hingga dua mata kaki, janganlah kau menjulurkan sarung karena itu termasuk kesombongan dan Allah tidak menyukai kesombongan.\""},"3393":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ مُهَاجِرٍ الصَّائِغِ عَنْ رَجُلٍ لَمْ يُسَمِّهِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُسَمِعَ رَجُلًا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ قُلْ يَا أَيُّهَا الْكَافِرُونَ فَقَالَ أَمَّا هَذَا فَقَدْ بَرِئَ مِنْ الشِّرْكِ وَسَمِعَ آخَرَ وَهُوَ يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ فَقَالَ أَمَّا هَذَا فَقَدْ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah bercerita kepada kami [Syarik] dari [Muhajir Ash Sha`igh] dari [seseorang yang tidak disebut namanya, salah seorang sahabat Nabi Shallallahu 'alaihi wa salam] bahwa ia mendengar Nabi Shallallahu 'alaihi wa salam, beliau mendengar orang membaca: Qul yaa`ayyyuhal kaafiruun. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang ini telah terbebas dari kesyirikan.\" Kemudian orang lain melintas dan ia membaca: Qul huwAllaahu ahad. Nabi Shallallahu 'alaihi wa salam bersabda: \"Sementara yang ini dosanya telah diampuni.\""},"3394":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْدًا أَوْ أَسْعَدَ بْنَ زُرَارَةَ فِي حَلْقِهِ مِنْ الذُّبْحَةِ وَقَالَ لَا أَدَعُ فِي نَفْسِي حَرَجًا مِنْ سَعْدٍ أَوْ أَسْعَدَ بْنِ زُرَارَةَ","id":"Telah menceritakan kepada kami [Hasan] telah bercerita kepada kami [Zuhair] dari [Abu Az Zubair] dari ['Amru bin Syu'aib] dari [ayahnya] dari [seorang sahabat Nabi Shallallahu 'alaihi wa salam] berkata; Rasulullah Shallallahu 'alaihi wa salam menyundut leher Sa'ad atau As'ad bin Zurarah dengan api karena sembelihan, beliau bersabda: Aku tidak akan membiarkan kesempitan dalam diriku karena Sa'ad atau As'ad bin Zurarah.\""},"3395":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنِ الْفَضْلِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَ سَمِعْتُ رِجَالًا يَتَحَدَّثُونَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا عُتِقَتْ الْأَمَةُ فَهِيَ بِالْخِيَارِ مَا لَمْ يَطَأْهَا إِنْ شَاءَتْ فَارَقَتْهُ وَإِنْ وَطِئَهَا فَلَا خِيَارَ لَهَا وَلَا تَسْتَطِيعُ فِرَاقَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Ibnu Lahi'ah] dari ['Ubaidullah bin Abu Ja'far] dari [Al Fadhl bin 'Amru bin Umaiyah] dari [ayahnya] berkata; Aku mendengar [beberapa orang] menceritakan dari Nabi Shallallahu 'alaihi wa salam bersabda: \"Bila budak wanita dimerdekakan, ia memiliki pilihan selama (suaminya) belum menggaulinya, bila ia mau ia boleh berpisah dengannya tapi bila (suaminya) Telah menggaulinya, maka ia tidak memiliki pilihan dan tidak bisa berpisah dengannya.\""},"3396":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي جَعْفَرٍ عَنِ الْفَضْلِ بْنِ الْحَسَنِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ قَالُ سَمِعْتُ رِجَالًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَدَّثُونَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُعْتِقَتْ الْأَمَةُ وَهِيَ تَحْتَ الْعَبْدِ فَأَمْرُهَا بِيَدِهَا فَإِنْ هِيَ أَقَرَّتْ حَتَّى يَطَأَهَا فَهِيَ امْرَأَتُهُ لَا تَسْتَطِيعُ فِرَاقَهُ","id":"Telah menceritakan kepada kami [Hasan] telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepada kami ['Ubaidullah bin Abu Ja'far] dari [Al Fadhl bin Al Hasan bin 'Amru bin Umaiyah Adl Dlamri] berkata; Aku mendengar [beberapa sahabat] Nabi Shallallahu 'alaihi wa salam bercerita bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bila budak wanita dimerdekakan sementara ia sebagai istri seorang budak, maka urusannya terserah dia, bila ia mengakuinya hingga suaminya menggaulinya maka ia adalah istrinya dan ia tidak bisa berpisah dengannya.\""},"3397":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ يَزِيدَ يَعْنِي ابْنَ جَابِرٍ عَنْ خَالِدِ بْنِ اللَّجْلَاجِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَائِشٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ ذَاتَ غَدَاةٍ وَهُوَ طَيِّبُ النَّفْسِ مُسْفِرُ الْوَجْهِ أَوْ مُشْرِقُ الْوَجْهِ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّا نَرَاكَ طَيِّبَ النَّفْسِ مُسْفِرَ الْوَجْهِ أَوْ مُشْرِقَ الْوَجْهِ فَقَالَ مَا يَمْنَعُنِي وَأَتَانِي رَبِّي اللَّيْلَةَ فِي أَحْسَنِ صُورَةٍ فَقَالَ يَا مُحَمَّدُ قُلْتُ لَبَّيْكَ رَبِّي وَسَعْدَيْكَ فَقَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قُلْتُ لَا أَدْرِي أَيْ رَبِّ قَالَ ذَلِكَ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ فَوَضَعَ كَفَّهُ بَيْنَ كَتِفَيَّ فَوَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ حَتَّى تَجَلَّى لِي مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَكَذَلِكَ نُرِي إِبْرَاهِيمَ مَلَكُوتَ السَّمَوَاتِ وَالْأَرْضِ }الْآيَةَ قَالَ يَا مُحَمَّدُ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى قَالَ قُلْتُ فِي الْكَفَّارَاتِ قَالَ وَمَا الْكَفَّارَاتُ قُلْتُ الْمَشْيُ عَلَى الْأَقْدَامِ إِلَى الْجَمَاعَاتِ وَالْجُلُوسُ فِي الْمَسَاجِدِ خِلَافَ الصَّلَوَاتِ وَإِبْلَاغُ الْوُضُوءِ فِي الْمَكَارِهِ قَالَ مَنْ فَعَلَ ذَلِكَ عَاشَ بِخَيْرٍ وَمَاتَ بِخَيْرٍ وَكَانَ مِنْ خَطِيئَتِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ وَمِنْ الدَّرَجَاتِ طَيِّبُ الْكَلَامِ وَبَذْلُ السَّلَامِ وَإِطْعَامُ الطَّعَامِ وَالصَّلَاةُ بِاللَّيْلِ وَالنَّاسُ نِيَامٌ فَقَالَ يَا مُحَمَّدُ إِذَا صَلَّيْتَ فَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ الطَّيِّبَاتِ وَتَرْكَ الْمُنْكَرَاتِ وَحُبَّ الْمَسَاكِينِ وَأَنْ تَتُوبَ عَلَيَّ وَإِذَا أَرَدْتَ فِتْنَةً فِي النَّاسِ فَتَوَفَّنِي غَيْرَ مَفْتُونٍ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah bercerita kepada kami [Zuhair bin Muhammad] dari [Yazid bin Yazid ibn Jabir] dari [Khalid bin Al Lajlaj] dari ['Abdur Rahman bin 'A`isy] dari [seorang] sahabat Nabi Shallallahu 'alaihi wa salam bahwa Nabi Shallallahu 'alaihi wa salam keluar menemui mereka pada suatu hari dalam keadaan gembira dan berseri, kami berkata; Wahai Rasulullah! baginda terlihat bahagia dan berseri. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Apa yang menghalangiku, tadi malam Rabbku mendatangiku dalam bentuk yang paling indah lalu berfirman: Hai Muhammad! Aku berkata; Baik Rabbku. Ia berfirman: Apa yang diperdebatkan oleh malaikat tertinggi? Aku menjawab: Aku tidak tahu wahai Rabb. -beliau mengucapkannya dua atau tiga kali- lalu Ia meletakkan telapak tanganNya diantara pundakku, aku merasakan dinginnya diantara dadaku hingga terlihatlah olehku seluruh yang ada dilangit dan dibumi, kemudian beliau membaca ayat: 'Dan Demikianlah kami perlihatkan kepada Ibrahim tanda-tanda keagungan (Kami yang terdapat) di langit dan bumi.' (Al-An'aam: 75) Ia berfirman: Hai Muhammad! Apa yang diperdebatkan oleh malaikat tertinggi? Aku menjawab: Tentang penghapus dosa. Ia bertanya: Penghapus dosa apa? Aku berkata; Berjalan kaki untuk berjamaah, duduk di masjid setelah shalat, menyempurnakan wudhu pada saat-saat tidak disukai. Rasulullah Shallallahu 'alaihi wa salam bersabda: Barangsiapa melakukan hal itu, ia hidup seperti itu, ia hidup dalam keadaan baik dan mati dalam keadaan baik, dan kesalahannya seperti pada saat ia dilahirkan ibunya. Termasuk derajat adalah berkata-kata baik, menyampaikan salam, memberi makan, shalat di malam saat orang-orang tidur. Allah berfirman: Hai Muhammad! Bila kau berdoa, ucapkanlah: Ya Allah! aku meminta kebaikan-kebaikan padaMu, meninggalkan kemungkaran-kemungkaran, mencintai orang-orang miskin, terimalah taubatku dan bila Kau menghendaki cobaan pada manusia maka wafatkanlah aku dalam keadaan tidak tertimpa cobaan.\""},"3398":{"ar":"حَدَّثَنَا الزُّبَيْرِيُّ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ عَامِرٍ حَدَّثَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَمَرَ بِرَجْمِ رَجُلٍ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَلَمَّا وَجَدَ مَسَّ الْحِجَارَةِ خَرَجَ فَهَرَبَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا تَرَكْتُمُوهُ","id":"Telah menceritakan kepada kami [Az Zubairi bin 'Abdullah] telah bercerita kepada kami [Isra`il] dari [Simak] berkata; telah bercerita kepadaku ['Abdul 'Aziz bin 'Abdullah bin 'Amir] telah bercerita kepadaku [orang] yang mendengar Rasulullah Shallallahu 'alaihi wa salam memerintahkan menghukum rajam seseorang diantara Makkah dan Madinah, saat terkena lemaparan batu, ia lari lalu hal itu terdengar oleh Nabi Shallallahu 'alaihi wa salam, namun beliau malah berkomentar: \"Kenapa kalian tidak membiarkannya?.\""},"3399":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ رَجُلٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَتَى جُعِلْتَ نَبِيًّا قَالَ وَآدَمُ بَيْنَ الرُّوحِ وَالْجَسَدِ","id":"Telah menceritakan kepada kami [Suraij bin An Nu'man] telah bercerita kepada kami [Hammad] dari [Khalid Al Hadzdza`] dari ['Abdullah bin Syaqiq] dari [seseorang] berkata; Aku berkata; Wahai Rasulullah! Kapan baginda dijadikan nabi? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Saat Adam berada diantara ruh dan jasad.\""},"3400":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْمُبَارَكُ حَدَّثَنَا الْحَسَنُ أَنَّ شَيْخًا مِنْ بَنِي سَلِيطٍ أَخْبَرَهُ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُكَلِّمُهُ فِي شَيْءٍ أُصِيبَ لَنَا فِي الْجَاهِلِيَّةِ فَإِذَا هُوَ قَاعِدٌ وَعَلَيْهِ حَلْقَةٌ قَدْ أَطَافَتْ بِهِ وَهُوَ يُحَدِّثُ الْقَوْمَ عَلَيْهِ إِزَارُ قُطْنٍ لَهُ غَلِيظٌ فَأَوَّلُ شَيْءٍ سَمِعْتُهُ يَقُولُ وَهُوَ يُشِيرُ بِإِصْبَعَيْهِ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا يَقُولُ أَيْ فِي الْقَلْبِ","id":"Telah menceritakan kepada kami [Abu An Nadhr] telah bercerita kepada kami [Al Mubarok] telah bercerita kepada kami [Al Hasan] bahwa [seorang tua] dari Bani Salith memberitahunya, ia berkata; Aku mendatangi Rasulullah Shallallahu 'alaihi wa salam, aku berbicara tentang sesuatu yang pernah kami lakukan di masa jahiliyah, ternyata beliau tengah duduk bersama jamaah yang mengelilinginya sementara beliau bercerita pada mereka, beliau mengenakan sarung katun tebal milik beliau, hal pertama yang aku dengar dari beliau adalah -dan beliau menunjuk dengan dua jari: \"Muslim itu saudara muslim lain, tidak menzhalimi dan merendahkannya, takwa itu disini, takwa itu disini.\" Maksudnya dihati."},"3401":{"ar":"حَدَّثَنَا عُمَرُ بْنُ سَعْدٍ أَبُو دَاوُدَ الْحَفَرِيُّ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا يَعْنِي ابْنَ أَبِي زَائِدَةَ حَدَّثَنِي سَعْدُ بْنُ طَارِقٍ عَنْ بِلَالِ بْنِ يَحْيَى عَنِ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَخْبَرَنِي أَعْرَابِيٌّ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَخَافُ عَلَى قُرَيْشٍ إِلَّا أَنْفُسَهَا قُلْتُ مَا لَهُمْ قَالَ أَشِحَّةٌ نَحِرَةٌ وَإِنْ طَالَ بِكَ عُمْرٌ لَتَنْظُرَنَّ إِلَيْهِمْ يَفْتِنُونَ النَّاسَ حَتَّى تَرَى النَّاسَ بَيْنَهُمْ كَالْغَنَمِ بَيْنَ الْحَوْضَيْنِ إِلَى هَذَا مَرَّةً وَإِلَى هَذَا مَرَّةً","id":"Telah menceritakan kepada kami ['Umar bin Sa'ad Abu Dawud Al Hafari] telah bercerita kepada kami [Yahya bin Zakariya bin Abu Za`idah] telah bercerita kepadaku [Sa'ad bin Thariq] dari [Bilal bin Yahya] dari ['Imran bin Hushain] berkata; [Seorang badui] bercerita kepadaku bahwa ia mendengar Nabi Shallallahu 'alaihi wa salam bersabda: \"Yang aku khawatirkan dari Quraisy adalah jiwa mereka.\" Aku (orang badui) bertanya: Mereka kenapa? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Mereka pelit dan suka memusuhi, bila umurmu panjang, kau pasti melihat mereka memfitnah manusia hingga kau melihat manusia seperti kambing diantara dua telaga, kadang kesini dan kadang kesana.\""},"3402":{"ar":"حَدَّثَنَا الزُبَيْرِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ مَعْبَدِ بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَيْرٍ أَوْ عُمَيْرَةَ قَالَ حَدَّثَنِي زَوْجُ ابْنَةِ أَبِي لَهَبٍ قَالَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تَزَوَّجْتُ ابْنَةَ أَبِي لَهَبٍ فَقَالَ هَلْ مِنْ لَهْوٍ","id":"Telah menceritakan kepada kami [Az Zubairi] telah bercerita kepada kami [Isra`il] dari [Simak] dari [Ma'bad bin Qais] dari ['Abdullah bin 'Umair atau 'Umairah] berkata; telah bercerita kepadaku [suami putri Abu Lahab] berkata; Rasulullah Shallallahu 'alaihi wa salam memasuki kami saat aku menikahi putri Abu Lahab, dan beliau bersabda: \"Apa ini lelucon?\""},"3403":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا حَيَّةُ التَّمِيمِيُّ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ وَأَصْدَقُ الطِّيَرِ الْفَأْلُ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah bercerita kepada kami ['Ali] dan telah bercerita kepadaku [Yahya bin Abu Katsir] telah bercerita kepada kami [Hayyah At Tamimi] bahwa [ayahnya] memberitahunya bahwa ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tak ada burung hantu yang mendatangkan kesialan, 'ain (penyakit yang ditimbulkan oleh pandangan mata orang yang hasud, pent.) itu haq dan sebenar-benar firasat adalah optimisme.\""},"3404":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبَانُ وَعَبْدُ الصَّمَدِ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي جَعْفَرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَبَيْنَمَا رَجُلٌ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ إِذْ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ قَالَ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ قَالَ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالُوا يَا رَسُولَ اللَّهِ مَا لَكَ أَمَرْتَهُ أَنْ يَتَوَضَّأَ ثُمَّ سَكَتَّ عَنْهُ قَالَ إِنَّهُ كَانَ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ وَإِنَّ اللَّهَ لَا يَقْبَلُ صَلَاةَ عَبْدٍ مُسْبِلٍ إِزَارَهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah bercerita kepada kami [Aban] dan ['Abdush Shamad] telah bercerita kepada kami [Hisyam] dari [Yahya] dari [Abu Ja'far] dari ['Atho` bin Yasar] dari [seorang] sahabat Nabi Shallallahu 'alaihi wa salam berkata; Saat seseorang tengah shalat sementara ia menjulurkan sarungnya, Nabi Shallallahu 'alaihi wa salam bersabda padanya: \"Pergi dan berwudhulah.\" Ia pun pergi lalu wudhu kemudian datang lalu Rasulullah Shallallahu 'alaihi wa salam bersabda padanya: \"Pergi dan berwudhulah.\" Ia pun pergi lalu wudhu kemudian mereka bertanya: Wahai Rasulullah! Kenapa baginda menyuruhnya berwudhu, beliau diam lalu bersabda: \" Ia shalat dalam keadaan menjulurkan sarungnya, Allah tidak menerima shalat seorang hamba yang menjulurkan sarungnya.\""},"3405":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَيَا أَيُّهَا النَّاسُ لَا يَقْتُلْ بَعْضُكُمْ بَعْضًا إِذَا رَمَيْتُمْ الْجَمْرَةَ فَارْمُوهَا بِمِثْلِ حَصَى الْخَذْفِوَقُرِئَ عَلَيْهِ إِسْنَادُهُ يَزِيدُ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ يَعْنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sufyan] berkata; Wahai sekalian manusia! Janganlah sebagaian dari kalian membunuh sebagaian yang lain saat kalian melempar jumrah, lemparkanlah batu seperti kerikil. [Yazid] membacakan sanadnya dari [Sulaiman bin 'Amru bin Al Ahwash] dari [ibunya] dari Nabi Shallallahu 'alaihi wa salam."},"3406":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا لَيْثٌ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أُمِّ جُنْدُبٍ الْأَزْدِيَّةِ أَنَّهاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَفَاضَ قَالَ يَا أَيُّهَا النَّاسُ عَلَيْكُمْ بِالسَّكِينَةِ وَالْوَقَارِ وَعَلَيْكُمْ بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Laits] dari ['Abdullah bin Syaddad] dari [Ummu Jundub Al Azdiyah] bahwa ia mendengar Nabi Shallallahu 'alaihi wa salam bersabda saat pergi (untuk melempar jumrah): \"Wahai sekalian manusia! Hendaklah kalian tenang dan tentram, hendaklah kalian melemparkan batu seperti kerikil.\""},"3407":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَنْصُورِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ عَنْ أُمِّ عُثْمَانَ ابْنَةِ سُفْيَانَ وَهِيَ أُمُّ بَنِي شَيْبَةَ الْأَكَابِرِ قَالَ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ وَقَدْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا شَيْبَةَ فَفَتَحَ فَلَمَّا دَخَلَ الْبَيْتَ وَرَجَعَ وَفَرَغَ وَرَجَعَ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَجِبْ فَأَتَاهُ فَقَالَ إِنِّي رَأَيْتُ فِي الْبَيْتِ قَرْنًا فَغَيِّبْهُقَالَ مَنْصُورٌ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ عَنْ أُمِّي عَنْ أُمِّ عُثْمَانَ ابْنَةِ سُفْيَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ فِي الْحَدِيثِ فَإِنَّهُ لَا يَنْبَغِي أَنْ يَكُونَ فِي الْبَيْتِ شَيْءٌ يُلْهِي الْمُصَلِّينَ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Muhammad bin 'Abdur Rahman] dari [Manshur bin 'Abdur Rahman] dari [ibunya] dari [Ummu 'Utsman binti Sufyah, ibunya keturunan pembesar Syaibah] berkata [Muhammad bin 'Abdur Rahman]: Ia (Ummu 'Usman) pernah berbaiat kepada Nabi Shallallahu 'alaihi wa salam, bahwa Nabi Shallallahu 'alaihi wa salam memanggil Syaibah lalu beliau menaklukkan Makkah, saat masuk ke baitullah lalu kembali lagi, ternyata Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Penuhilah panggilannya.\" Lalu Syaibah mendatangi beliau, ia berkata; Aku melihat tanduk di baitullah lalu aku menguburnya. Berkata [Manshur]: telah bercerita kepadaku ['Abdullah bin Musafi'] dari [ibuku] dari [Ummu 'Utsman, putri Sufyan] bahwa Nabi Shallallahu 'alaihi wa salam bersabda kepadanya tentang hadits ini: \" tidak patut didalam baitullah ada sesuatu yang mengalihkan perhatian orang-orang shalat.\""},"3408":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مَنْصُورٌ عَنْ خَالِهِ مُسَافِعٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ أُمِّ مَنْصُورٍ قَالَتْ أَخْبَرَتْنِي امْرَأَةٌ مِنْ بَنِي سُلَيْمٍ وَلَّدَتْ عَامَّةَ أَهْلِ دَارِنَاأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُثْمَانَ بْنِ طَلْحَةَ وَقَالَ مَرَّةً إِنَّهَا سَأَلَتْ عُثْمَانَ لِمَ دَعَاكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي كُنْتُ رَأَيْتُ قَرْنَيْ الْكَبْشِ حَيْثُ دَخَلْتُ الْبَيْتَ فَنَسِيتُ أَنْ آمُرَكَ أَنْ تُخَمِّرَهُمَا فَخَمِّرْهُمَا فَإِنَّهُ لَا يَنْبَغِي أَنْ يَكُونَ فِي الْبَيْتِ شَيْءٌ يَشْغَلُ الْمُصَلِّيَقَالَ سُفْيَانُ لَمْ يَزَلْ قَرْنَا الْكَبْشِ فِي الْبَيْتِ حَتَّى احْتَرَقَ الْبَيْتُ فَاحْتَرَقَا هَذَا آخِرُ حَدِيثِ","id":"Telah menceritakan kepada kami [Sufyan] telah bercerita kepadaku [Manshur] dari [pamannya, Musafi'] dari [Shafiyyah binti Syaibah, Ummu Manshur] berkata; [Seorang wanita dari Bani Sulaim] yang melahirkan sebagaian besar penghuni kawasan kami memberitahuku, Rasulullah Shallallahu 'alaihi wa salam mengirim utusan menemui 'Utsman bin Thalhah -sesekali ia berkata; Ia tanya 'Utsman: Kenapa Nabi Shallallahu 'alaihi wa salam memanggilmu? Ia menjawab: Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Aku melihat dua tanduk kambing saat aku memasuki baitullah tapi aku lupa menyuruhmu menutupinya, tutupilah kedua tanduk itu, karena tidak sepatutnya dibaitullah ada sesuatu yang mengalihkan perhatian orang shalat.\" Berkata Sufyan: Kedua tanduk kambing itu tetap berada dibaitullah hingga baitullah terbakar, kedua tanduk itu ikut terbakar. Inilah akhir hadits."},"3409":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ صَفِيَّةَ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى عَرَّافًا فَصَدَّقَهُ بِمَا يَقُولُ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah bercerita kepadaku [Nafi'] dari [Shafiyyah] dari [salah seorang istri] Nabi Shallallahu 'alaihi wa salam dari Nabi Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa mendatangi peramal lalu mempercayai ucapannya, shalatnya selama empatpuluh hari tidak diterima.\""},"3410":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَعَبْدُ الرَّزَّاقِ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُئِيَ بِالْعَرْجِ وَهُوَ يَصُبُّ عَلَى رَأْسِهِ الْمَاءَ وَهُوَ صَائِمٌ مِنْ الْحَرِّ أَوْ الْعَطَشِ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dan ['Abdur Razzaq] dari [Malik] dari [Sumayya] dari [Abu Bakr bin 'Abdur Rahman] dari [salah seorang sahabat] Nabi Shallallahu 'alaihi wa salam bahwa Nabi Shallallahu 'alaihi wa salam terlihat lemah, beliau mengguyurkan air diatas kepala saat beliau puasa karena panas atau haus."},"3411":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا حُسَيْنُ بْنُ ذَكْوَانَ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنِ امْرَأَةٍ مِنْهُمْ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آكُلُ بِشِمَالِي وَكُنْتُ امْرَأَةً عَسْرَاءَ فَضَرَبَ يَدِي فَسَقَطَتْ اللُّقْمَةُ فَقَالَ لَا تَأْكُلِي بِشِمَالِكِ وَقَدْ جَعَلَ اللَّهُ لَكِ يَمِينًا أَوْ قَالَ وَقَدْ أَطْلَقَ اللَّهُ يَمِينَكِ قَالَتْ فَتَحَوَّلَتْ شِمَالِي يَمِينِي فَمَا أَكَلْتُ بِهَا بَعْدُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah bercerita kepada kami [Husain bin Dzakwan] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari ['Abdullah bin Muhammad] dari [seorang wanita] kabilah mereka, ia berkata; Rasulullah Shallallahu 'alaihi wa salam masuk di kediamanku saat aku makan dengan tangan kiri, aku adalah wanita kidal, beliau memukul tanganku hingga makanan jatuh, beliau bersabda: \"Heih,,,, Jangan makan dengan tangan kiri, Allah telah membuat untukmu tangan kanan -atau bersabda: Allah telah melepas tangan kananmu.\" Ia berkata; Kemudian tangan kiriku berubah menjadi tangan kanan dan setelah sejak saat itu aku tidak lagi makan dengan tangan kiri."},"3412":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ مَوْلًى لَهُمْ عَنْ مُزَاحِمِ بْنِ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدِ بْنِ أَسِيدٍ عَنْ رَجُلٍ مِنْ خُزَاعَةَ يُقَالُ لَهُ مِحْرَشٌ أَوْ مُخَرِّشٌ لَمْ يَكُنْ سُفْيَانُ يَقِفُ عَلَى اسْمِهِ وَرُبَّمَا قَالَ مِخْرَشٌ وَلَمْ أَسْمَعْهُ أَنَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْجِعْرَانَةِ لَيْلًا فَاعْتَمَرَ ثُمَّ رَجَعَ فَأَصْبَحَ بِهَا كَبَائِتٍ فَنَظَرْتُ إِلَى ظَهْرِهِ كَأَنَّهَا سَبِيكَةُ فِضَّةٍ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Isma'il bin Umaiyah] dari [seorang budak mereka] dari [Muzahim bin Abu Muzahim] dari ['Abdul 'Aziz bin 'Abdullah bin Khalid bin Asid] dari seseorang dari Khuza'ah bernama [Mihrisy atau Mukharrisy] -Sufyan tidak pernah mengetahui namanya, kadang ia menyebut Mikrasy tapi aku tidak mendengarnya- bahwa Nabi Shallallahu 'alaihi wa salam pergi dari Ji'ranah lalu beliau berumrah, setelah itu beliau kembali, di pagi harinya beliau terlihat seperti menginap lalu melihat punggung beliau seperti leburan perak.\""},"3413":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ مِنْ ثَقِيفٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ وَنَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abi Najih] dari [Mujahid] dari [seseorang] dari Tsaqif dari ayahnya bahwa Nabi Shallallahu 'alaihi wa salam buang air kecil, beliau memercikkan pada kemaluan beliau."},"3414":{"ar":"وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَفْصُ بْنُ غِيَاثٍ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي جَبِيرَةَ بْنِ الضَّحَّاكِ الْأَنْصَارِيِّ عَنْ عُمُومَةٍ لَهُقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ أَحَدٌ مِنَّا إِلَّا لَهُ لَقَبٌ أَوْ لَقَبَانِ قَالَ فَكَانَ إِذَا دَعَا رَجُلًا بِلَقَبِهِ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَكْرَهُ هَذَا قَالَ فَنَزَلَتْ{ وَلَا تَنَابَزُوا بِالْأَلْقَابِ }","id":"Aku (Ahmad) menemukan dalam kitab ayahku dengan tulisan tangannya: [Hafsh bin Ghiyats] telah bercerita kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Abu Jabirah bin Adl Dlahhak Al Anshari] dari [bibinya], Nabi Shallallahu 'alaihi wa salam datang dan setiap orang dari kami pasti memiliki satu atau dua julukan. Ia berkata; Bila Rasulullah Shallallahu 'alaihi wa salam memanggil seseorang dengan julukannya, kami berkata; Wahai Rasulullah! orang itu tidak suka dengan panggilan ini. Kemudian turunlah ayat: \"Dan jangan memanggil dengan gelaran yang mengandung ejekan.\" (Al-Hujuraat: 11) "},"3415":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سُلَيْمَانَ شَيْخٌ صَالِحٌ حَسَنُ الْهَيْئَةِ مَدَنِيٌّ حَدَّثَنَا مُعَاذُ بْنُ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ عَنْ عَمِّهِ قَالَكُنَّا فِي مَجْلِسٍ فَطَلَعَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى رَأْسِهِ أَثَرُ مَاءٍ فَقُلْنَا يَا رَسُولَ اللَّهِ نَرَاكَ طَيِّبَ النَّفْسِ قَالَ أَجَلْ قَالَ ثُمَّ خَاضَ الْقَوْمُ فِي ذِكْرِ الْغِنَى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا بَأْسَ بِالْغِنَى لِمَنْ اتَّقَى وَالصِّحَّةُ لِمَنْ اتَّقَى خَيْرٌ مِنْ الْغِنَى وَطِيبُ النَّفْسِ مِنْ النَّعِيمِ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah bercerita kepada kami ['Abdullah bin Sulaiman], seorang guru shalih, berpenambilan bagus, dari Madinah telah bercerita kepada kami [Mu'adz bin 'Abdullah bin Khubaib] dari [ayahnya] dari [pamannya] berkata; Kami berada disuatu majlis kemudian Rasulullah Shallallahu 'alaihi wa salam datang, dirambut beliau ada sisa-sisa air, kami berkata; Wahai Rasulullah! Kami melihat baginda sedang bahagia. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Benar.\" Kemudian orang-orang memperbincangkan kekayaan. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidak apa-apa dengan kekayaan bagi orang yang bertakwa kepada Allah 'azza wajalla dan kesehatan bagi orang yang bertakwa kepada Allah itu lebih baik dan kebahagiaan jiwa itu termasuk kenikmatan.\""},"3416":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبَّادٌ يَعْنِي ابْنَ رَاشِدٍ عَنِ الْحَسَنِ عَنْ رَجُلٍ مِنْ بَنِي سَلِيطٍ أَنَّهُمَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَاعِدٌ عَلَى بَابِ مَسْجِدِهِ مُحْتَبٍ وَعَلَيْهِ ثَوْبٌ لَهُ قُطْنٌ لَيْسَ عَلَيْهِ ثَوْبٌ غَيْرُهُ وَهُوَ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ ثُمَّ أَشَارَ بِيَدِهِ إِلَى صَدْرِهِ يَقُولُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا","id":"Telah menceritakan kepada kami [Abu 'Amir] telah bercerita kepada kami ['Abbad bin Rasyid] dari [Al Hasan] dari [seseorang] dari Bani Salith, bahwa ia melewati Rasulullah Shallallahu 'alaihi wa salam saat duduk dipintu masjid dengan merangkul lutut, beliau mengenakan baju katun, beliau tidak mengenakan pakaian lain, beliau bersabda: \"Muslim itu saudara muslim lain, tidak menzhalimi dan merendahkannya, \" kemudian beliau menunjuk dada beliau dengan tangan seraya bersabda: \"Takwa itu disini, takwa itu disini.\""},"3417":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ حَدَّثَنَا الرُّكَيْنُ بْنُ الرَّبِيعِ بْنِ عُمَيْلَةَ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ رَجُلٍ مِنَ الْأَنْصَارِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ ثَلَاثَةٌ فَرَسٌ يَرْبُطُهُ الرَّجُلُ فِي سَبِيلِ اللَّهِ تَعَالَى فَثَمَنُهُ أَجْرٌ وَرُكُوبُهُ أَجْرٌ وَعَارِيَتُهُ أَجْرٌ وَعَلَفُهُ أَجْرٌ وَفَرَسٌ يُغَالِقُ عَلَيْهَا الرَّجُلُ وَيُرَاهِنُ فَثَمَنُهُ وِزْرٌ وَعَلَفُهُ وِزْرٌ وَرُكُوبُهُ وِزْرٌ وَفَرَسٌ لِلْبِطْنَةِ فَعَسَى أَنْ يَكُونَ سَدَّادًا مِنْ الْفَقْرِ إِنْ شَاءَ اللَّهُ تَعَالَى","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah bercerita kepada kami [Za`idah] telah bercerita kepada kami [Ar Rukain bin Ar Rabi' bin 'Umailah] dari [Abu 'Amru Asy Syaibani] dari [seorang] Anshar dari Nabi Shallallahu 'alaihi wa salam bersabda: \"Kuda itu ada tiga; Pertama kuda yang ditambatkan seseorang dijalan Allah Subhaanahu wa Ta'ala, maka harganya pahala, mengendarainya pahala, menyewakannya pahala dan memberi makanan padanya adalah pahala. Kedua adalah kuda yang dijadikan taruhan dan gadaian orang, maka harganya dosa, mengendarainya dosa dan ketiga adalah kuda untuk mengisi perut (mencari penghasilan), mudah-mudahan bisa mengatasi kemiskinan, insya Allah Ta'ala.\""},"3418":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنَاهُ يَحْيَى بْنُ حُصَيْنِ بْنِ عُرْوَةَ قَالَ حَدَّثَتْنِي جَدَّتِي قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah bercerita kepada kami [Yahya bin Hushain bin 'Urwah] berkata; telah bercerita kepadaku [nenekku] berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Andaikan seorang budak diangkat sebagai pemimpin kalian, dan ia menuntun kalian dengan kitab Allah, dengarlah dan taatilah.\""},"3419":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ حُصَيْنٍ عَنْ جَدَّتِهِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ قَالُوا فِي الثَّالِثَةِ وَالْمُقَصِّرِينَ قَالَ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Syu'bah] dari [Yahya bin Hushain] dari [neneknya] berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Semoga Allah merahmati orang-orang yang menggunduli rambutnya, Semoga Allah merahmati orang-orang yang menggunduli rambutnya, Semoga Allah merahmati orang-orang yang menggunduli rambutnya.\" Mereka berkata pada ketiga kalinya: Dan orang-orang yang memendekkan rambutnya. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dan orang-orang yang memendekkan rambutnya.\""},"3420":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورِ بْنِ حَي��َانَ الْأَسَدِيِّ عَنِ ابْنِ بِجَادٍ عَنْ جَدَّتِهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا السَّائِلَ وَلَوْ بِظِلْفِ شَاةٍ مُحْتَرِقٍ أَوْ مُحْرَقٍ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Sufyan] dari [Manshur bin Hayyan Al Asadi] dari [Ibnu Bijad] dari [neneknya] berkata; Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Berilah orang yang meminta meski dengan kuku kambing yang dibakar.\""},"3421":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ يَحْيَى بْنِ الْحُصَيْنِ عَنْ أُمِّهِ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَاسْمَعُوا وَأَطِيعُوا وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Yahya bin Al Hushain] dari [ibunya] berkata; Aku mendengar Nabi Shallallahu 'alaihi wa salam berkhutbah saat haji wada', beliau bersabda: \"Wahai sekalian manusia! Bertakwalah kepada Allah, dengar dan taatlah meski seorang budak Habasyah yang terpotong hidungnya memimpin kalian selama ia menegakkan kitab Allah 'azza wajalla ditengah-tengah kalian.\""},"3422":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ جَدَّتِهِ عَنِ امْرَأَةٍ مِنْ نِسَائِهِمْ قَالَ وَقَدْ كَانَتْ صَلَّتْ الْقِبْلَتَيْنِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي اخْتَضِبِي تَتْرُكُ إِحْدَاكُنَّ الْخِضَابَ حَتَّى تَكُونَ يَدُهَا كَيَدِ الرَّجُلِقَالَتْ فَمَا تَرَكَتْ الْخِضَابَ حَتَّى لَقِيَتْ اللَّهَ عَزَّ وَجَلَّ وَإِنْ كَانَتْ لَتَخْتَضِبُ وَإِنَّهَا لَابْنَةُ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Dhamrah bin Sa'id] dari [neneknya] dari [seorang wanita diantara mereka] -ia termasuk diantara orang yang shalat menghadap dua kiblat bersama Nabi Shallallahu 'alaihi wa salam- berkata; Aku masuk di kediaman Rasulullah Shallallahu 'alaihi wa salam, kemudian beliau bersabda padaku: \"Kenakan daun inai di kukumu, apa pantas salah seorang diantara kalian tidak mengenakan daun inai di kukunya hingga tangannya seperti tangan lelaki?.\" Ia berkata; Sejak saat itu ia tidak pernah ketinggalan mengenakan daun inai di kukunya hingga bertemu dengan Allah 'azza wajalla, ia tetap mengenakan daun inai dikukunya meski usianya mencapai delapanpuluh tahun."},"3423":{"ar":"حَدَّثَنَا هَيْثَمٌ يَعْنِي ابْنَ خَارِجَةَ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ عَنِ ابْنِ حَرْمَلَةَ عَنْ أَبِي ثِفِالٍ الْمُزَنِيِّ أَنَّهُ قَالَ سَمِعْتُ رَبَاحَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ حُوَيْطِبٍ يَقُولُ حَدَّثَتْنِي جَدَّتِي أَنَّها سَمِعَتْ أَبَاهَا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَلَا يُؤْمِنُ بِاللَّهِ مَنْ لَا يُؤْمِنُ بِي وَلَا يُؤْمِنُ بِي مَنْ لَا يُحِبُّ الْأَنْصَارَ","id":"Telah menceritakan kepada kami [Haitsam bin Kharijah] telah bercerita kepada kami [Hafsh bin Maisarah] dari [Ibnu Harmalah] dari [Abu Tsifal Al Muzanni] bahwa ia mendengar [Rabah bin 'Abdur Rahman bin Huwaithib] berkata; telah bercerita kepadaku [nenekku] bahwa ia mendengar [ayahnya] berkata; aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidak ada shalat bagi yang tidak berwudhu, tidak ada wudhu bagi yang tidak menyebut nama Allah, tidak beriman orang yang tidak beriman denganku dan tidaklah beriman orang yang tidak mencintai kaum Anshar.\""},"3424":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ خُثَيْمٍ أَبُو مَعْمَرٍ الْهِلَالِيُّ حَدَّثَتْنِي جَدَّتِي رِبْعِيَّةُ ابْنَةُ عِيَاضٍ الْكِلَابِيَّةُ قَالَتْ سَمِعْتُ عَلِيًّا يَقُولُكُلُوا الرُّمَّانَ بِشَحْمِهِ فَإِنَّهُ دِبَاغُ الْمَعِدَةِ","id":"Telah menceritakan kepada kami [Sa'id bin Khutsaim Abu Ma'mar Al Hilali] telah bercerita kepadaku [nenekku, Rib'iyyah binti 'Iyadl Al Kilabiyyah] berkata; Aku mendengar ['Ali] berkata; Makanlah delima dengan kulitnya karena ia membersihkan lambung."},"3425":{"ar":"حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ صَبَّاحٍ عَنْ أَشْرَسَ قَالَسُئِلَ ابْنُ عَبَّاسٍ عَنْ الْمَدِّ وَالْجَزْرِ فَقَالَ إِنَّ مَلَكًا مُوَكَّلٌ بِقَامُوسِ الْبَحْرِ فَإِذَا وَضَعَ رِجْلَهُ فَاضَتْ وَإِذَا رَفَعَهَا غَاضَتْو قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ دِينَارٍ حَدَّثَنَا صَالِحُ بْنُ صَبَّاحٍ عَنْ أَبِيهِ عَنْ أَشْرَسَ عَنِ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Shabbah] dari [Asyras] berkata; Ditanya [Ibnu 'Abbas] tentang pasang surutnya air laut, ia menjawab: seorang malaikat ditugaskan untuk mengurus laut, bila ia meletakkan kakinya, air laut pasang dan bila menangkatnya air laut surut. Berkata Ahmad: telah bercerita kepadaku [Ibrahim bin Dinar] telah bercerita kepada kami [Shalih bin Shabbah] dari [ayahnya] dari [Asyras] dari [Ibnu 'Abbas] sepertinya."},"3426":{"ar":"حَدَّثَنَا سُفْيَانُ يَعْنِي ابْنَ عُيَيْنَةَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَأَنَّ مَرْيَمَ فَقَدَتْ عِيسَى عَلَيْهِ السَّلَام فَدَارَتْ بِطَلَبِهِ فَلَقِيَتْ حَائِكًا فَلَمْ يُرْشِدْهَا فَدَعَتْ عَلَيْهِ فَلَا تَزَالُ تَرَاهُ تَائِهًا فَلَقِيَتْ خَيَّاطًا فَأَرْشَدَهَا فَدَعَتْ لَهُ فَهُمْ يُؤْنَسُ إِلَيْهِمْ أَيْ يُجْلَسُ إِلَيْهِمْ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Musa bin Abu 'A`isyah] bahwa Maryam pernah kehilangan Isa 'Alaihis Salam, ia berkeliling mencarinya, ia bertemu tukang tenun namun tukang tenun itu tidak menunjukkannya. Maryam tiada henti memanggilnya dan melihatnya dalam keadaan bingung, kemudian Maryam bertemu dengan tukang jahit lalu ia menunjukkannya, maka ia Maryam mendoakannya dan ia pun ditemani banyak orang."},"3427":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا يُوسُفُ يَعْنِي ابْنَ صُهَيْبٍ عَنْ مُوسَى بْنِ أَبِي الْمُخْتَارِ عَنْ بِلَالٍ الْعَبْسِيِّ قَالَقَالَ حُذَيْفَةُ مَا أَخْبِيَةٌ بَعْدَ أَخْبِيَةٍ كَانَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَدْرٍ مَا يُدْفَعُ عَنْهُمْ مَا يُدْفَعُ عَنْ أَهْلِ هَذِهِ الْأَخْبِيَةِ وَلَا يُرِيدُ بِهِمْ قَوْمٌ سُوءًا إِلَّا أَتَاهُمْ مَا يَشْغَلُهُمْ عَنْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah bercerita kepada kami [Yusuf bin Shuhaib] dari [Musa bin Abu Al Mukhta] dari [Bilal Al 'Absi] berkata; berkata [Hudzaifah bin Al Yaman]: Tenda demi tenda (muslimin) yang dipimpin oleh Rasulullah Shallallahu 'alaihi wa salam saat perang badar, kesemuanya dijaga (Allah) sebagaimana terjaganya penghuninya, tidaklah sekelompok musuh menginginkan keburukan pada mereka melainkan Allah mendatangkan sesuatu yang mengalihkan perhatian mereka."},"3428":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ حُذَيْفَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَآنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَقَالَ هُوَ لَهُمْ فِي الدُّنْيَا وَلَنَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Syu'bah] dari [Al Hakam] dari ['Abdur Rahman bin Abu Laila] dari [Hudzaifah bin Al Yaman] berkata; Rasulullah Shallallahu 'alaihi wa salam melarang mengenakan sutera tebal, sutera tipis, wadah emas dan perak. Beliau bersabda: \"Semua itu untuk orang kafir di dunia dan untuk kita di akhirat.\""},"3429":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ حَبِيبِ بْنِ سُلَيْمٍ الْعَبْسِيِّ عَنْ بِلَالِ بْنِ يَحْيَى الْعَبْسِيِّ عَنْ حُذَيْفَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّعْيِ","id":"Telah menceritakan kepada kami [Waki'] dari [Habib bin Sulaim Al 'Absi] dari [Bilal bin Yahya Al 'Absi] dari [Hudzaifah bin Al Yaman] berkata; Rasulullah Shallallahu 'alaihi wa salam melarang meratap."},"3430":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى إِلَى فِرَاشِهِ قَالَ بِاسْمِكَ اللَّهُمَّ أَمُوتُ وَأَحْيَا وَإِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَمَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Sufyan] dari ['Abdul Malik bin 'Umair] dari [Rib'i bin Hirasy] dari [Hudzaifah] berkata; Bila hendak berbaring ditempat tidur, Rasulullah Shallallahu 'alaihi wa salam berdoa: \"Dengan namaMu ya Allah! Aku mati dan aku hidup.\" Dan bila bangun beliau berdoa: \"Segala puji bagi Allah yang menghidupkan kami setelah mematikan kami dan kepadaNya-lah tempat kembali.\""},"3431":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ قَالَ حَدَّثَنِي مَنْ لَمْ يَكْذِبْنِي يَعْنِي حُذَيْفَةَ قَالَلَقِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلُ عَلَيْهِ السَّلَام وَهُوَ عِنْدَ أَحْجَارِ الْمِرَاءِ فَقَالَ إِنَّ أُمَّتَكَ يَقْرَءُونَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَمَنْ قَرَأَ مِنْهُمْ عَلَى حَرْفٍ فَلْيَقْرَأْ كَمَا عَلِمَ وَلَا يَرْجِعْ عَنْهُ قَالَ أَبِي وَقَالَ ابْنُ مَهْدِيٍّ إِنَّ مِنْ أُمَّتِكَ الضَّعِيفَ فَمَنْ قَرَأَ عَلَى حَرْفٍ فَلَا يَتَحَوَّلْ مِنْهُ إِلَى غَيْرِهِ رَغْبَةً عَنْهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibrahim bin Muhajir] dari [Rib'i bin Hirasy] berkata; telah bercerita kepadaku orang yang tidak berdusta padaku, maksudnya [Hudzaifah bin Al Yaman] ia berkata; Jibril 'alaihis Salam menemui Nabi Shallallahu 'alaihi wa salam saat beliau berada di Ahjarul Mira`, Jibril berkata; Ummatmu membaca Al Quran dengan tujuh dialek, maka barangsiapa diantara mereka yang membaca dengan satu dialek, hendaklah membaca seperti yang telah ia ketahui dan tidak menghentikannya. Ayahku berkata dan berkata [Ibnu Mahdi]: Sesungguhnya diantara ummatmu ada yang lemah, maka barangsiapa yang membaca dengan satu dialek maka jangan beralih kepada yang lain karena tidak menyukainya."},"3432":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَامًا فَمَا تَرَكَ شَيْئًا يَكُونُ بَيْنَ يَدَيْ السَّاعَةِ إِلَّا ذَكَرَهُ فِي مَقَامِهِ ذَلِكَ حَفِظَهُ مَنْ حَفِظَهُ وَنَسِيَهُ مَنْ نَسِيَهُقَالَ حُذَيْفَةُ فَإِنِّي لَأَرَى أَشْيَاءَ قَدْ كُنْتُ نُسِّيتُهَا فَأَعْرِفُهَا كَمَا يَعْرِفُ الرَّجُلُ وَجْهَ الرَّجُلِ قَدْ كَانَ غَائِبًا عَنْهُ يَرَاهُ فَيَعْرِفُهُ وَقَالَ وَكِيعٌ مَرَّةً فَرَآهُ فَعَرَفَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah bin Al Yaman] berkata; Rasulullah Shallallahu 'alaihi wa salam berdiri ditengah-tengah kami, tidaklah tertinggal suatu hal pun yang ada di hadapan kiamat melainkan beliau pasti menyebutnya di tempat beliau itu, orang yang menghafalnya pasti menghafalnya dan orang yang melupakannya pasti melupakannya. Berkata Hudzaifah bin Al Yaman: aku tahu banyak hal yang dulu aku lupakan layaknya seseorang mengenali wajah orang lain yang lama pergi lalu melihatnya dan mengenalinya. Berkata Waki': Lalu melihatnya dan mengenalinya."},"3433":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مَوْلًى لِرِبْعِيٍّ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسًا فَقَالَ إِنِّي لَا أَدْرِي مَا قَدْرُ بَقَائِي فِيكُمْ فَاقْتَدُوا بِاللَّذَيْنِ مِنْ بَعْدِي وَأَشَارَ إِلَى أَبِي بَكْرٍ وَعُمَرَ وَتَمَسَّكُوا بِعَهْدِ عَمَّارٍ وَمَا حَدَّثَكُمْ ابْنُ مَسْعُودٍ فَصَدّ��قُوهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Abdul Malik bin 'Umair] dari [seorang budak milik Rib'i] dari [Rib'i] dari [Hudzaifah bin Al Yaman] berkata; Kami duduk didekat Nabi Shallallahu 'alaihi wa salam, beliau bersabda: \" aku tidak tahu seberapa lama aku bersama kalian, maka teladanilah dua orang sepeninggalku\" beliau menunjuk Abu Bakar dan 'Umar \"Berpegangteguhlah pada janji 'Ammar, dan yang disampaikan Ibnu Mas'ud kepada kalian benarkanlah.\""},"3434":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو الْعُمَيْسِ عَنْ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ عُتْبَةَ عَنِ ابْنٍ لِحُذَيْفَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَعَا لِرَجُلٍ أَصَابَتْهُ وَأَصَابَتْ وَلَدَهُ وَوَلَدَ وَلَدِهِ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Abu Al 'Umais] dari [Abu Bakar bin 'Umru bin 'Utbah] dari [Ibnu Hudzaifah] dari [ayahnya] bahwa Nabi Shallallahu 'alaihi wa salam mendoakan seseorang yang tertimpa musibah bersama anak dan cucunya."},"3435":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا رَزِينُ بْنُ حَبِيبٍ الْجُهَنِيُّ عَنْ أَبِي الرُّقَادِ الْعَبْسِيِّ عَنْ حُذَيْفَةَ قَالَإِنْ كَانَ الرَّجُلُ لَيَتَكَلَّمُ بِالْكَلِمَةِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَصِيرُ بِهَا مُنَافِقًا وَإِنِّي لَأَسْمَعُهَا مِنْ أَحَدِكُمْ الْيَوْمَ فِي الْمَجْلِسِ عَشْرَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Waki'] telah bercerita kepada kami [Razin bin Habib Al Juhani] dari [Abu Ar Ruqqad Al 'Absi] dari [Hudzaifah bin Al Yaman] berkata; 'Bila seseorang mengucapkan sepatah kata dimasa Nabi Shallallahu 'alaihi wa salam ia bisa menjadi munafik karenanya, saat ini aku mendengarnya dari salah seorang diantara kalian sepuluh kali dalam satu majlis.'"},"3436":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا أَبُو مَالِكٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَأَنَّهُ قَدِمَ مِنْ عِنْدِ عُمَرَ قَالَ لَمَّا جَلَسْنَا إِلَيْهِ أَمْسِ سَأَلَ أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ سَمِعَ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتَنِ فَقَالُوا نَحْنُ سَمِعْنَاهُ قَالَ لَعَلَّكُمْ تَعْنُونَ فِتْنَةَ الرَّجُلِ فِي أَهْلِهِ وَمَالِهِ قَالُوا أَجَلْ قَالَ لَسْتُ عَنْ تِلْكَ أَسْأَلُ تِلْكَ يُكَفِّرُهَا الصَّلَاةُ وَالصِّيَامُ وَالصَّدَقَةُ وَلَكِنْ أَيُّكُمْ سَمِعَ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتَنِ الَّتِي تَمُوجُ مَوْجَ الْبَحْرِ قَالَ فَأَمْسَكَ الْقَوْمُ وَظَنَنْتُ أَنَّهُ إِيَّايَ يُرِيدُ قُلْتُ أَنَا قَالَ لِي أَنْتَ لِلَّهِ أَبُوكَ قَالَ قُلْتُ تُعْرَضُ الْفِتَنُ عَلَى الْقُلُوبِ عَرْضَ الْحَصِيرِ فَأَيُّ قَلْبٍ أَنْكَرَهَا نُكِتَتْ فِيهِ نُكْتَةٌ بَيْضَاءُ وَأَيُّ قَلْبٍ أُشْرِبَهَا نُكِتَتْ فِيهِ نُكْتَةٌ سَوْدَاءُ حَتَّى يَصِيرَ الْقَلْبُ عَلَى قَلْبَيْنِ أَبْيَضَ مِثْلِ الصَّفَا لَا يَضُرُّهُ فِتْنَةٌ مَا دَامَتْ السَّمَوَاتُ وَالْأَرْضُ وَالْآخَرِ أَسْوَدَ مُرْبَدٍّ كَالْكُوزِ مُخْجِيًا وَأَمَالَ كَفَّهُ لَا يَعْرِفُ مَعْرُوفًا وَلَا يُنْكِرُ مُنْكَرًا إِلَّا مَا أُشْرِبَ مِنْ هَوَاهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah bercerita kepada kami [Abu Malik] dari [Rib'i bin Hirasy] dari [Hudzaifah bin Al Yaman] bahwa ia pulang dari kediaman 'Umar. Saat kami menghampirinya, ia ('Umar) bertanya kepada sahabat-sahabat Muhammad Shallallahu 'alaihi wa salam: Siapa diantara kalian yang pernah mendengar sabda Rasulullah Shallallahu 'alaihi wa salam tentang berbagai fitnah? Mereka berkata; Kami mendengarnya. Berkata Hudzaifah bin Al Yaman: Mungkin yang kalian maksudkan fitnah seseorang terhadap keluarga dan hartanya. Mereka berkata; Betul. Berkata Hudzaifah bin Al Yaman: Bukan itu yang aku tanyakan yang (dosanya) bisa dihapus dengan shalat, puasa dan sedekah, tapi siapa diantara kalian yang pernah mendengar sabda Rasulullah Shallallahu 'alaihi wa salam tentang berbagai fitnah yang bergelombang layaknya samudera. Mereka terdiam dan aku Hudzaifah bin Al Yaman mengira bahwa yang dituju adalah aku lalu aku menjawab: Aku. 'Umar berkata; Kamu, bagus. Aku Hudzaifah bin Al Yaman berkata; Fitnah dibentangkan dihati seperti dibentangkannya tikar, setiap hati yang mengingkarinya maka diberi satu titik putih dan setiap hatinya menyerapnya maka diberi satu titik hitam hingga hati pun menjadi dua macam; hati putih seperti benda jernih, fitnah tidak akan membahayakannya selama langit dan bumi masih ada, dan yang lainnya hati hitam berdebu seperti panci kotor -beliau memiringkan telapan tangan- ia tidak mengenal kebaikan dan tidak mengingkari kemungkaran kecuali sesuatu yang terserap dari hawa nafsunya.\""},"3437":{"ar":"سَمِعْتُهُ وَحْدِي حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنَ الْأَنْصَارِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةِ رَجُلٍ مِنْ الْأَنْصَارِ وَأَنَا غُلَامٌ مَعَ أَبِي فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حُفْرَةِ الْقَبْرِ فَجَعَلَ يُوصِي الْحَافِرَ وَيَقُولُ أَوْسِعْ مِنْ قِبَلِ الرَّأْسِ وَأَوْسِعْ مِنْ قِبَلِ الرِّجْلَيْنِ لَرُبَّ عَذْقٍ لَهُ فِي الْجَنَّةِ","id":"Aku (Ahmad) mendengarnya sendiri, Telah menceritakan kepada kami [Muhammad bin Fudhail] dari ['Ashim bin Kulaib] dari [ayahnya] dari [seseorang dari Anshar] berkata; Kami pergi bersama Rasulullah Shallallahu 'alaihi wa salam mengantarkan jenazah seseorang dari kaum Anshar, saat itu aku masih kecil, aku bersama ayahku. Rasulullah Shallallahu 'alaihi wa salam duduk ditepi makam, beliau berpesan kepada penggali kubur: \"Lebarkan bagian kepala dan kedua kaki, semoga menjadi dahan baginya disurga.\""},"3438":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ الدَّالَانِيُّ عَنْ أَبِي الْعَلَاءِ الْأَوْدِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِذَا اجْتَمَعَ الدَّاعِيَانِ فَأَجِبْ أَقْرَبَهُمَا بَابًا فَإِنَّ أَقْرَبَهُمَا بَابًا أَقْرَبُهُمَا جِوَارًا فَإِذَا سَبَقَ أَحَدُهُمَا فَأَجِبْ الَّذِي سَبَقَ","id":"Telah menceritakan kepada kami ['Abdus Salam bin Harb] telah menceritakan kepadaku [Yazid bin 'Abdur Rahman Ad Dallani] dari [Abu Al 'Alla` Al Audi] dari [Humaid bin 'Abdur Rahman] dari [seorang] sahabat Nabi ShallallahuAlaihiWasallam berkata; Bila dua orang mengundang maka penuhilah yang pintunya lebih dekat karena yang pintunya paling dekat diantara keduanya adalah tetangga yang lebih dekat dan bila salah satu dari keduanya mendahului yang lain maka penuhilah undangan yang lebih dahulu mengundang.\""},"3439":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَعَبْدُ الرَّزَّاقِ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُئِيَ بِالْعَرْجِ وَهُوَ يَصُبُّ عَلَى رَأْسِهِ مَاءً وَهُوَ صَائِمٌ مِنْ الْحَرِّ أَوْ مِنْ الْعَطَشِ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dan ['Abdur Razzaq] dari [Malik] dari [Sumai] dari [Abu Bakar bin 'Abdur Rahman] dari [seorang] sahabat Nabi shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam terlihat lemah, beliau mengguyurkan air diatas kepala saat beliau puasa karena panas atau haus."},"3440":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّرَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرْنِي بِكَلِمَاتٍ أَعِيشُ بِهِنَّ وَلَا تُكْثِرْ عَلَيَّ فَأَنْسَى قَالَ اجْتَنِبْ الْغَضَبَ ثُمَّ أَعَادَ عَلَيْهِ فَقَالَ اجْتَنِبْ الْغَضَبَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Humaid bin 'Abdur Rahman bin 'Auf] dari [seorang] sahabat Nabi shallallahu 'alaihi wasallam bahwa seseorang berkata kepada Nabi shallallahu 'alaihi wasallam: Beritahukanlah kalimat-kalimat padaku yang dengannya aku hidup dan janganlah tuan memperbanyaknya hingga aku lupa. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Jauhilah marah.\" Orang itu mengulangi lagi lalu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Jauhilah marah.\""},"3441":{"ar":"حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ أَخْبَرَنَا سُفْيَانُ وَزَائِدَةُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنِ الْحَكَمِ بْنِ سُفْيَانَ أَوْ سُفْيَانَ بْنِ الْحَكَمِقَالَ عَبْدُ الرَّحْمَنِ فِي حَدِيثِهِ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ وَتَوَضَّأَ وَنَضَحَ فَرْجَهُ بِالْمَاءِ وَقَالَ يَحْيَى فِي حَدِيثِهِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ وَنَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Sufyan] dan ['Abdur Rahman bin Mahdi] telah mengabarkan kepada kami [Sufyan] dan [Za`idah] dari [Manshur] dari [Mujahid] dari Al Hakam bin Sufyan atau [Sufyan bin Al Hakam] berkata ['Abdur Rahman] dalam haditsnya: Aku melihat Rasulullah Shallallahu 'alaihi wa salam buang air kecil lalu berwudhu, beliau memercik-mercikkan air di kemaluan beliau. Berkata [Yahya] dalam haditsnya: Bahwa Nabi Shallallahu 'alaihi wa salam buang air kecil dan beliau memercik-mercikkan kemaluan beliau."},"3442":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ مِنْ ثَقِيفَ وَهُوَ الْحَكَمُ بْنُ سُفْيَانَ أَوْ سُفْيَانُ بْنُ الْحَكَمِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ نَضَحَ فَرْجَهُحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ قَالَ سَأَلْتُ أَهْلَ الْحَكَمِ بْنِ سُفْيَانَ فَذَكَرُوا أَنَّهُ لَمْ يُدْرِكْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عَبْد الرَّحْمَنِ وَرَوَاهُ شُعْبَةُ وَوُهَيْبٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنِ الْحَكَمِ بْنِ سُفْيَانَ عَنْ أَبِيهِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ غَيْرُهُمَا عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنِ الْحَكَمِ بْنِ سُفْيَانَ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari seseorang dari Tsaqif, [Al Hakam bin Sufyan] atau Sufyan bin Al Hakam berkata; Aku melihat Rasulullah Shallallahu 'alaihi wa salam buang air kecil, beliau memercik-mercikkan kemaluan beliau. Telah menceritakan kepada kami Aswad bin 'Amir Telah menceritakan kepada kami Syarik berkata; Aku bertanya pada keluarga Al Hakam bin Sufyan, mereka menyatakan bahwa Al Hakam tidak pernah bertemu Nabi Shallallahu 'alaihi wa salam. Berkata Abu 'Abdur Rahman dan diriwayatkan oleh [Syu'bah] dan [Wuhaib] dari [Manshur] dari [Mujahid] dari [Al Hakam bin Sufyan] dari [ayahnya] bahwa ia melihat Rasulullah Shallallahu 'alaihi wa salam. Berkata [selain keduanya] dari [Manshur] dari [Mujahid] dari [Al Hakam bin Sufyan] berkata; Aku melihat Nabi shallallahu 'alaihi wasallam. Ia menyebutkannya."},"3443":{"ar":"و قَالَ عَبْد اللَّهِ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنِ الْحَكَمِ بْنِ سُفْيَانَ أَوْ سُفْيَانَ بْنِ الْحَكَمِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ نَضَحَ فَرْجَهُ","id":"Berkata 'Abdullah: Aku menemukan dalam kitab ayahku dengan tulisan tangannya: Telah menceritakan kepada kami [Ya'la bin 'Ubaid] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari Al Hakam bin Sufyan atau [Sufyan bin Al Hakam] bahwa Nabi Shallallahu 'alaihi wa salam buang air kecil kemudian beliau mermecik-mercikkan kemaluan beliau."},"3444":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ مِنْ ثَقِيفَ وَهُوَ الْحَكَمُ بْنُ سُفْيَانَ أَوْ سُفْيَانُ بْنُ الْحَكَمِ قَ��لَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ نَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari seseorang dari Tsaqif, Al Hakam bin Sufyan atau [Sufyan bin Al Hakam] berkata; Aku melihat Nabi Shallallahu 'alaihi wa salam buang air kecil kemudian beliau memermeciki kemaluan beliau."},"3445":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ قَالَدَخَلْتُ أَنَا وَيَحْيَى بْنُ جَعْدَةَ عَلَى رَجُلٍ مِنَ الْأَنْصَارِ مِنْ أَصْحَابِ الرَّسُولِ قَالَ ذَكَرُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْلَاةً لِبَنِي عَبْدِ الْمُطَّلِبِ فَقَالَ إِنَّهَا تَقُومُ اللَّيْلَ وَتَصُومُ النَّهَارَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكِنِّي أَنَا أَنَامُ وَأُصَلِّي وَأَصُومُ وَأُفْطِرُ فَمَنْ اقْتَدَى بِي فَهُوَ مِنِّي وَمَنْ رَغِبَ عَنْ سُنَّتِي فَلَيْسَ مِنِّي إِنَّ لِكُلِّ عَمَلٍ شِرَّةً ثُمَّ فَتْرَةً فَمَنْ كَانَتْ فَتْرَتُهُ إِلَى بِدْعَةٍ فَقَدْ ضَلَّ وَمَنْ كَانَتْ فَتْرَتُهُ إِلَى سُنَّةٍ فَقَدْ اهْتَدَى","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] berkata; Aku dan Yahya bin Ja'dah bertamu ke kediaman [salah seorang Anshar], seorang sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata; Mereka menyebut seorang budak milik wanita milik Bani 'Abdul Muththalib didekat Rasulullah Shallallahu 'alaihi wa salam kemudian beliau bersabda: \" ia shalat malam dan puasa disiang harinya.\" Kemudian Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tapi aku kadang tidur dan kadang shalat (malam), kadang puasa dan kadang berbuka, maka barangsiapa yang mengikutiku maka ia termasuk golonganku dan barangsiapa yang membenci sunnahku berarti tidak termasuk golonganku, setiap amal itu ada saat-saat rajinnya dan ada saat jedanya, maka barangsiapa yang jedanya menuju bid'ah maka ia sesat dan barangsiapa jedanya menuju sunnah maka ia mendapat petunjuk.\""},"3446":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَلَمَةَ الْخُزَاعِيِّ عَنْ عَمِّهِ قَالَغَدَوْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَبِيحَةَ عَاشُورَاءَ وَقَدْ تَغَدَّيْنَا فَقَالَ أَصُمْتُمْ هَذَا الْيَوْمَ قَالَ قُلْنَا قَدْ تَغَدَّيْنَا قَالَ فَأَتِمُّوا بَقِيَّةَ يَوْمِكُمْ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Sa'id bin Abu 'Urubah] dari [Qotadah] dari ['Abdur Rahman bin Salamah Al Khuza`i] dari [pamannya] berkata; Pada pagi hari kami pergi menemui Rasulullah Shallallahu 'alaihi wa salam di hari 'Asyura` dan kami sudah makan pagi, beliau bertanya: \"Apa kalian puasa hari ini?\" kami menjawab: Kami sudah sarapan. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sempurnakanlah sisa hari kalian.\""},"3447":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَوْفٌ عَنْ حَسْنَاءَ بِنْتِ مُعَاوِيَةَ مِنْ بَنِي صُرَيْمٍ قَالَتْ حَدَّثَنَا عَمِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ فِي الْجَنَّةِ قَالَ النَّبِيُّ فِي الْجَنَّةِ وَالشَّهِيدُ فِي الْجَنَّةِ وَالْمَوْلُودُ وَالْوَلِيدَةُ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami ['Auf] dari [Hasna` binti Mu'awiyah], dari Bani Shuraim berkata; telah menceritakan kepa kami [pamanku] berkata; Aku berkata; Wahai Rasulullah! Siapa yang ada disurga? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Nabi di surga, orang mati syahid disurga, bayi lelaki dan bayi perempuan (disurga).\""},"3448":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ ذِي مِخْمَرٍ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَيُصَالِحُكُمْ الرُّومُ صُلْحًا آمِنًا ثُمَّ تَغْزُوهُمْ غَزْوًا فَتُنْصَرُونَ وَتَسْلَمُونَ وَتَغْنَمُونَ ثُمَّ تَنْصَرِفُونَ حَتَّى تَنْزِلُونَ بِمَرْجٍ ذِي تُلُولٍ فَيَرْفَعُ رَجُلٌ مِنْ النَّصْرَانِيَّةِ صَلِيبًا فَيَقُولُ غَلَبَ الصَّلِيبُ فَيَغْضَبُ رَجُلٌ مِنْ الْمُسْلِمِينَ فَيَقُومُ إِلَيْهِ فَيَدُقُّهُ فَعِنْدَ ذَلِكَ يَغْدُرُ الرُّومُ وَيَجْتَمِعُونَ لِلْمَلْحَمَةِ وَقَالَ رَوْحٌ مَرَّةً وَتَسْلَمُونَ وَتَغْنَمُونَ وَتُقِيمُونَ ثُمَّ تَنْصَرِفُونَ","id":"Telah menceritakan kami [Rauh] Telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Khalid bin Ma'dan] dari [Dzi Mikhmar], seorang sahabat Nabi Shallallahu 'alaihi wa salam berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Romawi akan berdamai dengan kalian dengan aman kemudian kalian akan memerangi mereka dan mereka adalah musuh lalu kalian menang, aman dan mendapat harta rampasan perang kemudian kalian pergi hingga singgah di tanah lapang yang berbukit, kemudian seorang nasrani menegakkan salib dan berkata; Salib menang, kemudian seseorang dari kalangan kaum muslimin marah lalu menghampirinya dan memukulnya, saat itu Romawi berkhianat dan mereka bersatu untuk menyerang.\" Berkata Rauh: \"Kalian selamat, mendapat harta rampasan perang, kalian tinggal kemudian pulang.\""},"3449":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مُجَالِدُ بْنُ سَعِيدٍ حَدَّثَنِي الشَّعْبِيُّ قَالَسَأَلْتُ ابْنَ عُمَرَ قُلْتُ الْجَزُورُ وَالْبَقَرَةُ تُجْزِئُ عَنْ سَبْعَةٍ قَالَ قَالَ يَا شَعْبِيُّ وَلَهَا سَبْعَةُ أَنْفُسٍ قَالَ قُلْتُ إِنَّ أَصْحَابَ مُحَمَّدٍ يَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَنَّ الْجَزُورَ وَالْبَقَرَةَ عَنْ سَبْعَةٍقَالَ فَقَالَ ابْنُ عُمَرَ لِرَجُلٍ أَكَذَاكَ يَا فُلَانُ قَالَ نَعَمْ قَالَ مَا شَعَرْتَ بِهَذَا","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] Telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] Telah menceritakan kepada kami [Mujalid bin Sa'id] telah menceritakan kepadaku [Asy Sya'bi] berkata; Aku bertanya kepada Ibnu 'Umar aku berkata; Unta dan sapi mencukupi tujuh orang. Berkata Ibnu 'Abbas: Hai Asy Sya'bi! Ia memiliki tujuh nyawa. Aku (Asy Sya'bi) Berkata; Para [sahabat Muhammad] mengira bahwa Rasulullah Shallallahu 'alaihi wa salam menyontohkan unta dan sapi untuk tujuh orang. Berkata Asy Sya'bi: Kemudian Ibnu 'Umar berkata kepada seseorang: Apa seperti itu hai Fulan? Ia menjawab: Ya. Berkata Ibnu 'Umar: Kau tidak merasa seperti itu."},"3450":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ بْنِ يَزِيدَ بْنِ رُكَانَةَ أَنَّ خَالَتَهُ أُخْتَ مَسْعُودِ ابْنِ الْعَجْمَاءِ حَدَّثَتْهُ أَنَّ أَبَاهَاقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ قَطِيفَةً يُفْدِيهَا يَعْنِي بِأَرْبَعِينَ أُوقِيَّةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ تُطَهَّرَ خَيْرٌ لَهَا فَأَمَرَ بِهَا فَقُطِعَتْ يَدُهَا وَهِيَ مِنْ بَنِي عَبْدِ الْأَسَدِ","id":"Telah menceritakan kepada kami [Yunus] Telah menceritakan kepada kami [Laits] dari [Yazid bin Abu Hubaib] dari [Muhammad bin Ishaq] dari [Muhammad bin Thalhah bin Yazid bin Rukanah] bahwa bibinya, [saudarinya Mas'ud bin Al 'Ajma`] bercerita kepadanya bahwa [ayahnya] berkata kepada Rasulullah Shallallahu 'alaihi wa salam tentang wanita dari Makhzumi yang mencuri kain sutera yang ditebus empatpuluh uqiyah, Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bahwa ia disucikan itu lebih baik baginya.\" Kemudian tangan wanita itu potong, ia berasal dari Bani 'Abdul Asad."},"3451":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا يَزِيدُ بْنُ عَمْرٍو الْمَعَافِرِيُّ عَنْ رَجُلٍ مِنْ بَنِي غِفَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَحْلِقْ عَانَتَهُ وَيُقَلِّمْ أَظْفَارَهُ وَيَجُزَّ شَارِبَهُ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Hasan] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Yazid bin 'Amru Al Ma'afiri] dari [seseorang dari Bani Ghifar] bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa tidak memotong bulu kemaluan, kuku dan kumisnya maka tidak termasuk golonganku.\" "},"3452":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَلِيدِ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ مُحَمَّدِ بْنِ أَبِي عَائِشَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ مُحَمَّدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكُمْ تَقْرَءُونَ وَالْإِمَامُ يَقْرَأُ قَالَهَا ثَلَاثًا قَالُوا إِنَّا لَنَفْعَلُ ذَلِكَ قَالَ فَلَا تَفْعَلُوا إِلَّا أَنْ يَقْرَأَ أَحَدُكُمْ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami ['Abdullah bin Al Walid Al 'Adani] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Khalid Al Hadzdaz`] dari [Abu Qilabah] dari [Muhammad bin Abu 'A`isyah] dari [seorang sahabat] Muhammad berkata; Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sepertinya kalian membaca saat imam membaca?\"beliau mengucapkannya tiga kali, mereka berkata; kami melakukannya. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Jangan kalian lakukan kecuali bila salah seorang diantara kalian membaca Al Faatihah.\""},"3453":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَطَاءٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا مَنْ كَانَ يُقْرِئُنَا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْكَانُوا يَقْتَرِئُونَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ آيَاتٍ فَلَا يَأْخُذُونَ فِي الْعَشْرِ الْأُخْرَى حَتَّى يَعْلَمُوا مَا فِي هَذِهِ مِنْ الْعِلْمِ وَالْعَمَلِ قَالُوا فَعَلِمْنَا الْعِلْمَ وَالْعَمَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Fudhail] dari ['Atho`] dari [Abu 'Abdur Rahman] berkata; Telah menceritakan kepada kami [seorang sahabat] Nabi Shallallahu 'alaihi wa salam yang pernah mengajari bacaan Al Quran pada kami, bahwa mereka mempelajari sepuluh ayat dari Rasulullah Shallallahu 'alaihi wa salam, mereka tidak mempelajari sepuluh ayat lain hingga mereka mengetahui ilmu dan amal yang ada didalamnya, kami mengetahui ilmu dan amal."},"3454":{"ar":"حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ حَرْبِ بْنِ هِلَالٍ الثَّقَفِيِّ عَنْ أَبِي أُمِّهِ رَجُلٍ مِنْ تَغْلِبَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ عَلَى الْمُسْلِمِينَ عُشُورٌ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى","id":"Telah menceritakan kepada kami [Jarir] dari ['Atho` bin As Sa`ib] dari [Harb bin Hilal Ats Tsaqafi] dari [Abu Ummah, seseorang dari Taghlib] bahwa ia mendeng ar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Kaum muslimin tidak berkewajiban membayar pajak, yang wajib membayar pajak adalah yahudi dan nasrani.\""},"3455":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنِ ابْنِ عَبَّاسٍ قَالَ كُنْتُ أَقُولُ فِي أَوْلَادِ الْمُشْرِكِينَ هُمْ مِنْهُمْ فَحَدَّثَنِي رَجُلٌ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيتُهُ فَحَدَّثَنِيعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ رَبُّهُمْ أَعْلَمُ بِهِمْ هُوَ خَلَقَهُمْ وَهُوَ أَعْلَمُ بِهِمْ وَبِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] Telah menceritakan kepada kami [Khalid Al Hadzdaz`] dari ['Ammar bin Abu 'Ammar] dari [Ibnu 'Abbas] berkata; Dulu aku mengatakan bahwa anak-anak kaum musyrik termasuk golongan mereka, lalu [seseorang] bercerita kepadaku dari sahabat Nabi Shallallahu 'alaihi wa salam bercerita, aku menemuinya lalu ia bercerita dari Nabi Shallallahu 'alaihi wa salam bahwa beliau bersabda: \"Rabb mereka lebih tahu tentang mereka, Dia yang menciptakan mereka, Dia lebih tahu tentang mereka dan apa yang mereka lakukan.\""},"3456":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي حَجَّاجٌ الصَّوّ��افُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنِ الْحَضْرَمِيِّ بْنِ لَاحِقٍ عَنْ رَجُلٍ مِنَ الْأَنْصَارِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَجَدَ أَحَدُكُمْ الْقَمْلَةَ فِي ثَوْبِهِ فَلْيَصُرَّهَا وَلَا يُلْقِيهَا فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Hajjaj Ash Shawwaf] dari [Yahya bin Abu Katsir] dari [Al Hadhrami bin Lahiq] dari [seorang Anshar] bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bila salah seorang diantara kalian menemukan kutu di bajunya hendaklah dibuang dan jangan dibuang di masjid.\""},"3457":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْنَاهُ مِنَ الْأَعْمَشِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَشُقُّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ مَعَ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; Kami mendengarnya dari [Al A'masy] telah menceritakan kepadaku ['Abdullah bin Yasar] dari ['Abdur Rahman bin Abu Laila] dari [seorang sahabat] Nabi shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam bersabda: \"Andai aku tidak memberatkan ummatku pasti aku perintahkan mereka bersiwak setiap hendak shalat.\""},"3458":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ بَعْدِكُمْ أَوْ إِنَّ مِنْ وَرَائِكُمْ الْكَذَّابَ الْمُضِلَّ وَإِنَّ رَأْسَهُ مِنْ وَرَائِهِ حُبُكٌ حُبُكٌ وَإِنَّهُ سَيَقُولُ أَنَا رَبُّكُمْ فَمَنْ قَالَ كَذَبْتَ لَسْتَ رَبَّنَا وَلَكِنَّ اللَّهَ رَبُّنَا وَعَلَيْهِ تَوَكَّلْنَا وَإِلَيْهِ أَنَبْنَا وَنَعُوذُ بِاللَّهِ مِنْكَ قَالَ فَلَا سَبِيلَ لَهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [seorang sahabat] Nabi Shallallahu 'alaihi wa salam dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sepeninggal kalian atau dibelakang kalian ada orang yang sangat pendusta dan menyesatkan, rambutnya ikal dan ia akan berkata; Aku Rabb kalian. Barangsiapa yang berkata; Kau dusta, kau bukan Rabb kami tapi Allah Rabb kami, padaNya kami bertawakal dan kepadaNya kami kembali, kami berlindung kepada Allah darimu, maka (Dajjal) tidak bisa menguasainya.\""},"3459":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا يُونُسُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ قَالَجَلَسْتُ إِلَى شَيْخٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ الْكُوفَةِ فَحَدَّثَنِي فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى اللَّهِ وَاسْتَغْفِرُوهُ فَإِنِّي أَتُوبُ إِلَى اللَّهِ وَأَسْتَغْفِرُهُ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ فَقُلْتُ اللَّهُمَّ إِنِّي أَسْتَغْفِرُكَ اثْنَتَانِ قَالَ هُوَ مَا أَقُولُ لَكَ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Yunus] dari [Humaid bin Hilal] dari [Abu Burdah] berkata; Aku menemani seorang tua, [salah seorang sahabat] Nabi Shallallahu 'alaihi wa salam di masjid Kufah, ia bercerita kepadaku, ia berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda atau Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Wahai sekalian manusia! Bertaubatlah kepada Allah dan memintalah ampunan padaNya, karena aku bertaubat dan meminta ampunan kepada Allah seratus kali dalam sehari.\" Lalu aku (Abu Burdah) berkata; Ya Allah! aku meminta ampunan kepadaMu dua kali. Sahabat itu berkata; Itu yang aku katakan padamu."},"3460":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ حَدَّثَنِي مَنْسَمِعَ خُطْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَسَطِ أَيَّامِ التَّشْرِيقِ فَقَالَ يَا أَيُّهَا النَّاسُ أَلَا إِنَّ رَبَّكُمْ وَاحِدٌ وَإِنَّ أَبَاكُمْ وَاحِدٌ أَلَا لَا فَضْلَ لِعَرَبِيٍّ عَلَى أَعْجَمِيٍّ وَلَا لِعَجَمِيٍّ عَلَى عَرَبِيٍّ وَلَا لِأَحْمَرَ عَلَى أَسْوَدَ وَلَا أَسْوَدَ عَلَى أَحْمَرَ إِلَّا بِالتَّقْوَى أَبَلَّغْتُ قَالُوا بَلَّغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أَيُّ يَوْمٍ هَذَا قَالُوا يَوْمٌ حَرَامٌ ثُمَّ قَالَ أَيُّ شَهْرٍ هَذَا قَالُوا شَهْرٌ حَرَامٌ قَالَ ثُمَّ قَالَ أَيُّ بَلَدٍ هَذَا قَالُوا بَلَدٌ حَرَامٌ قَالَ فَإِنَّ اللَّهَ قَدْ حَرَّمَ بَيْنَكُمْ دِمَاءَكُمْ وَأَمْوَالَكُمْ قَالَ وَلَا أَدْرِي قَالَ أَوْ أَعْرَاضَكُمْ أَمْ لَا كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَبَلَّغْتُ قَالُوا بَلَّغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu Nadhrah] telah menceritakan kepadaku [orang] yang pernah mendengar khutbah Rasulullah Shallallahu 'alaihi wa salam ditengah-tengah hari tasyriq, beliau bersabda: \"Wahai sekalian manusia! Rabb kalian satu, dan ayah kalian satu, ingat! Tidak ada kelebihan bagi orang arab atas orang ajam dan bagi orang ajam atas orang arab, tidak ada kelebihan bagi orang berkulit merah atas orang berkulit hitam, bagi orang berkulit hitam atas orang berkulit merah kecuali dengan ketakwaan. Apa aku sudah menyampaikan?\" mereka menjawab: Rasulullah Shallallahu 'alaihi wa salam telah menyampaikan. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hari apa ini?\" mereka menjawab: Hari haram. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bulan apa ini?\" mereka menjawab: Bulan haram. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tanah apa ini?\" mereka menjawab: Tanah haram. Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Allah mengharamkan darah dan harta kalian diantara kalian -aku (Abu Nadhrah) Berkata; Aku tidak tahu apakah beliau menyebut kehormatan atau tidak- seperti haramnya hari kalian ini, di bulan ini dan di tanah ini.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Apa aku sudah menyampaikan?\" mereka menjawab: Rasulullah Shallallahu 'alaihi wa salam telah menyampaikan. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hendaklah yang hadir menyampaikan kepada yang tidak hadir.\""},"3461":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ قَالَكَانَ مَرْثَدُ بْنُ عَبْدِ اللَّهِ لَا يَجِيءُ إِلَى الْمَسْجِدِ إِلَّا وَمَعَهُ شَيْءٌ يَتَصَدَّقُ بِهِ قَالَ فَجَاءَ ذَاتَ يَوْمٍ إِلَى الْمَسْجِدِ وَمَعَهُ بَصَلٌ فَقُلْتُ لَهُ أَبَا الْخَيْرِ مَا تُرِيدُ إِلَى هَذَا يُنْتِنُ عَلَيْكَ ثَوْبَكَ قَالَ يَا ابْنَ أَخِي إِنَّهُ وَاللَّهِ مَا كَانَ فِي مَنْزِلِي شَيْءٌ أَتَصَدَّقُ بِهِ غَيْرُهُ إِنَّهُ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ظِلُّ الْمُؤْمِنِ يَوْمَ الْقِيَامَةِ صَدَقَتُهُ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] berkata; tidaklah [Murtsid bin 'Abdullah] datang ke masjid melainkan pasti membawa sesuatu untuk disedekahkan. Pada suatu hari ia datang ke masjid membawa bawang merah. Aku (Yazid) Berkata padanya: Hai Abu Al Khair! Mau kau apakan bawang merah itu, bawang itu akan membuat bajumu berbau tidak sedap. Ia (Murstid) Berkata; Hai keponakanku! Demi Allah, dirumahku tidak ada apa pun untuk aku sedekahkan selain ini. Telah menceritakan kepadaku [seorang sahabat] Rasulullah Shallallahu 'alaihi wa salam dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Naungan orang mu`min pada hari kiamat adalah sedekahnya.\""},"3462":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ عَرْفَجَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُذَكَرَ رَمَضَانَ فَقَالَ تُفْتَحُ فِيهِ أَبْوَابُ الْجَنَّةِ وَتُغْلَقُ فِيهِ أَبْوَابُ النَّارِ وَتُصَفَّدُ فِيهِ الشَّيَاطِينُ وَيُنَادِي فِيهِ مُنَادٍ كُلَّ لَيْلَةٍ يَا بَاغِيَ الْخَيْرِ هَلُمَّ وَيَا بَاغِيَ الشَّرِّ أَقْصِرْ حَتَّى يَنْقَضِيَ رَمَضَانُ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami ['Atho` bin As Sa`ib] dari ['Arfajah] dari [salah seorang] sahabat Nabi Shallallahu 'alaihi wa salam bahwa beliau menyebut-nyebut ramadhan, beliau bersabda: \"Saat itu pintu-pintu surga dibuka, pintu-pintu neraka ditutup, setan-setan dibelenggu dan setiap malamnya ada yang menyerukan: Wahai pencari kebaikan kemarilah dan wahai pencari keburukan berhentilah, hingga ramadlan berakhir.\""},"3463":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي صَخْرٍ الْعُقَيْلِيِّ حَدَّثَنِي رَجُلٌ مِنَ الْأَعْرَابِ قَالَجَلَبْتُ جَلُوبَةً إِلَى الْمَدِينَةِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغْتُ مِنْ بَيْعَتِي قُلْتُ لَأَلْقَيَنَّ هَذَا الرَّجُلَ فَلَأَسْمَعَنَّ مِنْهُ قَالَ فَتَلَقَّانِي بَيْنَ أَبِي بَكْرٍ وَعُمَرَ يَمْشُونَ فَتَبِعْتُهُمْ فِي أَقْفَائِهِمْ حَتَّى أَتَوْا عَلَى رَجُلٍ مِنْ الْيَهُودِ نَاشِرًا التَّوْرَاةَ يَقْرَؤُهَا يُعَزِّي بِهَا نَفْسَهُ عَلَى ابْنٍ لَهُ فِي الْمَوْتِ كَأَحْسَنِ الْفِتْيَانِ وَأَجْمَلِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْشُدُكَ بِالَّذِي أَنْزَلَ التَّوْرَاةَ هَلْ تَجِدُ فِي كِتَابِكَ ذَا صِفَتِي وَمَخْرَجِي فَقَالَ بِرَأْسِهِ هَكَذَا أَيْ لَا فَقَالَ ابْنُهُ إِنِّي وَالَّذِي أَنْزَلَ التَّوْرَاةَ إِنَّا لَنَجِدُ فِي كِتَابِنَا صِفَتَكَ وَمَخْرَجَكَ وَأَشْهَدُ أَنَّ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّكَ رَسُولُ اللَّهِ فَقَالَ أَقِيمُوا الْيَهُودَ عَنْ أَخِيكُمْ ثُمَّ وَلِيَ كَفَنَهُ وَحَنَّطَهُ وَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Isma'il] dari [Al Jurairi] dari [Abu Shakr Al 'Uqaili] telah menceritakan kepadaku [seorang badui] ia berkata; Aku membawa barang ke Madinah dimasa hidup Rasulullah Shallallahu 'alaihi wa salam, seusai berjual beli, aku berkata; Aku akan menemui orang itu dan aku akan mendengarnya. Ia menemuiku diantara Abu Bakar dan 'Umar, mereka berjalan lalu aku mengikuti mereka dari belakang hingga mereka menemui seorang yahudi yang membuka taurat, orang itu membacanya untuk menghibur diri atas meninggalnya seorang putranya, putranya adalah pemuda yang tampan, lalu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku bersumpah padamu dengan Yang menurunkan taurat, apakah kau menemukan sifatku dan kemunculanku dikitab itu? Orang itu dengan isyarat kepala menjawab: Tidak. Anak orang itu berkata; Demi Yang menurunkan taurat, kami menemukan sifatmu dan kemunculanmu dalam kitab kami, aku bersaksi bahwa tidak ada Ilah (yang haq) kecuali Allah dan engkau adalah utusan Allah. Lalu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dirikan orang yahudi itu dari saudara kalian.\" Kemudian Rasulullah Shallallahu 'alaihi wa salam mengkafani, memberinya wewangian dan menshalatinya."},"3464":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنِ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عُقْبَةَ بْنِ أَوْسٍ وَقَالَ إِسْمَاعِيلُ مَرَّةً يَعْقُوبُ بْنُ أَوْسٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْفَتْحِ وَقَالَ مَرَّةً يَوْمَ فَتْحِ مَكَّةَ فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ صَدَقَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ أَلَا إِنَّ كُلَّ مَأْثُرَةٍ تُعَدُّ وَتُدَّعَى وَدَمٍ وَمَالٍ تَحْتَ قَدَمَيَّ هَاتَيْنِ إِلَّا سِدَانَةَ الْبَيْتِ أَوْ سِقَايَةَ الْحَاجِّ أَلَا وَإِنَّ قَتِيلَ خَطَإِ الْعَمْدِ قَالَ خَالِدٌ أَوْ قَالَ قَتِ��لُ الْخَطَإِ شِبْهِ الْعَمْدِ قَتِيلُ السَّوْطِ وَالْعَصَا مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Al Qasim bin Rabi'ah] dari ['Uqbah bin Aus] dan berkata Isma'il: Ya'qub bin Aus dari [seorang sahabat] Nabi Shallallahu 'alaihi wa salam berkata; Rasulullah Shallallahu 'alaihi wa salam berkhutbah saat penaklukkan Makkah, beliau bersabda: \"Tidak ada ilah (yang haq) kecuali Allah semata, Ia memenuhi janjiNya, menolong hambaNya, dan menghancurleburkan pasukan musuh. Ingatlah bahwa semua kebanggaan jahiliyah yang selama ini diagung-agungkan dan dibangga-banggakan, juga semua darah dan harta jahiliyah, harus ditumpas dibawah dua telapak kakiku ini, kecuali kepengurusan baitullah dan pemberian minum orang-orang haji, ingat! Korban pembunuhan secara sengaja -Khalid mengatakan; atau dia mengatakan korban pembunuhan setengah sengaja-- sengaja itu hampir sama dengan pembunuhan sengaja, korban karena cambuk dan tongkat dendanya seratus ekor onta, empatpuluh diantaranya bunting.\" "},"3465":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ الْمُحَرِّرِ بْنِ أَبِي هُرَيْرَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُصِيبَ بِشَيْءٍ فِي جَسَدِهِ فَتَرَكَهُ لِلَّهِ كَانَ كَفَّارَةً لَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Mujalid] dari ['Amir] dari [Al Muharrar bin Abu Hurairah] dari [seorang sahabat] Nabi Shallallahu 'alaihi wa salam dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang jasadnya tertimpa sesuatu kemudian dibiarkan karena Allah maka itu sebagai penghapus (dosa) baginya.\""},"3466":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي إِبْرَاهِيمَ الَأَشْهَلِيِّ عَنْ أَبِيهِ أَنَّهُ أَتَاهُ فَحَدَّثَهُ أَوْ أَخْبَرَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الصَّلَاةِ عَلَى الْمَيِّتِ اللَّهُمَّ اغْفِرْ لِحَيِّنَا وَمَيِّتِنَا وَشَاهِدِنَا وَغَائِبِنَا وَذَكَرِنَا وَأُنْثَانَا وَصَغِيرِنَا وَكَبِيرِنَا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] Telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Ibrahim Al Asyhali] dari [ayahnya] bahwa ia mendatanginya lalu bercerita atau memberi khabar padanya bahwa ia mendengar Nabi Shallallahu 'alaihi wa salam berdoa saat shalat jenazah: \"Ya Allah! Ampunilah ampunilah yang masih hidup diantara kami, yang sudah meninggal diantara kami, yang hadir dan yang tidak hadir diantara kami, lelaki dan perempuan diantara kami, anak kecil dan orang dewasa diantara kami.\""},"3467":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا أَبُو غِفَارٍ حَدَّثَنِي عَلْقَمَةُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ حَدَّثَنِي رَجُلٌ مِنْ قَوْمِي أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ ثَلَاثَ مِرَارٍ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُحْسِنْ إِلَى جَارِهِ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Abu Ghifar] telah menceritakan kepadaku ['Alqamah bin 'Abdullah Al Muzanni] telah menceritakan kepadaku [seseorang dari kaumku] bahwa ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa yang beriman kepada Allah dan hari akhir, hendaklah ia memuliakan tamunya -beliau mengucapkannya sebanyak tiga kali- barangsiapa yang beriman kepada Allah dan hari akhir, hendaklah berbuat baik terhadap tetangga, barangsiapa yang beriman kepada Allah dan hari akhir hendaklah berkata baik atau diam.\""},"3468":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ مُرَّةَ قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَةٍ حَمْرَاءَ مُخَضْرَمَةٍ فَقَالَ أَتَدْرُونَ أَيُّ يَوْمِكُمْ هَذَا قَالَ قُلْنَا يَوْمُ النَّحْرِ قَالَ صَدَقْتُمْ يَوْمُ الْحَجِّ الْأَكْبَرِ أَتَدْرُونَ أَيُّ شَهْرٍ شَهْرُكُمْ هَذَا قُلْنَا ذُو الْحِجَّةِ قَالَ صَدَقْتُمْ شَهْرُ اللَّهِ الْأَصَمُّ أَتَدْرُونَ أَيُّ بَلَدٍ بَلَدُكُمْ هَذَا قَالَ قُلْنَا الْمَشْعَرُ الْحَرَامُ قَالَ صَدَقْتُمْ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَوْ قَالَ كَحُرْمَةِ يَوْمِكُمْ هَذَا وَشَهْرِكُمْ هَذَا وَبَلَدِكُمْ هَذَا أَلَا وَإِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ أَنْظُرُكُمْ وَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تُسَوِّدُوا وَجْهِي أَلَا وَقَدْ رَأَيْتُمُونِي وَسَمِعْتُمْ مِنِّي وَسَتُسْأَلُونَ عَنِّي فَمَنْ كَذَبَ عَلَيَّ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ أَلَا وَإِنِّي مُسْتَنْقِذٌ رِجَالًا أَوْ إِنَاثًا وَمُسْتَنْقَذٌ مِنِّي آخَرُونَ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku ['Amru bin Murrah] berkata; Aku mendengar [Murrah] berkata; Telah menceritakan kepadaku [seorang sahabat] Nabi Shallallahu 'alaihi wa salam berkata; Rasulullah Shallallahu 'alaihi wa salam berdiri ditengah-tengah kami diatas unta merah dari Hadlramaut lalu beliau bersabda: \"Tahukah kalian, hari kalian ini hari apa?\" kami menjawab: Hari penyembelihan kurban. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Kalian benar, hari haji besar. Apa kalian tahu bulan kalian ini bulan apa?\" kami menjawab: Dzulhijjah. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Kalian benar, bulan Allah Yang Maha Kuat. Apa kalian tahu tempat apa ini?\" kami menjawab: Masy'arul haram. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Kalian benar.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \" darah kalian dan harta kalian haram bagi kalian seperti haramnya hari kalian ini, di bulan kalian ini dan ditempat kalian ini. Ingat! Aku mendahului kalian menuju telaga, aku menunggu kalian dan aku bangga jumlah kalian banyak melebihi ummat-ummat lain maka janganlah kalian memalukanku. Ingat! Kalian telah melihatku dan mendengarku, kalian akan dimintai pertanggung jawaban dariku. Barangsiapa berdusta atas namaku maka hendaklah mempersiapkan tempatnya dineraka. Ingat! aku menyelamatkan beberapa lelaki atau wanita atau orang-orang lain, aku bersabda: Wahai Rabb! Sahabat-sahabatku, lalu dikatakan: kau tidak tahu apa yang mereka perbuat sepeninggalmu.\""},"3469":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ حَدَّثَنَا حُيَيُّ بْنُ عَبْدِ اللَّهِ الْمَعَافِرِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ قَالَكُنَّا فِي الْبَحْرِ وَعَلَيْنَا عَبْدُ اللَّهِ بْنُ قَيْسٍ الْفَزَارِيُّ وَمَعَنَا أَبُو أَيُّوبَ الْأَنْصَارِيُّ فَمَرَّ بِصَاحِبِ الْمَقَاسِمِ وَقَدْ أَقَامَ السَّبْيَ فَإِذَا امْرَأَةٌ تَبْكِي فَقَالَ مَا شَأْنُ هَذِهِ قَالُوا فَرَّقُوا بَيْنَهَا وَبَيْنَ وَلَدِهَا قَالَ فَأَخَذَ بِيَدِ وَلَدِهَا حَتَّى وَضَعَهُ فِي يَدِهَا فَانْطَلَقَ صَاحِبُ الْمَقَاسِمِ إِلَى عَبْدِ اللَّهِ بْنِ قَيْسٍ فَأَخْبَرَهُ فَأَرْسَلَ إِلَى أَبِي أَيُّوبَ فَقَالَ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ فَرَّقَ بَيْنَ وَالِدَةٍ وَوَلَدِهَا فَرَّقَ اللَّهُ بَيْنَهُ وَبَيْنَ الْأَحِبَّةِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Abdullah bin Lahi'ah] Telah menceritakan kepada kami [Huyai bin 'Abdullah Al Ma'afiri] dari [Abu 'Abdur Rahman Al Hubali] berkata; Kami berada di laut, kami dipimpin oleh 'Abdullah bin Qais Al Fazari, kami bersama [Abu Ayyub Al Anshari], ia melewati pemilik harta rampasan perang yang menyuruh berdiri seorang tawanan, ternyata ada seorang wanita menangis, ia (Abu Ayyub) bertanya: Kenapa wanita itu? Mereka menjawab: Mereka memisahkannya dengan anaknya. Lalu Abu Ayyub meraih tangan anak wanita itu hingga disatukan dengan tangan ibunya, lalu pemilik harta rampasan perang mendatangi 'Abdullah bin Qais dan memberitahukan hal itu padanya, 'Abdullah mengirim utusan untuk menemui Abu Ayyub dan menanyakan: Kenapa kau melakukannya? Abu Ayyub menjawab: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa memisahkan seorang ibu dengan anaknya, Allah memisahkannya dengan orang-orang yang ia cintai pada hari kiamat.\""},"3470":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ يَحْيَى بْنِ جَابِرٍ قَالَ سَمِعْتُ ابْنَ أَخِي أَبِي أَيُّوبَ الْأَنْصَارِيِّ يَذْكُرُ عَنْ أَبِي أَيُّوبَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهَا سَتُفْتَحُ عَلَيْكُمْ الْأَمْصَارُ وَسَيَضْرِبُونَ عَلَيْكُمْ بُعُوثًا يُنْكِرُ الرَّجُلُ مِنْكُمْ الْبَعْثَ فَيَتَخَلَّصُ مِنْ قَوْمِهِ وَيَعْرِضُ نَفْسَهُ عَلَى الْقَبَائِلِ يَقُولُ مَنْ أَكْفِيهِ بَعْثَ كَذَا وَكَذَا أَلَا وَذَلِكَ الْأَجِيرُ إِلَى آخِرِ قَطْرَةٍ مِنْ دَمِهِحَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ هُو ابْنُ بَرِّيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ الْخَوْلَانِيُّ حَدَّثَنَا أَبُو سَلَمَةَ سُلَيْمَانُ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ أَخْبَرَنِي ابْنُ أَخِي أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَنَّهُ كَتَبَ إِلَيْهِ أَبُو أَيُّوبَ يُخْبِرُهُ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yazid bin 'Abdu Rabbih] Telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepadaku [Abu Salamah] dari [Yahya bin Jabir] berkata; Aku mendengar [keponakan Abu Ayyub Al Anshari] menyebutkan dari [Abu Ayyub] berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Beberapa wilayah akan ditaklukkan, dan mereka akan mengutus beberapa suka relawan perang untuk kalian, namun seseorang diantara kalian mengingkari suka relawan perang itu hingga sukarelawan itu melarikan diri dari kaumnya kemudian mendatangi kabilah-kabilah, ia berkata; Siapa yang mau menanggung diriku? Dan juga sukarelawan-sukarelawan perang yang lain? Bukankah itu semua memperoleh pahala hingga tetesan darah terakhirnya?. Telah menceritakan kepada kami ['Ali bin Bahr bin Barri] Telah menceritakan kepada kami [Muhammad bin Harb Al Khaulani] Telah menceritakan kepada kami [Abu Salamah Sulaiman] dari [Yahya bin Jabir Ath Tho`i] telah menceritakan kepadaku [keponakan Abu Ayyub Al Anshari] bahwa [Abu Ayyub] mengirim surat padanya seraya memberitahukan padanya bahwa ia mendengar Rasulullah Shallallahu 'alaihi wa salam, lalu ia menyebutkannya."},"3471":{"ar":"حَدَّثَنَا الْمُقْرِيُّ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ حَدَّثَنَا أَبُو رُهْمٍ السَّمَعِيُّ أَنَّ أَبَا أَيُّوبَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَاءَ يَعْبُدُ اللَّهَ لَا يُشْرِكُ بِهِ شَيْئًا وَيُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَصُومُ رَمَضَانَ وَيَجْتَنِبُ الْكَبَائِرَ فَإِنَّ لَهُ الْجَنَّةَ وَسَأَلُوهُ مَا الْكَبَائِرُ قَالَ الْإِشْرَاكُ بِاللَّهِ وَقَتْلُ النَّفْسِ الْمُسْلِمَةِ وَفِرَارٌ يَوِمَ الزَّحْفِ","id":"Telah menceritakan kepada kami [Al Muqri] Telah menceritakan kepada kami [Haiwah bin Syuraih] Telah menceritakan kepada kami [Baqiyah] telah menceritakan kepadaku [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] Telah menceritakan kepada kami [Abu Ruhm As Sama'i] bahwa [Abu Ayyub] bercerita padanya bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa datang dalam keadaan menyembah Allah tanpa menyekutukanNya dengan apa pun, mendirikan shalat, menunaikan zakat, puasa ramadhan dan menjauhi dosa-dosa besar, ia mendapatkan surga.\" Mereka bertanya: Apa itu dosa besar? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Menyekutukan Allah, membunuh seorang muslim dan melarikan diri saat perang.\""},"3472":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا ابْنُ هُبَيْرَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ أَنَّ أَبَا أَيُّوبَ الْأَنْصَارِيَّ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَصْعَةٍ فِيهَا بَصَلٌ فَقَالَ كُلُوا وَأَبَى أَنْ يَأْكُلَ وَقَالَ إِنِّي لَسْتُ كَمِثْلِكُمْ","id":"Telah menceritakan kepada kami [Hasan] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Ibnu Hubairah] dari [Abu 'Abdur Rahman Al Hubali] bahwa [Abu Ayyub Al Anshari] berkata; Rasulullah Shallallahu 'alaihi wa salam dihidangi sebuah piring yang ada bawang merahnya, beliau bersabda: \"Makanlah.\" Beliau enggan makan dan beliau bersabda: \" Aku tidak seperti kalian.\""},"3473":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ حَدَّثَنَا أَبُو قَبِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ نَاشِرٍ مِنْ بَنِي سَرِيعٍ قَالَ سَمِعْتُ أَبَا رُهْمٍ قَاصَّ أَهْلِ الشَّامِ يَقُولُ سَمِعْتُ أَبَا أَيُّوبَ الْأَنْصَارِيَّ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ ذَاتَ يَوْمٍ إِلَيْهِمْ فَقَالَ لَهُمْ إِنَّ رَبَّكُمْ عَزَّ وَجَلَّ خَيَّرَنِي بَيْنَ سَبْعِينَ أَلْفًا يَدْخَلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ وَبَيْنَ الْخَبِيئَةِ عِنْدَهُ لِأُمَّتِي فَقَالَ لَهُ بَعْضُ أَصْحَابِهِ يَا رَسُولَ اللَّهِ أَيُخَبِّئُ ذَلِكَ رَبُّكَ عَزَّ وَجَلَّ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ خَرَجَ وَهُوَ يُكَبِّرُ فَقَالَ إِنَّ رَبِّي عَزَّ وَجَلَّ زَادَنِي مَعَ كُلِّ أَلْفٍ سَبْعِينَ أَلْفًا وَالْخَبِيئَةُ عِنْدَهُ قَالَ أَبُو رُهْمٍ يَا أَبَا أَيُّوبَ وَمَا تَظُنُّ خَبِيئَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَهُ النَّاسُ بِأَفْوَاهِهِمْ فَقَالُوا وَمَا أَنْتَ وَخَبِيئَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو أَيُّوبَ دَعُوا الرَّجُلَ عَنْكُمْ أُخْبِرْكُمْ عَنْ خَبِيئَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَظُنُّ بَلْ كَالْمُسْتَيْقِنِ إِنَّ خَبِيئَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُولَ رَبِّ مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ مُصَدِّقًا لِسَانَهُ قَلْبُهُ أَدْخِلْهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Abu Qabil] dari ['Abdullah bin Nasyir dari Bani Sari'] berkata; Aku mendengar [Abu Ruhm, ahli ceramah penduduk Syam] berkata; Aku mendengar [Abu Ayyub Al Anshari] berkata; Pada suatu hari Rasulullah Shallallahu 'alaihi wa salam menemui mereka lalu bersabda: \" Rabb kalian menawariku antara tujuhpuluh ribu umatku masuk surga tanpa hisab atau simpanan disisiNya untuk ummatku.\" Sebagian sahabat bertanya kepada beliau: Wahai Rasulullah! Apakah Rabb baginda menyembunyikannya?. Rasulullah Shallallahu 'alaihi wa salam masuk rumah lalu keluar, beliau bertakbir lalu bersabda: \" Rabbku menambahiku, setiap seribunya bersama tujuhpuluh ribu, dan simpanan disisiNya.\" Berkata Abu Ruhm: Hai Abu Ayyub! Menurutmu, simpanan Rasulullah Shallallahu 'alaihi wa salam itu apa? lalu orang-orang memakannya dengan mulut-mulut mereka. Mereka bertanya: menurutmu, apa maksud simpanan Rasulullah Shallallahu 'alaihi wa salam? Berkata Abu Ayyub: Biarkan orang itu dan aku akan memberitahu kalian tentang simpanan Rasulullah Shallallahu 'alaihi wa salam seperti yang aku kira, bahkan seperti orang yang yakin bahwa simpanan Rasulullah Shallallahu 'alaihi wa salam adalah firman Rabb: \"Barangsiapa bersaksi bahwa tidak ada ilah (yang haq) kecuali Allah semata, tidak ada sekutu bagiNya dan bahwa Muhammad adalah hamba dan utusanNya seraya lisannya membenarkan hatinya, Aku memasukkannya ke surga.\""},"3474":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ أَخْبَرَنَا بَقِيَّةُ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي أَيُّوبَ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ اقْتَرَعَتْ الْأَنْصَارُ أَيُّهُمْ يُؤْوِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَعَهُمْ أَبُو أَيُّوبَ فَآوَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا أُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامٌ أُهْدِيَ لِأَبِي أَيُّوبَ قَالَ فَدَخَلَ أَبُو أَيُّوبَ يَوْمًا فَإِذَا قَصْعَةٌ فِيهَا بَصَلٌ فَقَالَ مَا هَذَا فَقَالُوا أَرْسَلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاطَّلَعَ أَبُو أَيُّوبَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا مَنَعَكَ مِنْ هَذِهِ الْقَصْعَةِ قَالَ رَأَيْتُ فِيهَا بَصَلًا قَالَ وَلَا يَحِلُّ لَنَا الْبَصَلُ قَالَ بَلَى فَكُلُوهُ وَلَكِنْ يَغْشَانِي مَا لَا يَغْشَاكُمْ وَقَالَ حَيْوَةُ إِنَّهُ يَغْشَانِي مَا لَا يَغْشَاكُمْ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah mengkhabarkan kepada kami [Baqiyah] dari [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Abu Ayyub] berkata; Saat Rasulullah Shallallahu 'alaihi wa salam tiba di Madinah, kaum Anshar membuat undian siapa diantara mereka yang memberi tempat untuk Rasulullah Shallallahu 'alaihi wa salam. Abu Ayyub mendapatkan undian lalu ia memberi tempat untuk Rasulullah Shallallahu 'alaihi wa salam, bila Rasulullah Shallallahu 'alaihi wa salam diberi hadiah makanan, maka hadiah itu otomatis dihadiahkan kepada Abu Ayyub. Pada suatu hari Abu Ayyub masuk, ternyata disana ada piring yang ada bawang merahnya. Abu Ayyub bertanya: Apa ini? Mereka menjawab: Rasulullah Shallallahu 'alaihi wa salam mengirimnya. Kemudian Abu Ayyub mendatangi Nabi Shallallahu 'alaihi wa salam dan berkata; Wahai Rasulullah! Apa yang menghalangimu dari piring ini? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku lihat ada bawang merahnya.\" Berkata Abu Ayyub: Tidak halalkah bawang merah bagi kita? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Halal, makanlah, hanya karena ada sesuatu yang aku merasa terganggu dan kalian tidak merasakannya.\" Berkata [Haiwah] dalam riwayatnya: \" Aku merasa terganggu, yang kalian tidak merasakannya.\""},"3475":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ فِيهِحَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ مُحَمَّدٍ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] Telah menceritakan kepada kami [Baqiyah] telah menceritakan kepadaku [Bahirah bin Sa'ad] dari [Khalid bin Ma'dan] dari [Al Miqdam bin M'adikarib] dari [Abu Ayyub Al Anshari] bahwa Nabi Shallallahu 'alaihi wa salam bersabda: \"Takarlah makanan kalian niscaya kalian akan diberkahi.\" Telah menceritakan kepada kami ['Abdul Jabbar bin Muhammad] Telah menceritakan kepada kami [Baqiyah] dari [Bahir] lalu ia menyebut sepertinya."},"3476":{"ar":"حَدَّثَنَا هَيْثَمٌ يَعْنِي ابْنَ خَارِجَةَ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Haitsam bin Kharijah] Telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib] dari [Abu Ayyub Al Anshari] berkata; Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Takarlah makanan kalian niscaya kalian akan diberkahi.\""},"3477":{"ar":"حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ حَدَّثَنَا رِشْدِينُ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ أَبِي إِسْحَاقَ مَوْلَى بَنِي هَاشِمٍ حَدَّثَهُمْأَنَّهُمْ ذَكَرُوا يَوْمًا مَا يُنْتَبَذُ فِيهِ فَتَنَازَعُوا فِي الْقَرْعِ فَمَرَّ بِهِمْ أَبُو أَيُّوبَ الْأَنْصَارِيُّ فَأَرْسَلُوا إِلَيْهِ إِنْسَانًا فَقَالَ يَا أَبَا أَيُّوبَ الْقَرْعُ يُنْتَبَذُ فِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ كُلِّ مُزَفَّتٍ يُنْتَبَذُ فِيهِ فَرَدَّ عَلَيْهِ الْقَرْعَ فَرَدَّ أَبَا أَيُّوبَ مِثْلَ قَوْلِهِ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Yahya bin Ghailan] Telah menceritakan kepada kami [Risydin] telah mengkhabarkan kepadaku ['Amru bin Al Harits] dari [Bukair] dari [Abu Ishaq, budak Bani Hasyim]; Suatu hari mereka berbincang-bincang tentang kurma basah yang direndam agar menjadi anggur. Lantas mereka berselish paham perihal alqar'. Kemudian [Abu Ayyub Al Anshari] melewati mereka, mereka mengirim seseorang untuk menemuinya dan bertanya: Hai Abu Ayyub! Bagaimana menurutmu perihal alqar' yang digunakan untuk merendam anggur? Ia (Abu Ayyub Al Anshari) Berkata; Aku mendengar Rasulullah Shallallahu 'alaihi wa salam melarang muzaffat yang digunakan untuk mengoplos anggur. Lalu orang itu menyerahkan alqar' kepada Abu Ayyub Al Anshari dan Abu Ayyub Al Anshari menjawab seperti ucapan pertamanya. "},"3478":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا رِشْدِينُ حَدَّثَنِي حُيَيُّ بْنُ عَبْدِ اللَّهِ رَجُلٌ مِنْ يَحْصَبَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ فَرَّقَ بَيْنَ الْوَلَدِ وَوَالِدِهِ فِي الْبَيْعِ فَرَّقَ اللَّهُ عَزَّ وَجَلَّ بَيْنَهُ وَبَيْنَ أَحِبَّتِهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Risydin] telah menceritakan kepadaku [Huyai bin 'Abdullah], seseorang dari Yahshab dari [Abu 'Abdur Rahman Al Hulabi] dari [Abu Ayyub Al Anshari] dari Rasulullah Shallallahu 'alaihi wa salam bahwa beliau bersabda: \"Barangsiapa memisahkan antara anak dan ayahnya dalam jual beli (dalam penjualan budak), Allah 'azza wajalla memisahkannya dengan orang-orang tercintanya pada hari kiamat.\""},"3479":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ سَمِعَ عُرْوَةَ يَقُولُ أَنَا أَبُو حُمَيْدٍ السَّاعِدِيُّ قَالَاسْتَعْمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ ابْنُ اللُّتْبِيَّةِ عَلَى صَدَقَةٍ فَجَاءَ فَقَالَ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَقَالَ مَا بَالُ الْعَامِلِ نَبْعَثُهُ فَيَجِيءُ فَيَقُولُ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي أَفَلَا جَلَسَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ فَيَنْظُرَ أَيُهْدَى إِلَيْهِ أَمْ لَا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَأْتِي أَحَدٌ مِنْكُمْ مِنْهَا بِشَيْءٍ إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ إِنْ كَانَ بَعِيرًا لَهُ رُغَاءٌ أَوْ بَقَرَةً لَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رَأَيْنَا عُفْرَةَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ ثَلَاثًاوَزَادَ هِشَامُ بْنُ عُرْوَةَ قَالَ أَبُو حُمَيْدٍ سَمِعَ أُذُنِي وَأَبْصَرَ عَيْنِي وَسَلُوا زَيْدَ بْنَ ثَابِتٍ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dia mendengar [Urwah] berkata; bahwasanya [Abu Humaid As Sa'idi] berkata; Nabi Shallallahu 'Alaihi wa Salam menugaskan seseorang dari Al Azd bernama Ibnu Al Lutbiyyah untuk mengurus zakat, ia datang lalu berkata: Ini untuk Tuan dan ini hadiah yang diberikan padaku. Lalu Rasulullah Shallallahu 'Alaihi wa Salam berdiri diatas mimbar dan bersabda: \"Ada apa dengan seorang petugas yang kami utus lalu datang dan berkata; Ini untuk Tuan dan ini hadiah yang diberikan padaku. Kenapa ia tidak duduk saja dirumah ayahnya dan ibunya lalu menunggu apakah ada yang memberinya hadiah atau tidak. Demi Dzat yang jiwa Muhammad berada ditanganNya, tidaklah seorang dari kalian membawanya sedikit pun melaikan akan membawanya pada hari kiamat dilehernya meski berupa unta yang berbusa, sapi lemah atau kambing bercacat.\" Kemudian beliau mengangkat kedua tangan hingga kami melihat kelabunya tangan beliau lalu beliau bersabda: \"Ya Allah! Apakah telah aku sampaikan?\" beliau mengucapkannya sebanyak tiga kali. [Hisyam bin 'Urwah] menambahkan: Berkata [Abu Humaid]: Telingaku mendengar dan mataku melihat, tanyakan kepada Zaid bin Tsabit."},"3480":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَسَمِعْتُهُ وَهُوَ فِي عَشَرَة�� مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمْ أَبُو قَتَادَةَ بْنُ رِبْعِيٍّ يَقُولُ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا لَهُ مَا كُنْتَ أَقْدَمَنَا صُحْبَةً وَلَا أَكْثَرَنَا لَهُ تَبَاعَةً قَالَ بَلَى قَالُوا فَاعْرِضْ قَالَ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ اعْتَدَلَ قَائِمًا وَرَفَعَ يَدَيْهِ حَتَّى حَاذَى بِهِمَا مَنْكِبَيْهِ فَإِذَا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ قَالَ اللَّهُ أَكْبَرُ فَرَكَعَ ثُمَّ اعْتَدَلَ فَلَمْ يَصُبَّ رَأْسَهُ وَلَمْ يَقْنَعْهُ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ رَفَعَ وَاعْتَدَلَ حَتَّى رَجَعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ مُعْتَدِلًا ثُمَّ هَوَى سَاجِدًا وَقَالَ اللَّهُ أَكْبَرُ ثُمَّ جَافَى وَفَتَحَ عَضُدَيْهِ عَنْ بَطْنِهِ وَفَتَحَ أَصَابِعَ رِجْلَيْهِ ثُمَّ ثَنَى رِجْلَهُ الْيُسْرَى وَقَعَدَ عَلَيْهَا وَاعْتَدَلَ حَتَّى رَجَعَ كُلُّ عَظْمٍ فِي مَوْضِعِهِ ثُمَّ هَوَى سَاجِدًا وَقَالَ اللَّهُ أَكْبَرُ ثُمَّ ثَنَى رِجْلَهُ وَقَعَدَ عَلَيْهَا حَتَّى يَرْجِعَ كُلُّ عُضْوٍ إِلَى مَوْضِعِهِ ثُمَّ نَهَضَ فَصَنَعَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ حَتَّى إِذَا قَامَ مِنْ السَّجْدَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا صَنَعَ حِينَ افْتَتَحَ الصَّلَاةَ ثُمَّ صَنَعَ كَذَلِكَ حَتَّى إِذَا كَانَتْ الرَّكْعَةُ الَّتِي تَنْقَضِي فِيهَا الصَّلَاةُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَقَعَدَ عَلَى شِقِّهِ مُتَوَرِّكًا ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdul Hamid bin Ja'far], dia berkata; telah menceritakan kepadaku [Muhammad bin Atha'] dari [Abu Humaid As Sa'idi] berkata; -aku mendengarnya dan dia berada diantara sepuluh orang sahabat Nabi shallallahu 'alaihi wasallam diantaranya ada Abu Qatadah bin Rabi'- dia berkata; aku lebih mengetahui shalat Rasulullah shallallahu 'alaihi wasallam dibanding kalian, mereka berkata kepadanya; mengapa demikian, bukanlah kami lebih dulu menjadi sahabat dan bukanlah kami lebih banyak menyertai beliau? Dia berkata; benar. Mereka berkata; lalu jelaskanlah. Dia berkata; apabila beliau hendak mendirikan shalat maka beliau berdiri tegak lalu mengangkat kedua tangannya hingga keduanya sejajar dengan pundak dan apabila beliau hendak ruku' maka beliau mengangkat tangannya hingga keduanya sejajar dengan pundak lalu membaca ALLAHU AKBAR lalu beliau ruku' kemudian meluruskan (punggung dan kepala) tidak menundukkan kepala dan juga tidak menengadah dan meletakkan kedua tangannya di lutut kemudian beliau membaca SAMI'ALLAHU LIMAN HAMIDAHU kemudian beliau meruluskan (badan) sehingga semua tulang beliau kembali pada tempat semula kemudian beliau turun sujud seraya mengucapkan ALLAHU AKBAR lalu merenggangkan dan membuka kedua tangannya dari kedua lambungnya dan membuka jari-jari kakinya, kemudian beliau melipat kaki kirinya dan mendudukinya dengan tegak hingga semua tulang kembali ke posisi semula, setelah itu beliau sujud dan membaca ALLAHU AKBAR lalu beliau melipat kaki kirinya dan mendudukinya hingga semua tulang kembali ke posisinya, kemudian beliau bangkit berdiri. beliau mengerjakan seperti itu di raka'at yang kedua hingga apabila beliau bangkit dari dua sujud beliau bertakbir dan mengangkat tangan hingga sejajar dengan pundak sebagaimana yang beliau perbuat ketika memulai shalat, kemudia beliau berbuat seperti itu hingga beliau berada pada rakaat yang terakhir, beliau mengubah posisi kaki kiri dan duduk pada betisnya secara tawaruk (dengan posisi kaki kiri masuk ke kaki kanan) kemudian beliau salam."},"3481":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ أَنَّهُ قَالَ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّ أَنَّهُمْ قَالُوايَا رَسُولَ اللَّهِ كَيْفَ نُصَلِّي عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"perawi berkata; saya membacakan riwayat kepada [Abdurrahman]: [Malik] dari [Abdullah bin Abu Bakar] dari [ayahnya] dari [Amru bin Sulaim] bahwasanya dia berkata; telah mengabarkan kepadaku [Abu Humaid As Sa'idi] bahwasanya mereka berkata; wahai Rasulullah bagaimana caranya kami bershalawat kepadamu? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"maka ucapkanlah ALLAHUMMA SHALLI 'ALA MUHAMMAD WA AZWAJIHI WA DZURRIYATIHI KAMA SHALLAITA 'ALA 'ALI IBRAHIM WA BARIK 'ALA MUHAMMAD WA AZWAJIHI WA DZURRIYATIHI KAMA BARAKTA 'ALA 'ALI IBRAHIM INNAKA HAMIDUN MAJIID."},"3482":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَدَايَا الْعُمَّالِ غُلُولٌ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Yahya bin Sa'id] dari [Urwah bin Az Zubair] dari [Abu Humaid As Sa'idi] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"hadiah bagi para kuli adalah ghulul (hasil ghanimah yang diambil secara sembunyi-senmbunyi sebelum pembagiannya)."},"3483":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ عَنْ أَبِي حُمَيْدٍ أَوْ حُمَيْدَةَ الشَّكُّ مِنْ زُهَيْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ أَحَدُكُمْ امْرَأَةً فَلَا جُنَاحَ عَلَيْهِ أَنْ يَنْظُرَ إِلَيْهَا إِذَا كَانَ إِنَّمَا يَنْظُرُ إِلَيْهَا لِخِطْبَتِهِ وَإِنْ كَانَتْ لَا تَعْلَمُ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Zuhair] dari [Abdullah bin Isa] dari [Musa bin Abdullah] dari [Abu Humaid atau Humaidah], keraguan ada pada Zuhair, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"jika seseorang dari kalian melamar seorang wanita, maka tidak mengapa baginya untuk melihat wanita tersebut, hanya saja dia melihatnya hanya untuk melamarnya saja meskipun wanita tersebut tidak mengetahuinya."},"3484":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِيسَى حَدَّثَنِي مُوسَى بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي حُمَيْدٍ أَوْ أَبِي حُمَيْدَةَ قَالَ وَقَدْ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ أَحَدُكُمْ امْرَأَةً فَلَا جُنَاحَ عَلَيْهِ أَنْ يَنْظُرَ إِلَيْهَا إِذَا كَانَ إِنَّمَا يَنْظُرُ إِلَيْهَا لِخِطْبَتِهِ وَإِنْ كَانَتْ لَا تَعْلَمُ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdullah bin Isa] telah menceritakan kepadaku [Musa bin Abdullah bin Yazid] dari [Abu Humaid atau Humaidah], dia berkata; dia telah melihat Rasulullah shallallahu 'alaihi wasallam, bersabda Rasulullah shallallahu 'alaihi wasallam: \"jika seorang kalian melamar seorang wanita, maka tidak mengapa baginya melihat wanita tersebut apabila dia melihatnya hanya dalam rangka untuk melamarnya meskipun wanita tersebut tidak mengetahuinya\"."},"3485":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنِ الْعَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ تَبُوكَ حَتَّى جِئْنَا وَادِيَ الْقُرَى فَإِذَا امْرَأَةٌ فِي حَدِيقَةٍ لَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ اخْرُصُوا فَخَرَصَ الْقَوْمُ وَخَرَصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشَرَةَ أَوْسُقٍ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمَرْأَةِ أَحْصِي مَا يَخْرُجُ مِنْهَا حَتَّى أَرْجِعَ إِلَيْكِ إِنْ شَاءَ اللَّهُ قَالَ فَخَرَجَ حَتَّى قَدِمَ تَبُوكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَبِيتُ عَلَيْكُمْ اللَّيْلَةَ رِيحٌ شَدِيدَةٌ فَلَا يَقُومُ مِنْكُمْ فِيهَا رَجُلٌ فَمَنْ كَانَ لَهُ بَعِيرٌ فَلْيُوثِقْ عِقَالَهُ قَالَ قَالَ أَبُو حُمَيْدٍ فَعَقَلْنَاهَا فَلَمَّا كَانَ مِنْ اللَّيْلِ هَبَّتْ عَلَيْنَا رِيحٌ شَدِيدَةٌ فَقَامَ فِيهَا رَجُلٌ فَأَلْقَتْهُ فِي جَبَلِ طَيِّئٍ ثُمَّ جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَلِكُ أَيْلَةَ فَأَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةً بَيْضَاءَ فَكَسَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدًا وَكَتَبَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَحْرِهِ قَالَ ثُمَّ أَقْبَلَ وَأَقْبَلْنَا مَعَهُ حَتَّى جِئْنَا وَادِيَ الْقُرَى فَقَالَ لِلْمَرْأَةِ كَمْ حَدِيقَتُكِ قَالَتْ عَشَرَةُ أَوْسُقٍ خَرْصُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي مُتَعَجِّلٌ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَتَعَجَّلَ فَلْيَفْعَلْ قَالَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجْنَا مَعَهُ حَتَّى إِذَا أَوْفَى عَلَى الْمَدِينَةِ قَالَ هِيَ هَذِهِ طَابَةُ فَلَمَّا رَأَى أُحُدًا قَالَ هَذَا أُحُدٌ يُحِبُّنَا وَنُحِبُّهُ أَلَا أُخْبِرُكُمْ بِخَيْرِ دُورِ الْأَنْصَارِ قَالَ قُلْنَا بَلَى يَا رَسُولَ اللَّهِ قَالَ خَيْرُ دُورِ الْأَنْصَارِ بَنُو النَّجَّارِ ثُمَّ دَارُ بَنِي عَبْدِ الْأَشْهَلِ ثُمَّ دَارُ بَنِي سَاعِدَةَ ثُمَّ فِي كُلِّ دُورِ الْأَنْصَارِ خَيْرٌ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Wuhaib bin Khalid] telah bercerita kepada kami ['Amru bin Yahya] dari [Al 'Abbas bin Sahal bin Sa'ad As Sa'idi] dari [Abu Humaid As Sa'idi] berkata: Kami pergi bersama Rasulullah Shallallahu 'Alaihi wa Salam saat perang Tabuk hingga kami tiba di lembah Quraa, disana ada seorang wanita dikebun miliknya lalu Rasulullah Shallallahu 'Alaihi wa Salam bersabda kepada para sahabat beliau: \"Perkirakanlah.\" Orang-orang membuat perkiraan dan Rasulullah Shallallahu 'Alaihi wa Salam memperkirakan sebanyak lima wasaq. Rasulullah Shallallahu 'Alaihi wa Salam bersabda kepada wanita itu: \"Hitunglah kurma yang dihasilkan hingga aku akan kembali menemuimu lagi insya Allah.\" Rasulullah Shallallahu 'Alaihi wa Salam pergi hingga sampai di Tabuk lalu beliau bersabda: \"Sesunggunya dimalam ini akan ada angin kencang, maka jangan ada seorang pun diantara kalian yang berdiri, yang punya unta hendaklah menguatkan ikatannya.\" Berkata Abu Hamid: Kami mengikat unta kemudian pada malam harinya angin kencang menerpa kami lalu seseorang berdiri hingga terpental ke gunung Thayyi` lalu penguasa Ailah mendatangi Rasulullah Shallallahu 'Alaihi wa Salam dan memberi hadiah seekor keledai putih, kemudian Rasulullah Shallallahu 'Alaihi wa Salam mengenakan selimut pada keledai itu kemudian beliau memberi tulisan dikuda orang itu. Selanjutnya beliau pulang dan kami pun turut bergegas hingga tiba di lembah Quraa, beliau bersabda kepada wanita itu: \"Berapa banyak hasil kebunmu?\" wanita itu menjawab: Sepuluh wasaq, seperti yang Rasulullah Shallallahu 'Alaihi wa Salam perkirakan. Rasulullah Shallallahu 'Alaihi wa Salam bersabda: \"Sesungguhnya aku terburu-buru, maka barangsiapa diantara kalian yang ingin segera pulang silahkan lakukan.\" Rasulullah Shallallahu 'Alaihi wa Salam berangkat dan kami juga berangkat bersama beliau hingga tiba di Madinah, beliau bersabda: \"Inilah dia yang baik.\" Saat melihat seseorang, beliau bersabda: \"Dia adalah orang yang mencintai kami dan kami mencintainya. Maukah kalian aku beritahu rumah-rumah kaum Anshar yang terbaik?\" mereka menjawab: Ya, wahai Rasulullah! Rasulullah Shallallahu 'Alaihi wa Salam bersabda: \"Rumah-rumah kaum Anshar yang terbaik adalah rumah-rumah Bani An Najjar, Bani 'Abdul Asyhal, Bani Sa'idah kemudian semua rumah-rumah kaum Anshar itu baik.\""},"3486":{"ar":"و قَالَ عُبَيْدُ بْنُ أَبِي قُرَّةَ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنِي سُهَيْلُ بْنُ أَبِي صَالِحٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ سَعِيدٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِلرَّجُلِ أَنْ يَأْخُذَ عَصَا أَخِيهِ بِغَيْرِ طِيبِ نَفْسِهِ وَذَلِكَ لِشِدَّةِ مَا حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَالِ الْمُسْلِمِ عَلَى الْمُسْلِمِ","id":"Dan [Ubaid bin Abu Qurrah] telah menceritakan kepada kami [Sulaiman] telah menceritakan kepadaku [Suhail bin Abu Shalih] telah menceritakan kepadaku [Abdurrahman bin Sa'id] dari [Abu Humaid As Sa'idi] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang mengambil tongkat saudaranya tanpa kerelaan dari dirinya karena Rasulullah shallallahu 'alaihi wasallam sangat mengharamkan harta seorang muslim atas muslim lain.\""},"3487":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ عَنْ أَبِي حُمَيْدٍ وَأَبِي أُسَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ الْحَدِيثَ عَنِّي تَعْرِفُهُ قُلُوبُكُمْ وَتَلِينُ لَهُ أَشْعَارُكُمْ وَأَبْشَارُكُمْ وَتَرَوْنَ أَنَّهُ مِنْكُمْ قَرِيبٌ فَأَنَا أَوْلَاكُمْ بِهِ وَإِذَا سَمِعْتُمْ الْحَدِيثَ عَنِّي تُنْكِرُهُ قُلُوبُكُمْ وَتَنْفِرُ مِنْهُ أَشْعَارُكُمْ وَأَبْشَارُكُمْ وَتَرَوْنَ أَنَّهُ مِنْكُمْ بَعِيدٌ فَأَنَا أَبْعَدُكُمْ مِنْهُ وَشَكَّ فِيهِمَا عُبَيْدُ بْنُ أَبِي قُرَّةَ فَقَالَ عَنْ أَبِي حُمَيْدٍ أَوْ أَبِي أُسَيْدٍ وَقَالَ تَرَوْنَ أَنَّكُمْ مِنْهُ قَرِيبٌ وَشَكَّ أَبُو سَعِيدٍ فِي أَحَدِهِمَا فِي إِذَا سَمِعْتُمْ الْحَدِيثَ عَنِّي","id":"Telah bercerita kepada kami [Abu 'Amir] telah bercerita kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abu 'Abdur Rahman] dari ['Abdul Malik bin Sa'id bin Suwaid] dari [Abu Humaid] dan [Abu Usaid] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Bila kalian mendengar hadits dariku yang dikenal oleh hati kalian, perasaan dan kulit kalian melunak karenanya dan kalian menganggap bahwa ia dekat dengan kalian maka aku paling berhak terhadapnya diantara kalian dan bila kalian mendengar hadits yang diingkari oleh hati kalian, perasaan dan kulit kalian menjauhinya dan kalian mengganggapnya ia jauh dari kalian maka aku adalah yang paling jauh darinya diantara kalian - ['Ubaid bin Abu Qurrah] ragu pada keduanya dan berkata: Dari [Abu Humaid] atau [Abu Usaid] dan berkata dalam riwayatnya: Kalian menganggap bahwa kalian dekat dengannya -Abu Sa'id ragu pada salah satu dari keduanya pada bagian: Bila kalian mendengar hadits dariku."},"3488":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ الْأَنْصَارِيِّ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ وَأَبَا أُسَيْدٍ يَقُولَانِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ فَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"Telah bercerita kepada kami [Abu 'Amir] telah bercerita kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abu 'Abdur Rahman] dari ['Abdul Malik bin Sa'id bin Suwaid Al Anshari] berkata: Aku mendengar [Abu Humaid] dan [Abu Usaid] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila salah seorang diantara kalian masuk masjid hendaklah mengucapkan: ALLAHUMMAFTAHLII ABWAABA RAHMATIKA (Ya Allah! Bukakanlah pintu-pintu rahmatMu untukku) dan bila keluar hendaklah mengucapkan: AS`ALUKA MIN FADLLIKA (aku memohon karuniaMu)."},"3489":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمْةَ عَنْ مُعَيْقِيبٍ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْحَ فِي الْمَسْجِدِ يَعْنِي الْحَصَى فَقَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَوَاحِدَةً","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Ad Dustuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Mu'aiqib] berkata: nabi shallallahu 'alaihi wasallam menyebutkan tentang membasuh kantong kemaluan dimasjid, beliau bersabda: \"Bila kau tidak bisa tidak melakukannya maka sekali saja.\""},"3490":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ حَدَّثَنِي مُعَيْقِيبٌ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْحُ فِي الْمَسْجِدِ يَعْنِي الْحَصَى فَقَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَوَاحِدَةً","id":"Telah bercerita kepada kami [Yahya bin Sa'id] telah bercerita kepada kami [Hisyam] telah bercerita kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] telah bercerita kepadaku [Mu'aiqib] berkata: Dikatakan kepada nabi shallallahu 'alaihi wasallam tentang membasuh kantong kemaluan dimasjid, beliau bersabda: \"Bila kau tidak bisa tidak melakukannya maka sekali saja.\""},"3491":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ مُعَيْقِيبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah bercerita kepada kami [Khalaf bin Al Walid] telah bercerita kepada kami [Ayyub bin 'Utbah] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Mu'aiqib] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah tumit-tumit (yang tidak tersentuh air, merupakan bagian) dari neraka.\""},"3492":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ حَدَّثَنِي مُعَيْقِيبٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الرَّجُلِ يُسَوِّي التُّرَابَ حَيْثُ يَسْجُدُ قَالَ إِنْ كُنْتَ فَاعِلًا فَوَاحِدَةً","id":"Telah bercerita kepada kami [Yahya bin Abu Bukair] telah bercerita kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] telah bercerita kepadaku [Mu'aiqib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda tentang orang yang meratakan tanah saat sujud: \"Bila kau tidak bisa tidak melakukannya maka sekali saja.\""},"3493":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَطَاءٍ عَنْ نَفَرٍ مِنْ بَنِي سَلِمَةَ قَالُواكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا فَشَقَّ ثَوْبَهُ فَقَالَ إِنِّي وَاعَدْتُ هَدْيًا يُشْعَرُ الْيَوْمَ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Hisyam bin Sa'id] dari [Zaid bin Aslam] dari ['Abdur Rahman bin 'Atho`] dari [beberapa orang] dari Bani Salamah, mereka berkata: Nabi shallallahu 'alaihi wasallam duduk lalu beliau merobek baju beliau kemudian bersabda: \"Sesungguhnya aku menjanjikan hadiah yang dirasakan hari ini.\""},"3494":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا زُهَيْرٌ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي طِخْفَةَ الْغِفَارِيِّ قَالَ أَخْبَرَنِي أَبِي أَنَّهُضَافَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ نَفَرٍ قَالَ فَبِتْنَا عِنْدَهُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ يَطَّلِعُ فَرَآهُ مُنْبَطِحًا عَلَى وَجْهِهِ فَرَكَضَهُ بِرِجْلِهِ فَأَيْقَظَهُ وَقَالَ هَذِهِ ضِجْعَةُ أَهْلِ النَّارِ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] telah bercerita kepada kami [Zuhair] dari [Muhammad bin 'Amru bin Halhalah] dari [Nu'aim bin 'Abdullah] dari [Abu Thikhfah Al Ghifari] berkata: Telah mengkhabarkan kepadaku [ayahku] bahwa ia bertamu ke kediaman Rasulullah shallallahu 'alaihi wasallam bersama beberapa orang. Berkata ayah Abu Thikfah: Kami menginap dirumah beliau kemudian dimalam harinya Rasulullah shallallahu 'alaihi wasallam keluar memeriksa, beliau melihatnya menelungkupkan wajah lalu beliau menggerak-gerakkannya dengan kaki beliau dan membangunkannya, beliau bersabda: \"Ini adalah telungkupan penghuni neraka.\""},"3495":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ يَعِيشَ بْنِ طِخْفَةَ الْغِفَارِيِّ عَنْ أَبِيهِ قَالَضِفْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَنْ تَضَيَّفَهُ مِنْ الْمَسَاكِينِ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي اللَّيْلِ يَتَعَاهَدُ ضَيْفَهُ فَرَآنِي مُنْبَطِحًا عَلَى بَطْنِي فَرَكَضَنِي بِرِجْلِهِ وَقَالَ لَا تَضْطَجِعْ هَذِهِ الضِّجْعَةَ فَإِنَّهَا ضِجْعَةٌ يَبْغَضُهَا اللَّهُ عَزَّ وَجَلَّ","id":"Telah bercerita kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Muhammad bin 'Amru bin 'Atho`] dari [Ya'isy bin Thikfah Al Ghifari] dari [ayahnya] berkata: Aku bertamu ke kediaman Rasulullah shallallahu 'alaihi wasallam bersama orang-orang miskin yang beliau jamu, kemudian pada malam harinya Rasulullah shallallahu 'alaihi wasallam keluar memeriksa tamu beliau, beliau melihatku tengkurap, beliau menggerak-gerakkannya dengan kaki beliau dan membangunkannya, beliau bersabda: \"Jangan tengkurap karena sesungguhnya tengkurap itu dibenci Allah 'azza wajalla.\""},"3496":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ قَالَبَيْنَا أَنَا جَالِسٌ مَعَ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ إِذْ طَلَعَ عَلَيْنَا رَجُلٌ مِنْ بَنِي غِفَارٍ ابْنٌ لِعَبْدِ اللَّهِ بْنِ طِخْفَةَ فَقَالَ أَبُو سَلَمَةَ أَلَا تُخْبِرُنَا عَنْ خَبَرِ أَبِيكَ قَالَ حَدَّثَنِي أَبِي عَبْدُ اللَّهِ بْنُ طِخْفَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَثُرَ الضَّيْفُ عِنْدَهُ قَالَ لِيَنْقَلِبْ كُلُّ رَجُلٍ بِضَيْفِهِ حَتَّى إِذَا كَانَ ذَاتَ لَيْلَةٍ اجْتَمَعَ عِنْدَهُ ضِيفَانٌ كَثِيرٌ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَنْقَلِبْ كُلُّ رَجُلٍ مَعَ جَلِيسِهِ قَالَ فَكُنْتُ مِمَّنْ انْقَلَبَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا دَخَلَ قَالَ يَا عَائِشَةُ هَلْ مِنْ شَيْءٍ قَالَتْ نَعَمْ حُوَيْسَةُ كُنْتُ أَعْدَدْتُهَا لِإِفْطَارِكَ قَالَ فَجَاءَتْ بِهَا فِي قُعَيْبَةٍ لَهَا فَتَنَاوَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا قَلِيلًا فَأَكَلَهُ ثُمَّ قَالَ خُذُوا بِسْمِ اللَّهِ فَأَكَلْنَا مِنْهَا حَتَّى مَا نَنْظُرُ إِلَيْهَا ثُمَّ قَالَ هَلْ عِنْدَكِ مِنْ شَرَابٍ قَالَتْ نَعَمْ لُبَيْنَةٌ كُنْتُ أَعْدَدْتُهَا لَكَ قَالَ هَلُمِّيهَا فَجَاءَتْ بِهَا فَتَنَاوَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَهَا إِلَى فِيهِ فَشَرِبَ قَلِيلًا ثُمَّ قَالَ اشْرَبُوا بِسْمِ اللَّهِ فَشَرِبْنَا حَتَّى وَاللَّهِ مَا نَنْظُرُ إِلَيْهَا ثُمَّ خَرَجْنَا فَأَتَيْنَا الْمَسْجِدَ فَاضْطَجَعْتُ عَلَى وَجْهِي فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُوقِظُ النَّاسَ الصَّلَاةَ الصَّلَاةَ وَكَانَ إِذَا خَرَجَ يُوقِظُ النَّاسَ لِلصَّلَاةِ فَمَرَّ بِي وَأَنَا عَلَى وَجْهِي فَقَالَ مَنْ هَذَا فَقُلْتُ أَنَا عَبْدُ اللَّهِ بْنُ طِخْفَةَ فَقَالَ إِنَّ هَذِهِ ضِجْعَةٌ يَكْرَهُهَا اللَّهُ عَزَّ وَجَلَّ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Ibnu Abi Dzi`b] dari [Al Harits bin 'Abdur Rahman] berkata: Saat aku duduk bersama Abu Salamah bin 'Abdur Rahman, tiba-tiba seseorang dari Bani Ghifar [salah satu putra 'Abdullah bin Thikhfah] datang lalu Abu Salamah berkata: Maukah kau memberitahu kami khabar dari ayahmu? Ia berkata: Telah bercerita kepadaku [ayahku, 'Abdullah bin Thikhfah] bahwa bila banyak tamu dirumah Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Hendaklah masing-masing orang berbalik dengan tamunya.\" Kemudian pada suatu malam ada dua kelompok tamu banyak berkumpul dikediaman beliau, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah masing-masing orang berbalik dengan temannya.\" Dan aku termasuk orang yang berbalik bersama Rasulullah shallallahu 'alaihi wasallam. Saat beliau masuk, beliau bersabda: \"Hai 'A`isyah, apa ada sesuatu?\" 'A`isyah menjawab: Ya, sup yang sudah aku persiapkan untuk sarapan Tuan. Lalu 'A`isyah membawanya dalam tungku miliknya lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya sedikit dan memakannya kemudian beliau bersabda: \"Ambillah, bismillaah.\" Kami pun memakannya hingga tersisa seperti yang kami lihat. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa kau punya minuman?\" 'A`isyah berkata: Ya, susu yang telah aku persiapkan untuk Tuan.\" Beliau bersabda: \"Bawa kemari.\" 'A`isyah membawanya lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya, beliau mengangkat didekat mulut beliau, beliau minum sedikit kemudian beliau bersabda: \"Minumlah, bismillaah.\" Kami pun minum hingga demi Allah tersisa seperti yang kami lihat. Setelah itu kami keluar dan pergi ke masjid, aku menelungkupkan wajah lalu Rasulullah shallallahu 'alaihi wasallam keluar, beliau membangunkan orang-orang: \"Shalat shalat.\" Bila beliau keluar, beliau membangunkan orang-orang untuk shalat, beliau melewatiku saat wajahku terkelungkup, beliau bersabda: \"Siapa ini?\" aku menajwab: Saya, 'Abdullah bin Thikhfah. Beliau bersabda: \"Ini adalah telungkupan yang dibenci Allah 'azza wajalla.\""},"3497":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ يَعِيشَ بْنِ طِخْفَةَ الْغِفَارِيِّ قَالَكَانَ أَبِي مِنْ أَصْحَابِ الصُّفَّةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِمْ فَجَعَلَ يَنْقَلِبُ الرَّجُلُ بِالرَّجُلِ وَالرَّجُلَيْنِ حَتَّى بَقِيتُ خَامِسَ خَمْسَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقُوا فَانْطَلَقْنَا مَعَهُ إِلَى بَيْتِ عَائِشَةَ فَقَالَ يَا عَائِشَةُ أَطْعِمِينَا فَجَاءَتْ بِحَشِيشَةٍ فَأَكَلْنَا ثُمَّ جَاءَتْ بِحَيْسَةٍ مِثْلِ الْقَطَاةِ فَأَكَلْنَا ثُمَّ قَالَ يَا عَائِشَةُ اسْقِينَا فَجَاءَتْ بِعُسٍّ فَشَرِبْنَا ثُمَّ جَاءَتْ بِقَدَحٍ صَغِيرٍ فِيهِ لَبَنٌ فَشَرِبْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمْ بِتُّمْ وَإِنْ شِئْتُمْ انْطَلَقْتُمْ إِلَى الْمَسْجِدِ فَقُلْنَا لَا بَلْ نَنْطَلِقُ إِلَى الْمَسْجِدِ قَالَ فَبَيْنَا أَنَا فِي الْمَسْجِدِ مُضْطَجِعًا عَلَى بَطْنِي إِذَا رَجُلٌ يُحَرِّكُنِي بِرِجْلِهِ فَقَالَ إِنَّ هَذِهِ ضِجْعَةٌ يَبْغَضُهَا اللَّهُ فَنَظَرْتُ فَإِذَا هُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا هَاشِمٌ يَعْنِي ابْنَ الْقَاسِمِ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ أَخْبَرَنِي يَعِيشُ بْنُ قَيْسِ بْنِ طِخْفَةَ عَنْ أَبِيهِ وَكَانَ أَبُوهُ مِنْ أَهْلِ الصُّفَّةِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ انْطَلِقْ بِهَذَا مَعَكَ وَذَكَرَ مَعْنَاهُ","id":"Telah bercerita kepada kami [Isma'il bin Ibrahim] dari [Hisyam Ad Dustuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ya'isy bin Thikhfah Al Ghifari] berkata: [Ayahku] adalah sala satu penghuni emperan masjid lalu Rasulullah shallallahu 'alaihi wasallam memerintakan mereka agar setiap orang berbalik dengan satu dan dua orang hingga hanya tersisa satu dari seperlimanya lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah.\" Kami pergi bersama beliau ke rumah 'A`isyah, beliau bersabda: \"Hai 'A`isyah! Berilah kami makan.\" Ia membawa lalapan kamudian kami makan, ia membawa sup seperti burung, kami makan lalu beliau bersabda: \"Hai 'A`isyah! Berilah kami minum.\" Ia membawa bejana besar dan setelah itu ia membawa gelas kecil bersisi susu, kami minum kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila kalian mau menginap silahkan dan bila mau pergi ke masjid silahkan.\" Kami berkata: Kami akan pergi ke masjid. Berkata Thikhfah: Saat berada dimasjid, aku tidur terkelungkup, lalu ada seseorang menggerak-gerakkanku dengan kakinya, ia berkata: \"Ini adalah telungkupan yang dibenci Allah.\" Aku melihat ternyata ia adalah Rasulullah shallallahu 'alaihi wasallam. Telah bercerita kepada kami [Hasyim bin Al Qasim] telah bercerita kepada kami [Abu Mu'awiyah Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata: Telah mengkhabarkan kepadaku [Ya'isy bin Qais bin Thikhfah] dari [ayahnya] dan ayahnya adalah satu penghuni emperan masjid, berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hai fulan! Pergilah dengan membawa ini.\" Lalu ia menyebut makna hadits."},"3498":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ مَحْمُودِ بْنِ رَبِيعٍ وَقَدْكَانَ عَقَلَ مَجَّةً مَجَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِهِ مِنْ دَلْوٍ مِنْ بِئْرٍ لَهُمْ","id":"Telah bercerita kepada kami [Bahz] telah bercerita kepadaku [Ibrahim bin Sa'ad] telah bercerita kepadaku [Ibnu Syihab] dari [Mahmud bin Rabi'] ia membayar diyat timba yang dibuang di wajahnya oleh Rasulullah shallallahu 'alaihi wasallam dari salah satu sumur milik mereka."},"3499":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا شُعْبَةُ بْنُ الْحَجَّاجِ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ قَالَحَدَّثَنِي مَنْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أَحْجَارِ الزَّيْتِ يَدْعُو هَكَذَا وَأَشَارَ بِبَاطِنِ كَفَّيْهِ نَحْوَ وَجْهِهِ","id":"Telah bercerita kepada kami [Yazid] telah bercerita kepada kami [Syu'bah bin Al Hajjaj] dari ['Abdur Rabbih bin Sa'id] dari [Muhammad bin Ibrahim] berkata: Telah bercerita kepadaku [orang] yang pernah melihat Rasulullah shallallahu 'alaihi wasallam di Ahjar Zait berdoa seperti ini. Ia menghadapkan telapak tangannya ke wajah."},"3500":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا سُلَيْمَانُ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَحْمِي عَبْدَهُ الْمُؤْمِنَ مِنْ الدُّنْيَا وَهُوَ يَحْمِيهِ كَمَا تَحْمُونَ مَرِيضَكُمْ مِنْ الطَّعَامِ وَالشَّرَابِ تَخَافُونَهُ عَلَيْهِ","id":"Telah bercerita kepada kami [Abu Sa'id] telah bercerita kepada kami [Sulaiman] dari ['Amru bin Abu 'Amru] dari ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla sungguh menjaga hambaNya yang beriman dari dunia dan Ia menjaganya layaknya kalian menjaga orang-orang sakit dari makan dan minuman yang kalian khawatirkan membahayakannya.\""}};
